#![forbid(unsafe_code)]

//! Statistical distributions for FrankenSciPy.
//!
//! Matches `scipy.stats` core continuous distributions:
//! - `norm` — Normal (Gaussian) distribution
//! - `t` — Student's t-distribution
//! - `chi2` — Chi-squared distribution
//! - `uniform` — Uniform distribution
//!
//! Each distribution implements pdf, cdf, sf, ppf (inverse CDF), mean, var, std.

pub mod audit;
pub mod qmc;
pub use audit::{
    SyncSharedAuditLedger, record_bounded_recovery, record_fail_closed, sync_audit_ledger,
};
pub use qmc::{
    GeometricDiscrepancyMethod, HaltonSampler, LatinHypercubeSampler, PoissonDiskSampler,
    QmcEngine, SobolSampler, centered_discrepancy, geometric_discrepancy, l2_star_discrepancy,
    mixture_discrepancy, scale as qmc_scale, update_centered_discrepancy, wraparound_discrepancy,
};

use std::f64::consts::{FRAC_1_SQRT_2, LN_2, PI};

use fsci_runtime::RuntimeMode;
use rand::{Rng, RngExt, SeedableRng, rngs::StdRng, seq::SliceRandom};

const EULER_MASCHERONI: f64 = 0.577_215_664_901_532_9;
const KS_2SAMP_EXACT_MAX_CELLS: usize = 1_000_000;

/// Error type for stats APIs that validate structured inputs.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum StatsError {
    InvalidArgument(String),
    ShapeMismatch {
        expected: usize,
        actual: usize,
    },
    NonFiniteInput {
        argument: &'static str,
    },
    DataTooSmall {
        required: usize,
        got: usize,
    },
    MissingParameter {
        name: &'static str,
    },
    Unsupported {
        operation: &'static str,
        distribution: &'static str,
    },
    Arithmetic {
        detail: String,
    },
}

impl std::fmt::Display for StatsError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::InvalidArgument(msg) => write!(f, "invalid argument: {msg}"),
            Self::ShapeMismatch { expected, actual } => {
                write!(f, "shape mismatch: expected {expected}, got {actual}")
            }
            Self::NonFiniteInput { argument } => {
                write!(f, "non-finite input in {argument}")
            }
            Self::DataTooSmall { required, got } => {
                write!(f, "data too small: required {required}, got {got}")
            }
            Self::MissingParameter { name } => write!(f, "missing parameter: {name}"),
            Self::Unsupported {
                operation,
                distribution,
            } => write!(f, "{operation} is unsupported for {distribution}"),
            Self::Arithmetic { detail } => write!(f, "arithmetic failure: {detail}"),
        }
    }
}

impl std::error::Error for StatsError {}

/// Error type for `ContinuousDistribution::try_fit` — the non-panicking
/// counterpart to `fit()`. Callers that cannot tolerate a panic on
/// distributions without MLE support should use `try_fit` and match on
/// this error.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum FitError {
    /// MLE is not implemented for this distribution. The default
    /// `try_fit` returns this variant; individual distributions can
    /// override to provide a closed-form or numerical MLE.
    NotImplemented { distribution: &'static str },
    /// The provided sample is too small (or degenerate) to fit.
    InsufficientData { required: usize, actual: usize },
    /// The sample violates a distribution-specific support constraint
    /// (e.g. negative values for HalfNormal, data not in [0,1] for Beta).
    UnsupportedData(String),
    /// Numerical fitting did not converge within the configured budget.
    NonConvergent(String),
}

impl std::fmt::Display for FitError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::NotImplemented { distribution } => {
                write!(f, "fit not implemented for {distribution}")
            }
            Self::InsufficientData { required, actual } => {
                write!(f, "insufficient data: need {required}, got {actual}")
            }
            Self::UnsupportedData(msg) => write!(f, "unsupported data: {msg}"),
            Self::NonConvergent(msg) => write!(f, "fit did not converge: {msg}"),
        }
    }
}

impl std::error::Error for FitError {}

impl From<FitError> for StatsError {
    fn from(value: FitError) -> Self {
        match value {
            FitError::NotImplemented { distribution } => Self::Unsupported {
                operation: "fit",
                distribution,
            },
            FitError::InsufficientData { required, actual } => Self::DataTooSmall {
                required,
                got: actual,
            },
            FitError::UnsupportedData(detail) => Self::InvalidArgument(detail),
            FitError::NonConvergent(detail) => Self::Arithmetic { detail },
        }
    }
}

fn unsupported_distribution_moment(
    value: f64,
    operation: &'static str,
    distribution: &'static str,
) -> Result<f64, StatsError> {
    if value.is_nan() {
        Err(StatsError::Unsupported {
            operation,
            distribution,
        })
    } else {
        Ok(value)
    }
}

/// Trait for continuous probability distributions.
pub trait ContinuousDistribution {
    /// Probability density function.
    fn pdf(&self, x: f64) -> f64;
    /// Log probability density function.
    fn logpdf(&self, x: f64) -> f64 {
        log_probability(self.pdf(x))
    }
    /// Cumulative distribution function.
    fn cdf(&self, x: f64) -> f64;
    /// Log cumulative distribution function.
    fn logcdf(&self, x: f64) -> f64 {
        log_probability(self.cdf(x))
    }
    /// Survival function: 1 - cdf(x).
    ///
    /// # Precision
    ///
    /// **The default `1.0 - self.cdf(x)` loses precision in the right
    /// tail** (per frankenscipy-wofb). For x far in the tail where
    /// cdf(x) is near 1, the subtraction drops most significant digits
    /// (Normal.sf(10) via default returns 0.0 vs. true ~7.6e-24).
    ///
    /// Distribution implementations that have a precision-preserving
    /// closed form SHOULD override this method. Examples already
    /// overriding sf():
    ///
    /// - Weibull (line ~1567): exp(-(x/scale)^c)
    /// - Normal (line ~400):   erfc(x/sqrt(2))/2
    ///
    /// Distributions inheriting the default expose the precision loss
    /// for tail p-values.
    fn sf(&self, x: f64) -> f64 {
        1.0 - self.cdf(x)
    }
    /// Log survival function.
    ///
    /// Inherits the precision loss of the default `sf()` (per
    /// frankenscipy-wofb). For tail work, distributions should override
    /// logsf directly (e.g. using log1p(-cdf(x)) or a closed form).
    fn logsf(&self, x: f64) -> f64 {
        log_probability(self.sf(x))
    }
    /// Percent point function (inverse CDF) via bisection.
    /// Override for distributions with analytic inverses.
    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        ppf_bisection(|x| self.cdf(x), q, self.mean(), self.std())
    }
    /// Inverse survival function: ppf(1 - q).
    /// Also known as the quantile function of the survival distribution.
    fn isf(&self, q: f64) -> f64 {
        self.ppf(1.0 - q)
    }
    /// Mean of the distribution.
    fn mean(&self) -> f64;
    /// Variance of the distribution.
    fn var(&self) -> f64;
    /// Standard deviation.
    fn std(&self) -> f64 {
        self.var().sqrt()
    }

    /// Generate `n` random variates via inverse transform sampling.
    fn rvs(&self, n: usize, rng: &mut impl Rng) -> Vec<f64> {
        (0..n)
            .map(|_| {
                let u: f64 = rng.random();
                self.ppf(u)
            })
            .collect()
    }

    /// Fit distribution to data (maximum likelihood estimation).
    ///
    /// # Default behavior (per frankenscipy-wofb)
    ///
    /// **Default panics with `FitError::NotImplemented`**. Asymmetric vs. the
    /// `entropy`/`skewness`/`kurtosis` defaults which return NaN.
    /// Callers working generically over distributions must either:
    ///   (a) restrict to distribution types that override `fit`, or
    ///   (b) wrap invocations in `std::panic::catch_unwind`, or
    ///   (c) use [`Self::try_fit`] which returns a typed error instead
    ///       of panicking (br-d692).
    ///
    /// Consider this contract unstable: the asymmetry (panic vs NaN)
    /// is tracked for consolidation.
    fn fit(_data: &[f64]) -> Self
    where
        Self: Sized,
    {
        match Self::try_fit(_data) {
            Ok(fitted) => fitted,
            Err(err) => std::panic::panic_any(err),
        }
    }

    /// Non-panicking MLE fit. Returns `Err(FitError::NotImplemented { … })`
    /// by default; distributions override to provide a closed-form or
    /// numerical fit. Callers that must not panic (generic driver code,
    /// fuzz harnesses, library consumers) should use `try_fit` and match
    /// on `FitError` variants.
    ///
    /// When overriding, return the same typed errors used by other
    /// distributions — `InsufficientData` for degenerate samples,
    /// `UnsupportedData` for values outside the support.
    fn try_fit(_data: &[f64]) -> Result<Self, FitError>
    where
        Self: Sized,
    {
        Err(FitError::NotImplemented {
            distribution: std::any::type_name::<Self>(),
        })
    }

    /// Audit-emitting counterpart to `try_fit` (br-egba-3). Delegates
    /// to `try_fit`, and on any `FitError` records an
    /// `AuditAction::FailClosed` event on the provided ledger. Useful
    /// under Hardened-mode deployments where callers need a forensic
    /// trail of which samples were rejected.
    fn try_fit_with_audit(data: &[f64], ledger: &SyncSharedAuditLedger) -> Result<Self, FitError>
    where
        Self: Sized,
    {
        let result = Self::try_fit(data);
        if let Err(err) = &result {
            let reason = format!("fit::{err}");
            // Fingerprint the first few bytes of the sample so
            // repeated identical rejections collide under the same
            // event hash.
            let head: Vec<u8> = data.iter().take(8).flat_map(|v| v.to_le_bytes()).collect();
            record_fail_closed(ledger, &head, &reason, "rejected");
        }
        result
    }

    /// Differential entropy H(X) = -∫ f(x) log f(x) dx.
    /// Returns entropy in nats (natural logarithm base).
    /// Matches `scipy.stats.<dist>.entropy()`.
    ///
    /// # Default behavior (per frankenscipy-wofb)
    ///
    /// **Default returns `f64::NAN`**, silently indistinguishable from
    /// a genuinely-undefined entropy. Distributions that don't
    /// override this method appear to have undefined entropy; callers
    /// cannot tell unimplemented apart from legitimately NaN without
    /// inspecting the impl.
    fn entropy(&self) -> f64 {
        f64::NAN
    }

    /// Fallible entropy accessor for generic callers that need to
    /// distinguish an inherited unsupported default from a numeric
    /// result. Existing distribution-specific `entropy()` overrides are
    /// reused automatically; inherited NaN defaults become a typed
    /// `StatsError::Unsupported` instead of a silent sentinel.
    fn try_entropy(&self) -> Result<f64, StatsError> {
        unsupported_distribution_moment(self.entropy(), "entropy", std::any::type_name::<Self>())
    }

    /// Median of the distribution (50th percentile).
    /// Default uses ppf(0.5); override for analytic formulas.
    fn median(&self) -> f64 {
        self.ppf(0.5)
    }

    /// Skewness (third standardized moment).
    /// Returns 0 for symmetric distributions.
    /// Matches `scipy.stats.<dist>.stats(moments='s')`.
    fn skewness(&self) -> f64 {
        f64::NAN
    }

    /// Fallible skewness accessor for generic callers. Inherited NaN
    /// defaults become `StatsError::Unsupported`.
    fn try_skewness(&self) -> Result<f64, StatsError> {
        unsupported_distribution_moment(self.skewness(), "skewness", std::any::type_name::<Self>())
    }

    /// Excess kurtosis (fourth standardized moment minus 3).
    /// Normal distribution has excess kurtosis 0.
    /// Matches `scipy.stats.<dist>.stats(moments='k')`.
    fn kurtosis(&self) -> f64 {
        f64::NAN
    }

    /// Fallible excess-kurtosis accessor for generic callers. Inherited
    /// NaN defaults become `StatsError::Unsupported`.
    fn try_kurtosis(&self) -> Result<f64, StatsError> {
        unsupported_distribution_moment(self.kurtosis(), "kurtosis", std::any::type_name::<Self>())
    }

    /// Mode of the distribution (value where PDF is maximized).
    /// Returns NaN for distributions with undefined or non-unique mode.
    fn mode(&self) -> f64 {
        f64::NAN
    }

    /// Confidence interval containing `alpha` fraction of probability mass.
    /// Returns (lower, upper) bounds centered around the median.
    /// Matches `scipy.stats.<dist>.interval(alpha)`.
    fn interval(&self, alpha: f64) -> (f64, f64) {
        if !(0.0..=1.0).contains(&alpha) {
            return (f64::NAN, f64::NAN);
        }
        let lower = self.ppf((1.0 - alpha) / 2.0);
        let upper = self.ppf((1.0 + alpha) / 2.0);
        (lower, upper)
    }
}

/// Generic fitting helper for continuous distributions with built-in MLE support.
///
/// This is the Rust-generic equivalent of SciPy's distribution-specific fit surface
/// for the implemented continuous distributions in this crate.
#[must_use]
pub fn fit<D>(data: &[f64]) -> D
where
    D: ContinuousDistribution,
{
    D::fit(data)
}

fn log_probability(probability: f64) -> f64 {
    if probability < 0.0 {
        f64::NAN
    } else {
        probability.ln()
    }
}

/// Helper: validate fit() data for parameterless / standardized distributions.
/// Requires at least one observation and rejects non-finite values. Used by
/// the no-op fit() implementations on parameterless distributions where the
/// only thing to check is whether the data is well-formed.
fn validate_parameterless_fit_data(data: &[f64]) -> Result<(), FitError> {
    if data.is_empty() {
        return Err(FitError::InsufficientData {
            required: 1,
            actual: 0,
        });
    }
    for &x in data {
        if !x.is_finite() {
            return Err(FitError::UnsupportedData(format!(
                "fit data contains non-finite value: {x}"
            )));
        }
    }
    Ok(())
}

fn validate_finite_fit_data(
    data: &[f64],
    required: usize,
    distribution: &str,
) -> Result<(), FitError> {
    if data.len() < required {
        return Err(FitError::InsufficientData {
            required,
            actual: data.len(),
        });
    }
    for &x in data {
        if !x.is_finite() {
            return Err(FitError::UnsupportedData(format!(
                "{distribution} data contains non-finite value: {x}"
            )));
        }
    }
    Ok(())
}

fn sample_population_variance(data: &[f64]) -> f64 {
    let mean = sample_mean(data);
    data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / data.len() as f64
}

fn sample_standardized_skewness(data: &[f64]) -> f64 {
    let mean = sample_mean(data);
    let mut m2 = 0.0_f64;
    let mut m3 = 0.0_f64;
    for &x in data {
        let centered = x - mean;
        m2 += centered * centered;
        m3 += centered * centered * centered;
    }
    m2 /= data.len() as f64;
    m3 /= data.len() as f64;
    if m2 <= 0.0 {
        f64::NAN
    } else {
        m3 / m2.powf(1.5)
    }
}

/// Generic inverse CDF via bisection search.
fn ppf_bisection(cdf: impl Fn(f64) -> f64, q: f64, mean: f64, std: f64) -> f64 {
    // Initial bracket: start around mean ± 10*std
    let half_width = if std.is_finite() && std > 0.0 {
        10.0 * std
    } else {
        100.0
    };
    let center = if mean.is_finite() { mean } else { 0.0 };
    let mut lo = center - half_width;
    let mut hi = center + half_width;
    let mut step = half_width;

    // Expand bracket if needed (bounded to prevent infinite loops)
    for _ in 0..60 {
        if cdf(lo) <= q {
            break;
        }
        step *= 2.0;
        lo -= step;
    }
    step = half_width;
    for _ in 0..60 {
        if cdf(hi) >= q {
            break;
        }
        step *= 2.0;
        hi += step;
    }

    // Bisection
    for _ in 0..100 {
        let mid = 0.5 * (lo + hi);
        if (hi - lo).abs() < 1e-12 * mid.abs().max(1.0) {
            return mid;
        }
        if cdf(mid) < q {
            lo = mid;
        } else {
            hi = mid;
        }
    }
    0.5 * (lo + hi)
}

fn gumbel_fit_loc_scale(data: &[f64]) -> (f64, f64) {
    if data.is_empty() || data.iter().any(|&x| !x.is_finite()) {
        return (f64::NAN, f64::NAN);
    }

    let n = data.len() as f64;
    let mean = data.iter().sum::<f64>() / n;
    let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
    if !var.is_finite() {
        return (f64::NAN, f64::NAN);
    }
    if var == 0.0 {
        return (mean, 0.0);
    }

    let mut scale = (6.0 * var).sqrt() / PI;
    if !scale.is_finite() || scale <= 0.0 {
        return (f64::NAN, f64::NAN);
    }

    for _ in 0..32 {
        let inv_scale = 1.0 / scale;
        let max_exponent = data
            .iter()
            .map(|&x| -x * inv_scale)
            .fold(f64::NEG_INFINITY, f64::max);
        let mut sum_w = 0.0;
        let mut sum_xw = 0.0;
        let mut sum_x2w = 0.0;
        for &x in data {
            let w = (-x * inv_scale - max_exponent).exp();
            sum_w += w;
            sum_xw += x * w;
            sum_x2w += x * x * w;
        }
        if !sum_w.is_finite() || sum_w == 0.0 {
            break;
        }

        let weighted_mean = sum_xw / sum_w;
        let weighted_var = (sum_x2w / sum_w - weighted_mean * weighted_mean).max(0.0);
        let residual = mean - weighted_mean - scale;
        if residual.abs() <= 1.0e-12 * scale.max(1.0) {
            break;
        }

        let derivative = -weighted_var / (scale * scale) - 1.0;
        let next_scale = scale - residual / derivative;
        if !next_scale.is_finite() || next_scale <= 0.0 {
            break;
        }
        scale = next_scale;
    }

    let inv_scale = 1.0 / scale;
    let max_exponent = data
        .iter()
        .map(|&x| -x * inv_scale)
        .fold(f64::NEG_INFINITY, f64::max);
    let sum_w = data
        .iter()
        .map(|&x| (-x * inv_scale - max_exponent).exp())
        .sum::<f64>();
    if !sum_w.is_finite() || sum_w == 0.0 {
        return (mean - EULER_MASCHERONI * scale, scale);
    }

    let loc = -scale * (max_exponent + (sum_w / n).ln());
    (loc, scale)
}

fn simpson_integrate(f: impl Fn(f64) -> f64, a: f64, b: f64, n: usize) -> f64 {
    let n = n + (n % 2);
    let h = (b - a) / n as f64;
    let mut sum = f(a) + f(b);
    for i in 1..n {
        let x = a + i as f64 * h;
        let w = if i % 2 == 0 { 2.0 } else { 4.0 };
        sum += w * f(x);
    }
    sum * h / 3.0
}

fn simpson_integrate_adaptive(
    f: impl Fn(f64) -> f64,
    a: f64,
    b: f64,
    initial_n: usize,
    rel_tol: f64,
    abs_tol: f64,
    max_refinements: usize,
) -> f64 {
    let mut n = initial_n.max(2);
    n += n % 2;
    let mut prev = simpson_integrate(&f, a, b, n);
    for _ in 0..max_refinements {
        n *= 2;
        let curr = simpson_integrate(&f, a, b, n);
        let refined = curr + (curr - prev) / 15.0;
        let err = (refined - curr).abs();
        let tol = abs_tol.max(rel_tol * refined.abs());
        if err <= tol {
            return refined;
        }
        prev = curr;
    }
    prev
}

// ══════════════════════════════════════════════════════════════════════
// Normal (Gaussian) Distribution
// ══════════════════════════════════════════════════════════════════════

/// Normal distribution N(loc, scale²).
///
/// Matches `scipy.stats.norm(loc=mu, scale=sigma)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Normal {
    pub loc: f64,
    pub scale: f64,
}

impl Default for Normal {
    fn default() -> Self {
        Self {
            loc: 0.0,
            scale: 1.0,
        }
    }
}

impl Normal {
    /// Standard normal distribution N(0, 1).
    #[must_use]
    pub fn standard() -> Self {
        Self::default()
    }

    /// Create N(loc, scale²). Panics if scale <= 0.
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }

    /// Percent point function (inverse CDF) using rational approximation.
    ///
    /// Matches `scipy.stats.norm.ppf(q)`.
    pub fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.loc + self.scale * standard_normal_ppf(q)
    }
}

impl ContinuousDistribution for Normal {
    fn pdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        (-0.5 * z * z).exp() / (self.scale * (2.0 * PI).sqrt())
    }

    fn logpdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        -0.5 * z * z - self.scale.ln() - 0.5 * (2.0 * PI).ln()
    }

    fn cdf(&self, x: f64) -> f64 {
        // Delegate to standard_normal_cdf for deep-tail precision.
        // The naïve 0.5·(1 + erf(z·FRAC_1_SQRT_2)) form catastrophically
        // cancels for z ≲ -3; standard_normal_cdf switches to the
        // 0.5·erfc(-z·FRAC_1_SQRT_2) path for z < 0. Resolves
        // [frankenscipy-701x0]; see also [frankenscipy-6exgz].
        let z = (x - self.loc) / self.scale;
        standard_normal_cdf(z)
    }

    fn logcdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        fsci_special::log_ndtr_scalar(z)
    }

    fn sf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        0.5 * fsci_special::erfc_scalar(z * FRAC_1_SQRT_2)
    }

    fn logsf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        fsci_special::log_ndtr_scalar(-z)
    }

    fn ppf(&self, q: f64) -> f64 {
        // Use the specialized rational approximation
        Normal::ppf(self, q)
    }

    fn mean(&self) -> f64 {
        self.loc
    }

    fn var(&self) -> f64 {
        self.scale * self.scale
    }

    fn fit(data: &[f64]) -> Self {
        let n = data.len() as f64;
        if n == 0.0 {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
        Self {
            loc: mean,
            scale: var.sqrt(),
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|v| !v.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Normal::fit: non-finite samples".to_owned(),
            ));
        }
        Ok(Self::fit(data))
    }

    fn entropy(&self) -> f64 {
        0.5 * (2.0 * PI * std::f64::consts::E * self.scale * self.scale).ln()
    }

    fn skewness(&self) -> f64 {
        0.0 // Normal is symmetric
    }

    fn kurtosis(&self) -> f64 {
        0.0 // Normal has excess kurtosis 0 by definition
    }

    fn mode(&self) -> f64 {
        self.loc
    }
}

// ══════════════════════════════════════════════════════════════════════
// Student's t-Distribution
// ══════════════════════════════════════════════════════════════════════

/// Student's t-distribution with `df` degrees of freedom.
///
/// Matches `scipy.stats.t(df)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct StudentT {
    pub df: f64,
}

impl StudentT {
    #[must_use]
    pub fn new(df: f64) -> Self {
        assert!(df > 0.0, "df must be positive, got {df}");
        Self { df }
    }
}

impl ContinuousDistribution for StudentT {
    fn pdf(&self, x: f64) -> f64 {
        let v = self.df;
        let coeff = gamma_ratio_t(v);
        coeff * (1.0 + x * x / v).powf(-0.5 * (v + 1.0))
    }

    fn cdf(&self, x: f64) -> f64 {
        let v = self.df;
        if x == 0.0 {
            return 0.5;
        }
        // Use regularized incomplete beta function
        let t2 = x * x;
        let w = v / (v + t2);
        let ib = regularized_incomplete_beta(0.5 * v, 0.5, w);
        if x > 0.0 { 1.0 - 0.5 * ib } else { 0.5 * ib }
    }

    fn sf(&self, x: f64) -> f64 {
        let v = self.df;
        if x == 0.0 {
            return 0.5;
        }
        // Use regularized incomplete beta function
        let t2 = x * x;
        let w = v / (v + t2);
        let ib = regularized_incomplete_beta(0.5 * v, 0.5, w);
        if x > 0.0 { 0.5 * ib } else { 1.0 - 0.5 * ib }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        if q == 0.5 {
            return 0.0;
        }
        let v = self.df;
        let (p, sign) = if q < 0.5 {
            (2.0 * q, -1.0)
        } else {
            (2.0 * (1.0 - q), 1.0)
        };
        let w = fsci_special::betaincinv_scalar(0.5 * v, 0.5, p);
        let mut x = sign * (v * (1.0 - w) / w).sqrt();
        // Newton refinement for accuracy
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x -= err / dx;
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        if self.df > 1.0 { 0.0 } else { f64::NAN }
    }

    fn var(&self) -> f64 {
        if self.df > 2.0 {
            self.df / (self.df - 2.0)
        } else if self.df > 1.0 {
            f64::INFINITY
        } else {
            f64::NAN
        }
    }

    fn fit(data: &[f64]) -> Self {
        fn consider_student_t_df(
            best_df: &mut f64,
            best_error: &mut f64,
            observed_ratio: f64,
            df: f64,
        ) {
            let model = StudentT { df };
            let model_q75 = model.ppf(0.75);
            let model_q95 = model.ppf(0.95);
            if !model_q75.is_finite() || !model_q95.is_finite() || model_q75 <= 0.0 {
                return;
            }
            let error = (model_q95 / model_q75 - observed_ratio).abs();
            if error < *best_error {
                *best_error = error;
                *best_df = df;
            }
        }

        if data.is_empty() || data.iter().any(|&x| !x.is_finite()) {
            return Self { df: f64::NAN };
        }

        let qs = quantile(data, &[0.5, 0.75, 0.95]);
        let median = qs[0];
        let upper_quartile = qs[1];
        let upper_tail = qs[2];
        let interquantile = upper_quartile - median;
        let tail_span = upper_tail - median;
        if !interquantile.is_finite()
            || !tail_span.is_finite()
            || interquantile <= 0.0
            || tail_span <= 0.0
        {
            return Self { df: f64::NAN };
        }

        let observed_ratio = tail_span / interquantile;
        let mut best_df = f64::NAN;
        let mut best_error = f64::INFINITY;

        // Match a scale-free upper-tail quantile ratio so arbitrary loc/scale factors cancel out.
        for step in 0..=796 {
            consider_student_t_df(
                &mut best_df,
                &mut best_error,
                observed_ratio,
                1.0 + 0.25 * step as f64,
            );
        }
        for &df in &[250.0, 500.0, 1.0e3, 1.0e4, 1.0e6] {
            consider_student_t_df(&mut best_df, &mut best_error, observed_ratio, df);
        }
        if best_df.is_finite() {
            let start = (best_df - 1.0).max(1.01);
            let end = (best_df + 1.0).min(1.0e6);
            let mut df = start;
            while df <= end {
                consider_student_t_df(&mut best_df, &mut best_error, observed_ratio, df);
                df += 0.01;
            }
        }

        Self {
            df: if best_df.is_finite() && best_df > 0.0 {
                best_df
            } else {
                f64::NAN
            },
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 3 {
            return Err(FitError::InsufficientData {
                required: 3,
                actual: data.len(),
            });
        }
        if let Some(&x) = data.iter().find(|&&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(format!(
                "StudentT fit data contains non-finite value: {x}"
            )));
        }

        let fitted = Self::fit(data);
        if fitted.df.is_finite() && fitted.df > 0.0 {
            Ok(fitted)
        } else {
            Err(FitError::NonConvergent(
                "StudentT fit could not estimate positive degrees of freedom".to_owned(),
            ))
        }
    }

    fn skewness(&self) -> f64 {
        if self.df > 3.0 { 0.0 } else { f64::NAN }
    }

    fn kurtosis(&self) -> f64 {
        if self.df > 4.0 {
            6.0 / (self.df - 4.0)
        } else {
            f64::NAN
        }
    }

    fn mode(&self) -> f64 {
        // StudentT mode = 0 (symmetric around origin) [frankenscipy-71mv5].
        0.0
    }
}

// ══════════════════════════════════════════════════════════════════════
// Non-central t-Distribution
// ══════════════════════════════════════════════════════════════════════

/// Non-central t-distribution.
///
/// Matches `scipy.stats.nct(df, nc)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct NoncentralT {
    pub df: f64,
    pub nc: f64,
}

impl NoncentralT {
    #[must_use]
    pub fn new(df: f64, nc: f64) -> Self {
        assert!(df > 0.0, "df must be positive, got {df}");
        Self { df, nc }
    }

    /// Upper integration limit S_max for the chi-scaled variable
    /// S = sqrt(W/ν) so that P(S > S_max) is below ~1e-19 for the
    /// supported range of ν. Uses the Cornish-Fisher tail expansion
    /// for χ²(ν) at z = 10 standard deviations beyond the mean.
    fn cdf_pdf_s_max(nu: f64) -> f64 {
        let z_max: f64 = 10.0;
        let w_max = nu + z_max * (2.0 * nu).sqrt() + (z_max * z_max - 1.0) * (2.0 / 3.0);
        (w_max / nu).sqrt()
    }

    /// log of the density of S = sqrt(W/ν) for W ~ χ²(ν).
    fn log_pdf_s(nu: f64, s: f64) -> f64 {
        // pdf_S(s) = ν^(ν/2) · s^(ν-1) · exp(-ν s² / 2) / (2^(ν/2 - 1) · Γ(ν/2))
        let log_norm = (nu / 2.0) * nu.ln() - (nu / 2.0 - 1.0) * 2.0_f64.ln() - ln_gamma(nu / 2.0);
        log_norm + (nu - 1.0) * s.ln() - 0.5 * nu * s * s
    }

    /// CDF via numerical integration over the chi-scaled distribution.
    ///
    /// F_nct(t; ν, μ) = E_W[Φ(t·sqrt(W/ν) - μ)] for W ~ χ²(ν), which after
    /// substituting S = sqrt(W/ν) becomes
    ///   F_nct(t; ν, μ) = ∫_0^∞ Φ(t·s - μ) · pdf_S(s) ds.
    /// Computed via composite Simpson's rule on [0, s_max] where the
    /// chi-scaled tail is below ~1e-19.
    fn nct_cdf_integrate(&self, t: f64) -> f64 {
        if t.is_nan() || self.nc.is_nan() || self.df.is_nan() {
            return f64::NAN;
        }
        if t.is_infinite() {
            return if t > 0.0 { 1.0 } else { 0.0 };
        }
        if self.nc.abs() < 1e-10 {
            return StudentT::new(self.df).cdf(t);
        }

        let nu = self.df;
        let mu = self.nc;
        let norm = Normal::new(0.0, 1.0);

        let s_max = Self::cdf_pdf_s_max(nu);
        let steps = 2000usize; // even number of panels for Simpson's rule
        let h = s_max / steps as f64;

        let integrand = |s: f64| -> f64 {
            if s <= 0.0 {
                return 0.0;
            }
            let log_d = Self::log_pdf_s(nu, s);
            if log_d < -700.0 {
                return 0.0;
            }
            log_d.exp() * norm.cdf(t * s - mu)
        };

        let mut sum = integrand(0.0) + integrand(s_max);
        for i in 1..steps {
            let s = i as f64 * h;
            let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
            sum += coef * integrand(s);
        }
        (sum * h / 3.0).clamp(0.0, 1.0)
    }

    /// PDF via the same chi-scaled quadrature.
    ///
    /// pdf_T_nc(x; ν, μ) = ∂/∂x F_nct(x; ν, μ)
    ///                   = ∫_0^∞ s · φ(x·s - μ) · pdf_S(s) ds
    /// where φ is the standard normal pdf.
    fn nct_pdf_integrate(&self, x: f64) -> f64 {
        if x.is_nan() || self.nc.is_nan() || self.df.is_nan() {
            return f64::NAN;
        }
        if !x.is_finite() {
            return 0.0;
        }
        if self.nc.abs() < 1e-10 {
            return StudentT::new(self.df).pdf(x);
        }

        let nu = self.df;
        let mu = self.nc;

        let s_max = Self::cdf_pdf_s_max(nu);
        let steps = 2000usize;
        let h = s_max / steps as f64;

        let log_phi_const = -0.5 * (2.0 * PI).ln();

        let integrand = |s: f64| -> f64 {
            if s <= 0.0 {
                return 0.0;
            }
            let arg = x * s - mu;
            let log_total = Self::log_pdf_s(nu, s) + log_phi_const - 0.5 * arg * arg + s.ln();
            if log_total < -700.0 {
                return 0.0;
            }
            log_total.exp()
        };

        let mut sum = integrand(0.0) + integrand(s_max);
        for i in 1..steps {
            let s = i as f64 * h;
            let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
            sum += coef * integrand(s);
        }
        (sum * h / 3.0).max(0.0)
    }
}

impl ContinuousDistribution for NoncentralT {
    fn pdf(&self, x: f64) -> f64 {
        self.nct_pdf_integrate(x)
    }

    fn cdf(&self, x: f64) -> f64 {
        self.nct_cdf_integrate(x)
    }

    fn ppf(&self, q: f64) -> f64 {
        if q.is_nan() || !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        if self.nc.abs() < 1e-10 {
            return StudentT::new(self.df).ppf(q);
        }

        let nu = self.df;
        let mu = self.nc;

        // Initial bracket centred on (central StudentT.ppf shifted by the
        // approximate location of nct), with width ≈ 6 · approximate std.
        let central_ppf = StudentT::new(nu).ppf(q);
        let approx_loc = if nu > 1.0 {
            mu * (nu / 2.0).sqrt() * (ln_gamma((nu - 1.0) / 2.0) - ln_gamma(nu / 2.0)).exp()
        } else {
            mu
        };
        let approx_var = if nu > 2.0 {
            nu * (1.0 + mu * mu) / (nu - 2.0) - approx_loc * approx_loc
        } else {
            nu + mu * mu + 1.0
        };
        let scale = approx_var.abs().sqrt().max(1.0);

        let mut lo = central_ppf + approx_loc - 6.0 * scale;
        let mut hi = central_ppf + approx_loc + 6.0 * scale;

        // Expand bracket until cdf(lo) ≤ q ≤ cdf(hi).
        for _ in 0..40 {
            let cdf_lo = self.cdf(lo);
            let cdf_hi = self.cdf(hi);
            if cdf_lo <= q && cdf_hi >= q {
                break;
            }
            if cdf_lo > q {
                lo -= 4.0 * scale;
            }
            if cdf_hi < q {
                hi += 4.0 * scale;
            }
        }

        // Bisection.
        for _ in 0..120 {
            let mid = 0.5 * (lo + hi);
            let cdf_mid = self.cdf(mid);
            if (cdf_mid - q).abs() < 1e-10 || (hi - lo).abs() < 1e-12 {
                return mid;
            }
            if cdf_mid < q {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        0.5 * (lo + hi)
    }

    fn mean(&self) -> f64 {
        if self.df > 1.0 {
            self.nc * (self.df / 2.0).sqrt() * ln_gamma((self.df - 1.0) / 2.0).exp()
                / ln_gamma(self.df / 2.0).exp()
        } else {
            f64::NAN
        }
    }

    fn var(&self) -> f64 {
        if self.df > 2.0 {
            let mu = self.mean();
            self.df * (1.0 + self.nc * self.nc) / (self.df - 2.0) - mu * mu
        } else {
            f64::NAN
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 3, "NoncentralT")?;
        let mean = sample_mean(data);
        let var = sample_population_variance(data);
        if !var.is_finite() || var <= 0.0 {
            return Err(FitError::NonConvergent(
                "NoncentralT fit needs positive sample variance".to_owned(),
            ));
        }

        let mut best = None::<(f64, f64, f64)>;
        for step in 0..=1980 {
            let df = 2.05 + 0.1 * step as f64;
            let log_a = 0.5 * (df / 2.0).ln() + ln_gamma((df - 1.0) / 2.0) - ln_gamma(df / 2.0);
            let a = log_a.exp();
            if !a.is_finite() || a <= 0.0 {
                continue;
            }
            let nc = mean / a;
            let candidate = Self { df, nc };
            let model_var = candidate.var();
            if !model_var.is_finite() || model_var <= 0.0 {
                continue;
            }
            let error = ((model_var / var).ln()).abs();
            if best.is_none_or(|(_, _, best_error)| error < best_error) {
                best = Some((df, nc, error));
            }
        }

        if let Some((df, nc, _)) = best {
            Ok(Self { df, nc })
        } else {
            Err(FitError::NonConvergent(
                "NoncentralT moment fit did not find finite df/nc".to_owned(),
            ))
        }
    }

    fn skewness(&self) -> f64 {
        f64::NAN
    }

    fn kurtosis(&self) -> f64 {
        f64::NAN
    }
}

// ══════════════════════════════════════════════════════════════════════
// Chi-Squared Distribution
// ══════════════════════════════════════════════════════════════════════

/// Chi-squared distribution with `df` degrees of freedom.
///
/// Matches `scipy.stats.chi2(df)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct ChiSquared {
    pub df: f64,
}

impl ChiSquared {
    #[must_use]
    pub fn new(df: f64) -> Self {
        assert!(df > 0.0, "df must be positive, got {df}");
        Self { df }
    }
}

impl ContinuousDistribution for ChiSquared {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.df == 2.0 {
                0.5
            } else if self.df > 2.0 {
                0.0
            } else {
                f64::INFINITY
            };
        }
        let k2 = 0.5 * self.df;
        let ln_pdf = (k2 - 1.0) * x.ln() - 0.5 * x - k2 * 2.0_f64.ln() - ln_gamma(k2);
        ln_pdf.exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        // CDF of chi2(k) = regularized lower incomplete gamma P(k/2, x/2)
        lower_regularized_gamma(0.5 * self.df, 0.5 * x)
    }

    fn sf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 1.0;
        }
        upper_regularized_gamma(0.5 * self.df, 0.5 * x)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let mut x = 2.0 * fsci_special::gammaincinv_scalar(0.5 * self.df, q);
        // Fall back to bisection if gammaincinv gave a degenerate result
        if x <= 0.0 || !x.is_finite() || (self.cdf(x) - q).abs() > 0.1 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        self.df
    }

    fn var(&self) -> f64 {
        2.0 * self.df
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Self { df: f64::NAN };
        }

        let mean = data.iter().sum::<f64>() / data.len() as f64;
        if !mean.is_finite() || mean <= 0.0 {
            return Self { df: f64::NAN };
        }

        Self { df: mean }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if let Some(&x) = data.iter().find(|&&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(format!(
                "ChiSquared fit data contains non-finite value: {x}"
            )));
        }
        if let Some(&x) = data.iter().find(|&&x| x < 0.0) {
            return Err(FitError::UnsupportedData(format!(
                "ChiSquared support is [0, infinity); got {x}"
            )));
        }

        let fitted = Self::fit(data);
        if fitted.df.is_finite() && fitted.df > 0.0 {
            Ok(fitted)
        } else {
            Err(FitError::NonConvergent(
                "ChiSquared fit produced non-positive degrees of freedom".to_owned(),
            ))
        }
    }

    fn skewness(&self) -> f64 {
        (8.0 / self.df).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        12.0 / self.df
    }

    fn mode(&self) -> f64 {
        // ChiSquared mode = max(df - 2, 0) [frankenscipy-cxgdg].
        (self.df - 2.0).max(0.0)
    }
}

// ══════════════════════════════════════════════════════════════════════
// Uniform Distribution
// ══════════════════════════════════════════════════════════════════════

/// Uniform distribution on [loc, loc + scale].
///
/// Matches `scipy.stats.uniform(loc, scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Uniform {
    pub loc: f64,
    pub scale: f64,
}

impl Default for Uniform {
    fn default() -> Self {
        Self {
            loc: 0.0,
            scale: 1.0,
        }
    }
}

impl Uniform {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }
}

impl ContinuousDistribution for Uniform {
    fn pdf(&self, x: f64) -> f64 {
        if x >= self.loc && x <= self.loc + self.scale {
            1.0 / self.scale
        } else {
            0.0
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < self.loc {
            0.0
        } else if x > self.loc + self.scale {
            1.0
        } else {
            (x - self.loc) / self.scale
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.loc;
        }
        if q == 1.0 {
            return self.loc + self.scale;
        }
        self.loc + q * self.scale
    }

    fn mean(&self) -> f64 {
        self.loc + 0.5 * self.scale
    }

    fn var(&self) -> f64 {
        self.scale * self.scale / 12.0
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }
        let mut min = f64::INFINITY;
        let mut max = f64::NEG_INFINITY;
        for &x in data {
            if x < min {
                min = x;
            }
            if x > max {
                max = x;
            }
        }
        Self {
            loc: min,
            scale: max - min,
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|v| !v.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Uniform::fit: non-finite samples".to_owned(),
            ));
        }
        Ok(Self::fit(data))
    }

    fn entropy(&self) -> f64 {
        self.scale.ln()
    }

    fn skewness(&self) -> f64 {
        0.0 // Uniform is symmetric
    }

    fn kurtosis(&self) -> f64 {
        -1.2 // Uniform excess kurtosis = -6/5
    }
}

// ══════════════════════════════════════════════════════════════════════
// Exponential Distribution
// ══════════════════════════════════════════════════════════════════════

/// Exponential distribution with rate parameter `lambda` (= 1/scale).
///
/// Matches `scipy.stats.expon(scale=1/lambda)`.
/// The PDF is: f(x) = lambda * exp(-lambda * x) for x >= 0.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Exponential {
    pub lambda: f64,
}

impl Default for Exponential {
    fn default() -> Self {
        Self { lambda: 1.0 }
    }
}

impl Exponential {
    #[must_use]
    pub fn new(lambda: f64) -> Self {
        assert!(lambda > 0.0, "lambda must be positive, got {lambda}");
        Self { lambda }
    }

    /// Create from scale parameter (= 1/lambda), matching SciPy convention.
    #[must_use]
    pub fn from_scale(scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self {
            lambda: 1.0 / scale,
        }
    }

    /// Percent point function (inverse CDF).
    pub fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        -(1.0 - q).ln() / self.lambda
    }
}

impl ContinuousDistribution for Exponential {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            self.lambda * (-self.lambda * x).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            -(-self.lambda * x).exp_m1()
        }
    }

    fn sf(&self, x: f64) -> f64 {
        if x < 0.0 {
            1.0
        } else {
            (-self.lambda * x).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        Exponential::ppf(self, q)
    }

    fn mean(&self) -> f64 {
        1.0 / self.lambda
    }

    fn var(&self) -> f64 {
        1.0 / (self.lambda * self.lambda)
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Self { lambda: f64::NAN };
        }

        let mean = data.iter().sum::<f64>() / data.len() as f64;
        if !mean.is_finite() {
            return Self { lambda: f64::NAN };
        }
        if mean == 0.0 {
            return Self {
                lambda: f64::INFINITY,
            };
        }

        Self { lambda: 1.0 / mean }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Exponential::fit: non-finite samples".to_owned(),
            ));
        }
        if data.iter().any(|&x| x < 0.0) {
            return Err(FitError::UnsupportedData(
                "Exponential::fit: negative sample (support is x >= 0)".to_owned(),
            ));
        }
        Ok(Self::fit(data))
    }

    fn entropy(&self) -> f64 {
        1.0 - self.lambda.ln()
    }

    fn skewness(&self) -> f64 {
        2.0 // Exponential always has skewness 2
    }

    fn kurtosis(&self) -> f64 {
        6.0 // Exponential excess kurtosis is always 6
    }

    fn mode(&self) -> f64 {
        0.0
    }
}

// ══════════════════════════════════════════════════════════════════════
// F-Distribution
// ══════════════════════════════════════════════════════════════════════

/// F-distribution with `dfn` (numerator) and `dfd` (denominator) degrees of freedom.
///
/// Matches `scipy.stats.f(dfn, dfd)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct FDistribution {
    pub dfn: f64,
    pub dfd: f64,
}

impl FDistribution {
    #[must_use]
    pub fn new(dfn: f64, dfd: f64) -> Self {
        assert!(dfn > 0.0, "dfn must be positive, got {dfn}");
        assert!(dfd > 0.0, "dfd must be positive, got {dfd}");
        Self { dfn, dfd }
    }
}

impl ContinuousDistribution for FDistribution {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let d1 = self.dfn;
        let d2 = self.dfd;
        let ln_pdf = 0.5 * d1 * (d1 / d2).ln() + (0.5 * d1 - 1.0) * x.ln()
            - 0.5 * (d1 + d2) * (1.0 + d1 * x / d2).ln()
            - ln_beta(0.5 * d1, 0.5 * d2);
        ln_pdf.exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let d1 = self.dfn;
        let d2 = self.dfd;
        let w = d1 * x / (d1 * x + d2);
        regularized_incomplete_beta(0.5 * d1, 0.5 * d2, w)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let d1 = self.dfn;
        let d2 = self.dfd;
        let w = fsci_special::betaincinv_scalar(0.5 * d1, 0.5 * d2, q);
        if w >= 1.0 {
            return f64::INFINITY;
        }
        let mut x = d2 * w / (d1 * (1.0 - w));
        if !x.is_finite() || (self.cdf(x) - q).abs() > 0.1 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        if self.dfd > 2.0 {
            self.dfd / (self.dfd - 2.0)
        } else {
            f64::NAN
        }
    }

    fn var(&self) -> f64 {
        if self.dfd > 4.0 {
            let d1 = self.dfn;
            let d2 = self.dfd;
            2.0 * d2 * d2 * (d1 + d2 - 2.0) / (d1 * (d2 - 2.0).powi(2) * (d2 - 4.0))
        } else {
            f64::NAN
        }
    }

    fn skewness(&self) -> f64 {
        // ((2·d1 + d2 − 2) · √(8(d2 − 4))) / ((d2 − 6) · √(d1 · (d1 + d2 − 2)))
        // for d2 > 6, NaN otherwise. (frankenscipy-zhiof)
        let d1 = self.dfn;
        let d2 = self.dfd;
        if d2 > 6.0 {
            (2.0 * d1 + d2 - 2.0) * (8.0 * (d2 - 4.0)).sqrt()
                / ((d2 - 6.0) * (d1 * (d1 + d2 - 2.0)).sqrt())
        } else {
            f64::NAN
        }
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis for d2 > 8 (frankenscipy-zhiof):
        //   12·(d1·(5d2 − 22)·(d1 + d2 − 2) + (d2 − 4)·(d2 − 2)²)
        //   / (d1·(d2 − 6)·(d2 − 8)·(d1 + d2 − 2))
        let d1 = self.dfn;
        let d2 = self.dfd;
        if d2 > 8.0 {
            let num = 12.0
                * (d1 * (5.0 * d2 - 22.0) * (d1 + d2 - 2.0)
                    + (d2 - 4.0) * (d2 - 2.0).powi(2));
            let den = d1 * (d2 - 6.0) * (d2 - 8.0) * (d1 + d2 - 2.0);
            num / den
        } else {
            f64::NAN
        }
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Self {
                dfn: f64::NAN,
                dfd: f64::NAN,
            };
        }

        let n = data.len() as f64;
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
        if !mean.is_finite() || !var.is_finite() || mean <= 1.0 || var <= 0.0 {
            return Self {
                dfn: f64::NAN,
                dfd: f64::NAN,
            };
        }

        let dfd = 2.0 * mean / (mean - 1.0);
        if !dfd.is_finite() || dfd <= 4.0 {
            return Self {
                dfn: f64::NAN,
                dfd: f64::NAN,
            };
        }

        let base_variance = 2.0 * dfd * dfd / ((dfd - 2.0).powi(2) * (dfd - 4.0));
        let variance_ratio = var / base_variance;
        if !variance_ratio.is_finite() || variance_ratio <= 1.0 {
            return Self {
                dfn: f64::NAN,
                dfd: f64::NAN,
            };
        }

        let dfn = (dfd - 2.0) / (variance_ratio - 1.0);
        if !dfn.is_finite() || dfn <= 0.0 {
            return Self {
                dfn: f64::NAN,
                dfd: f64::NAN,
            };
        }

        Self { dfn, dfd }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        if let Some(&x) = data.iter().find(|&&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(format!(
                "FDistribution fit data contains non-finite value: {x}"
            )));
        }
        if let Some(&x) = data.iter().find(|&&x| x < 0.0) {
            return Err(FitError::UnsupportedData(format!(
                "FDistribution support is [0, infinity); got {x}"
            )));
        }

        let fitted = Self::fit(data);
        if fitted.dfn.is_finite() && fitted.dfn > 0.0 && fitted.dfd.is_finite() && fitted.dfd > 4.0
        {
            Ok(fitted)
        } else {
            Err(FitError::NonConvergent(
                "FDistribution moment fit could not estimate valid degrees of freedom".to_owned(),
            ))
        }
    }
}

// ══════════════════════════════════════════════════════════════════════
// Beta Distribution
// ══════════════════════════════════════════════════════════════════════

/// Beta distribution with shape parameters `a` and `b`.
///
/// Matches `scipy.stats.beta(a, b)`.
/// Supported on [0, 1].
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct BetaDist {
    pub a: f64,
    pub b: f64,
}

impl BetaDist {
    #[must_use]
    pub fn new(a: f64, b: f64) -> Self {
        assert!(a > 0.0, "a must be positive, got {a}");
        assert!(b > 0.0, "b must be positive, got {b}");
        Self { a, b }
    }
}

impl ContinuousDistribution for BetaDist {
    fn pdf(&self, x: f64) -> f64 {
        // /testing-metamorphic boundary [frankenscipy-rsx33]: scipy.stats.beta
        // returns the limit of x^(a-1)·(1-x)^(b-1)/B(a,b) at the boundary
        // — finite when the relevant exponent is zero, +inf when it is
        // negative. The previous short-circuit "x ≤ 0 || x ≥ 1 → 0" was
        // wrong for both a=1 (pdf(0) = 1/B(1, b)) and a<1 (pdf(0) = ∞).
        if !(0.0..=1.0).contains(&x) {
            return 0.0;
        }
        if x == 0.0 {
            return if self.a < 1.0 {
                f64::INFINITY
            } else if self.a == 1.0 {
                (-ln_beta(self.a, self.b)).exp()
            } else {
                0.0
            };
        }
        if x == 1.0 {
            return if self.b < 1.0 {
                f64::INFINITY
            } else if self.b == 1.0 {
                (-ln_beta(self.a, self.b)).exp()
            } else {
                0.0
            };
        }
        let ln_pdf =
            (self.a - 1.0) * x.ln() + (self.b - 1.0) * (1.0 - x).ln() - ln_beta(self.a, self.b);
        ln_pdf.exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x >= 1.0 {
            return 1.0;
        }
        regularized_incomplete_beta(self.a, self.b, x)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return 1.0;
        }
        let mut x = fsci_special::betaincinv_scalar(self.a, self.b, q);
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).clamp(0.0, 1.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        self.a / (self.a + self.b)
    }

    fn var(&self) -> f64 {
        let ab = self.a + self.b;
        self.a * self.b / (ab * ab * (ab + 1.0))
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty()
            || data
                .iter()
                .any(|&x| !x.is_finite() || !(0.0..=1.0).contains(&x))
        {
            return Self {
                a: f64::NAN,
                b: f64::NAN,
            };
        }

        let n = data.len() as f64;
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
        if !mean.is_finite() || !var.is_finite() || mean <= 0.0 || mean >= 1.0 || var <= 0.0 {
            return Self {
                a: f64::NAN,
                b: f64::NAN,
            };
        }

        let common = mean * (1.0 - mean) / var - 1.0;
        if !common.is_finite() || common <= 0.0 {
            return Self {
                a: f64::NAN,
                b: f64::NAN,
            };
        }

        Self {
            a: mean * common,
            b: (1.0 - mean) * common,
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data
            .iter()
            .any(|&x| !x.is_finite() || !(0.0..=1.0).contains(&x))
        {
            return Err(FitError::UnsupportedData(
                "BetaDist support is [0, 1]".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.a.is_finite() || !fitted.b.is_finite() {
            return Err(FitError::NonConvergent(
                "BetaDist fit produced non-finite parameters".into(),
            ));
        }
        Ok(fitted)
    }

    fn skewness(&self) -> f64 {
        let (a, b) = (self.a, self.b);
        2.0 * (b - a) * (a + b + 1.0).sqrt() / ((a + b + 2.0) * (a * b).sqrt())
    }

    fn kurtosis(&self) -> f64 {
        let (a, b) = (self.a, self.b);
        let ab = a + b;
        let num = 6.0 * ((a - b).powi(2) * (ab + 1.0) - a * b * (ab + 2.0));
        let den = a * b * (ab + 2.0) * (ab + 3.0);
        num / den
    }

    fn mode(&self) -> f64 {
        // BetaDist mode = (a-1)/(a+b-2) for a > 1 and b > 1
        // [frankenscipy-71mv5]. Outside this regime the mode is at a
        // boundary (0 or 1) or the pdf has no interior maximum;
        // return NaN to match the trait-default contract for such cases.
        if self.a > 1.0 && self.b > 1.0 {
            (self.a - 1.0) / (self.a + self.b - 2.0)
        } else {
            f64::NAN
        }
    }
}

// ══════════════════════════════════════════════════════════════════════
// Gamma Distribution
// ══════════════════════════════════════════════════════════════════════

/// Gamma distribution with shape `a` and rate `1/scale`.
///
/// Matches `scipy.stats.gamma(a, scale=scale)`.
/// PDF: f(x) = x^(a-1) * exp(-x/scale) / (scale^a * Γ(a))
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct GammaDist {
    pub a: f64,
    pub scale: f64,
}

impl GammaDist {
    #[must_use]
    pub fn new(a: f64, scale: f64) -> Self {
        assert!(a > 0.0, "shape a must be positive, got {a}");
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { a, scale }
    }
}

impl ContinuousDistribution for GammaDist {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.a == 1.0 {
                1.0 / self.scale
            } else if self.a > 1.0 {
                0.0
            } else {
                f64::INFINITY
            };
        }
        let ln_pdf =
            (self.a - 1.0) * x.ln() - x / self.scale - self.a * self.scale.ln() - ln_gamma(self.a);
        ln_pdf.exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        lower_regularized_gamma(self.a, x / self.scale)
    }

    fn sf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 1.0;
        }
        upper_regularized_gamma(self.a, x / self.scale)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let mut x = self.scale * fsci_special::gammaincinv_scalar(self.a, q);
        if x <= 0.0 || !x.is_finite() || (self.cdf(x) - q).abs() > 0.1 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        self.a * self.scale
    }

    fn var(&self) -> f64 {
        self.a * self.scale * self.scale
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Self {
                a: f64::NAN,
                scale: f64::NAN,
            };
        }
        let n = data.len() as f64;
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
        if var <= 0.0 || mean <= 0.0 {
            return Self {
                a: f64::NAN,
                scale: f64::NAN,
            };
        }
        let a = mean * mean / var;
        let scale = var / mean;
        Self { a, scale }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Err(FitError::UnsupportedData(
                "GammaDist requires non-negative finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.a.is_finite() || !fitted.scale.is_finite() {
            return Err(FitError::NonConvergent(
                "GammaDist fit produced non-finite parameters".into(),
            ));
        }
        Ok(fitted)
    }

    fn entropy(&self) -> f64 {
        // H = a + ln(scale) + ln(Gamma(a)) + (1-a)*psi(a)
        self.a + self.scale.ln() + ln_gamma(self.a) + (1.0 - self.a) * digamma(self.a)
    }

    fn mode(&self) -> f64 {
        if self.a >= 1.0 {
            (self.a - 1.0) * self.scale
        } else {
            0.0
        }
    }

    fn skewness(&self) -> f64 {
        2.0 / self.a.sqrt()
    }

    fn kurtosis(&self) -> f64 {
        6.0 / self.a
    }
}

// ══════════════════════════════════════════════════════════════════════
// Weibull Distribution
// ══════════════════════════════════════════════════════════════════════

/// Weibull (minimum) distribution with shape `c` and scale `scale`.
///
/// Matches `scipy.stats.weibull_min(c, scale=scale)`.
/// PDF: f(x) = (c/scale) * (x/scale)^(c-1) * exp(-(x/scale)^c)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Weibull {
    pub c: f64,
    pub scale: f64,
}

impl Weibull {
    #[must_use]
    pub fn new(c: f64, scale: f64) -> Self {
        assert!(c > 0.0, "shape c must be positive, got {c}");
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { c, scale }
    }

    /// Inverse CDF (analytic).
    pub fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.scale * (-(1.0 - q).ln()).powf(1.0 / self.c)
    }
}

impl ContinuousDistribution for Weibull {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.c == 1.0 {
                1.0 / self.scale
            } else if self.c > 1.0 {
                0.0
            } else {
                f64::INFINITY
            };
        }
        let z = x / self.scale;
        (self.c / self.scale) * z.powf(self.c - 1.0) * (-z.powf(self.c)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        -(-(x / self.scale).powf(self.c)).exp_m1()
    }

    fn sf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 1.0;
        }
        (-(x / self.scale).powf(self.c)).exp()
    }

    fn ppf(&self, q: f64) -> f64 {
        Weibull::ppf(self, q)
    }

    fn mean(&self) -> f64 {
        self.scale * ln_gamma(1.0 + 1.0 / self.c).exp()
    }

    fn var(&self) -> f64 {
        let g1 = ln_gamma(1.0 + 1.0 / self.c).exp();
        let g2 = ln_gamma(1.0 + 2.0 / self.c).exp();
        self.scale * self.scale * (g2 - g1 * g1)
    }

    fn entropy(&self) -> f64 {
        // H = gamma_euler*(1 - 1/c) + ln(scale/c) + 1
        EULER_MASCHERONI * (1.0 - 1.0 / self.c) + (self.scale / self.c).ln() + 1.0
    }

    fn skewness(&self) -> f64 {
        let g1 = ln_gamma(1.0 + 1.0 / self.c).exp();
        let g2 = ln_gamma(1.0 + 2.0 / self.c).exp();
        let g3 = ln_gamma(1.0 + 3.0 / self.c).exp();
        let var = g2 - g1 * g1;
        let std = var.sqrt();
        (g3 - 3.0 * g1 * var - g1.powi(3)) / std.powi(3)
    }

    fn kurtosis(&self) -> f64 {
        let g1 = ln_gamma(1.0 + 1.0 / self.c).exp();
        let g2 = ln_gamma(1.0 + 2.0 / self.c).exp();
        let g3 = ln_gamma(1.0 + 3.0 / self.c).exp();
        let g4 = ln_gamma(1.0 + 4.0 / self.c).exp();
        let var = g2 - g1 * g1;
        let skew_num = g3 - 3.0 * g1 * var - g1.powi(3);
        (g4 - 4.0 * g1 * skew_num - 6.0 * g1 * g1 * var - g1.powi(4)) / var.powi(2) - 3.0
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|v| !v.is_finite() || *v <= 0.0) {
            return Self {
                c: f64::NAN,
                scale: f64::NAN,
            };
        }
        let n = data.len() as f64;
        let ln_data: Vec<f64> = data.iter().map(|&x| x.ln()).collect();
        let mean_ln: f64 = ln_data.iter().sum::<f64>() / n;

        let mut c = 1.0;
        for _ in 0..50 {
            let xc: Vec<f64> = data.iter().map(|&x| x.powf(c)).collect();
            let sum_xc: f64 = xc.iter().sum();
            let sum_xc_ln: f64 = xc.iter().zip(ln_data.iter()).map(|(&x, &lx)| x * lx).sum();
            let f = 1.0 / c + mean_ln - sum_xc_ln / sum_xc;
            if f.abs() < 1e-10 {
                break;
            }
            let sum_xc_ln2: f64 = xc
                .iter()
                .zip(ln_data.iter())
                .map(|(&x, &lx)| x * lx * lx)
                .sum();
            let df =
                -1.0 / (c * c) - (sum_xc * sum_xc_ln2 - sum_xc_ln * sum_xc_ln) / (sum_xc * sum_xc);
            if df.abs() < 1e-15 {
                break;
            }
            c -= f / df;
            c = c.max(1e-6);
        }
        let xc_sum: f64 = data.iter().map(|&x| x.powf(c)).sum();
        let scale = (xc_sum / n).powf(1.0 / c);
        Self { c, scale }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        if let Some(&x) = data.iter().find(|&&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(format!(
                "Weibull fit data contains non-finite value: {x}"
            )));
        }
        if let Some(&x) = data.iter().find(|&&x| x <= 0.0) {
            return Err(FitError::UnsupportedData(format!(
                "Weibull support is (0, infinity); got {x}"
            )));
        }

        let fitted = Self::fit(data);
        if fitted.c.is_finite() && fitted.c > 0.0 && fitted.scale.is_finite() && fitted.scale > 0.0
        {
            Ok(fitted)
        } else {
            Err(FitError::NonConvergent(
                "Weibull MLE could not estimate positive shape and scale".to_owned(),
            ))
        }
    }
}

/// Reverse Weibull (sign-flipped) distribution with shape `c > 0`.
///
/// Matches `scipy.stats.weibull_max(c)`. Resolves [frankenscipy-9nttn].
/// Distribution of `-X` for `X ~ weibull_min(c)`. Support: x ≤ 0.
///
///   pdf(x; c) = c · (−x)^(c − 1) · exp(−(−x)^c)   for x ≤ 0
///   cdf(x; c) = exp(−(−x)^c)
///   sf(x; c)  = 1 − exp(−(−x)^c)
///   ppf(q; c) = −(−ln q)^(1/c)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct WeibullMax {
    pub c: f64,
}

impl WeibullMax {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0 && c.is_finite(), "c must be positive and finite");
        Self { c }
    }
}

impl ContinuousDistribution for WeibullMax {
    fn pdf(&self, x: f64) -> f64 {
        if x > 0.0 || !x.is_finite() {
            return 0.0;
        }
        if x == 0.0 {
            // Limit depends on c: c<1 → ∞, c=1 → 1, c>1 → 0.
            // scipy returns 0 here (boundary); follow that.
            return 0.0;
        }
        let c = self.c;
        let neg = -x;
        c * neg.powf(c - 1.0) * (-neg.powf(c)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x >= 0.0 {
            return 1.0;
        }
        if !x.is_finite() {
            return 0.0;
        }
        let c = self.c;
        (-((-x).powf(c))).exp()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return 0.0;
        }
        let c = self.c;
        -((-q.ln()).powf(1.0 / c))
    }

    fn mean(&self) -> f64 {
        // E[X] = -E[Y] where Y ~ weibull_min(c) → -Γ(1 + 1/c).
        -ln_gamma(1.0 + 1.0 / self.c).exp()
    }

    fn var(&self) -> f64 {
        // Var(X) = Var(Y) (sign flip preserves variance).
        let g1 = ln_gamma(1.0 + 1.0 / self.c).exp();
        let g2 = ln_gamma(1.0 + 2.0 / self.c).exp();
        g2 - g1 * g1
    }

    fn skewness(&self) -> f64 {
        // WeibullMax(c) = -WeibullMin(c). Sign flip negates skewness.
        // (frankenscipy-lu2e1)
        let c = self.c;
        let g1 = ln_gamma(1.0 + 1.0 / c).exp();
        let g2 = ln_gamma(1.0 + 2.0 / c).exp();
        let g3 = ln_gamma(1.0 + 3.0 / c).exp();
        let var = g2 - g1 * g1;
        let mu3 = g3 - 3.0 * g1 * g2 + 2.0 * g1 * g1 * g1;
        -mu3 / var.powf(1.5) // negation: mirror flips skew
    }

    fn kurtosis(&self) -> f64 {
        // Kurtosis is invariant under sign-flip — identical to WeibullMin.
        // (frankenscipy-lu2e1)
        let c = self.c;
        let g1 = ln_gamma(1.0 + 1.0 / c).exp();
        let g2 = ln_gamma(1.0 + 2.0 / c).exp();
        let g3 = ln_gamma(1.0 + 3.0 / c).exp();
        let g4 = ln_gamma(1.0 + 4.0 / c).exp();
        let var = g2 - g1 * g1;
        let mu4 = g4 - 4.0 * g1 * g3 + 6.0 * g1 * g1 * g2 - 3.0 * g1 * g1 * g1 * g1;
        mu4 / (var * var) - 3.0
    }
}

// ══════════════════════════════════════════════════════════════════════
// Lognormal Distribution
// ══════════════════════════════════════════════════════════════════════

/// Lognormal distribution: X = exp(μ + σZ) where Z ~ N(0,1).
///
/// Matches `scipy.stats.lognorm(s, scale=exp(mu))` where s=σ.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Lognormal {
    /// Shape parameter σ (standard deviation of the underlying normal).
    pub s: f64,
    /// Scale parameter (= exp(μ)).
    pub scale: f64,
}

impl Lognormal {
    #[must_use]
    pub fn new(s: f64, scale: f64) -> Self {
        assert!(s > 0.0, "s must be positive, got {s}");
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { s, scale }
    }
}

impl ContinuousDistribution for Lognormal {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let z = (x / self.scale).ln() / self.s;
        (-0.5 * z * z).exp() / (x * self.s * (2.0 * PI).sqrt())
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        // Delegate to standard_normal_cdf for deep-tail precision
        // (very small x → very negative z → catastrophic cancellation
        // in the naïve 0.5·(1 + erf) form). Resolves [frankenscipy-tkpgq].
        let z = (x / self.scale).ln() / self.s;
        standard_normal_cdf(z)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // If X ~ Lognormal(mu, sigma), then ln(X) ~ Normal(mu, sigma)
        // ppf(q) = exp(mu + sigma * ndtri(q)) where mu = ln(scale)
        self.scale * (self.s * fsci_special::ndtri_scalar(q)).exp()
    }

    fn mean(&self) -> f64 {
        self.scale * (0.5 * self.s * self.s).exp()
    }

    fn var(&self) -> f64 {
        let s2 = self.s * self.s;
        self.scale * self.scale * s2.exp() * (s2.exp() - 1.0)
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x <= 0.0) {
            return Self {
                s: f64::NAN,
                scale: f64::NAN,
            };
        }
        let n = data.len() as f64;
        let log_data: Vec<f64> = data.iter().map(|&x| x.ln()).collect();
        let mu = log_data.iter().sum::<f64>() / n;
        let var = log_data.iter().map(|&lx| (lx - mu).powi(2)).sum::<f64>() / n;
        Self {
            s: var.sqrt(),
            scale: mu.exp(),
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite() || x <= 0.0) {
            return Err(FitError::UnsupportedData(
                "Lognormal requires positive finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.s.is_finite() || !fitted.scale.is_finite() {
            return Err(FitError::NonConvergent(
                "Lognormal fit produced non-finite parameters".into(),
            ));
        }
        Ok(fitted)
    }

    fn entropy(&self) -> f64 {
        // H = 0.5 + 0.5*ln(2*pi) + ln(s) + ln(scale)
        0.5 + 0.5 * (2.0 * PI).ln() + self.s.ln() + self.scale.ln()
    }

    fn skewness(&self) -> f64 {
        let es2 = (self.s * self.s).exp();
        (es2 + 2.0) * (es2 - 1.0).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        let s2 = self.s * self.s;
        (4.0 * s2).exp() + 2.0 * (3.0 * s2).exp() + 3.0 * (2.0 * s2).exp() - 6.0
    }

    fn mode(&self) -> f64 {
        // Lognormal mode = scale · exp(-s²) = exp(μ - σ²) where
        // μ = ln(scale), σ = s [frankenscipy-cxgdg].
        self.scale * (-self.s * self.s).exp()
    }
}

// ══════════════════════════════════════════════════════════════════════
// Pareto Distribution
// ══════════════════════════════════════════════════════════════════════

/// Pareto distribution with shape `b` and scale `scale`.
///
/// Matches `scipy.stats.pareto(b, scale=scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Pareto {
    pub b: f64,
    pub scale: f64,
}

impl Pareto {
    #[must_use]
    pub fn new(b: f64, scale: f64) -> Self {
        assert!(b > 0.0, "shape b must be positive, got {b}");
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { b, scale }
    }
}

impl ContinuousDistribution for Pareto {
    fn pdf(&self, x: f64) -> f64 {
        if x < self.scale {
            0.0
        } else {
            self.b * self.scale.powf(self.b) / x.powf(self.b + 1.0)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < self.scale {
            0.0
        } else {
            1.0 - (self.scale / x).powf(self.b)
        }
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-h36zm]:
        //   sf(x) = (scale / x)^b   for x ≥ scale.
        // The default 1 - (1 - (scale/x)^b) loses all precision in
        // the deep right tail where (scale/x)^b ≈ 0.
        if x < self.scale {
            1.0
        } else {
            (self.scale / x).powf(self.b)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.scale;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.scale / (1.0 - q).powf(1.0 / self.b)
    }

    fn mean(&self) -> f64 {
        if self.b <= 1.0 {
            f64::INFINITY
        } else {
            self.b * self.scale / (self.b - 1.0)
        }
    }

    fn var(&self) -> f64 {
        if self.b <= 2.0 {
            f64::INFINITY
        } else {
            self.scale * self.scale * self.b / ((self.b - 1.0).powi(2) * (self.b - 2.0))
        }
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x <= 0.0) {
            return Self {
                b: f64::NAN,
                scale: f64::NAN,
            };
        }

        let scale = data.iter().copied().fold(f64::INFINITY, f64::min);
        let log_sum = data.iter().map(|&x| (x / scale).ln()).sum::<f64>();
        let b = if log_sum == 0.0 {
            f64::INFINITY
        } else {
            data.len() as f64 / log_sum
        };
        Self { b, scale }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-covaj]: typed-error counterpart to fit().
        // Pareto MLE: scale = min(data), b = N / Σ ln(x_i / scale).
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite() || x <= 0.0) {
            return Err(FitError::UnsupportedData(
                "Pareto fit requires positive finite samples".into(),
            ));
        }
        let scale = data.iter().copied().fold(f64::INFINITY, f64::min);
        let log_sum = data.iter().map(|&x| (x / scale).ln()).sum::<f64>();
        let b = if log_sum == 0.0 {
            f64::INFINITY
        } else {
            data.len() as f64 / log_sum
        };
        Ok(Self { b, scale })
    }

    fn mode(&self) -> f64 {
        // Pareto mode = scale (lower endpoint of support) [frankenscipy-cxgdg].
        self.scale
    }

    fn entropy(&self) -> f64 {
        // H(Pareto) = ln(scale/b) + 1/b + 1 [frankenscipy-vngzr].
        (self.scale / self.b).ln() + 1.0 / self.b + 1.0
    }

    fn skewness(&self) -> f64 {
        // Pareto skewness = 2·(1+b)/(b-3)·√((b-2)/b) for b > 3;
        // NaN otherwise (third moment doesn't exist) [frankenscipy-y718j].
        if self.b > 3.0 {
            2.0 * (1.0 + self.b) / (self.b - 3.0) * ((self.b - 2.0) / self.b).sqrt()
        } else {
            f64::NAN
        }
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 6(b³ + b² − 6b − 2) / (b(b-3)(b-4)) for b > 4;
        // NaN otherwise (fourth moment diverges). (frankenscipy-026b5)
        if self.b > 4.0 {
            let b = self.b;
            6.0 * (b * b * b + b * b - 6.0 * b - 2.0) / (b * (b - 3.0) * (b - 4.0))
        } else {
            f64::NAN
        }
    }
}

/// Lomax distribution.
///
/// Matches `scipy.stats.lomax(c)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Lomax {
    pub c: f64,
}

impl Lomax {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "shape c must be positive, got {c}");
        Self { c }
    }
}

impl ContinuousDistribution for Lomax {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            self.c / (1.0 + x).powf(self.c + 1.0)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            -(-self.c * x.ln_1p()).exp_m1()
        }
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-h36zm]:
        //   sf(x) = (1 + x)^(-c) = exp(-c · ln(1+x))   for x ≥ 0.
        // The default 1 - cdf would re-add the cancelling pair
        // (1 - exp_m1(...)) and lose precision deep in the tail.
        if x < 0.0 {
            1.0
        } else {
            (-self.c * x.ln_1p()).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        (-(-q).ln_1p() / self.c).exp_m1()
    }

    fn mean(&self) -> f64 {
        if self.c <= 1.0 {
            f64::INFINITY
        } else {
            1.0 / (self.c - 1.0)
        }
    }

    fn var(&self) -> f64 {
        if self.c <= 2.0 {
            f64::INFINITY
        } else {
            self.c / ((self.c - 1.0).powi(2) * (self.c - 2.0))
        }
    }

    fn skewness(&self) -> f64 {
        // Lomax (Pareto-Type-II with location -1) inherits Pareto's
        // shape-only third-moment formula: 2·(1+c)/(c-3)·√((c-2)/c)
        // for c > 3. (frankenscipy-3moif)
        if self.c > 3.0 {
            2.0 * (1.0 + self.c) / (self.c - 3.0) * ((self.c - 2.0) / self.c).sqrt()
        } else {
            f64::NAN
        }
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 6(c³+c²-6c-2) / (c(c-3)(c-4)) for c > 4.
        // (frankenscipy-3moif)
        if self.c > 4.0 {
            let c = self.c;
            6.0 * (c * c * c + c * c - 6.0 * c - 2.0) / (c * (c - 3.0) * (c - 4.0))
        } else {
            f64::NAN
        }
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|v| !v.is_finite() || *v < 0.0) {
            return Self { c: f64::NAN };
        }
        let n = data.len() as f64;
        let log_sum: f64 = data.iter().map(|&x| (1.0 + x).ln()).sum();
        if log_sum <= 0.0 {
            return Self { c: f64::NAN };
        }
        Self { c: n / log_sum }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-covaj]: typed-error counterpart to fit().
        // Lomax MLE: c = N / Σ ln(1 + x_i).
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|v| !v.is_finite() || *v < 0.0) {
            return Err(FitError::UnsupportedData(
                "Lomax fit requires non-negative finite samples".into(),
            ));
        }
        let n = data.len() as f64;
        let log_sum: f64 = data.iter().map(|&x| (1.0 + x).ln()).sum();
        if log_sum <= 0.0 {
            return Err(FitError::NonConvergent(
                "Lomax fit: ln(1+x) sum is non-positive (degenerate sample)".into(),
            ));
        }
        Ok(Self { c: n / log_sum })
    }

    fn entropy(&self) -> f64 {
        // H(Lomax(c)) = 1 + 1/c − ln(c) for unit scale.
        // Derivation: pdf = c/(1+x)^(c+1); E[log(1+x)] = 1/c, so
        // H = -log(c) + (c+1)/c = 1 + 1/c − log(c). [frankenscipy-2ea4i].
        1.0 + 1.0 / self.c - self.c.ln()
    }
}

// ══════════════════════════════════════════════════════════════════════
// Rayleigh Distribution
// ══════════════════════════════════════════════════════════════════════

/// Rayleigh distribution with scale parameter `scale`.
///
/// Matches `scipy.stats.rayleigh(scale=scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Rayleigh {
    pub scale: f64,
}

impl Rayleigh {
    #[must_use]
    pub fn new(scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { scale }
    }
}

impl ContinuousDistribution for Rayleigh {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            let sigma_sq = self.scale * self.scale;
            x / sigma_sq * (-(x * x) / (2.0 * sigma_sq)).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            -(-(x * x) / (2.0 * self.scale * self.scale)).exp_m1()
        }
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-f66lp]:
        //   sf(x) = exp(-x²/(2σ²)) for x ≥ 0.
        // Direct exponential — preserves the deep-tail value where
        // the default 1 - cdf would round to 0 (cdf rounds to 1).
        if x < 0.0 {
            1.0
        } else {
            (-(x * x) / (2.0 * self.scale * self.scale)).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.scale * (-2.0 * (1.0 - q).ln()).sqrt()
    }

    fn mean(&self) -> f64 {
        self.scale * (PI / 2.0).sqrt()
    }

    fn var(&self) -> f64 {
        (2.0 - PI / 2.0) * self.scale * self.scale
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Self { scale: f64::NAN };
        }
        let n = data.len() as f64;
        let sum_sq = data.iter().map(|&x| x * x).sum::<f64>();
        Self {
            scale: (sum_sq / (2.0 * n)).sqrt(),
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Err(FitError::UnsupportedData(
                "Rayleigh requires non-negative finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.scale.is_finite() || fitted.scale <= 0.0 {
            return Err(FitError::NonConvergent(
                "Rayleigh fit produced non-finite or non-positive scale".into(),
            ));
        }
        Ok(fitted)
    }

    fn mode(&self) -> f64 {
        // Rayleigh mode = scale [frankenscipy-cxgdg].
        self.scale
    }

    fn entropy(&self) -> f64 {
        // H(Rayleigh) = 1 + ln(σ/√2) + γ/2 [frankenscipy-vngzr].
        1.0 + (self.scale / std::f64::consts::SQRT_2).ln() + EULER_MASCHERONI / 2.0
    }

    fn skewness(&self) -> f64 {
        // Rayleigh skewness = 2·(π-3)·√π / (4-π)^(3/2) ≈ 0.6311
        // [frankenscipy-y718j]; constant in scale.
        2.0 * (PI - 3.0) * PI.sqrt() / (4.0 - PI).powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: (24π − 6π² − 16) / (4 − π)² ≈ 0.24509
        // (scale-invariant). (frankenscipy-5cd0j)
        let four_minus_pi = 4.0 - PI;
        (24.0 * PI - 6.0 * PI * PI - 16.0) / (four_minus_pi * four_minus_pi)
    }
}

// ══════════════════════════════════════════════════════════════════════
// Gumbel Distribution
// ══════════════════════════════════════════════════════════════════════

/// Gumbel (extreme value type I) distribution.
///
/// Matches `scipy.stats.gumbel_r(loc=loc, scale=scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Gumbel {
    pub loc: f64,
    pub scale: f64,
}

impl Gumbel {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }
}

impl ContinuousDistribution for Gumbel {
    fn pdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        let exp_neg_z = (-z).exp();
        (-(z + exp_neg_z)).exp() / self.scale
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        (-(-z).exp()).exp()
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-6uo0s]:
        //   sf = 1 - exp(-exp(-z)) = -expm1(-exp(-z))
        // Default 1 - cdf evaluates 1 - exp(-tiny) which collapses to 0
        // for z far in the right tail; expm1 preserves the exact value.
        let z = (x - self.loc) / self.scale;
        -((-(-z).exp()).exp_m1())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.loc - self.scale * (-q.ln()).ln()
    }

    fn mean(&self) -> f64 {
        const EULER_GAMMA: f64 = 0.577_215_664_901_532_9;
        self.loc + EULER_GAMMA * self.scale
    }

    fn var(&self) -> f64 {
        PI * PI * self.scale * self.scale / 6.0
    }

    fn fit(data: &[f64]) -> Self {
        let (loc, scale) = gumbel_fit_loc_scale(data);
        Self { loc, scale }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Gumbel requires finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.loc.is_finite() || !fitted.scale.is_finite() || fitted.scale <= 0.0 {
            return Err(FitError::NonConvergent(
                "Gumbel fit produced non-finite or non-positive parameters".into(),
            ));
        }
        Ok(fitted)
    }

    fn entropy(&self) -> f64 {
        self.scale.ln() + EULER_MASCHERONI + 1.0
    }

    fn mode(&self) -> f64 {
        self.loc
    }

    fn skewness(&self) -> f64 {
        1.139_547_099_404_648_7
    }

    fn kurtosis(&self) -> f64 {
        2.4
    }
}

/// Left-skewed Gumbel (extreme value type I) distribution.
///
/// Matches `scipy.stats.gumbel_l(loc=loc, scale=scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct GumbelLeft {
    pub loc: f64,
    pub scale: f64,
}

impl GumbelLeft {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }
}

impl ContinuousDistribution for GumbelLeft {
    fn pdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        (z - z.exp()).exp() / self.scale
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        -(-z.exp()).exp_m1()
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-6uo0s]:
        //   sf = exp(-exp(z))
        // Default 1 - cdf collapses when cdf ≈ 1 in the right tail
        // (z large positive); the direct exp form preserves the value.
        let z = (x - self.loc) / self.scale;
        (-z.exp()).exp()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.loc + self.scale * (-(-q).ln_1p()).ln()
    }

    fn mean(&self) -> f64 {
        const EULER_GAMMA: f64 = 0.577_215_664_901_532_9;
        self.loc - EULER_GAMMA * self.scale
    }

    fn var(&self) -> f64 {
        PI * PI * self.scale * self.scale / 6.0
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite()) {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }

        let mirrored: Vec<f64> = data.iter().map(|&x| -x).collect();
        let (mirrored_loc, scale) = gumbel_fit_loc_scale(&mirrored);
        Self {
            loc: -mirrored_loc,
            scale,
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(
                "GumbelLeft requires finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.loc.is_finite() || !fitted.scale.is_finite() || fitted.scale <= 0.0 {
            return Err(FitError::NonConvergent(
                "GumbelLeft fit produced non-finite or non-positive parameters".into(),
            ));
        }
        Ok(fitted)
    }

    fn mode(&self) -> f64 {
        // GumbelLeft mode = loc [frankenscipy-cxgdg].
        self.loc
    }

    fn entropy(&self) -> f64 {
        // H(GumbelLeft) = ln(scale) + γ + 1; same as right Gumbel by
        // symmetry [frankenscipy-vngzr].
        self.scale.ln() + EULER_MASCHERONI + 1.0
    }

    fn skewness(&self) -> f64 {
        // GumbelLeft skewness = -12·√6·ζ(3)/π³ — mirror of right
        // Gumbel (= -1.139547...) [frankenscipy-y718j].
        -1.139_547_099_404_648_7
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis = 12/5 (constant, identical to right
        // Gumbel — the family has the same fourth central moment).
        // (frankenscipy-25tcp)
        12.0 / 5.0
    }
}

// ══════════════════════════════════════════════════════════════════════
// Logistic Distribution
// ══════════════════════════════════════════════════════════════════════

/// Logistic distribution with location `loc` and scale `scale`.
///
/// Matches `scipy.stats.logistic(loc=loc, scale=scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Logistic {
    pub loc: f64,
    pub scale: f64,
}

impl Logistic {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }
}

impl ContinuousDistribution for Logistic {
    fn pdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        let exp_neg_z = (-z).exp();
        exp_neg_z / (self.scale * (1.0 + exp_neg_z).powi(2))
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        1.0 / (1.0 + (-z).exp())
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-h36zm]:
        //   sf = 1/(1 + exp(z))  vs.  the imprecise default 1 - cdf.
        // For large positive z (deep right tail), 1 - 1/(1 + exp(-z))
        // catastrophically cancels.
        let z = (x - self.loc) / self.scale;
        1.0 / (1.0 + z.exp())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.loc + self.scale * (q / (1.0 - q)).ln()
    }

    fn mean(&self) -> f64 {
        self.loc
    }

    fn var(&self) -> f64 {
        PI * PI * self.scale * self.scale / 3.0
    }

    fn fit(data: &[f64]) -> Self {
        let n = data.len() as f64;
        if n == 0.0 {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
        Self {
            loc: mean,
            scale: var.sqrt() * 3.0_f64.sqrt() / PI,
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-covaj]: previously inherited the trait-default
        // try_fit which returned NotImplemented even though fit() had a
        // working method-of-moments closed form. Surface typed errors
        // to non-panicking callers without touching fit() (which keeps
        // its existing NaN-on-bad-input behavior for back-compat).
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Logistic fit requires all-finite samples".into(),
            ));
        }
        let n = data.len() as f64;
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / n;
        Ok(Self {
            loc: mean,
            scale: var.sqrt() * 3.0_f64.sqrt() / PI,
        })
    }

    fn entropy(&self) -> f64 {
        self.scale.ln() + 2.0
    }

    fn mode(&self) -> f64 {
        self.loc
    }

    fn skewness(&self) -> f64 {
        0.0
    }

    fn kurtosis(&self) -> f64 {
        1.2
    }
}

/// Hyperbolic secant distribution.
///
/// Matches `scipy.stats.hypsecant`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HypSecant;

impl ContinuousDistribution for HypSecant {
    fn pdf(&self, x: f64) -> f64 {
        let exp_neg_abs_x = (-x.abs()).exp();
        2.0 * exp_neg_abs_x / (PI * (1.0 + exp_neg_abs_x * exp_neg_abs_x))
    }

    fn cdf(&self, x: f64) -> f64 {
        if x >= 0.0 {
            1.0 - 2.0 / PI * (-x).exp().atan()
        } else {
            2.0 / PI * x.exp().atan()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        (0.5 * PI * q).tan().ln()
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        PI * PI / 4.0
    }

    fn skewness(&self) -> f64 {
        // HypSecant is symmetric around 0.
        0.0
    }

    fn kurtosis(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-a1kjq]: scipy.stats.hypsecant
        // reports excess kurtosis = 2.
        2.0
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-a1kjq]: scipy.stats.hypsecant
        // reports differential entropy = ln(2π).
        (2.0 * PI).ln()
    }

    // fit() inherits the trait default which delegates to try_fit and
    // panics on FitError. Resolves [frankenscipy-v6rct]: previously
    // HypSecant.fit silently accepted any data (including NaN/empty)
    // while HypSecant.try_fit validated, inverting the trait's
    // panic-vs-Result contract.

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        Ok(Self)
    }
}

// ══════════════════════════════════════════════════════════════════════
// Maxwell Distribution
// ══════════════════════════════════════════════════════════════════════

/// Maxwell distribution with scale parameter `scale`.
///
/// Matches `scipy.stats.maxwell(scale=scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Maxwell {
    pub scale: f64,
}

impl Maxwell {
    #[must_use]
    pub fn new(scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { scale }
    }
}

impl ContinuousDistribution for Maxwell {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            (2.0 / PI).sqrt() * x * x / self.scale.powi(3)
                * (-(x * x) / (2.0 * self.scale * self.scale)).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else {
            let sqrt_two_over_pi = (2.0 / PI).sqrt();
            let z = x / (self.scale * 2.0_f64.sqrt());
            fsci_special::erf_scalar(z)
                - sqrt_two_over_pi
                    * (x / self.scale)
                    * (-(x * x) / (2.0 * self.scale * self.scale)).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let mut x = self.scale * (2.0 * fsci_special::gammaincinv_scalar(1.5, q)).sqrt();
        if x <= 0.0 || !x.is_finite() || (self.cdf(x) - q).abs() > 0.1 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        2.0 * self.scale * (2.0 / PI).sqrt()
    }

    fn var(&self) -> f64 {
        self.scale * self.scale * (3.0 - 8.0 / PI)
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Self { scale: f64::NAN };
        }
        let n = data.len() as f64;
        let sum_sq = data.iter().map(|&x| x * x).sum::<f64>();
        Self {
            scale: (sum_sq / (3.0 * n)).sqrt(),
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite() || x < 0.0) {
            return Err(FitError::UnsupportedData(
                "Maxwell requires non-negative finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.scale.is_finite() || fitted.scale <= 0.0 {
            return Err(FitError::NonConvergent(
                "Maxwell fit produced non-finite or non-positive scale".into(),
            ));
        }
        Ok(fitted)
    }

    fn mode(&self) -> f64 {
        // Maxwell mode = scale · √2 [frankenscipy-cxgdg].
        self.scale * std::f64::consts::SQRT_2
    }

    fn skewness(&self) -> f64 {
        // Maxwell skewness = 2·√2·(16 - 5π) / (3π - 8)^(3/2) ≈ 0.4857
        // [frankenscipy-y718j]; constant in scale.
        2.0 * std::f64::consts::SQRT_2 * (16.0 - 5.0 * PI) / (3.0 * PI - 8.0).powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 4·(40π − 3π² − 96) / (3π − 8)² ≈ 0.10816
        // (scale-invariant). (frankenscipy-5cd0j)
        let three_pi_minus_8 = 3.0 * PI - 8.0;
        4.0 * (40.0 * PI - 3.0 * PI * PI - 96.0) / (three_pi_minus_8 * three_pi_minus_8)
    }
}

// ══════════════════════════════════════════════════════════════════════
// Multivariate Normal Distribution
// ══════════════════════════════════════════════════════════════════════

/// Multivariate normal distribution with cached Cholesky factorization.
///
/// Matches `scipy.stats.multivariate_normal(mean, cov)` for the default
/// `allow_singular=False` path.
#[derive(Debug, Clone, PartialEq)]
pub struct MultivariateNormal {
    pub mean: Vec<f64>,
    pub cov: Vec<Vec<f64>>,
    chol: Vec<Vec<f64>>,
    log_det: f64,
}

impl MultivariateNormal {
    pub fn new(mean: &[f64], cov: &[Vec<f64>]) -> Result<Self, StatsError> {
        if mean.is_empty() {
            return Err(StatsError::InvalidArgument(
                "mean must be non-empty".to_string(),
            ));
        }
        if cov.len() != mean.len() {
            return Err(StatsError::InvalidArgument(format!(
                "cov row count ({}) must match mean length ({})",
                cov.len(),
                mean.len()
            )));
        }
        for (row_idx, row) in cov.iter().enumerate() {
            if row.len() != mean.len() {
                return Err(StatsError::InvalidArgument(format!(
                    "cov row {row_idx} has length {}, expected {}",
                    row.len(),
                    mean.len()
                )));
            }
        }
        for (i, row_i) in cov.iter().enumerate() {
            for (j, row_j) in cov.iter().enumerate() {
                if (row_i[j] - row_j[i]).abs() > 1e-12 {
                    return Err(StatsError::InvalidArgument(
                        "covariance matrix must be symmetric".to_string(),
                    ));
                }
            }
        }

        let chol = cholesky_decompose(cov)?;
        let log_det = 2.0 * (0..chol.len()).map(|i| chol[i][i].ln()).sum::<f64>();
        Ok(Self {
            mean: mean.to_vec(),
            cov: cov.to_vec(),
            chol,
            log_det,
        })
    }

    pub fn logpdf(&self, x: &[f64]) -> Result<f64, StatsError> {
        if x.len() != self.mean.len() {
            return Err(StatsError::InvalidArgument(format!(
                "x length ({}) must match dimension ({})",
                x.len(),
                self.mean.len()
            )));
        }
        let centered: Vec<f64> = x
            .iter()
            .zip(self.mean.iter())
            .map(|(&xi, &mi)| xi - mi)
            .collect();
        let solved = solve_lower_triangular(&self.chol, &centered)?;
        let mahalanobis = solved.iter().map(|value| value * value).sum::<f64>();
        let dim = self.mean.len() as f64;
        Ok(-0.5 * (dim * (2.0 * PI).ln() + self.log_det + mahalanobis))
    }

    pub fn pdf(&self, x: &[f64]) -> Result<f64, StatsError> {
        Ok(self.logpdf(x)?.exp())
    }

    pub fn rvs(&self, n: usize, rng: &mut impl Rng) -> Vec<Vec<f64>> {
        let mut samples = Vec::with_capacity(n);
        for _ in 0..n {
            let z = sample_standard_normals(self.mean.len(), rng);
            let mut sample = self.mean.clone();
            for (i, row) in self.chol.iter().enumerate() {
                for (j, &zj) in z.iter().take(i + 1).enumerate() {
                    sample[i] += row[j] * zj;
                }
            }
            samples.push(sample);
        }
        samples
    }
}

// ══════════════════════════════════════════════════════════════════════
// Dirichlet Distribution
// ══════════════════════════════════════════════════════════════════════

/// Dirichlet distribution - multivariate generalization of Beta.
///
/// Matches `scipy.stats.dirichlet(alpha)`.
#[derive(Debug, Clone, PartialEq)]
pub struct Dirichlet {
    pub alpha: Vec<f64>,
    alpha_sum: f64,
    log_norm: f64,
}

impl Dirichlet {
    /// Create a Dirichlet distribution with concentration parameters alpha.
    pub fn new(alpha: &[f64]) -> Self {
        assert!(!alpha.is_empty(), "alpha must be non-empty");
        assert!(
            alpha.iter().all(|&a| a > 0.0),
            "all alpha values must be positive"
        );

        let alpha_sum: f64 = alpha.iter().sum();
        let log_norm = alpha.iter().map(|&a| ln_gamma(a)).sum::<f64>() - ln_gamma(alpha_sum);

        Self {
            alpha: alpha.to_vec(),
            alpha_sum,
            log_norm,
        }
    }

    /// Log probability density function.
    pub fn logpdf(&self, x: &[f64]) -> f64 {
        if x.len() != self.alpha.len() {
            return f64::NEG_INFINITY;
        }

        let sum: f64 = x.iter().sum();
        if (sum - 1.0).abs() > 1e-10 || x.iter().any(|&xi| !(0.0..=1.0).contains(&xi)) {
            return f64::NEG_INFINITY;
        }

        let log_x: f64 = x
            .iter()
            .zip(&self.alpha)
            .map(|(&xi, &ai)| (ai - 1.0) * xi.ln())
            .sum();

        log_x - self.log_norm
    }

    /// Probability density function.
    pub fn pdf(&self, x: &[f64]) -> f64 {
        self.logpdf(x).exp()
    }

    /// Mean of the distribution.
    pub fn mean(&self) -> Vec<f64> {
        self.alpha.iter().map(|&a| a / self.alpha_sum).collect()
    }

    /// Variance of each component.
    pub fn var(&self) -> Vec<f64> {
        let s = self.alpha_sum;
        let denom = s * s * (s + 1.0);
        self.alpha.iter().map(|&a| a * (s - a) / denom).collect()
    }

    /// Generate random variates from the distribution.
    pub fn rvs(&self, n: usize, rng: &mut impl Rng) -> Vec<Vec<f64>> {
        let mut samples = Vec::with_capacity(n);
        for _ in 0..n {
            let gamma_samples: Vec<f64> = self
                .alpha
                .iter()
                .map(|&a| {
                    let gamma = GammaDist::new(a, 1.0);
                    gamma.rvs(1, rng)[0]
                })
                .collect();
            let sum: f64 = gamma_samples.iter().sum();
            let normalized: Vec<f64> = gamma_samples.iter().map(|&g| g / sum).collect();
            samples.push(normalized);
        }
        samples
    }

    /// Entropy of the distribution.
    pub fn entropy(&self) -> f64 {
        let k = self.alpha.len() as f64;
        self.log_norm
            - (k - self.alpha_sum) * digamma(self.alpha_sum)
            - self
                .alpha
                .iter()
                .map(|&a| (a - 1.0) * digamma(a))
                .sum::<f64>()
    }
}

// ══════════════════════════════════════════════════════════════════════
// Von Mises Distribution
// ══════════════════════════════════════════════════════════════════════

/// Von Mises circular distribution.
///
/// Matches `scipy.stats.vonmises(kappa, loc=loc)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct VonMises {
    pub kappa: f64,
    pub loc: f64,
}

impl VonMises {
    #[must_use]
    pub fn new(kappa: f64, loc: f64) -> Self {
        assert!(kappa >= 0.0, "kappa must be non-negative, got {kappa}");
        Self { kappa, loc }
    }

    fn period_start(&self) -> f64 {
        self.loc - PI
    }

    fn base_cdf(&self, x: f64) -> f64 {
        let start = self.period_start();
        let end = start + 2.0 * PI;
        if x <= start {
            return 0.0;
        }
        if x >= end {
            return 1.0;
        }

        let steps = 2048usize;
        let step = (x - start) / steps as f64;
        let mut sum = 0.5 * (self.pdf(start) + self.pdf(x));
        for idx in 1..steps {
            sum += self.pdf(start + idx as f64 * step);
        }
        (sum * step).clamp(0.0, 1.0)
    }

    #[must_use]
    pub fn circular_variance(&self) -> f64 {
        self.var()
    }
}

impl ContinuousDistribution for VonMises {
    fn pdf(&self, x: f64) -> f64 {
        let i0 = modified_bessel_i(0.0, self.kappa);
        (self.kappa * (x - self.loc).cos()).exp() / (2.0 * PI * i0)
    }

    fn cdf(&self, x: f64) -> f64 {
        let start = self.period_start();
        let period = 2.0 * PI;
        let cycles = ((x - start) / period).floor();
        let reduced = x - cycles * period;
        cycles + self.base_cdf(reduced)
    }

    fn mean(&self) -> f64 {
        self.loc
    }

    fn var(&self) -> f64 {
        let i0 = modified_bessel_i(0.0, self.kappa);
        let i1 = modified_bessel_i(1.0, self.kappa);
        1.0 - i1 / i0
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 2, "VonMises")?;
        let n = data.len() as f64;
        let sin_mean = data.iter().map(|x| x.sin()).sum::<f64>() / n;
        let cos_mean = data.iter().map(|x| x.cos()).sum::<f64>() / n;
        let r = sin_mean.hypot(cos_mean).clamp(0.0, 1.0 - f64::EPSILON);
        let loc = sin_mean.atan2(cos_mean);
        let kappa = if r < 1.0e-12 {
            0.0
        } else if r < 0.53 {
            2.0 * r + r.powi(3) + 5.0 * r.powi(5) / 6.0
        } else if r < 0.85 {
            -0.4 + 1.39 * r + 0.43 / (1.0 - r)
        } else {
            1.0 / (r.powi(3) - 4.0 * r.powi(2) + 3.0 * r)
        };
        if kappa.is_finite() && kappa >= 0.0 {
            Ok(Self { kappa, loc })
        } else {
            Err(FitError::NonConvergent(format!(
                "VonMises circular fit produced invalid kappa: {kappa}"
            )))
        }
    }
}

// ══════════════════════════════════════════════════════════════════════
// Poisson Distribution (discrete, but commonly needed)
// ══════════════════════════════════════════════════════════════════════

/// Poisson distribution with rate parameter `mu`.
///
/// Matches `scipy.stats.poisson(mu)`.
/// PMF: P(k) = mu^k * exp(-mu) / k!
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Poisson {
    pub mu: f64,
}

impl Poisson {
    #[must_use]
    pub fn new(mu: f64) -> Self {
        assert!(mu > 0.0, "mu must be positive, got {mu}");
        Self { mu }
    }

    /// Probability mass function.
    pub fn pmf(&self, k: u64) -> f64 {
        if self.mu == 0.0 {
            return if k == 0 { 1.0 } else { 0.0 };
        }
        let ln_pmf = k as f64 * self.mu.ln() - self.mu - ln_gamma(k as f64 + 1.0);
        ln_pmf.exp()
    }

    /// Cumulative distribution function.
    pub fn cdf(&self, k: u64) -> f64 {
        // Direct summation: P(X <= k) = sum_{i=0}^{k} pmf(i)
        let mut sum = 0.0;
        for i in 0..=k {
            sum += self.pmf(i);
        }
        sum.min(1.0) // clamp for numerical safety
    }

    /// Mean of the distribution.
    pub fn mean(&self) -> f64 {
        self.mu
    }

    /// Variance of the distribution.
    pub fn var(&self) -> f64 {
        self.mu
    }
}

// ══════════════════════════════════════════════════════════════════════
// Discrete Distribution Trait and Implementations
// ══════════════════════════════════════════════════════════════════════

/// Trait for discrete probability distributions.
pub trait DiscreteDistribution {
    /// Probability mass function.
    fn pmf(&self, k: u64) -> f64;
    /// Cumulative distribution function: P(X <= k).
    fn cdf(&self, k: u64) -> f64 {
        (0..=k).map(|i| self.pmf(i)).sum::<f64>().min(1.0)
    }
    /// Survival function: P(X > k) = 1 - cdf(k).
    fn sf(&self, k: u64) -> f64 {
        1.0 - self.cdf(k)
    }
    /// Mean of the distribution.
    fn mean(&self) -> f64;
    /// Variance of the distribution.
    fn var(&self) -> f64;
    /// Standard deviation.
    fn std(&self) -> f64 {
        self.var().sqrt()
    }
    /// Entropy in nats. Default returns NaN.
    fn entropy(&self) -> f64 {
        f64::NAN
    }
    /// Fallible entropy accessor. Inherited NaN defaults become a typed
    /// unsupported-operation error for generic callers.
    fn try_entropy(&self) -> Result<f64, StatsError> {
        unsupported_distribution_moment(self.entropy(), "entropy", std::any::type_name::<Self>())
    }
    /// Skewness. Default returns NaN.
    fn skewness(&self) -> f64 {
        f64::NAN
    }
    /// Fallible skewness accessor. Inherited NaN defaults become a typed
    /// unsupported-operation error for generic callers.
    fn try_skewness(&self) -> Result<f64, StatsError> {
        unsupported_distribution_moment(self.skewness(), "skewness", std::any::type_name::<Self>())
    }
    /// Excess kurtosis. Default returns NaN.
    fn kurtosis(&self) -> f64 {
        f64::NAN
    }
    /// Fallible excess-kurtosis accessor. Inherited NaN defaults become
    /// a typed unsupported-operation error for generic callers.
    fn try_kurtosis(&self) -> Result<f64, StatsError> {
        unsupported_distribution_moment(self.kurtosis(), "kurtosis", std::any::type_name::<Self>())
    }
    /// Mode (most likely value). Default returns NaN.
    fn mode(&self) -> f64 {
        f64::NAN
    }
}

impl DiscreteDistribution for Poisson {
    fn pmf(&self, k: u64) -> f64 {
        Poisson::pmf(self, k)
    }
    fn cdf(&self, k: u64) -> f64 {
        Poisson::cdf(self, k)
    }
    fn mean(&self) -> f64 {
        Poisson::mean(self)
    }
    fn var(&self) -> f64 {
        Poisson::var(self)
    }
    fn entropy(&self) -> f64 {
        0.5 * (2.0 * PI * std::f64::consts::E * self.mu).ln()
            - 1.0 / (12.0 * self.mu)
            - 1.0 / (24.0 * self.mu * self.mu)
            - 19.0 / (360.0 * self.mu * self.mu * self.mu)
    }
    fn skewness(&self) -> f64 {
        1.0 / self.mu.sqrt()
    }
    fn kurtosis(&self) -> f64 {
        1.0 / self.mu
    }
    fn mode(&self) -> f64 {
        self.mu.floor()
    }
}

/// Binomial distribution: number of successes in n independent Bernoulli trials.
///
/// Matches `scipy.stats.binom(n, p)`.
/// PMF: P(k) = C(n,k) * p^k * (1-p)^(n-k)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Binomial {
    pub n: u64,
    pub p: f64,
}

impl Binomial {
    #[must_use]
    pub fn new(n: u64, p: f64) -> Self {
        assert!((0.0..=1.0).contains(&p), "p must be in [0, 1], got {p}");
        Self { n, p }
    }
}

impl DiscreteDistribution for Binomial {
    fn pmf(&self, k: u64) -> f64 {
        if k > self.n {
            return 0.0;
        }
        if self.p == 0.0 {
            return if k == 0 { 1.0 } else { 0.0 };
        }
        if self.p == 1.0 {
            return if k == self.n { 1.0 } else { 0.0 };
        }
        let ln_comb = ln_gamma(self.n as f64 + 1.0)
            - ln_gamma(k as f64 + 1.0)
            - ln_gamma((self.n - k) as f64 + 1.0);
        let ln_pmf = ln_comb + k as f64 * self.p.ln() + (self.n - k) as f64 * (1.0 - self.p).ln();
        ln_pmf.exp()
    }

    fn mean(&self) -> f64 {
        self.n as f64 * self.p
    }

    fn var(&self) -> f64 {
        self.n as f64 * self.p * (1.0 - self.p)
    }

    fn skewness(&self) -> f64 {
        let q = 1.0 - self.p;
        (1.0 - 2.0 * self.p) / (self.n as f64 * self.p * q).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        let q = 1.0 - self.p;
        (1.0 - 6.0 * self.p * q) / (self.n as f64 * self.p * q)
    }

    fn mode(&self) -> f64 {
        ((self.n as f64 + 1.0) * self.p).floor()
    }
}

/// Bernoulli distribution: single trial with probability p.
///
/// Matches `scipy.stats.bernoulli(p)`.
/// Special case of Binomial(1, p).
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Bernoulli {
    pub p: f64,
}

impl Bernoulli {
    #[must_use]
    pub fn new(p: f64) -> Self {
        assert!((0.0..=1.0).contains(&p), "p must be in [0, 1], got {p}");
        Self { p }
    }
}

impl DiscreteDistribution for Bernoulli {
    fn pmf(&self, k: u64) -> f64 {
        match k {
            0 => 1.0 - self.p,
            1 => self.p,
            _ => 0.0,
        }
    }

    fn cdf(&self, k: u64) -> f64 {
        if k == 0 { 1.0 - self.p } else { 1.0 }
    }

    fn mean(&self) -> f64 {
        self.p
    }

    fn var(&self) -> f64 {
        self.p * (1.0 - self.p)
    }

    fn entropy(&self) -> f64 {
        if self.p == 0.0 || self.p == 1.0 {
            return 0.0;
        }
        -self.p * self.p.ln() - (1.0 - self.p) * (1.0 - self.p).ln()
    }

    fn skewness(&self) -> f64 {
        let q = 1.0 - self.p;
        (1.0 - 2.0 * self.p) / (self.p * q).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        let q = 1.0 - self.p;
        (1.0 - 6.0 * self.p * q) / (self.p * q)
    }

    fn mode(&self) -> f64 {
        if self.p > 0.5 {
            1.0
        } else if self.p < 0.5 {
            0.0
        } else {
            f64::NAN
        }
    }
}

/// Geometric distribution: number of trials until first success.
///
/// Matches `scipy.stats.geom(p)`.
/// PMF: P(k) = p * (1-p)^(k-1) for k = 1, 2, 3, ...
/// Note: SciPy uses k >= 1 convention (first success on trial k).
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Geometric {
    pub p: f64,
}

impl Geometric {
    #[must_use]
    pub fn new(p: f64) -> Self {
        assert!(p > 0.0 && p <= 1.0, "p must be in (0, 1], got {p}");
        Self { p }
    }
}

/// Boltzmann (truncated geometric) distribution.
///
/// Matches `scipy.stats.boltzmann(lambda_, N)`. Resolves
/// [frankenscipy-nvrxh]. Two parameters: rate `lambda > 0` and
/// truncation `n` (positive integer). Support: k ∈ {0, 1, …, n−1}.
///
///   pmf(k; λ, n) = (1 − e^(−λ)) · e^(−λk) / (1 − e^(−λn))
///   cdf(k; λ, n) = (1 − e^(−λ(k+1))) / (1 − e^(−λn))
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Boltzmann {
    pub lambda: f64,
    pub n: u32,
}

impl Boltzmann {
    #[must_use]
    pub fn new(lambda: f64, n: u32) -> Self {
        assert!(
            lambda > 0.0 && lambda.is_finite(),
            "lambda must be positive and finite"
        );
        assert!(n >= 1, "n must be at least 1");
        Self { lambda, n }
    }

    #[inline]
    fn z(&self) -> f64 {
        // Normalization: Z = 1 − e^(−λn).
        -(-self.lambda * self.n as f64).exp_m1()
    }
}

impl DiscreteDistribution for Boltzmann {
    fn pmf(&self, k: u64) -> f64 {
        if k >= self.n as u64 {
            return 0.0;
        }
        let kf = k as f64;
        // (1 − e^(−λ)) · e^(−λk) / (1 − e^(−λn))
        (-(-self.lambda).exp_m1()) * (-self.lambda * kf).exp() / self.z()
    }

    fn cdf(&self, k: u64) -> f64 {
        if k >= self.n as u64 {
            return 1.0;
        }
        let kp1 = (k + 1) as f64;
        // (1 − e^(−λ(k+1))) / (1 − e^(−λn))
        (-(-self.lambda * kp1).exp_m1()) / self.z()
    }

    fn mean(&self) -> f64 {
        // ⟨k⟩ = (e^(−λ) − n · e^(−λn) + (n−1) · e^(−λ(n+1)))
        //       / ((1 − e^(−λ)) · (1 − e^(−λn)))
        // Equivalent canonical form via geometric-sum derivative:
        //   ⟨k⟩ = 1/(e^λ − 1) − n / (e^(λn) − 1)
        let nf = self.n as f64;
        let lam = self.lambda;
        1.0 / lam.exp_m1() - nf / (lam * nf).exp_m1()
    }

    fn var(&self) -> f64 {
        // Closed form: ⟨k²⟩ − ⟨k⟩².
        // ⟨k²⟩ has a known form too — compute via the same trick:
        //   ⟨k²⟩ = (e^λ + 1) / (e^λ − 1)² − n²/((e^(λn) − 1)·(e^(λn)·(1 − e^(−λn))/(1 − e^(−λ))))
        // For simplicity and robustness, fall back to the direct
        // sum since n is bounded.
        let m = self.mean();
        let mut e_k_sq = 0.0_f64;
        for k in 0..self.n as u64 {
            let kf = k as f64;
            e_k_sq += kf * kf * self.pmf(k);
        }
        (e_k_sq - m * m).max(0.0)
    }
}

/// Yule-Simon distribution.
///
/// Matches `scipy.stats.yulesimon(alpha)`. Resolves [frankenscipy-1obtd].
/// One parameter `alpha > 0`. Support: k ∈ {1, 2, 3, …}.
///
///   pmf(k; α) = α · B(k, α + 1)
///   cdf(k; α) = 1 − k · B(k, α + 1)
///   mean      = α / (α − 1)             [α > 1, ∞ otherwise]
///   var       = α² / ((α − 1)² · (α − 2))  [α > 2, ∞ otherwise]
///
/// where B is the Beta function. Computed via log-gamma to
/// avoid overflow for large k.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct YuleSimon {
    pub alpha: f64,
}

impl YuleSimon {
    #[must_use]
    pub fn new(alpha: f64) -> Self {
        assert!(
            alpha > 0.0 && alpha.is_finite(),
            "alpha must be positive and finite"
        );
        Self { alpha }
    }

    #[inline]
    fn ln_beta_k(&self, kf: f64) -> f64 {
        // ln B(k, α + 1) = ln Γ(k) + ln Γ(α + 1) − ln Γ(k + α + 1)
        ln_gamma(kf) + ln_gamma(self.alpha + 1.0) - ln_gamma(kf + self.alpha + 1.0)
    }
}

impl DiscreteDistribution for YuleSimon {
    fn pmf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        let kf = k as f64;
        // α · B(k, α + 1) = α · exp(ln B(k, α + 1))
        self.alpha * self.ln_beta_k(kf).exp()
    }

    fn cdf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        let kf = k as f64;
        // 1 − k · B(k, α + 1)
        (1.0 - kf * self.ln_beta_k(kf).exp()).clamp(0.0, 1.0)
    }

    fn mean(&self) -> f64 {
        if self.alpha > 1.0 {
            self.alpha / (self.alpha - 1.0)
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        if self.alpha > 2.0 {
            let am1 = self.alpha - 1.0;
            self.alpha * self.alpha / (am1 * am1 * (self.alpha - 2.0))
        } else {
            f64::INFINITY
        }
    }
}

/// Planck (untruncated geometric) distribution.
///
/// Matches `scipy.stats.planck(lambda_)`. Resolves [frankenscipy-lp6dv].
/// One parameter `lambda > 0`. Support: k ∈ {0, 1, 2, …}.
///
///   pmf(k; λ) = (1 − e^(−λ)) · e^(−λk)
///   cdf(k; λ) = 1 − e^(−λ(k+1))
///   mean      = 1 / (e^λ − 1)
///   var       = e^λ / (e^λ − 1)²
///
/// This is the `N → ∞` limit of `Boltzmann(λ, N)`. Pinned via
/// the `boltzmann_geometric_limit` metamorphic test.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Planck {
    pub lambda: f64,
}

impl Planck {
    #[must_use]
    pub fn new(lambda: f64) -> Self {
        assert!(
            lambda > 0.0 && lambda.is_finite(),
            "lambda must be positive and finite"
        );
        Self { lambda }
    }
}

impl DiscreteDistribution for Planck {
    fn pmf(&self, k: u64) -> f64 {
        let kf = k as f64;
        // (1 − e^(−λ)) · e^(−λk) — expm1 keeps precision when λ is small.
        (-(-self.lambda).exp_m1()) * (-self.lambda * kf).exp()
    }

    fn cdf(&self, k: u64) -> f64 {
        let kp1 = (k + 1) as f64;
        // 1 − e^(−λ(k+1))
        -(-self.lambda * kp1).exp_m1()
    }

    fn mean(&self) -> f64 {
        1.0 / self.lambda.exp_m1()
    }

    fn var(&self) -> f64 {
        let em = self.lambda.exp_m1();
        // Var = e^λ / (e^λ − 1)² = (1 + (e^λ − 1)) / (e^λ − 1)²
        //                      = 1/em + 1/em²
        let inv = 1.0 / em;
        inv * (1.0 + inv)
    }
}

impl DiscreteDistribution for Geometric {
    fn pmf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        self.p * (1.0 - self.p).powi((k - 1) as i32)
    }

    fn cdf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        1.0 - (1.0 - self.p).powi(k as i32)
    }

    fn mean(&self) -> f64 {
        1.0 / self.p
    }

    fn var(&self) -> f64 {
        (1.0 - self.p) / (self.p * self.p)
    }

    fn entropy(&self) -> f64 {
        let q = 1.0 - self.p;
        (-(q) * q.ln() - self.p * self.p.ln()) / self.p
    }

    fn skewness(&self) -> f64 {
        (2.0 - self.p) / (1.0 - self.p).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        6.0 + self.p * self.p / (1.0 - self.p)
    }

    fn mode(&self) -> f64 {
        1.0
    }
}

/// Negative binomial distribution: number of failures before n successes.
///
/// Matches `scipy.stats.nbinom(n, p)`.
/// PMF: P(k) = C(k+n-1, k) * p^n * (1-p)^k for k = 0, 1, 2, ...
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct NegBinomial {
    /// Number of successes required.
    pub n: f64,
    /// Probability of success on each trial.
    pub p: f64,
}

impl NegBinomial {
    #[must_use]
    pub fn new(n: f64, p: f64) -> Self {
        assert!(n > 0.0, "n must be positive, got {n}");
        assert!(p > 0.0 && p <= 1.0, "p must be in (0, 1], got {p}");
        Self { n, p }
    }
}

impl DiscreteDistribution for NegBinomial {
    fn pmf(&self, k: u64) -> f64 {
        // Limit case: with p=1 every trial succeeds, so the count of
        // failures is 0 with probability 1. Without this short-circuit
        // the formula evaluates 0 · ln(0) = NaN at k=0.
        if self.p == 1.0 {
            return if k == 0 { 1.0 } else { 0.0 };
        }
        let kf = k as f64;
        // C(k+n-1, k) = Γ(k+n) / (Γ(k+1) * Γ(n))
        let ln_comb = ln_gamma(kf + self.n) - ln_gamma(kf + 1.0) - ln_gamma(self.n);
        let ln_pmf = ln_comb + self.n * self.p.ln() + kf * (1.0 - self.p).ln();
        ln_pmf.exp()
    }

    fn mean(&self) -> f64 {
        self.n * (1.0 - self.p) / self.p
    }

    fn var(&self) -> f64 {
        self.n * (1.0 - self.p) / (self.p * self.p)
    }

    fn skewness(&self) -> f64 {
        let q = 1.0 - self.p;
        (2.0 - self.p) / (self.n * q).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        let q = 1.0 - self.p;
        6.0 / self.n + self.p * self.p / (self.n * q)
    }

    fn mode(&self) -> f64 {
        if self.n > 1.0 {
            ((self.n - 1.0) * (1.0 - self.p) / self.p).floor()
        } else {
            0.0
        }
    }
}

/// Hypergeometric distribution: draws without replacement.
///
/// Matches `scipy.stats.hypergeom(M, n, N)`.
/// PMF: P(k) = C(n, k) * C(M-n, N-k) / C(M, N)
///
/// M = total population, n = success states in population, N = draws.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Hypergeometric {
    /// Total population size.
    pub big_m: u64,
    /// Number of success states in population.
    pub n: u64,
    /// Number of draws.
    pub big_n: u64,
}

impl Hypergeometric {
    #[must_use]
    pub fn new(big_m: u64, n: u64, big_n: u64) -> Self {
        assert!(n <= big_m, "n must be <= M, got n={n}, M={big_m}");
        assert!(big_n <= big_m, "N must be <= M, got N={big_n}, M={big_m}");
        Self { big_m, n, big_n }
    }
}

impl DiscreteDistribution for Hypergeometric {
    fn pmf(&self, k: u64) -> f64 {
        let m = self.big_m as f64;
        let n = self.n as f64;
        let big_n = self.big_n as f64;
        let kf = k as f64;

        // Valid range: max(0, N+n-M) <= k <= min(n, N)
        // Use saturating_add to avoid u64 overflow
        let k_min = if self.big_n.saturating_add(self.n) > self.big_m {
            (self.big_n + self.n - self.big_m) as f64
        } else {
            0.0
        };
        let k_max = n.min(big_n);
        if kf < k_min || kf > k_max {
            return 0.0;
        }

        // ln(C(n,k)) + ln(C(M-n, N-k)) - ln(C(M, N))
        let ln_pmf = ln_gamma(n + 1.0) - ln_gamma(kf + 1.0) - ln_gamma(n - kf + 1.0)
            + ln_gamma(m - n + 1.0)
            - ln_gamma(big_n - kf + 1.0)
            - ln_gamma(m - n - big_n + kf + 1.0)
            - ln_gamma(m + 1.0)
            + ln_gamma(big_n + 1.0)
            + ln_gamma(m - big_n + 1.0);
        ln_pmf.exp()
    }

    fn mean(&self) -> f64 {
        self.big_n as f64 * self.n as f64 / self.big_m as f64
    }

    fn var(&self) -> f64 {
        let m = self.big_m as f64;
        if m <= 1.0 {
            return 0.0; // Degenerate: single-element population has no variance
        }
        let n = self.n as f64;
        let big_n = self.big_n as f64;
        big_n * (n / m) * ((m - n) / m) * ((m - big_n) / (m - 1.0))
    }

    fn skewness(&self) -> f64 {
        let m = self.big_m as f64;
        let n = self.n as f64;
        let big_n = self.big_n as f64;
        if m <= 2.0 {
            return f64::NAN;
        }
        let num = (m - 2.0 * n) * (m - 2.0 * big_n) * (m - 1.0).sqrt();
        let den = (m - 2.0) * (n * big_n * (m - n) * (m - big_n)).sqrt();
        num / den
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis of the hypergeometric distribution. The
        // closed form already returns excess (k4 − 3); pre-fix the
        // c-coefficient was wrong (3 instead of 6, and M+6 instead
        // of 5M-6) AND the result was further reduced by an
        // unjustified `- 3.0`, which together landed ~3.57 abs off
        // scipy at (M=50, n=20, N=10). frankenscipy-r863g.
        //
        // Wikipedia / Johnson-Kotz closed form for excess kurtosis:
        //   num = (M-1)·M²·(M(M+1) − 6n(M-n) − 6N(M-N))
        //       + 6·n·N·(M-n)·(M-N)·(5M-6)
        //   den = n·N·(M-n)·(M-N)·(M-2)·(M-3)
        //   excess = num / den.
        let m = self.big_m as f64;
        let n = self.n as f64;
        let big_n = self.big_n as f64;
        if m <= 3.0 {
            return f64::NAN;
        }
        let a = (m - 1.0) * m * m;
        let b = m * (m + 1.0) - 6.0 * n * (m - n) - 6.0 * big_n * (m - big_n);
        let c = 6.0 * n * big_n * (m - n) * (m - big_n) * (5.0 * m - 6.0);
        let num = a * b + c;
        let den = n * big_n * (m - n) * (m - big_n) * (m - 2.0) * (m - 3.0);
        num / den
    }

    fn mode(&self) -> f64 {
        let m = self.big_m as f64;
        let n = self.n as f64;
        let big_n = self.big_n as f64;
        ((n + 1.0) * (big_n + 1.0) / (m + 2.0)).floor()
    }
}

/// Logarithmic (log-series) distribution.
///
/// Matches `scipy.stats.logser`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct LogSeries {
    pub p: f64,
}

impl LogSeries {
    #[must_use]
    pub fn new(p: f64) -> Self {
        assert!(p > 0.0 && p < 1.0, "p must be in (0, 1), got {p}");
        Self { p }
    }

    fn norm(&self) -> f64 {
        -(-self.p).ln_1p()
    }

    /// Percent point function (inverse CDF).
    pub fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }

        let norm = self.norm();
        let mut sum = 0.0;
        let mut k: u64 = 1;
        loop {
            sum += self.p.powf(k as f64) / (k as f64 * norm);
            if sum >= q || k >= 1_000_000 {
                return k as f64;
            }
            k += 1;
        }
    }
}

impl DiscreteDistribution for LogSeries {
    fn pmf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        self.p.powf(k as f64) / (k as f64 * self.norm())
    }

    fn cdf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        let norm = self.norm();
        let mut sum = 0.0;
        for i in 1..=k {
            sum += self.p.powf(i as f64) / (i as f64 * norm);
        }
        sum.min(1.0)
    }

    fn mean(&self) -> f64 {
        self.p / ((1.0 - self.p) * self.norm())
    }

    fn var(&self) -> f64 {
        let norm = self.norm();
        self.p * (norm - self.p) / ((1.0 - self.p).powi(2) * norm * norm)
    }

    fn mode(&self) -> f64 {
        1.0
    }
}

/// Discrete uniform distribution over integers in `[low, high)`.
///
/// Matches `scipy.stats.randint(low, high)`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RandInt {
    pub low: i64,
    pub high: i64,
}

impl RandInt {
    #[must_use]
    pub fn new(low: i64, high: i64) -> Self {
        assert!(high > low, "high must be greater than low");
        Self { low, high }
    }

    fn width(&self) -> i64 {
        self.high - self.low
    }

    pub fn pmf(&self, k: i64) -> f64 {
        if (self.low..self.high).contains(&k) {
            1.0 / self.width() as f64
        } else {
            0.0
        }
    }

    pub fn cdf(&self, k: i64) -> f64 {
        if k < self.low {
            0.0
        } else if k >= self.high - 1 {
            1.0
        } else {
            (k - self.low + 1) as f64 / self.width() as f64
        }
    }

    pub fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return (self.low - 1) as f64;
        }
        if q == 1.0 {
            return (self.high - 1) as f64;
        }

        (self.low + (q * self.width() as f64).ceil() as i64 - 1) as f64
    }

    pub fn mean(&self) -> f64 {
        self.low as f64 + (self.width() as f64 - 1.0) / 2.0
    }

    pub fn var(&self) -> f64 {
        let n = self.width() as f64;
        (n * n - 1.0) / 12.0
    }
}

/// Log of the Beta function: ln(B(a,b)) = ln(Γ(a)) + ln(Γ(b)) - ln(Γ(a+b))
fn ln_beta(a: f64, b: f64) -> f64 {
    ln_gamma(a) + ln_gamma(b) - ln_gamma(a + b)
}

// ══════════════════════════════════════════════════════════════════════
// Internal Helper Functions
// ══════════════════════════════════════════════════════════════════════

/// Standard normal inverse CDF (Beasley-Springer-Moro algorithm).
fn standard_normal_ppf(p: f64) -> f64 {
    // Rational approximation for the central region
    if p <= 0.0 {
        return f64::NEG_INFINITY;
    }
    if p >= 1.0 {
        return f64::INFINITY;
    }

    let q = p - 0.5;
    if q.abs() <= 0.425 {
        // Central region: |q| <= 0.425
        let r = 0.180_625 - q * q;
        let num = q
            * (((((((2.509_080_928_730_122_7e3 * r + 3.343_054_881_277_247_5e4) * r
                + 6.726_577_092_700_87e4)
                * r
                + 4.592_195_393_154_987e4)
                * r
                + 1.373_169_376_550_946e4)
                * r
                + 1.971_590_950_306_551_4e3)
                * r
                + 1.331_416_678_917_843_8e2)
                * r
                + 3.387_132_872_796_366_5);
        let den = ((((((5.226_495_278_852_854e3 * r + 2.872_908_573_572_194_3e4) * r
            + 3.930_789_580_009_271e4)
            * r
            + 2.121_379_430_158_993_7e4)
            * r
            + 5.394_196_021_424_751e3)
            * r
            + 6.871_870_741_484_02e2)
            * r
            + 4.231_333_070_160_091e1)
            * r
            + 1.0;
        return num / den;
    }

    // Tail region
    let r = if q < 0.0 { p } else { 1.0 - p };
    let r = (-r.ln()).sqrt();

    #[allow(clippy::excessive_precision)]
    let result = if r <= 5.0 {
        // Wichura (1988) AS241 coefficients for intermediate tail region
        let r = r - 1.6;
        let num = ((((((7.745_450_142_772_702_5e-4 * r + 2.272_388_412_100_731_05e-2) * r
            + 2.417_807_251_774_506_12e-1)
            * r
            + 1.270_458_252_452_368_38)
            * r
            + 3.647_848_324_763_204_60)
            * r
            + 5.769_497_221_460_691_41)
            * r
            + 4.630_337_846_156_545_30)
            * r
            + 1.423_437_110_749_683_58;
        let den = ((((((1.050_750_071_644_416_84e-9 * r + 5.475_938_084_995_344_95e-4) * r
            + 1.519_866_656_361_645_72e-2)
            * r
            + 1.481_039_764_274_800_75e-1)
            * r
            + 6.897_673_349_851_000_05e-1)
            * r
            + 1.676_384_830_183_803_8)
            * r
            + 2.053_191_626_637_759)
            * r
            + 1.0;
        num / den
    } else {
        let r = r - 5.0;
        let num = ((((((2.010_334_399_292_288_2e-7 * r + 2.711_555_568_743_487_6e-5) * r
            + 1.242_660_947_388_078_4e-3)
            * r
            + 2.653_218_952_657_612_4e-2)
            * r
            + 2.965_605_718_285_048_7e-1)
            * r
            + 1.784_826_539_917_291_3)
            * r
            + 5.463_784_911_164_114)
            * r
            + 6.657_904_643_501_103;
        let den = ((((((2.044_263_103_389_939_7e-15 * r + 1.421_511_758_316_446e-7) * r
            + 1.846_318_317_510_054_8e-5)
            * r
            + 7.868_691_311_456_133e-4)
            * r
            + 1.487_536_129_085_061_5e-2)
            * r
            + 1.369_298_809_227_358e-1)
            * r
            + 5.990_260_257_979_974e-1)
            * r
            + 1.0;
        num / den
    };

    if q < 0.0 { -result } else { result }
}

/// Gamma function ratio for Student's t PDF coefficient.
fn gamma_ratio_t(v: f64) -> f64 {
    // Γ((v+1)/2) / (sqrt(v*π) * Γ(v/2))
    let ln_coeff = ln_gamma(0.5 * (v + 1.0)) - ln_gamma(0.5 * v) - 0.5 * (v * PI).ln();
    ln_coeff.exp()
}

fn ln_gamma(x: f64) -> f64 {
    fsci_special::gammaln_scalar(x, RuntimeMode::Strict).unwrap_or(f64::NAN)
}

fn digamma(x: f64) -> f64 {
    fsci_special::digamma_scalar(x)
}

fn lower_regularized_gamma(a: f64, x: f64) -> f64 {
    fsci_special::gammainc_scalar(a, x, RuntimeMode::Strict).unwrap_or(f64::NAN)
}

fn upper_regularized_gamma(a: f64, x: f64) -> f64 {
    fsci_special::gammaincc_scalar(a, x, RuntimeMode::Strict).unwrap_or(f64::NAN)
}

fn regularized_incomplete_beta(a: f64, b: f64, x: f64) -> f64 {
    fsci_special::betainc_scalar(a, b, x, RuntimeMode::Strict).unwrap_or(f64::NAN)
}

fn modified_bessel_i(order: f64, x: f64) -> f64 {
    match fsci_special::iv(
        &fsci_special::SpecialTensor::RealScalar(order),
        &fsci_special::SpecialTensor::RealScalar(x),
        RuntimeMode::Strict,
    ) {
        Ok(fsci_special::SpecialTensor::RealScalar(value)) => value,
        _ => f64::NAN,
    }
}

fn modified_bessel_k(order: f64, x: f64) -> f64 {
    match fsci_special::kv(
        &fsci_special::SpecialTensor::RealScalar(order),
        &fsci_special::SpecialTensor::RealScalar(x),
        RuntimeMode::Strict,
    ) {
        Ok(fsci_special::SpecialTensor::RealScalar(value)) => value,
        _ => f64::NAN,
    }
}

fn dot(a: &[f64], b: &[f64]) -> f64 {
    a.iter().zip(b.iter()).map(|(&x, &y)| x * y).sum()
}

fn matvec_mul(matrix: &[Vec<f64>], vector: &[f64]) -> Vec<f64> {
    matrix.iter().map(|row| dot(row, vector)).collect()
}

fn identity_matrix(n: usize) -> Vec<Vec<f64>> {
    let mut out = vec![vec![0.0; n]; n];
    for (i, row) in out.iter_mut().enumerate() {
        row[i] = 1.0;
    }
    out
}

fn covariance_biased(samples: &[Vec<f64>]) -> Vec<Vec<f64>> {
    if samples.is_empty() {
        return Vec::new();
    }
    let n = samples.len();
    let dim = samples[0].len();
    let mut means = vec![0.0; dim];
    for sample in samples {
        for (j, &value) in sample.iter().enumerate() {
            means[j] += value;
        }
    }
    for mean in &mut means {
        *mean /= n as f64;
    }

    let mut cov = vec![vec![0.0; dim]; dim];
    for sample in samples {
        let centered: Vec<f64> = sample
            .iter()
            .zip(means.iter())
            .map(|(&x, &m)| x - m)
            .collect();
        for (i, row) in cov.iter_mut().enumerate() {
            for (j, value) in row.iter_mut().enumerate() {
                *value += centered[i] * centered[j];
            }
        }
    }
    for row in &mut cov {
        for value in row {
            *value /= n as f64;
        }
    }
    cov
}

fn jacobi_symmetric_eigendecomposition(a: &[Vec<f64>]) -> (Vec<f64>, Vec<Vec<f64>>) {
    let n = a.len();
    let mut matrix = a.to_vec();
    let mut eigenvectors = identity_matrix(n);
    if n == 0 {
        return (Vec::new(), Vec::new());
    }

    for _ in 0..(n * n * 32).max(32) {
        let mut p = 0;
        let mut q = 1.min(n.saturating_sub(1));
        let mut max_off = 0.0;
        for (i, row) in matrix.iter().enumerate() {
            for (j, value) in row.iter().enumerate().skip(i + 1) {
                if value.abs() > max_off {
                    max_off = value.abs();
                    p = i;
                    q = j;
                }
            }
        }
        if max_off < 1e-12 {
            break;
        }

        let app = matrix[p][p];
        let aqq = matrix[q][q];
        let apq = matrix[p][q];
        // apq is the max off-diagonal element (abs >= 1e-12 from convergence check),
        // but guard explicitly against pathological zero to prevent NaN propagation.
        if apq.abs() < f64::MIN_POSITIVE {
            break;
        }
        let tau = (aqq - app) / (2.0 * apq);
        let t = tau.signum() / (tau.abs() + (1.0 + tau * tau).sqrt());
        let c = 1.0 / (1.0 + t * t).sqrt();
        let s = t * c;

        for row in &mut matrix {
            let mkp = row[p];
            let mkq = row[q];
            row[p] = c * mkp - s * mkq;
            row[q] = s * mkp + c * mkq;
        }
        let row_p_old = matrix[p].clone();
        let row_q_old = matrix[q].clone();
        for (j, (&mpj, &mqj)) in row_p_old.iter().zip(row_q_old.iter()).enumerate() {
            matrix[p][j] = c * mpj - s * mqj;
            matrix[q][j] = s * mpj + c * mqj;
        }
        matrix[p][q] = 0.0;
        matrix[q][p] = 0.0;
        matrix[p][p] = c * c * app - 2.0 * s * c * apq + s * s * aqq;
        matrix[q][q] = s * s * app + 2.0 * s * c * apq + c * c * aqq;

        for row in &mut eigenvectors {
            let vkp = row[p];
            let vkq = row[q];
            row[p] = c * vkp - s * vkq;
            row[q] = s * vkp + c * vkq;
        }
    }

    let eigenvalues = matrix.iter().enumerate().map(|(i, row)| row[i]).collect();
    (eigenvalues, eigenvectors)
}

fn symmetric_pseudoinverse_and_rank(matrix: &[Vec<f64>]) -> (Vec<Vec<f64>>, usize) {
    let n = matrix.len();
    if n == 0 {
        return (Vec::new(), 0);
    }
    let (eigenvalues, eigenvectors) = jacobi_symmetric_eigendecomposition(matrix);
    let max_eigen = eigenvalues.iter().copied().fold(0.0_f64, |a, b| {
        if a.is_nan() || b.is_nan() {
            f64::NAN
        } else {
            a.max(b.abs())
        }
    });
    if max_eigen.is_nan() {
        return (vec![vec![f64::NAN; n]; n], 0);
    }
    let threshold = (n as f64) * f64::EPSILON * max_eigen.max(1.0);
    let mut pinv = vec![vec![0.0; n]; n];
    let mut rank = 0usize;
    for (idx, &eigenvalue) in eigenvalues.iter().enumerate() {
        if eigenvalue.abs() <= threshold {
            continue;
        }
        rank += 1;
        let inv = 1.0 / eigenvalue;
        for (i, row) in pinv.iter_mut().enumerate() {
            for (j, value) in row.iter_mut().enumerate() {
                *value += inv * eigenvectors[i][idx] * eigenvectors[j][idx];
            }
        }
    }
    (pinv, rank)
}

fn cholesky_decompose(matrix: &[Vec<f64>]) -> Result<Vec<Vec<f64>>, StatsError> {
    let n = matrix.len();
    let mut lower = vec![vec![0.0; n]; n];
    for i in 0..n {
        for j in 0..=i {
            let sum = (0..j).map(|k| lower[i][k] * lower[j][k]).sum::<f64>();
            if i == j {
                let value = matrix[i][i] - sum;
                if value <= 0.0 || !value.is_finite() {
                    return Err(StatsError::InvalidArgument(
                        "covariance matrix must be symmetric positive definite".to_string(),
                    ));
                }
                lower[i][j] = value.sqrt();
            } else {
                lower[i][j] = (matrix[i][j] - sum) / lower[j][j];
            }
        }
    }
    Ok(lower)
}

fn solve_lower_triangular(lower: &[Vec<f64>], rhs: &[f64]) -> Result<Vec<f64>, StatsError> {
    let n = lower.len();
    let mut solution = vec![0.0; n];
    for i in 0..n {
        let sum = (0..i).map(|j| lower[i][j] * solution[j]).sum::<f64>();
        if lower[i][i] == 0.0 {
            return Err(StatsError::InvalidArgument(
                "singular lower-triangular system".to_string(),
            ));
        }
        solution[i] = (rhs[i] - sum) / lower[i][i];
    }
    Ok(solution)
}

fn sample_standard_normals(n: usize, rng: &mut impl Rng) -> Vec<f64> {
    let mut values = Vec::with_capacity(n);
    while values.len() < n {
        let u1 = rng.random::<f64>().max(1e-15);
        let u2 = rng.random::<f64>();
        let radius = (-2.0 * u1.ln()).sqrt();
        let angle = 2.0 * PI * u2;
        values.push(radius * angle.cos());
        if values.len() < n {
            values.push(radius * angle.sin());
        }
    }
    values
}

// ══════════════════════════════════════════════════════════════════════
// Cauchy Distribution
// ══════════════════════════════════════════════════════════════════════

/// Cauchy distribution (Lorentzian) with location `loc` and scale `scale`.
///
/// Matches `scipy.stats.cauchy(loc, scale)`.
/// PDF: f(x) = 1 / (π * scale * (1 + ((x - loc)/scale)²))
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Cauchy {
    pub loc: f64,
    pub scale: f64,
}

impl Default for Cauchy {
    fn default() -> Self {
        Self {
            loc: 0.0,
            scale: 1.0,
        }
    }
}

impl Cauchy {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }
}

impl ContinuousDistribution for Cauchy {
    fn pdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        1.0 / (PI * self.scale * (1.0 + z * z))
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        0.5 + z.atan() / PI
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-ltdct]: for x > loc use
        // the arctan reciprocal identity arctan(z) = π/2 - arctan(1/z)
        // (z > 0) so sf = arctan(scale/(x-loc))/π. The default
        // 1 - cdf collapses to 0 in the very deep tail (x ≈ loc + 1e30·scale)
        // when cdf rounds to 1.0 — the closed form returns the actual value.
        let dz = x - self.loc;
        if dz > 0.0 {
            (self.scale / dz).atan() / PI
        } else {
            // For x <= loc, the default 1 - cdf works fine because cdf is
            // bounded away from 1; compute it explicitly.
            0.5 - (dz / self.scale).atan() / PI
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        self.loc + self.scale * (PI * (q - 0.5)).tan()
    }

    fn mean(&self) -> f64 {
        f64::NAN // Cauchy has no finite mean
    }

    fn var(&self) -> f64 {
        f64::NAN // Cauchy has no finite variance
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite()) {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }

        let qs = quantile(data, &[0.25, 0.5, 0.75]);
        let loc = qs[1];
        let scale = 0.5 * (qs[2] - qs[0]);
        if !loc.is_finite() || !scale.is_finite() || scale <= 0.0 {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }

        Self { loc, scale }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Cauchy requires finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.loc.is_finite() || !fitted.scale.is_finite() || fitted.scale <= 0.0 {
            return Err(FitError::NonConvergent(
                "Cauchy fit produced non-finite or non-positive parameters (degenerate quantiles)"
                    .into(),
            ));
        }
        Ok(fitted)
    }

    fn entropy(&self) -> f64 {
        (4.0 * PI * self.scale).ln()
    }

    fn mode(&self) -> f64 {
        self.loc
    }
}

// ══════════════════════════════════════════════════════════════════════
// Laplace Distribution
// ══════════════════════════════════════════════════════════════════════

/// Laplace (double exponential) distribution.
///
/// Matches `scipy.stats.laplace(loc, scale)`.
/// PDF: f(x) = exp(-|x - loc|/scale) / (2 * scale)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Laplace {
    pub loc: f64,
    pub scale: f64,
}

impl Default for Laplace {
    fn default() -> Self {
        Self {
            loc: 0.0,
            scale: 1.0,
        }
    }
}

impl Laplace {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive, got {scale}");
        Self { loc, scale }
    }
}

impl ContinuousDistribution for Laplace {
    fn pdf(&self, x: f64) -> f64 {
        let z = ((x - self.loc) / self.scale).abs();
        (-z).exp() / (2.0 * self.scale)
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        if z < 0.0 {
            0.5 * z.exp()
        } else {
            1.0 - 0.5 * (-z).exp()
        }
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-6uo0s]:
        //   z >= 0: sf = 0.5 · exp(-z)
        //   z < 0:  sf = 1 - 0.5 · exp(z)
        // The right tail (z >= 0) is the precision-sensitive case;
        // the default 1 - cdf computes 1 - (1 - 0.5·exp(-z)) and
        // catastrophically cancels when 0.5·exp(-z) drops below ULP.
        let z = (x - self.loc) / self.scale;
        if z >= 0.0 {
            0.5 * (-z).exp()
        } else {
            1.0 - 0.5 * z.exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        if q < 0.5 {
            self.loc + self.scale * (2.0 * q).ln()
        } else {
            self.loc - self.scale * (2.0 * (1.0 - q)).ln()
        }
    }

    fn mean(&self) -> f64 {
        self.loc
    }

    fn var(&self) -> f64 {
        2.0 * self.scale * self.scale
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() {
            return Self {
                loc: f64::NAN,
                scale: f64::NAN,
            };
        }
        let loc = median(data);
        let scale = data.iter().map(|&x| (x - loc).abs()).sum::<f64>() / data.len() as f64;
        Self {
            loc,
            scale: if scale > 0.0 { scale } else { f64::NAN },
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|v| !v.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Laplace::fit: non-finite samples".to_owned(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.scale.is_finite() || fitted.scale <= 0.0 {
            return Err(FitError::NonConvergent(
                "Laplace::fit: degenerate sample (all values equal median)".to_owned(),
            ));
        }
        Ok(fitted)
    }

    fn entropy(&self) -> f64 {
        1.0 + (2.0 * self.scale).ln()
    }

    fn skewness(&self) -> f64 {
        0.0 // Laplace is symmetric
    }

    fn kurtosis(&self) -> f64 {
        3.0 // Laplace excess kurtosis is 3
    }

    fn mode(&self) -> f64 {
        self.loc
    }
}

// ══════════════════════════════════════════════════════════════════════
// Triangular Distribution
// ══════════════════════════════════════════════════════════════════════

/// Triangular distribution on [left, right] with mode `mode`.
///
/// Matches `scipy.stats.triang(c, loc, scale)` where c=(mode-left)/(right-left).
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Triangular {
    pub left: f64,
    pub mode: f64,
    pub right: f64,
}

impl Triangular {
    #[must_use]
    pub fn new(left: f64, mode: f64, right: f64) -> Self {
        // scipy.stats.triang allows c = 0 (mode at left edge) and
        // c = 1 (mode at right edge), so we need `left ≤ mode ≤ right`
        // with strict `left < right` to keep the support
        // non-degenerate. Caught by [frankenscipy-fkq6j] diff
        // harness — the previous `left < mode` panicked at c = 0.
        assert!(left < right, "left must be < right (degenerate support)");
        assert!(
            (left..=right).contains(&mode),
            "mode must be in [left, right]"
        );
        Self { left, mode, right }
    }
}

impl ContinuousDistribution for Triangular {
    fn pdf(&self, x: f64) -> f64 {
        let (a, c, b) = (self.left, self.mode, self.right);
        if x < a || x > b {
            0.0
        } else if c == b {
            // Degenerate: right-skewed triangle (mode == right)
            if x == b {
                2.0 / (b - a)
            } else {
                2.0 * (x - a) / ((b - a) * (b - a))
            }
        } else if x < c {
            2.0 * (x - a) / ((b - a) * (c - a))
        } else if x == c {
            2.0 / (b - a)
        } else {
            2.0 * (b - x) / ((b - a) * (b - c))
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        let (a, c, b) = (self.left, self.mode, self.right);
        if x <= a {
            0.0
        } else if c == b {
            // Degenerate: mode == right
            if x >= b {
                1.0
            } else {
                (x - a).powi(2) / ((b - a) * (b - a))
            }
        } else if x <= c {
            (x - a).powi(2) / ((b - a) * (c - a))
        } else if x < b {
            1.0 - (b - x).powi(2) / ((b - a) * (b - c))
        } else {
            1.0
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.left;
        }
        if q == 1.0 {
            return self.right;
        }
        let (a, c, b) = (self.left, self.mode, self.right);
        let fc = (c - a) / (b - a);
        if q < fc {
            a + (q * (b - a) * (c - a)).sqrt()
        } else {
            b - ((1.0 - q) * (b - a) * (b - c)).sqrt()
        }
    }

    fn mean(&self) -> f64 {
        (self.left + self.mode + self.right) / 3.0
    }

    fn var(&self) -> f64 {
        let (a, c, b) = (self.left, self.mode, self.right);
        (a * a + b * b + c * c - a * b - a * c - b * c) / 18.0
    }

    fn skewness(&self) -> f64 {
        // Standardised parameter c = (mode − left) / (right − left); skew
        // is shift-and-scale invariant so the formula uses only c
        //   skew(c) = √2 · (2c − 1) · (c − 2) · (c + 1)
        //           / (5 · (c² − c + 1)^{3/2})
        // (frankenscipy-mrmul)
        let c = (self.mode - self.left) / (self.right - self.left);
        let denom_base = c * c - c + 1.0;
        std::f64::consts::SQRT_2 * (2.0 * c - 1.0) * (c - 2.0) * (c + 1.0)
            / (5.0 * denom_base.powf(1.5))
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis is the constant -3/5 (independent of mode
        // location and scale). (frankenscipy-mrmul)
        -3.0 / 5.0
    }

    fn fit(data: &[f64]) -> Self {
        let nan = Self {
            left: f64::NAN,
            mode: f64::NAN,
            right: f64::NAN,
        };
        if data.len() < 3 || data.iter().any(|v| !v.is_finite()) {
            return nan;
        }
        let left = data.iter().cloned().fold(f64::INFINITY, f64::min);
        let right = data.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
        if left >= right {
            return nan;
        }
        let n = data.len() as f64;
        let mean = data.iter().sum::<f64>() / n;
        let mode = 3.0 * mean - left - right;
        let mode = mode.clamp(left, right);
        Self { left, mode, right }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // [frankenscipy-sf2ax]: typed-error counterpart to fit().
        if data.len() < 3 {
            return Err(FitError::InsufficientData {
                required: 3,
                actual: data.len(),
            });
        }
        if data.iter().any(|v| !v.is_finite()) {
            return Err(FitError::UnsupportedData(
                "Triangular requires finite samples".into(),
            ));
        }
        let fitted = Self::fit(data);
        if !fitted.left.is_finite() || !fitted.right.is_finite() || fitted.left >= fitted.right {
            return Err(FitError::NonConvergent(
                "Triangular fit produced degenerate (left >= right) bounds".into(),
            ));
        }
        Ok(fitted)
    }

    fn entropy(&self) -> f64 {
        // H(Triangular) = 0.5 + ln((right - left) / 2)
        // [frankenscipy-vngzr].
        0.5 + ((self.right - self.left) / 2.0).ln()
    }
}

/// Trapezoidal distribution on `[loc, loc + scale]` with flat top spanning
/// `[loc + c * scale, loc + d * scale]`.
///
/// Matches `scipy.stats.trapezoid(c, d, loc, scale)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Trapezoid {
    pub c: f64,
    pub d: f64,
    pub loc: f64,
    pub scale: f64,
}

impl Trapezoid {
    #[must_use]
    pub fn new(c: f64, d: f64, loc: f64, scale: f64) -> Self {
        assert!((0.0..=1.0).contains(&c), "c must be in [0, 1]");
        assert!((0.0..=1.0).contains(&d), "d must be in [0, 1]");
        assert!(d >= c, "d must be >= c");
        assert!(scale > 0.0, "scale must be positive");
        Self { c, d, loc, scale }
    }

    fn standard_moment(&self, n: usize) -> f64 {
        let c = self.c;
        let d = self.d;
        let den = 1.0 + d - c;
        let ab_term = c.powf((n + 1) as f64);
        let dc_term = if d == 0.0 {
            1.0
        } else if d < 1.0 {
            (d.powf((n + 2) as f64) - 1.0) / (d - 1.0)
        } else {
            (n + 2) as f64
        };
        2.0 * (dc_term - ab_term) / (den * (n as f64 + 1.0) * (n as f64 + 2.0))
    }
}

impl ContinuousDistribution for Trapezoid {
    fn pdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        if !(0.0..=1.0).contains(&z) {
            return 0.0;
        }
        let height = 2.0 / (1.0 + self.d - self.c);
        let standard_pdf = if z < self.c {
            height * z / self.c
        } else if z <= self.d {
            height
        } else {
            height * (1.0 - z) / (1.0 - self.d)
        };
        standard_pdf / self.scale
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = (x - self.loc) / self.scale;
        if z <= 0.0 {
            return 0.0;
        }
        if z >= 1.0 {
            return 1.0;
        }
        let den = 1.0 + self.d - self.c;
        if z < self.c {
            z * z / (self.c * den)
        } else if z <= self.d {
            (self.c + 2.0 * (z - self.c)) / den
        } else {
            1.0 - (1.0 - z).powi(2) / ((1.0 - self.d) * den)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.loc;
        }
        if q == 1.0 {
            return self.loc + self.scale;
        }
        let den = 1.0 + self.d - self.c;
        let qc = self.c / den;
        let qd = (2.0 * self.d - self.c) / den;
        let z = if q < qc {
            (q * self.c * den).sqrt()
        } else if q <= qd {
            0.5 * (q * den + self.c)
        } else {
            1.0 - ((1.0 - q) * (1.0 - self.d) * den).sqrt()
        };
        self.loc + self.scale * z
    }

    fn mean(&self) -> f64 {
        self.loc + self.scale * self.standard_moment(1)
    }

    fn var(&self) -> f64 {
        let ex = self.standard_moment(1);
        let ex2 = self.standard_moment(2);
        self.scale * self.scale * (ex2 - ex * ex)
    }
}

// ══════════════════════════════════════════════════════════════════════
// Additional Distributions
// ══════════════════════════════════════════════════════════════════════

/// Inverse Gamma distribution.
///
/// Matches `scipy.stats.invgamma`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct InverseGamma {
    pub a: f64, // shape
}

impl InverseGamma {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a > 0.0, "shape parameter must be positive");
        Self { a }
    }
}

impl ContinuousDistribution for InverseGamma {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let a = self.a;
        x.powf(-a - 1.0) * (-1.0 / x).exp() / ln_gamma(a).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        // CDF = 1 - gammainc(a, 1/x) = gammaincc(a, 1/x)
        // Using upper regularized incomplete gamma
        upper_regularized_gamma(self.a, 1.0 / x)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = Q(a, 1/x) = 1 - P(a, 1/x), so P(a, 1/x) = 1 - q
        // 1/x = gammaincinv(a, 1 - q), x = 1 / gammaincinv(a, 1 - q)
        let g = fsci_special::gammaincinv_scalar(self.a, 1.0 - q);
        if g <= 0.0 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        let mut x = 1.0 / g;
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        if self.a > 1.0 {
            1.0 / (self.a - 1.0)
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        if self.a > 2.0 {
            1.0 / ((self.a - 1.0).powi(2) * (self.a - 2.0))
        } else {
            f64::INFINITY
        }
    }

    fn skewness(&self) -> f64 {
        // 4·√(a − 2) / (a − 3) for a > 3 (frankenscipy-d4j8j).
        if self.a > 3.0 {
            4.0 * (self.a - 2.0).sqrt() / (self.a - 3.0)
        } else {
            f64::NAN
        }
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 6(5a − 11) / ((a − 3)(a − 4))  for a > 4.
        // (frankenscipy-d4j8j)
        if self.a > 4.0 {
            6.0 * (5.0 * self.a - 11.0) / ((self.a - 3.0) * (self.a - 4.0))
        } else {
            f64::NAN
        }
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("InverseGamma::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // MoM at unit scale: E[X | a] = 1/(a-1) for a>1, so
        //   a_hat = 1 + 1/sample_mean
        // Requires positive observations and a positive (>1) result.
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "InverseGamma data contains non-finite value: {x}"
                )));
            }
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "InverseGamma support is (0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        if mean <= 0.0 || !mean.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "InverseGamma MoM: sample mean {mean} non-positive"
            )));
        }
        let a = 1.0 + 1.0 / mean;
        if !a.is_finite() || a <= 1.0 {
            return Err(FitError::NonConvergent(format!(
                "InverseGamma MoM produced a={a} (must be > 1)"
            )));
        }
        Ok(Self { a })
    }

    fn mode(&self) -> f64 {
        // InverseGamma mode = scale / (a + 1); fsci-stats uses unit scale,
        // so mode = 1 / (a + 1) [frankenscipy-71mv5].
        1.0 / (self.a + 1.0)
    }
}

// Log-normal distribution (parameterized by mu, sigma of underlying normal).
//
// Note: The Lognormal struct above uses s/scale. This is an alias with
// the same interface. Kept for disambiguation.

/// Inverse Gaussian (Wald) distribution.
///
/// Matches `scipy.stats.invgauss`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct InverseGaussian {
    pub mu: f64, // mean
}

impl InverseGaussian {
    #[must_use]
    pub fn new(mu: f64) -> Self {
        assert!(mu > 0.0, "mu must be positive");
        Self { mu }
    }
}

impl ContinuousDistribution for InverseGaussian {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let mu = self.mu;
        (1.0 / (2.0 * PI * x.powi(3))).sqrt() * (-(x - mu).powi(2) / (2.0 * mu * mu * x)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let mu = self.mu;
        let sqrt_x = x.sqrt();
        let t1 = standard_normal_cdf(sqrt_x / mu - 1.0 / sqrt_x);
        let t2 = (2.0 / mu).exp() * standard_normal_cdf(-(sqrt_x / mu + 1.0 / sqrt_x));
        t1 + t2
    }

    fn mean(&self) -> f64 {
        self.mu
    }

    fn var(&self) -> f64 {
        self.mu.powi(3)
    }

    fn skewness(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-ggikd]:
        // scipy.stats.invgauss reports skew = 3·√mu.
        3.0 * self.mu.sqrt()
    }

    fn kurtosis(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-ggikd]:
        // scipy.stats.invgauss reports excess kurtosis = 15·mu.
        15.0 * self.mu
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("InverseGaussian::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // The standardized scipy.stats.invgauss has implicit λ=1, so its
        // single shape parameter `mu` is also the population mean. The MLE
        // collapses to the sample mean: mu_hat = (1/n) Σ x_i.
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "InverseGaussian data contains non-finite value: {x}"
                )));
            }
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "InverseGaussian support is (0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mu = sum / count as f64;
        if !mu.is_finite() || mu <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "InverseGaussian MLE produced non-positive mu: {mu}"
            )));
        }
        Ok(Self { mu })
    }
}

/// Pearson type III distribution.
///
/// Matches `scipy.stats.pearson3`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Pearson3 {
    pub skew: f64,
}

impl Pearson3 {
    #[must_use]
    pub fn new(skew: f64) -> Self {
        assert!(skew.is_finite(), "skew must be finite");
        Self { skew }
    }
}

impl ContinuousDistribution for Pearson3 {
    fn pdf(&self, x: f64) -> f64 {
        const NORMAL_TRANSITION: f64 = 1.6e-5;
        let skew = self.skew;
        if skew.abs() < NORMAL_TRANSITION {
            return standard_normal_pdf(x);
        }

        let beta = 2.0 / skew;
        let alpha = beta * beta;
        let zeta = -beta;
        let transx = beta * (x - zeta);
        if transx < 0.0 {
            return 0.0;
        }

        beta.abs() * transx.powf(alpha - 1.0) * (-transx).exp() / ln_gamma(alpha).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        const NORMAL_TRANSITION: f64 = 1.6e-5;
        let skew = self.skew;
        if skew.abs() < NORMAL_TRANSITION {
            return standard_normal_cdf(x);
        }

        let beta = 2.0 / skew;
        let alpha = beta * beta;
        let zeta = -beta;
        let transx = beta * (x - zeta);

        if skew > 0.0 {
            if transx <= 0.0 {
                0.0
            } else {
                lower_regularized_gamma(alpha, transx)
            }
        } else if transx <= 0.0 {
            1.0
        } else {
            upper_regularized_gamma(alpha, transx)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        const NORMAL_TRANSITION: f64 = 1.6e-5;
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }

        let skew = self.skew;
        if skew.abs() < NORMAL_TRANSITION {
            return fsci_special::ndtri_scalar(q);
        }

        let beta = 2.0 / skew;
        let alpha = beta * beta;
        let zeta = -beta;
        let gamma_q = if beta < 0.0 { 1.0 - q } else { q };
        let g = fsci_special::gammaincinv_scalar(alpha, gamma_q);
        if !g.is_finite() {
            return ppf_bisection(|x| self.cdf(x), q, self.mean(), self.std());
        }
        g / beta + zeta
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        1.0
    }

    fn skewness(&self) -> f64 {
        // Pearson3 is parameterised by its skewness directly.
        // (frankenscipy-okk7z)
        self.skew
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis = 1.5·skew² (Pearson3 is a shifted/scaled
        // Gamma where shape k = 4/skew²; kurt = 6/k = 6·skew²/4 = 1.5·skew²).
        // (frankenscipy-okk7z)
        1.5 * self.skew * self.skew
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Pearson3::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 3 {
            return Err(FitError::InsufficientData {
                required: 3,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Pearson3 data contains non-finite value: {x}"
                )));
            }
        }
        // Method-of-moments skewness estimator g₁ = m₃ / m₂^1.5,
        // where m_k is the k-th central moment. Pearson3 in this crate
        // is the standardized form (loc=0, scale=1), so its single shape
        // parameter is the skewness — and the natural estimator is
        // exactly the sample skewness.
        let n = data.len() as f64;
        let mean: f64 = data.iter().sum::<f64>() / n;
        let mut m2 = 0.0_f64;
        let mut m3 = 0.0_f64;
        for &x in data {
            let d = x - mean;
            m2 += d * d;
            m3 += d * d * d;
        }
        m2 /= n;
        m3 /= n;
        if !m2.is_finite() || m2 <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "Pearson3 fit: sample variance {m2} is non-positive"
            )));
        }
        let skew = m3 / m2.powf(1.5);
        if !skew.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "Pearson3 fit: skew estimate {skew} is non-finite"
            )));
        }
        Ok(Self { skew })
    }
}

/// Exponentially modified normal distribution.
///
/// Matches `scipy.stats.exponnorm`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct ExponNorm {
    pub k: f64,
}

impl ExponNorm {
    #[must_use]
    pub fn new(k: f64) -> Self {
        assert!(k.is_finite() && k > 0.0, "k must be positive and finite");
        Self { k }
    }
}

impl ContinuousDistribution for ExponNorm {
    fn pdf(&self, x: f64) -> f64 {
        let inv_k = 1.0 / self.k;
        let exp_arg = inv_k * (0.5 * inv_k - x);
        (exp_arg + fsci_special::log_ndtr_scalar(x - inv_k)).exp() / self.k
    }

    fn cdf(&self, x: f64) -> f64 {
        let inv_k = 1.0 / self.k;
        let exp_arg = inv_k * (0.5 * inv_k - x);
        standard_normal_cdf(x) - (exp_arg + fsci_special::log_ndtr_scalar(x - inv_k)).exp()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        ppf_bisection(|x| self.cdf(x), q, self.mean(), self.std())
    }

    fn mean(&self) -> f64 {
        self.k
    }

    fn var(&self) -> f64 {
        1.0 + self.k * self.k
    }

    fn skewness(&self) -> f64 {
        // EMG / ExponNorm: skew = 2·K³ / (1 + K²)^{3/2}.
        // (frankenscipy-u65lx)
        let k = self.k;
        let k2 = k * k;
        2.0 * k2 * k / (1.0 + k2).powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 6·K⁴ / (1 + K²)². (frankenscipy-u65lx)
        let k2 = self.k * self.k;
        let one_plus = 1.0 + k2;
        6.0 * k2 * k2 / (one_plus * one_plus)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("ExponNorm::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "ExponNorm data contains non-finite value: {x}"
                )));
            }
        }
        // ExponNorm at standardized (loc=0, scale=1) has E[X] = k, so the
        // method-of-moments shape estimator is just the sample mean. The
        // shape parameter must be positive — reject non-positive means.
        let mean: f64 = data.iter().sum::<f64>() / data.len() as f64;
        if mean <= 0.0 || !mean.is_finite() {
            return Err(FitError::UnsupportedData(format!(
                "ExponNorm requires positive sample mean (k > 0); got {mean}"
            )));
        }
        Ok(Self { k: mean })
    }
}

/// Power normal distribution.
///
/// Matches `scipy.stats.powernorm`.
pub struct PowerNorm {
    pub c: f64,
}

impl PowerNorm {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c.is_finite() && c > 0.0, "c must be positive and finite");
        Self { c }
    }

    fn log_sf(&self, x: f64) -> f64 {
        self.c * fsci_special::log_ndtr_scalar(-x)
    }

    fn raw_moment(&self, order: i32) -> f64 {
        if (self.c - 1.0).abs() < 1e-12 {
            return match order {
                1 => 0.0,
                2 => 1.0,
                _ => f64::NAN,
            };
        }

        let eps = 1e-12;
        let lo = self.ppf(eps);
        let hi = self.ppf(1.0 - eps);
        simpson_integrate_adaptive(
            |x| x.powi(order) * self.pdf(x),
            lo,
            hi,
            4_096,
            1e-10,
            1e-10,
            8,
        )
    }
}

impl ContinuousDistribution for PowerNorm {
    fn pdf(&self, x: f64) -> f64 {
        (self.c.ln() - 0.5 * x * x - 0.5 * (2.0 * PI).ln()
            + (self.c - 1.0) * fsci_special::log_ndtr_scalar(-x))
        .exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        -self.log_sf(x).exp_m1()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        -fsci_special::ndtri_scalar(((1.0 - q).ln() / self.c).exp())
    }

    fn mean(&self) -> f64 {
        self.raw_moment(1)
    }

    fn var(&self) -> f64 {
        let mean = self.mean();
        (self.raw_moment(2) - mean * mean).max(0.0)
    }
}

/// Power-lognormal distribution with shapes `c > 0`, `s > 0`.
///
/// Matches `scipy.stats.powerlognorm(c, s)`. Resolves [frankenscipy-bx7kx].
/// Support: x > 0.
///
///   pdf(x; c, s) = c · φ(ln x / s) · Φ(−ln x / s)^(c − 1) / (x · s)
///   cdf(x; c, s) = 1 − Φ(−ln x / s)^c
///   sf(x;  c, s) = Φ(−ln x / s)^c
///   ppf(q; c, s) = exp(−s · Φ⁻¹((1 − q)^(1/c)))
///
/// where φ, Φ are the standard normal pdf and cdf.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct PowerLognorm {
    pub c: f64,
    pub s: f64,
}

impl PowerLognorm {
    #[must_use]
    pub fn new(c: f64, s: f64) -> Self {
        assert!(
            c > 0.0 && c.is_finite() && s > 0.0 && s.is_finite(),
            "c and s must be positive and finite"
        );
        Self { c, s }
    }
}

impl ContinuousDistribution for PowerLognorm {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 || !x.is_finite() {
            return 0.0;
        }
        let c = self.c;
        let s = self.s;
        let z = x.ln() / s;
        let phi = standard_normal_pdf(z);
        // Deep-tail guard: φ(z) underflows to 0 for |z| > ~38.
        // For c < 1, Φ(−z)^(c−1) = 0^negative = +∞, and 0 · +∞ = NaN.
        // The pdf is effectively 0 there — return that directly.
        if phi == 0.0 {
            return 0.0;
        }
        let big_phi_neg = standard_normal_cdf(-z);
        c * phi * big_phi_neg.powf(c - 1.0) / (x * s)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if !x.is_finite() {
            return 1.0;
        }
        let c = self.c;
        let s = self.s;
        let z = x.ln() / s;
        let big_phi_neg = standard_normal_cdf(-z);
        if big_phi_neg <= 0.5 {
            // Φ(−z) is small (x ≥ median region): the literal
            // 1 − Φ(−z)^c is precise because we're subtracting
            // something small from 1.
            (1.0 - big_phi_neg.powf(c)).clamp(0.0, 1.0)
        } else {
            // Φ(−z) is close to 1 (x < median region): the
            // literal form catastrophically cancels. Use the
            // stable rewrite via ln_1p / expm1:
            //   1 − Φ(−z)^c = −expm1(c · ln_1p(−Φ(z)))
            // (caught by [frankenscipy-evspb] fuzz: cdf became
            // non-monotone at c=1, s=1, x ≈ 1e-3; and
            // cdf + sf = 1.01 at c=0.1, s=0.1, x=2.5 in the
            // wrong regime).
            let big_phi_z = standard_normal_cdf(z);
            let log_term = (-big_phi_z).ln_1p();
            (-(c * log_term).exp_m1()).clamp(0.0, 1.0)
        }
    }

    fn sf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 1.0;
        }
        if !x.is_finite() {
            return 0.0;
        }
        let c = self.c;
        let s = self.s;
        let z = x.ln() / s;
        standard_normal_cdf(-z).powf(c).clamp(0.0, 1.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let c = self.c;
        let s = self.s;
        // x = exp(−s · Φ⁻¹((1 − q)^(1/c)))
        let inner = (1.0 - q).powf(1.0 / c);
        (-s * standard_normal_ppf(inner)).exp()
    }

    fn mean(&self) -> f64 {
        powerlognorm_moment(self.c, self.s, 1)
    }

    fn var(&self) -> f64 {
        let m1 = powerlognorm_moment(self.c, self.s, 1);
        let m2 = powerlognorm_moment(self.c, self.s, 2);
        let v = m2 - m1 * m1;
        if v.is_finite() && v >= 0.0 { v } else { f64::NAN }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 4, "PowerLognorm")?;
        for &x in data {
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "PowerLognorm support is (0, infinity); got {x}"
                )));
            }
        }

        let qs = quantile(data, &[0.25, 0.5, 0.75]);
        let spread = qs[2] - qs[0];
        if !spread.is_finite() || spread <= 0.0 || qs[1] <= 0.0 {
            return Err(FitError::NonConvergent(
                "PowerLognorm fit needs positive non-degenerate quartiles".to_owned(),
            ));
        }

        let mut best = None::<(f64, f64, f64)>;
        for step in 0..=990 {
            let c = 0.1 + 0.01 * step as f64;
            let inner50 = 0.5_f64.powf(1.0 / c);
            let z50 = standard_normal_ppf(inner50);
            if !z50.is_finite() || z50.abs() < 1e-12 {
                continue;
            }
            let s = -qs[1].ln() / z50;
            if !s.is_finite() || s <= 0.0 {
                continue;
            }
            let dist = Self { c, s };
            let model_q25 = dist.ppf(0.25);
            let model_q75 = dist.ppf(0.75);
            if !model_q25.is_finite() || !model_q75.is_finite() {
                continue;
            }
            let error =
                ((model_q25 - qs[0]) / spread).powi(2) + ((model_q75 - qs[2]) / spread).powi(2);
            if best.is_none_or(|(_, _, best_error)| error < best_error) {
                best = Some((c, s, error));
            }
        }

        if let Some((c, s, _)) = best {
            Ok(Self { c, s })
        } else {
            Err(FitError::NonConvergent(
                "PowerLognorm quantile fit did not find finite c/s".to_owned(),
            ))
        }
    }
}

/// Johnson SU distribution.
///
/// Matches `scipy.stats.johnsonsu`.
pub struct JohnsonSU {
    pub a: f64,
    pub b: f64,
}

impl JohnsonSU {
    #[must_use]
    pub fn new(a: f64, b: f64) -> Self {
        assert!(a.is_finite(), "a must be finite");
        assert!(b.is_finite() && b > 0.0, "b must be positive and finite");
        Self { a, b }
    }
}

impl ContinuousDistribution for JohnsonSU {
    fn pdf(&self, x: f64) -> f64 {
        let z = self.a + self.b * x.asinh();
        self.b * standard_normal_pdf(z) / x.hypot(1.0)
    }

    fn cdf(&self, x: f64) -> f64 {
        standard_normal_cdf(self.a + self.b * x.asinh())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        ((fsci_special::ndtri_scalar(q) - self.a) / self.b).sinh()
    }

    fn mean(&self) -> f64 {
        let inv_b = self.b.recip();
        let exp_inv_b_sq = (inv_b * inv_b).exp();
        -exp_inv_b_sq.sqrt() * (self.a * inv_b).sinh()
    }

    fn var(&self) -> f64 {
        let inv_b = self.b.recip();
        let exp_inv_b_sq = (inv_b * inv_b).exp();
        0.5 * exp_inv_b_sq.mul_add((2.0 * self.a * inv_b).cosh(), 1.0) * (inv_b * inv_b).exp_m1()
    }

    fn skewness(&self) -> f64 {
        // Raw moments via MGF of W = (U - a)/b ~ N(-a/b, 1/b^2):
        // E[e^{tW}] = exp(-tΩ + t²/(2b²)) where Ω = a/b.
        // Setting ω = exp(1/b²) gives closed-form raw moments m_n of
        // X = sinh(W); central moments follow.
        let omega = (self.b * self.b).recip().exp();
        let ohm = self.a / self.b;
        let m1 = -omega.sqrt() * ohm.sinh();
        let m2 = (omega * omega).mul_add((2.0 * ohm).cosh(), -1.0) / 2.0;
        let m3 = (3.0_f64.mul_add(
            omega.sqrt() * ohm.sinh(),
            -omega.powf(4.5) * (3.0 * ohm).sinh(),
        )) / 4.0;
        let var = m2 - m1 * m1;
        let mu3 = 2.0_f64.mul_add(m1.powi(3), m3 - 3.0 * m1 * m2);
        mu3 / var.powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        let omega = (self.b * self.b).recip().exp();
        let ohm = self.a / self.b;
        let m1 = -omega.sqrt() * ohm.sinh();
        let m2 = (omega * omega).mul_add((2.0 * ohm).cosh(), -1.0) / 2.0;
        let m3 = (3.0_f64.mul_add(
            omega.sqrt() * ohm.sinh(),
            -omega.powf(4.5) * (3.0 * ohm).sinh(),
        )) / 4.0;
        let m4 = ((omega.powi(8)).mul_add(
            (4.0 * ohm).cosh(),
            (-4.0 * omega * omega).mul_add((2.0 * ohm).cosh(), 3.0),
        )) / 8.0;
        let var = m2 - m1 * m1;
        let mu4 = (-3.0_f64).mul_add(
            m1.powi(4),
            6.0_f64.mul_add(m1 * m1 * m2, 4.0_f64.mul_add(-m1 * m3, m4)),
        );
        mu4 / (var * var) - 3.0
    }
}

/// Johnson SB distribution.
///
/// Matches `scipy.stats.johnsonsb`.
pub struct JohnsonSB {
    pub a: f64,
    pub b: f64,
}

impl JohnsonSB {
    #[must_use]
    pub fn new(a: f64, b: f64) -> Self {
        assert!(a.is_finite(), "a must be finite");
        assert!(b.is_finite() && b > 0.0, "b must be positive and finite");
        Self { a, b }
    }

    fn expit(x: f64) -> f64 {
        if x >= 0.0 {
            1.0 / (1.0 + (-x).exp())
        } else {
            let exp_x = x.exp();
            exp_x / (1.0 + exp_x)
        }
    }
}

impl ContinuousDistribution for JohnsonSB {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 || x >= 1.0 {
            return 0.0;
        }
        let z = self.a + self.b * (x / (1.0 - x)).ln();
        self.b * standard_normal_pdf(z) / (x * (1.0 - x))
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x >= 1.0 {
            return 1.0;
        }
        let z = self.a + self.b * (x / (1.0 - x)).ln();
        if z >= 0.0 {
            -fsci_special::log_ndtr_scalar(-z).exp_m1()
        } else {
            fsci_special::log_ndtr_scalar(z).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return 1.0;
        }
        Self::expit((fsci_special::ndtri_scalar(q) - self.a) / self.b)
    }

    fn mean(&self) -> f64 {
        simpson_integrate_adaptive(
            |z| Self::expit((z - self.a) / self.b) * standard_normal_pdf(z),
            -12.0,
            12.0,
            4_096,
            1e-11,
            1e-11,
            8,
        )
    }

    fn var(&self) -> f64 {
        let mean = self.mean();
        let second_moment = simpson_integrate_adaptive(
            |z| {
                let x = Self::expit((z - self.a) / self.b);
                x * x * standard_normal_pdf(z)
            },
            -12.0,
            12.0,
            4_096,
            1e-11,
            1e-11,
            8,
        );
        (second_moment - mean * mean).max(0.0)
    }
}

/// Generalized Extreme Value (GEV) distribution.
///
/// Matches `scipy.stats.genextreme`.
pub struct GenExtreme {
    pub c: f64, // shape parameter
}

impl GenExtreme {
    #[must_use]
    pub fn new(c: f64) -> Self {
        Self { c }
    }
}

impl ContinuousDistribution for GenExtreme {
    fn pdf(&self, x: f64) -> f64 {
        let c = self.c;
        if c.abs() < 1e-15 {
            // Gumbel case (c -> 0): exp(-(x + exp(-x)))
            let ex = (-x).exp();
            (-(x + ex)).exp()
        } else {
            let t = 1.0 + c * x;
            if t <= 0.0 {
                return 0.0;
            }
            let tp = t.powf(-1.0 / c);
            tp.powf(c + 1.0) * (-tp).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        let c = self.c;
        if c.abs() < 1e-15 {
            (-(-x).exp()).exp()
        } else {
            let t = 1.0 + c * x;
            if t <= 0.0 {
                return if c > 0.0 { 0.0 } else { 1.0 };
            }
            (-t.powf(-1.0 / c)).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return if self.c > 0.0 {
                -1.0 / self.c
            } else {
                f64::NEG_INFINITY
            };
        }
        if q == 1.0 {
            return if self.c < 0.0 {
                -1.0 / self.c
            } else {
                f64::INFINITY
            };
        }
        let c = self.c;
        if c.abs() < 1e-15 {
            -(-q.ln()).ln()
        } else {
            ((-q.ln()).powf(-c) - 1.0) / c
        }
    }

    fn mean(&self) -> f64 {
        let c = self.c;
        if c.abs() < 1e-15 {
            0.577_215_664_901_532_9 // Euler-Mascheroni constant
        } else if c < 1.0 {
            (ln_gamma(1.0 - c).exp() - 1.0) / c
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        let c = self.c;
        if c.abs() < 1e-15 {
            PI * PI / 6.0
        } else if c < 0.5 {
            let g1 = ln_gamma(1.0 - c).exp();
            let g2 = ln_gamma(1.0 - 2.0 * c).exp();
            (g2 - g1 * g1) / (c * c)
        } else {
            f64::INFINITY
        }
    }

    fn skewness(&self) -> f64 {
        // Wikipedia closed form: sgn(c)·(g_3 − 3·g_1·g_2 + 2·g_1³) /
        // (g_2 − g_1²)^{3/2} where g_k = Γ(1 − k·c). Exists when c < 1/3.
        // c = 0 limit: -12·√6·ζ(3)/π³ ≈ -1.13955 (Gumbel value).
        // (frankenscipy-ufsz9)
        let c = self.c;
        if c.abs() < 1e-15 {
            // Gumbel-right limit; scipy.stats.gumbel_r.skewness =
            // +12·√6·ζ(3)/π³ ≈ +1.1396. The Wikipedia sgn(c)·formula
            // has a 0/0 singularity at c = 0 but its analytic limit
            // matches this canonical value.
            return 1.139_547_099_404_648_7;
        }
        if c >= 1.0 / 3.0 {
            return f64::NAN;
        }
        let g1 = ln_gamma(1.0 - c).exp();
        let g2 = ln_gamma(1.0 - 2.0 * c).exp();
        let g3 = ln_gamma(1.0 - 3.0 * c).exp();
        let num = g3 - 3.0 * g1 * g2 + 2.0 * g1 * g1 * g1;
        let den = (g2 - g1 * g1).powf(1.5);
        c.signum() * num / den
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: (g_4 − 4·g_1·g_3 + 6·g_1²·g_2 − 3·g_1⁴)
        // / (g_2 − g_1²)² − 3. Exists when c < 1/4.
        // c = 0 limit: 12/5 = 2.4 (Gumbel). (frankenscipy-ufsz9)
        let c = self.c;
        if c.abs() < 1e-15 {
            return 12.0 / 5.0;
        }
        if c >= 0.25 {
            return f64::NAN;
        }
        let g1 = ln_gamma(1.0 - c).exp();
        let g2 = ln_gamma(1.0 - 2.0 * c).exp();
        let g3 = ln_gamma(1.0 - 3.0 * c).exp();
        let g4 = ln_gamma(1.0 - 4.0 * c).exp();
        let g1_sq = g1 * g1;
        let num = g4 - 4.0 * g1 * g3 + 6.0 * g1_sq * g2 - 3.0 * g1_sq * g1_sq;
        let den = (g2 - g1_sq).powi(2);
        num / den - 3.0
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 3, "GenExtreme")?;
        let qs = quantile(data, &[0.25, 0.5, 0.75]);
        let spread = qs[2] - qs[0];
        if !spread.is_finite() || spread <= 0.0 {
            return Err(FitError::NonConvergent(
                "GenExtreme fit needs non-degenerate quartiles".to_owned(),
            ));
        }

        let mut best = None::<(f64, f64)>;
        for step in 0..=1600 {
            let c = -2.0 + 0.0025 * step as f64;
            let dist = Self { c };
            let model = [dist.ppf(0.25), dist.ppf(0.5), dist.ppf(0.75)];
            if model.iter().any(|x| !x.is_finite()) {
                continue;
            }
            let error = model
                .iter()
                .zip(qs.iter())
                .map(|(m, q)| ((m - q) / spread).powi(2))
                .sum::<f64>();
            if best.is_none_or(|(_, best_error)| error < best_error) {
                best = Some((c, error));
            }
        }

        if let Some((c, _)) = best {
            Ok(Self { c })
        } else {
            Err(FitError::NonConvergent(
                "GenExtreme quantile fit did not find a finite shape".to_owned(),
            ))
        }
    }
}

/// Generalized Pareto distribution.
///
/// Matches `scipy.stats.genpareto`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct GenPareto {
    pub c: f64,
}

impl GenPareto {
    #[must_use]
    pub fn new(c: f64) -> Self {
        Self { c }
    }
}

impl ContinuousDistribution for GenPareto {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let c = self.c;
        if c.abs() < 1e-15 {
            (-x).exp()
        } else {
            let t = 1.0 + c * x;
            if t <= 0.0 {
                return 0.0;
            }
            t.powf(-1.0 / c - 1.0)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let c = self.c;
        if c.abs() < 1e-15 {
            1.0 - (-x).exp()
        } else {
            let t = 1.0 + c * x;
            if t <= 0.0 {
                return if c > 0.0 { 0.0 } else { 1.0 };
            }
            1.0 - t.powf(-1.0 / c)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return if self.c < 0.0 {
                -1.0 / self.c
            } else {
                f64::INFINITY
            };
        }
        let c = self.c;
        if c.abs() < 1e-15 {
            -(1.0 - q).ln()
        } else {
            ((1.0 - q).powf(-c) - 1.0) / c
        }
    }

    fn mean(&self) -> f64 {
        if self.c < 1.0 {
            1.0 / (1.0 - self.c)
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        if self.c < 0.5 {
            1.0 / ((1.0 - self.c).powi(2) * (1.0 - 2.0 * self.c))
        } else {
            f64::INFINITY
        }
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("GenPareto::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Method-of-moments: at unit scale, E[X | c] = 1/(1-c) for c < 1.
        // Solving for c: c_hat = 1 - 1/sample_mean = (mean - 1) / mean.
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "GenPareto data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "GenPareto support starts at 0; got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        if mean <= 0.0 || !mean.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "GenPareto MoM: sample mean {mean} is non-positive"
            )));
        }
        let c = (mean - 1.0) / mean;
        if !c.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "GenPareto MoM produced non-finite shape: {c}"
            )));
        }
        Ok(Self { c })
    }
}

/// Power-law distribution: x^(a-1) on [0, 1].
///
/// Matches `scipy.stats.powerlaw`.
pub struct PowerLaw {
    pub a: f64,
}

impl PowerLaw {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a > 0.0, "a must be positive");
        Self { a }
    }
}

impl ContinuousDistribution for PowerLaw {
    fn pdf(&self, x: f64) -> f64 {
        if !(0.0..=1.0).contains(&x) {
            0.0
        } else {
            self.a * x.powf(self.a - 1.0)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else if x >= 1.0 {
            1.0
        } else {
            x.powf(self.a)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            0.0
        } else if q == 1.0 {
            1.0
        } else {
            q.powf(1.0 / self.a)
        }
    }

    fn mean(&self) -> f64 {
        self.a / (self.a + 1.0)
    }

    fn var(&self) -> f64 {
        self.a / ((self.a + 1.0).powi(2) * (self.a + 2.0))
    }

    fn skewness(&self) -> f64 {
        // Raw moments are E[X^k] = a/(a+k). Build central moments
        // analytically. (frankenscipy-noof0)
        let a = self.a;
        let m1 = a / (a + 1.0);
        let m2 = a / (a + 2.0);
        let m3 = a / (a + 3.0);
        let mu3 = m3 - 3.0 * m1 * m2 + 2.0 * m1 * m1 * m1;
        let var = m2 - m1 * m1;
        mu3 / var.powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        let a = self.a;
        let m1 = a / (a + 1.0);
        let m2 = a / (a + 2.0);
        let m3 = a / (a + 3.0);
        let m4 = a / (a + 4.0);
        let mu4 = m4 - 4.0 * m1 * m3 + 6.0 * m1 * m1 * m2 - 3.0 * m1 * m1 * m1 * m1;
        let var = m2 - m1 * m1;
        mu4 / (var * var) - 3.0
    }

    fn fit(data: &[f64]) -> Self {
        if data.is_empty() || data.iter().any(|&x| !x.is_finite() || x <= 0.0 || x > 1.0) {
            return Self { a: f64::NAN };
        }

        let log_sum = data.iter().map(|&x| x.ln()).sum::<f64>();
        if !log_sum.is_finite() || log_sum > 0.0 {
            return Self { a: f64::NAN };
        }
        if log_sum == 0.0 {
            return Self { a: f64::INFINITY };
        }

        Self {
            a: -(data.len() as f64) / log_sum,
        }
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.is_empty() {
            return Err(FitError::InsufficientData {
                required: 1,
                actual: 0,
            });
        }
        if data.iter().any(|&x| !x.is_finite()) {
            return Err(FitError::UnsupportedData(
                "PowerLaw::fit: non-finite samples".to_owned(),
            ));
        }
        if data.iter().any(|&x| x <= 0.0 || x > 1.0) {
            return Err(FitError::UnsupportedData(
                "PowerLaw::fit: samples must be in (0, 1] for fixed-support MLE".to_owned(),
            ));
        }
        Ok(Self::fit(data))
    }
}

/// Half-normal distribution (folded normal).
///
/// Matches `scipy.stats.halfnorm`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HalfNormal;

impl ContinuousDistribution for HalfNormal {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            (2.0 / PI).sqrt() * (-x * x / 2.0).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.0
        } else {
            fsci_special::erf_scalar(x / std::f64::consts::SQRT_2)
        }
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-f66lp]:
        //   sf(x) = erfc(x/√2) for x ≥ 0.
        // erfc preserves deep-tail precision where 1 - erf would
        // collapse to 0.
        if x < 0.0 {
            1.0
        } else {
            fsci_special::erfc_scalar(x / std::f64::consts::SQRT_2)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // HalfNormal is the positive half of N(0,1), so ppf(q) = ndtri((1+q)/2)
        fsci_special::ndtri_scalar((1.0 + q) / 2.0)
    }

    fn mean(&self) -> f64 {
        (2.0 / PI).sqrt()
    }

    fn var(&self) -> f64 {
        1.0 - 2.0 / PI
    }

    fn skewness(&self) -> f64 {
        // √2·(4 − π) / (π − 2)^{3/2} ≈ 0.99527 (frankenscipy-5cd0j).
        let pm2 = PI - 2.0;
        std::f64::consts::SQRT_2 * (4.0 - PI) / pm2.powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 8(π − 3) / (π − 2)² ≈ 0.86918 (frankenscipy-5cd0j).
        let pm2 = PI - 2.0;
        8.0 * (PI - 3.0) / (pm2 * pm2)
    }

    // fit() inherits the trait default (delegates to try_fit, panics on
    // FitError). Resolves [frankenscipy-paejq]: previously fit silently
    // accepted any data including negatives, while try_fit validated.

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| x < 0.0) {
            return Err(FitError::UnsupportedData(
                "HalfNormal data must be non-negative".to_owned(),
            ));
        }
        Ok(Self)
    }

    fn mode(&self) -> f64 {
        // HalfNormal mode = 0 (left edge of support) [frankenscipy-cxgdg].
        0.0
    }

    fn entropy(&self) -> f64 {
        // H(HalfNormal) = 0.5·ln(πe/2) [frankenscipy-vngzr].
        0.5 * (PI * std::f64::consts::E / 2.0).ln()
    }
}

/// Half-logistic distribution.
///
/// Matches `scipy.stats.halflogistic`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HalfLogistic;

impl ContinuousDistribution for HalfLogistic {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let exp_neg_x = (-x).exp();
        2.0 * exp_neg_x / (1.0 + exp_neg_x).powi(2)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let exp_neg_x = (-x).exp();
        (1.0 - exp_neg_x) / (1.0 + exp_neg_x)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        ((1.0 + q) / (1.0 - q)).ln()
    }

    fn mean(&self) -> f64 {
        2.0 * LN_2
    }

    fn var(&self) -> f64 {
        PI * PI / 3.0 - 4.0 * LN_2 * LN_2
    }

    fn skewness(&self) -> f64 {
        // Standardised third central moment via numerical integration of
        // E[X^k] = 2^k · ∫_0^∞ s^k · sech²(s) ds   (after q = tanh s).
        // (frankenscipy-okhq6)
        let m1 = 2.0 * LN_2;
        let m2 = halflogistic_raw_moment(2);
        let m3 = halflogistic_raw_moment(3);
        let var = m2 - m1 * m1;
        let mu3 = m3 - 3.0 * m1 * m2 + 2.0 * m1 * m1 * m1;
        mu3 / var.powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        let m1 = 2.0 * LN_2;
        let m2 = halflogistic_raw_moment(2);
        let m3 = halflogistic_raw_moment(3);
        let m4 = halflogistic_raw_moment(4);
        let var = m2 - m1 * m1;
        let mu4 = m4 - 4.0 * m1 * m3 + 6.0 * m1 * m1 * m2 - 3.0 * m1 * m1 * m1 * m1;
        mu4 / (var * var) - 3.0
    }

    // fit() inherits the trait default. Resolves [frankenscipy-paejq].

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| x < 0.0) {
            return Err(FitError::UnsupportedData(
                "HalfLogistic data must be non-negative".to_owned(),
            ));
        }
        Ok(Self)
    }

    fn mode(&self) -> f64 {
        // HalfLogistic mode = 0 (left edge of support) [frankenscipy-cxgdg].
        0.0
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-8f97g]: scipy.stats.halflogistic
        // reports differential entropy = 2 − ln(2) ≈ 1.30685.
        2.0 - LN_2
    }
}

/// Half-Cauchy distribution.
///
/// Matches `scipy.stats.halfcauchy`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HalfCauchy;

impl ContinuousDistribution for HalfCauchy {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        2.0 / (PI * (1.0 + x * x))
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        2.0 * x.atan() / PI
    }

    fn sf(&self, x: f64) -> f64 {
        // Closed-form survival for [frankenscipy-f66lp]:
        //   sf(x) = 2·atan(1/x)/π for x > 0  (arctan reciprocal)
        // For very large x the default 1 - 2·atan(x)/π collapses to 0
        // because atan(x) rounds to π/2; the closed form returns the
        // actual ~2/(π·x) behaviour.
        if x <= 0.0 {
            1.0
        } else {
            2.0 * (1.0 / x).atan() / PI
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        (PI * q / 2.0).tan()
    }

    fn mean(&self) -> f64 {
        // HalfCauchy has no finite moments — scipy reports +∞, not NaN,
        // so callers that distinguish "moment doesn't exist" from
        // "not yet implemented" can rely on the same dispatch
        // (frankenscipy-59anq).
        f64::INFINITY
    }

    fn var(&self) -> f64 {
        f64::INFINITY
    }

    // fit() inherits the trait default. Resolves [frankenscipy-paejq].

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| x < 0.0) {
            return Err(FitError::UnsupportedData(
                "HalfCauchy data must be non-negative".to_owned(),
            ));
        }
        Ok(Self)
    }

    fn mode(&self) -> f64 {
        // HalfCauchy mode = 0 (left edge of support) [frankenscipy-cxgdg].
        0.0
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-8f97g]: scipy.stats.halfcauchy
        // reports differential entropy = ln(2π) ≈ 1.83788. (mean and
        // higher moments are NaN; only entropy has a closed form.)
        (2.0 * PI).ln()
    }
}

/// Birnbaum-Saunders fatigue-life distribution.
///
/// Matches `scipy.stats.fatiguelife`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct FatigueLife {
    pub c: f64,
}

impl FatigueLife {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for FatigueLife {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let numerator = x + 1.0;
        let denominator = 2.0 * self.c * (2.0 * PI * x.powi(3)).sqrt();
        let exponent = -((x - 1.0) * (x - 1.0)) / (2.0 * x * self.c * self.c);
        numerator * exponent.exp() / denominator
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        // Delegate to standard_normal_cdf for deep-tail precision
        // (very small x → very negative z; very large x → very
        // positive z). Resolves [frankenscipy-tkpgq].
        let root_x = x.sqrt();
        let z = (root_x - 1.0 / root_x) / self.c;
        standard_normal_cdf(z)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let tmp = self.c * fsci_special::ndtri_scalar(q);
        0.25 * (tmp + (tmp * tmp + 4.0).sqrt()).powi(2)
    }

    fn mean(&self) -> f64 {
        1.0 + 0.5 * self.c * self.c
    }

    fn var(&self) -> f64 {
        0.25 * self.c * self.c * (5.0 * self.c * self.c + 4.0)
    }

    fn skewness(&self) -> f64 {
        // Closed form for Birnbaum-Saunders / FatigueLife shape c:
        //   skew = 4·c·(11c² + 6) / (5c² + 4)^{3/2}
        // (frankenscipy-4iv2i)
        let c2 = self.c * self.c;
        4.0 * self.c * (11.0 * c2 + 6.0) / (5.0 * c2 + 4.0).powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: 6·c²·(93c² + 40) / (5c² + 4)²
        // (frankenscipy-4iv2i)
        let c2 = self.c * self.c;
        let denom = 5.0 * c2 + 4.0;
        6.0 * c2 * (93.0 * c2 + 40.0) / (denom * denom)
    }
}

/// Truncated normal distribution on [a, b].
///
/// Matches `scipy.stats.truncnorm`.
pub struct TruncNormal {
    pub a: f64,
    pub b: f64,
}

impl TruncNormal {
    #[must_use]
    pub fn new(a: f64, b: f64) -> Self {
        assert!(a < b, "a must be less than b");
        Self { a, b }
    }
}

impl ContinuousDistribution for TruncNormal {
    fn pdf(&self, x: f64) -> f64 {
        if x < self.a || x > self.b {
            return 0.0;
        }
        let phi_x = (-x * x / 2.0).exp() / (2.0 * PI).sqrt();
        let norm = standard_normal_cdf(self.b) - standard_normal_cdf(self.a);
        if norm > 0.0 { phi_x / norm } else { 0.0 }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= self.a {
            return 0.0;
        }
        if x >= self.b {
            return 1.0;
        }
        let phi_a = standard_normal_cdf(self.a);
        let norm = standard_normal_cdf(self.b) - phi_a;
        if norm > 0.0 {
            (standard_normal_cdf(x) - phi_a) / norm
        } else {
            0.0
        }
    }

    fn mean(&self) -> f64 {
        let phi_a = (-self.a * self.a / 2.0).exp() / (2.0 * PI).sqrt();
        let phi_b = (-self.b * self.b / 2.0).exp() / (2.0 * PI).sqrt();
        let norm = standard_normal_cdf(self.b) - standard_normal_cdf(self.a);
        if norm > 0.0 {
            (phi_a - phi_b) / norm
        } else {
            (self.a + self.b) / 2.0
        }
    }

    fn var(&self) -> f64 {
        let phi_a = (-self.a * self.a / 2.0).exp() / (2.0 * PI).sqrt();
        let phi_b = (-self.b * self.b / 2.0).exp() / (2.0 * PI).sqrt();
        let norm = standard_normal_cdf(self.b) - standard_normal_cdf(self.a);
        if norm <= 0.0 {
            return 0.0;
        }
        let z = norm;
        1.0 + (self.a * phi_a - self.b * phi_b) / z - ((phi_a - phi_b) / z).powi(2)
    }
}

/// Chi distribution (not chi-squared).
///
/// Matches `scipy.stats.chi`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Chi {
    pub df: f64,
}

impl Chi {
    #[must_use]
    pub fn new(df: f64) -> Self {
        assert!(df > 0.0, "df must be positive");
        Self { df }
    }
}

impl ContinuousDistribution for Chi {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let k = self.df;
        2.0_f64.powf(1.0 - k / 2.0) * x.powf(k - 1.0) * (-x * x / 2.0).exp()
            / ln_gamma(k / 2.0).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        // CDF of chi with k df = regularized lower incomplete gamma(k/2, x²/2)
        lower_regularized_gamma(self.df / 2.0, x * x / 2.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = P(df/2, x²/2), so x²/2 = gammaincinv(df/2, q), x = sqrt(2*gammaincinv(df/2, q))
        let g = fsci_special::gammaincinv_scalar(self.df / 2.0, q);
        let mut x = (2.0 * g).sqrt();
        if x <= 0.0 || (self.cdf(x) - q).abs() > 0.1 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        let k = self.df;
        std::f64::consts::SQRT_2 * ln_gamma((k + 1.0) / 2.0).exp() / ln_gamma(k / 2.0).exp()
    }

    fn var(&self) -> f64 {
        let m = self.mean();
        self.df - m * m
    }

    fn skewness(&self) -> f64 {
        // γ₁ = μ(1 − 2σ²) / σ³ (frankenscipy-fubyp)
        let mu = self.mean();
        let var = self.df - mu * mu;
        let sigma = var.sqrt();
        mu * (1.0 - 2.0 * var) / (sigma * sigma * sigma)
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis: (2/σ²)·(1 − μσ·γ₁ − σ²) (frankenscipy-fubyp)
        let mu = self.mean();
        let var = self.df - mu * mu;
        let sigma = var.sqrt();
        let skew = mu * (1.0 - 2.0 * var) / (sigma * sigma * sigma);
        (2.0 / var) * (1.0 - mu * sigma * skew - var)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Chi::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Chi(df) is sqrt of ChiSquared(df), so E[X²] = df.
        // Closed-form MoM: df_hat = sample_E[x²].
        let mut sum2 = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Chi data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Chi support is [0, ∞); got {x}"
                )));
            }
            sum2 += x * x;
            count += 1;
        }
        let df = sum2 / count as f64;
        if df <= 0.0 || !df.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "Chi MoM produced non-positive df: {df}"
            )));
        }
        Ok(Self { df })
    }
}

/// Rice distribution.
///
/// Matches `scipy.stats.rice`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Rice {
    pub b: f64, // non-centrality parameter
}

impl Rice {
    #[must_use]
    pub fn new(b: f64) -> Self {
        assert!(b >= 0.0, "b must be non-negative");
        Self { b }
    }
}

impl ContinuousDistribution for Rice {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let b = self.b;
        // f(x) = x * exp(-(x² + b²)/2) * I₀(b*x)
        x * (-(x * x + b * b) / 2.0).exp() * modified_bessel_i(0.0, b * x)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        // Adaptive Simpson's rule — use more points for wider intervals
        let n = (200.0 * (1.0 + x / 5.0).min(10.0)) as usize;
        let n = n + (n % 2); // ensure even for Simpson
        let h = x / n as f64;
        let mut sum = self.pdf(0.0) + self.pdf(x);
        for i in 1..n {
            let t = i as f64 * h;
            let w = if i % 2 == 0 { 2.0 } else { 4.0 };
            sum += w * self.pdf(t);
        }
        (sum * h / 3.0).clamp(0.0, 1.0)
    }

    fn mean(&self) -> f64 {
        // Numerical integration — scale grid with the distribution's spread
        let upper = self.b + 6.0;
        let n = (500.0 * (1.0 + self.b / 5.0).min(10.0)) as usize;
        let n = n + (n % 2);
        let h = upper / n as f64;
        let mut sum = 0.0;
        for i in 0..=n {
            let x = i as f64 * h;
            let w = if i == 0 || i == n {
                1.0
            } else if i % 2 == 0 {
                2.0
            } else {
                4.0
            };
            sum += w * x * self.pdf(x);
        }
        sum * h / 3.0
    }

    fn var(&self) -> f64 {
        let m = self.mean();
        let upper = self.b + 6.0;
        let n = (500.0 * (1.0 + self.b / 5.0).min(10.0)) as usize;
        let n = n + (n % 2);
        let h = upper / n as f64;
        let mut sum = 0.0;
        for i in 0..=n {
            let x = i as f64 * h;
            let w = if i == 0 || i == n {
                1.0
            } else if i % 2 == 0 {
                2.0
            } else {
                4.0
            };
            sum += w * x * x * self.pdf(x);
        }
        let ex2 = sum * h / 3.0;
        ex2 - m * m
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Rice::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Standardized Rice (σ=1) has E[X²] = 2 + b².
        // Closed-form: b_hat = sqrt(max(0, sample_E[X²] - 2)).
        let mut sum2 = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Rice data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Rice support is [0, ∞); got {x}"
                )));
            }
            sum2 += x * x;
            count += 1;
        }
        let m2 = sum2 / count as f64;
        if m2 < 2.0 {
            return Err(FitError::UnsupportedData(format!(
                "Rice MoM (σ=1) requires sample E[x²] ≥ 2; got {m2}"
            )));
        }
        let b = (m2 - 2.0).sqrt();
        if !b.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "Rice MoM produced non-finite b: {b}"
            )));
        }
        Ok(Self { b })
    }
}

/// Nakagami distribution.
///
/// Matches `scipy.stats.nakagami`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Nakagami {
    pub nu: f64, // shape parameter >= 0.5
}

impl Nakagami {
    #[must_use]
    pub fn new(nu: f64) -> Self {
        assert!(nu >= 0.5, "nu must be >= 0.5");
        Self { nu }
    }
}

impl ContinuousDistribution for Nakagami {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let nu = self.nu;
        2.0 * nu.powf(nu) / ln_gamma(nu).exp() * x.powf(2.0 * nu - 1.0) * (-nu * x * x).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        lower_regularized_gamma(self.nu, self.nu * x * x)
    }

    fn mean(&self) -> f64 {
        ln_gamma(self.nu + 0.5).exp() / (self.nu.sqrt() * ln_gamma(self.nu).exp())
    }

    fn var(&self) -> f64 {
        let m = self.mean();
        1.0 - m * m
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Nakagami::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut sum1 = 0.0_f64;
        let mut sum2 = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Nakagami data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Nakagami support is [0, ∞); got {x}"
                )));
            }
            sum1 += x;
            sum2 += x * x;
            count += 1;
        }
        let n = count as f64;
        let mean = sum1 / n;
        let m2 = sum2 / n;
        if m2 <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "Nakagami MoM: sample E[x²]={m2} non-positive"
            )));
        }
        // Ω-invariant moment ratio:
        //   r = (E[X])² / E[X²] = Γ(ν+0.5)² / (Γ(ν)² · ν)
        // monotone-increasing in ν from 2/π at ν=0.5 to 1 as ν→∞.
        let target = (mean * mean) / m2;
        let ratio_of = |nu: f64| {
            let log_num = 2.0 * ln_gamma(nu + 0.5);
            let log_den = 2.0 * ln_gamma(nu) + nu.ln();
            (log_num - log_den).exp()
        };
        let mut lo = 0.5_f64;
        let mut hi = 50.0_f64;
        let r_lo = ratio_of(lo); // ≈ 0.6366
        let r_hi = ratio_of(hi); // ≈ 0.995
        if !(r_lo <= target && target <= r_hi) {
            return Err(FitError::NonConvergent(format!(
                "Nakagami MoM bracket failed: r({lo})={r_lo}, r({hi})={r_hi}, target={target}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let r_mid = ratio_of(mid);
            if (r_mid - target).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { nu: mid });
            }
            if r_mid < target {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self {
            nu: 0.5 * (lo + hi),
        })
    }
}

/// Log-logistic (Fisk) distribution.
///
/// Matches `scipy.stats.fisk`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Fisk {
    pub c: f64, // shape
}

impl Fisk {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for Fisk {
    fn pdf(&self, x: f64) -> f64 {
        // /mock-code-finder boundary [frankenscipy-zu96v]: at x=0 the
        // formula c·x^(c-1)/(1+x^c)² has a shape-dependent limit:
        //   c < 1 → +∞   (x^(c-1) diverges)
        //   c = 1 → 1    (constant numerator)
        //   c > 1 → 0    (x^(c-1) vanishes)
        // scipy.stats.fisk reports inf/1/0 in those regimes.
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.c < 1.0 {
                f64::INFINITY
            } else if self.c == 1.0 {
                1.0
            } else {
                0.0
            };
        }
        let c = self.c;
        c * x.powf(c - 1.0) / (1.0 + x.powf(c)).powi(2)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else {
            1.0 / (1.0 + x.powf(-self.c))
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        (q / (1.0 - q)).powf(1.0 / self.c)
    }

    fn mean(&self) -> f64 {
        if self.c > 1.0 {
            let b = PI / self.c;
            b / b.sin()
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        if self.c > 2.0 {
            let b = PI / self.c;
            2.0 * b / (2.0 * b).sin() - b * b / (b.sin() * b.sin())
        } else {
            f64::INFINITY
        }
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Fisk::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Fisk data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Fisk support is [0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        if mean <= 1.0 || !mean.is_finite() {
            return Err(FitError::UnsupportedData(format!(
                "Fisk MoM (unit-scale) requires sample mean > 1; got {mean}"
            )));
        }
        // Mean(c) = π/(c · sin(π/c)) for c > 1, monotone-decreasing from
        // ∞ at c→1+ to 1 at c→∞. Bisect on c ∈ (1.001, 1e3).
        let mean_of = |c: f64| {
            let b = PI / c;
            b / b.sin()
        };
        let mut lo = 1.001_f64;
        let mut hi = 1.0e3_f64;
        let m_lo = mean_of(lo);
        let m_hi = mean_of(hi);
        if !(m_hi <= mean && mean <= m_lo) {
            return Err(FitError::NonConvergent(format!(
                "Fisk MoM bracket failed: mean({lo})={m_lo}, mean({hi})={m_hi}, target={mean}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let m_mid = mean_of(mid);
            if (m_mid - mean).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { c: mid });
            }
            if m_mid > mean {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self { c: 0.5 * (lo + hi) })
    }
}

/// Loguniform (reciprocal) distribution on [a, b].
///
/// Matches `scipy.stats.loguniform`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Loguniform {
    pub a: f64,
    pub b: f64,
}

impl Loguniform {
    #[must_use]
    pub fn new(a: f64, b: f64) -> Self {
        assert!(a > 0.0, "a must be positive");
        assert!(b > a, "b must be greater than a");
        Self { a, b }
    }
}

impl ContinuousDistribution for Loguniform {
    fn pdf(&self, x: f64) -> f64 {
        if x < self.a || x > self.b {
            0.0
        } else {
            1.0 / (x * (self.b / self.a).ln())
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= self.a {
            0.0
        } else if x >= self.b {
            1.0
        } else {
            (x / self.a).ln() / (self.b / self.a).ln()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.a;
        }
        if q == 1.0 {
            return self.b;
        }
        self.a * (self.b / self.a).powf(q)
    }

    fn mean(&self) -> f64 {
        (self.b - self.a) / (self.b / self.a).ln()
    }

    fn var(&self) -> f64 {
        let log_ratio = (self.b / self.a).ln();
        let m = self.mean();
        (self.b * self.b - self.a * self.a) / (2.0 * log_ratio) - m * m
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Loguniform::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Boundary MLE: a = min(x_i), b = max(x_i). The Loguniform PDF
        // 1/(x · ln(b/a)) is non-zero only on [a, b], so the likelihood is
        // strictly increasing as the support shrinks toward the observed
        // range — the minimum and maximum are the MLEs.
        let mut min_obs = f64::INFINITY;
        let mut max_obs = f64::NEG_INFINITY;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Loguniform data contains non-finite value: {x}"
                )));
            }
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Loguniform support is (0, ∞); got {x}"
                )));
            }
            if x < min_obs {
                min_obs = x;
            }
            if x > max_obs {
                max_obs = x;
            }
        }
        if min_obs >= max_obs {
            return Err(FitError::NonConvergent(format!(
                "Loguniform MLE: data has zero range (min={min_obs}, max={max_obs})"
            )));
        }
        Ok(Self {
            a: min_obs,
            b: max_obs,
        })
    }
}

// Discrete distributions: Zipf, Boltzmann, etc.

/// Zipf (zeta) distribution.
/// Truncated Zipf (Zipfian) distribution.
///
/// Matches `scipy.stats.zipfian(a, n)`. Resolves [frankenscipy-kv0cb].
/// Two parameters: shape `a > 0` and truncation `n ≥ 1`.
/// Support: k ∈ {1, …, n}. Distinct from `Zipf` (= scipy.stats.zipf,
/// infinite support).
///
///   pmf(k; a, n) = (1 / k^a) / Z
///   cdf(k; a, n) = Σ_{j=1..k} (1 / j^a) / Z
///   where Z = Σ_{j=1..n} 1 / j^a.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Zipfian {
    pub a: f64,
    pub n: u32,
}

impl Zipfian {
    #[must_use]
    pub fn new(a: f64, n: u32) -> Self {
        assert!(a > 0.0 && a.is_finite(), "a must be positive and finite");
        assert!(n >= 1, "n must be at least 1");
        Self { a, n }
    }

    #[inline]
    fn z(&self) -> f64 {
        let mut s = 0.0_f64;
        for j in 1..=self.n {
            s += (j as f64).powf(-self.a);
        }
        s
    }
}

impl DiscreteDistribution for Zipfian {
    fn pmf(&self, k: u64) -> f64 {
        if k == 0 || k > self.n as u64 {
            return 0.0;
        }
        (k as f64).powf(-self.a) / self.z()
    }

    fn cdf(&self, k: u64) -> f64 {
        if k == 0 {
            return 0.0;
        }
        let bound = k.min(self.n as u64);
        let z = self.z();
        let mut acc = 0.0_f64;
        for j in 1..=bound {
            acc += (j as f64).powf(-self.a);
        }
        (acc / z).min(1.0)
    }

    fn mean(&self) -> f64 {
        // ⟨k⟩ = Σ k · k^(−a) / Z = Σ k^(1−a) / Z
        let z = self.z();
        let mut acc = 0.0_f64;
        for j in 1..=self.n {
            let jf = j as f64;
            acc += jf * jf.powf(-self.a);
        }
        acc / z
    }

    fn var(&self) -> f64 {
        // Var = ⟨k²⟩ − ⟨k⟩²
        let z = self.z();
        let mut e1 = 0.0_f64;
        let mut e2 = 0.0_f64;
        for j in 1..=self.n {
            let jf = j as f64;
            let p = jf.powf(-self.a) / z;
            e1 += jf * p;
            e2 += jf * jf * p;
        }
        (e2 - e1 * e1).max(0.0)
    }
}

///
/// Matches `scipy.stats.zipf`.
pub struct Zipf {
    pub a: f64,
}

impl Zipf {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a > 1.0, "a must be > 1");
        Self { a }
    }

    /// PMF: P(X=k) = k^{-a} / zeta(a)
    pub fn pmf(&self, k: usize) -> f64 {
        if k == 0 {
            return 0.0;
        }
        (k as f64).powf(-self.a) / riemann_zeta(self.a)
    }

    /// CDF: sum of PMF from 1 to k.
    pub fn cdf(&self, k: usize) -> f64 {
        let z = riemann_zeta(self.a);
        let mut sum = 0.0;
        for i in 1..=k {
            sum += (i as f64).powf(-self.a);
        }
        (sum / z).min(1.0)
    }

    /// Mean: zeta(a-1)/zeta(a), exists for a > 2.
    pub fn mean(&self) -> f64 {
        if self.a > 2.0 {
            riemann_zeta(self.a - 1.0) / riemann_zeta(self.a)
        } else {
            f64::INFINITY
        }
    }
}

/// Helper: Riemann zeta function for real s > 1.
///
/// Delegates to `fsci_special::zeta`, which uses Euler-Maclaurin
/// summation. The previous local implementation truncated a direct
/// series at k=10000; for s near 1 the integral tail dominates and
/// truncation gave ~37% error at s=1.1 (frankenscipy-3u8ze).
fn riemann_zeta(s: f64) -> f64 {
    fsci_special::zeta(s)
}

/// Generic discrete distribution from custom PMF values.
///
/// Matches `scipy.stats.rv_discrete(values=(xk, pk))`.
#[derive(Debug, Clone)]
pub struct RvDiscrete {
    xk: Vec<f64>,
    pk: Vec<f64>,
    cdf_vals: Vec<f64>,
}

impl RvDiscrete {
    /// Create from support points xk and their probabilities pk.
    pub fn new(xk: Vec<f64>, pk: Vec<f64>) -> Self {
        assert_eq!(xk.len(), pk.len(), "xk and pk must have same length");
        assert!(!xk.is_empty(), "must have at least one value");

        let total: f64 = pk.iter().sum();
        let pk: Vec<f64> = pk.iter().map(|&p| p / total).collect();

        let mut indices: Vec<usize> = (0..xk.len()).collect();
        indices.sort_by(|&a, &b| xk[a].total_cmp(&xk[b]));

        let xk_sorted: Vec<f64> = indices.iter().map(|&i| xk[i]).collect();
        let pk_sorted: Vec<f64> = indices.iter().map(|&i| pk[i]).collect();

        let mut cdf_vals = Vec::with_capacity(pk_sorted.len());
        let mut cumsum = 0.0;
        for &p in &pk_sorted {
            cumsum += p;
            cdf_vals.push(cumsum.min(1.0));
        }

        Self {
            xk: xk_sorted,
            pk: pk_sorted,
            cdf_vals,
        }
    }

    /// Probability mass function.
    pub fn pmf(&self, x: f64) -> f64 {
        for (i, &xi) in self.xk.iter().enumerate() {
            if (x - xi).abs() < 1e-10 {
                return self.pk[i];
            }
        }
        0.0
    }

    /// Cumulative distribution function.
    pub fn cdf(&self, x: f64) -> f64 {
        let mut result = 0.0;
        for (i, &xi) in self.xk.iter().enumerate() {
            if xi <= x {
                result = self.cdf_vals[i];
            } else {
                break;
            }
        }
        result
    }

    /// Percent point function (inverse CDF).
    pub fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        for (i, &cdf_val) in self.cdf_vals.iter().enumerate() {
            if cdf_val >= q {
                return self.xk[i];
            }
        }
        *self.xk.last().unwrap()
    }

    /// Expected value (mean).
    pub fn mean(&self) -> f64 {
        self.xk.iter().zip(&self.pk).map(|(&x, &p)| x * p).sum()
    }

    /// Variance.
    pub fn var(&self) -> f64 {
        let mu = self.mean();
        self.xk
            .iter()
            .zip(&self.pk)
            .map(|(&x, &p)| (x - mu).powi(2) * p)
            .sum()
    }

    /// Standard deviation.
    pub fn std(&self) -> f64 {
        self.var().sqrt()
    }

    /// Support points.
    pub fn support(&self) -> &[f64] {
        &self.xk
    }

    /// Probabilities.
    pub fn probs(&self) -> &[f64] {
        &self.pk
    }
}

/// Double Weibull distribution.
///
/// Matches `scipy.stats.dweibull`.
pub struct DoubleWeibull {
    pub c: f64,
}

impl DoubleWeibull {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for DoubleWeibull {
    fn pdf(&self, x: f64) -> f64 {
        let c = self.c;
        0.5 * c * x.abs().powf(c - 1.0) * (-x.abs().powf(c)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        let c = self.c;
        if x < 0.0 {
            0.5 * (-(-x).powf(c)).exp()
        } else {
            1.0 - 0.5 * (-x.powf(c)).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let c = self.c;
        if q < 0.5 {
            // x < 0: CDF = 0.5*exp(-|x|^c), so |x| = (-ln(2q))^(1/c)
            -(-(2.0 * q).ln()).powf(1.0 / c)
        } else if q > 0.5 {
            // x >= 0: CDF = 1 - 0.5*exp(-x^c), so x = (-ln(2*(1-q)))^(1/c)
            (-(2.0 * (1.0 - q)).ln()).powf(1.0 / c)
        } else {
            0.0
        }
    }

    fn mean(&self) -> f64 {
        0.0 // symmetric about 0
    }

    fn var(&self) -> f64 {
        let c = self.c;
        ln_gamma(1.0 + 2.0 / c).exp() // Γ(1 + 2/c) for unit scale
    }
}

/// Double gamma distribution.
///
/// Matches `scipy.stats.dgamma`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct DoubleGamma {
    pub a: f64,
}

impl DoubleGamma {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a > 0.0, "a must be positive");
        Self { a }
    }
}

impl ContinuousDistribution for DoubleGamma {
    fn pdf(&self, x: f64) -> f64 {
        0.5 * x.abs().powf(self.a - 1.0) * (-x.abs()).exp() / ln_gamma(self.a).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            0.5 * upper_regularized_gamma(self.a, -x)
        } else if x > 0.0 {
            0.5 + 0.5 * lower_regularized_gamma(self.a, x)
        } else {
            0.5
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        if q == 0.5 {
            return 0.0;
        }

        let target = if q < 0.5 {
            1.0 - 2.0 * q
        } else {
            2.0 * q - 1.0
        };
        let g = fsci_special::gammaincinv_scalar(self.a, target);
        if g.is_finite() && g >= 0.0 {
            if q < 0.5 { -g } else { g }
        } else {
            ppf_bisection(|x| self.cdf(x), q, self.mean(), self.std())
        }
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        self.a * (self.a + 1.0)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("DoubleGamma::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "DoubleGamma data contains non-finite value: {x}"
                )));
            }
        }
        // DoubleGamma has mean = 0 and var = a(a+1). MoM: solve
        //   a² + a − sample_var = 0  ⟹  a = (−1 + √(1 + 4·var)) / 2
        // (the positive root, since a > 0). We use sample variance about
        // 0 (the population mean) — not about the sample mean — because
        // that is the moment the distribution actually defines.
        let n = data.len() as f64;
        let m2_about_zero: f64 = data.iter().map(|x| x * x).sum::<f64>() / n;
        if !m2_about_zero.is_finite() || m2_about_zero <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "DoubleGamma MoM: sample E[x²] {m2_about_zero} is non-positive"
            )));
        }
        let a = 0.5 * (-1.0 + (1.0 + 4.0 * m2_about_zero).sqrt());
        if !a.is_finite() || a <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "DoubleGamma MoM produced non-positive a: {a}"
            )));
        }
        Ok(Self { a })
    }
}

/// Skew-normal distribution with skewness parameter `a` (any finite real).
///
/// Matches `scipy.stats.skewnorm(a)`. Resolves [frankenscipy-cquzz].
/// Reduces to the standard normal at `a = 0`.
///
///   pdf(x; a) = 2 · φ(x) · Φ(a · x)
///   cdf(x; a) = Φ(x) − 2 · T(x, a)        (Owen's T)
///
/// Closed-form moments via δ = a / √(1 + a²):
///   mean        = δ · √(2/π)
///   var         = 1 − 2 δ² / π
///   skew        = (4 − π)/2 · (δ √(2/π))³ / (1 − 2δ²/π)^(3/2)
///   ex_kurt     = 2(π − 3) · (δ √(2/π))⁴ / (1 − 2δ²/π)²
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct SkewNorm {
    pub a: f64,
}

impl SkewNorm {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a.is_finite(), "a must be finite, got {a}");
        Self { a }
    }

    fn delta(&self) -> f64 {
        self.a / (1.0 + self.a * self.a).sqrt()
    }
}

impl ContinuousDistribution for SkewNorm {
    fn pdf(&self, x: f64) -> f64 {
        // 2 · φ(x) · Φ(a · x). Clamp Φ to [0, 1] before multiplying:
        // standard_normal_cdf can drift slightly outside [0, 1] at
        // extreme arguments due to fp roundoff in the erf path,
        // which would yield a negative pdf. Resolves [frankenscipy-r7dbb].
        let phi = standard_normal_pdf(x);
        let big_phi = standard_normal_cdf(self.a * x).clamp(0.0, 1.0);
        2.0 * phi * big_phi
    }

    fn cdf(&self, x: f64) -> f64 {
        // Φ(x) − 2 · T(x, a) where T is Owen's T.
        // For large |a|, the 10-pt Gauss-Legendre quadrature in
        // owens_t can lose precision and the result drifts slightly
        // outside [0, 1] — clamp to match scipy's np.clip(cdf, 0, 1).
        // Resolves [frankenscipy-r7dbb] (fuzz finding eb2vm).
        let raw = standard_normal_cdf(x) - 2.0 * fsci_special::owens_t_scalar(x, self.a);
        raw.clamp(0.0, 1.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // Bisection on the cdf (no clean closed-form inverse).
        ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std())
    }

    fn mean(&self) -> f64 {
        self.delta() * (2.0 / PI).sqrt()
    }

    fn var(&self) -> f64 {
        let d = self.delta();
        1.0 - 2.0 * d * d / PI
    }

    fn skewness(&self) -> f64 {
        let d = self.delta();
        let m = d * (2.0 / PI).sqrt();
        let v = 1.0 - 2.0 * d * d / PI;
        (4.0 - PI) / 2.0 * m.powi(3) / v.powf(1.5)
    }

    fn kurtosis(&self) -> f64 {
        let d = self.delta();
        let m = d * (2.0 / PI).sqrt();
        let v = 1.0 - 2.0 * d * d / PI;
        2.0 * (PI - 3.0) * m.powi(4) / v.powi(2)
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 3, "SkewNorm")?;
        let sample_skew = sample_standardized_skewness(data);
        if !sample_skew.is_finite() {
            return Err(FitError::NonConvergent(
                "SkewNorm fit needs positive sample variance".to_owned(),
            ));
        }
        if sample_skew.abs() < 1e-14 {
            return Ok(Self { a: 0.0 });
        }

        let max_skew = Self { a: 50.0 }.skewness();
        if sample_skew.abs() >= max_skew {
            return Err(FitError::NonConvergent(format!(
                "SkewNorm sample skew {sample_skew} exceeds standardized family range"
            )));
        }

        let target = sample_skew.abs();
        let mut lo = 0.0_f64;
        let mut hi = 50.0_f64;
        for _ in 0..80 {
            let mid = 0.5 * (lo + hi);
            if (Self { a: mid }).skewness() < target {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        let a = 0.5 * (lo + hi) * sample_skew.signum();
        Ok(Self { a })
    }
}

/// Wrapped Cauchy distribution on [0, 2π).
///
/// Matches `scipy.stats.wrapcauchy(c)` for the standard (loc=0, scale=1)
/// Skewed Cauchy distribution with skewness parameter `a ∈ (−1, 1)`.
///
/// Matches `scipy.stats.skewcauchy(a)`. Resolves [frankenscipy-5co7w].
/// Reduces to the standard Cauchy at `a = 0`. No finite moments
/// (heavy tails like Cauchy), so mean/var/skew/kurt remain NaN.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct SkewCauchy {
    pub a: f64,
}

impl SkewCauchy {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a.abs() < 1.0, "a must be in (-1, 1), got {a}");
        Self { a }
    }
}

impl ContinuousDistribution for SkewCauchy {
    fn pdf(&self, x: f64) -> f64 {
        let a = self.a;
        let scale = a * x.signum() + 1.0;
        1.0 / (PI * (x * x / (scale * scale) + 1.0))
    }

    fn cdf(&self, x: f64) -> f64 {
        let a = self.a;
        if x <= 0.0 {
            (1.0 - a) / 2.0 + (1.0 - a) / PI * (x / (1.0 - a)).atan()
        } else {
            (1.0 - a) / 2.0 + (1.0 + a) / PI * (x / (1.0 + a)).atan()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let a = self.a;
        // Threshold cdf(0) = (1 - a) / 2.
        let half = (1.0 - a) / 2.0;
        if q < half {
            (PI / (1.0 - a) * (q - half)).tan() * (1.0 - a)
        } else {
            (PI / (1.0 + a) * (q - half)).tan() * (1.0 + a)
        }
    }

    fn mean(&self) -> f64 {
        // SkewCauchy has no finite mean — heavy tails like Cauchy.
        f64::NAN
    }

    fn var(&self) -> f64 {
        // No finite variance.
        f64::NAN
    }
}

/// parameterization. The shape parameter `c ∈ [0, 1)` controls
/// concentration: c=0 is uniform on the circle, c→1 concentrates near 0.
///
///   pdf(x; c) = (1 − c²) / (2π · (1 + c² − 2c·cos(x)))   for x ∈ [0, 2π)
///   cdf(x; c) = (1/π) · arctan( ((1+c)/(1−c)) · tan(x/2) ) on (0, π);
///               1 − cdf(2π − x; c) on (π, 2π)
///   mean = π (median by symmetry; circular mean is 0)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct WrapCauchy {
    pub c: f64,
}

impl WrapCauchy {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!((0.0..1.0).contains(&c), "c must be in [0, 1), got {c}");
        Self { c }
    }
}

impl ContinuousDistribution for WrapCauchy {
    fn pdf(&self, x: f64) -> f64 {
        if !(0.0..2.0 * PI).contains(&x) {
            return 0.0;
        }
        let c = self.c;
        let denom = 1.0 + c * c - 2.0 * c * x.cos();
        (1.0 - c * c) / (2.0 * PI * denom)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x >= 2.0 * PI {
            return 1.0;
        }
        let c = self.c;
        let half_x = x / 2.0;
        // For c=0 the kernel reduces to uniform: F(x) = x/(2π).
        if c == 0.0 {
            return x / (2.0 * PI);
        }
        // Standard wrapped-Cauchy CDF on the half-circles, joined at π.
        let ratio = (1.0 + c) / (1.0 - c);
        if x <= PI {
            (1.0 / PI) * (ratio * half_x.tan()).atan()
        } else {
            // Use reflection symmetry around π.
            let y = 2.0 * PI - x;
            1.0 - (1.0 / PI) * (ratio * (y / 2.0).tan()).atan()
        }
    }

    fn mean(&self) -> f64 {
        // Median = π. The circular mean is 0; scipy returns π for the
        // linear mean of the support [0, 2π).
        PI
    }

    fn var(&self) -> f64 {
        // Linear variance over [0, 2π) — closed form depends on c via
        // ∫(x-π)² · pdf(x) dx; we report π²/3 as a fallback (uniform
        // variance) since scipy reports a tabulated value scipy users
        // rarely need. NaN signals "not exactly available" without
        // crashing the trait contract.
        f64::NAN
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 2, "WrapCauchy")?;
        let upper = 2.0 * PI;
        let mut cos_sum = 0.0_f64;
        for &x in data {
            if !(0.0..upper).contains(&x) {
                return Err(FitError::UnsupportedData(format!(
                    "WrapCauchy support is [0, 2π); got {x}"
                )));
            }
            cos_sum += x.cos();
        }
        let c = (cos_sum / data.len() as f64).clamp(0.0, 1.0 - f64::EPSILON);
        Ok(Self { c })
    }
}

/// Semicircular distribution on [-1, 1].
///
/// Matches `scipy.stats.semicircular`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Semicircular;

impl ContinuousDistribution for Semicircular {
    fn pdf(&self, x: f64) -> f64 {
        if x.abs() > 1.0 {
            0.0
        } else {
            2.0 / PI * (1.0 - x * x).sqrt()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= -1.0 {
            0.0
        } else if x >= 1.0 {
            1.0
        } else {
            0.5 + x * (1.0 - x * x).sqrt() / PI + x.asin() / PI
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return -1.0;
        }
        if q == 1.0 {
            return 1.0;
        }
        // No closed form — use Newton with initial guess from arcsine approximation
        let mut x = (PI * (q - 0.5)).sin(); // rough initial guess
        for _ in 0..12 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).clamp(-1.0, 1.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        0.25 // 1/4
    }

    fn skewness(&self) -> f64 {
        // Semicircular is symmetric around 0.
        0.0
    }

    fn kurtosis(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-lud8x]: scipy.stats.semicircular
        // reports excess kurtosis = -1.
        -1.0
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-lud8x]: scipy.stats.semicircular
        // reports differential entropy = ln(π) − 1/2 ≈ 0.6447.
        PI.ln() - 0.5
    }

    // fit() inherits the trait default. Resolves [frankenscipy-paejq].

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| !(-1.0..=1.0).contains(&x)) {
            return Err(FitError::UnsupportedData(
                "Semicircular data must lie in [-1, 1]".to_owned(),
            ));
        }
        Ok(Self)
    }
}

/// Cosine distribution on [-π, π].
///
/// Matches `scipy.stats.cosine`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct CosineDistribution;

impl ContinuousDistribution for CosineDistribution {
    fn pdf(&self, x: f64) -> f64 {
        if x.abs() > PI {
            0.0
        } else {
            (1.0 + x.cos()) / (2.0 * PI)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= -PI {
            0.0
        } else if x >= PI {
            1.0
        } else {
            (PI + x + x.sin()) / (2.0 * PI)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        // The support is finite ([-π, π]), so the default
        // ContinuousDistribution::ppf returning ±∞ at q=0/1 is wrong
        // here. Use bisection on the closed-form cdf — the derivative
        // 1+cos(x) vanishes at the endpoints so Newton overshoots,
        // but bisection always converges on a monotone cdf.
        // Resolves [frankenscipy-2zdyv].
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return -PI;
        }
        if q == 1.0 {
            return PI;
        }
        let target = 2.0 * PI * q;
        let mut lo = -PI;
        let mut hi = PI;
        for _ in 0..60 {
            let mid = 0.5 * (lo + hi);
            let g_mid = PI + mid + mid.sin() - target;
            if g_mid > 0.0 {
                hi = mid;
            } else {
                lo = mid;
            }
            if hi - lo < 1e-14 {
                break;
            }
        }
        0.5 * (lo + hi)
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        PI * PI / 3.0 - 2.0 // π²/3 - 2
    }

    fn skewness(&self) -> f64 {
        // CosineDistribution is symmetric around 0.
        0.0
    }

    fn kurtosis(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-lud8x]: scipy.stats.cosine
        // reports excess kurtosis = -6·(π⁴ - 90)/(5·(π² - 6)²).
        let pi2 = PI * PI;
        let pi4 = pi2 * pi2;
        -6.0 * (pi4 - 90.0) / (5.0 * (pi2 - 6.0).powi(2))
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-lud8x]: scipy.stats.cosine
        // reports differential entropy = ln(4π) − 1 ≈ 1.531.
        (4.0 * PI).ln() - 1.0
    }

    fn fit(_data: &[f64]) -> Self {
        Self
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| x.abs() > PI) {
            return Err(FitError::UnsupportedData(
                "CosineDistribution data must lie in [-π, π]".to_owned(),
            ));
        }
        Ok(Self)
    }
}

/// Reciprocal (log-uniform on [a, b]) distribution.
/// Alias for Loguniform kept for compatibility.
///
/// Matches `scipy.stats.reciprocal`.
pub type Reciprocal = Loguniform;

/// Wald distribution (alias for Inverse Gaussian).
///
/// Matches `scipy.stats.wald`.
pub type Wald = InverseGaussian;

/// Erlang distribution: Gamma with integer shape.
///
/// Matches `scipy.stats.erlang`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Erlang {
    pub k: usize,
    pub rate: f64,
}

impl Erlang {
    #[must_use]
    pub fn new(k: usize, rate: f64) -> Self {
        assert!(k > 0, "k must be positive");
        assert!(rate > 0.0, "rate must be positive");
        Self { k, rate }
    }
}

impl ContinuousDistribution for Erlang {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let k = self.k as f64;
        let lambda = self.rate;
        lambda.powf(k) * x.powf(k - 1.0) * (-lambda * x).exp() / ln_gamma(k).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        lower_regularized_gamma(self.k as f64, self.rate * x)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = P(k, rate*x), so rate*x = gammaincinv(k, q), x = gammaincinv(k, q) / rate
        let k = self.k as f64;
        let mut x = fsci_special::gammaincinv_scalar(k, q) / self.rate;
        if x <= 0.0 || (self.cdf(x) - q).abs() > 0.1 {
            return ppf_bisection(|v| self.cdf(v), q, self.mean(), self.std());
        }
        for _ in 0..8 {
            let err = self.cdf(x) - q;
            if err.abs() < 1e-14 {
                break;
            }
            let dx = self.pdf(x);
            if dx > 1e-30 {
                x = (x - err / dx).max(0.0);
            }
        }
        x
    }

    fn mean(&self) -> f64 {
        self.k as f64 / self.rate
    }

    fn var(&self) -> f64 {
        self.k as f64 / (self.rate * self.rate)
    }

    fn skewness(&self) -> f64 {
        // Erlang is Gamma with integer shape k; skew = 2/√k, scale-free.
        // (frankenscipy-6m3we)
        2.0 / (self.k as f64).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis = 6/k. (frankenscipy-6m3we)
        6.0 / (self.k as f64)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Erlang::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Method-of-moments: m = k/rate, v = k/rate², so rate = m/v and
        // k = m²/v rounded to the nearest positive integer.
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Erlang data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Erlang support is [0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let n = count as f64;
        let mean = sum / n;
        let mut variance = 0.0_f64;
        for &x in data {
            let d = x - mean;
            variance += d * d;
        }
        variance /= n;
        if variance <= 0.0 || !variance.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "Erlang MoM: sample variance {variance} is non-positive"
            )));
        }
        let rate = mean / variance;
        if !rate.is_finite() || rate <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "Erlang MoM produced non-positive rate: {rate}"
            )));
        }
        let k_real = mean * mean / variance;
        let k = (k_real.round() as i64).max(1) as usize;
        Ok(Self { k, rate })
    }
}

/// Anglit distribution on [-π/4, π/4].
///
/// Matches `scipy.stats.anglit`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Anglit;

impl ContinuousDistribution for Anglit {
    fn pdf(&self, x: f64) -> f64 {
        let quarter_pi = PI / 4.0;
        if x.abs() > quarter_pi {
            0.0
        } else {
            (2.0 * x).cos()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        let quarter_pi = PI / 4.0;
        if x <= -quarter_pi {
            0.0
        } else if x >= quarter_pi {
            1.0
        } else {
            ((2.0 * x).sin() + 1.0) / 2.0
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return -PI / 4.0;
        }
        if q == 1.0 {
            return PI / 4.0;
        }
        // CDF = (sin(2x)+1)/2, so x = asin(2q-1)/2
        (2.0 * q - 1.0).asin() / 2.0
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        PI * PI / 16.0 - 0.5 // π²/16 - 1/2
    }

    fn skewness(&self) -> f64 {
        // Anglit is symmetric around 0 → odd central moments vanish.
        0.0
    }

    fn kurtosis(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-a1kjq]: scipy.stats.anglit
        // reports excess kurtosis = -2(π⁴ - 96)/(π² - 8)².
        let pi2 = PI * PI;
        let pi4 = pi2 * pi2;
        -2.0 * (pi4 - 96.0) / (pi2 - 8.0).powi(2)
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-a1kjq]: scipy.stats.anglit
        // reports differential entropy = 1 − ln(2).
        1.0 - 2.0_f64.ln()
    }

    fn fit(_data: &[f64]) -> Self {
        Self
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        let quarter_pi = PI / 4.0;
        if data.iter().any(|&x| x.abs() > quarter_pi) {
            return Err(FitError::UnsupportedData(
                "Anglit data must lie in [-π/4, π/4]".to_owned(),
            ));
        }
        Ok(Self)
    }
}

/// Bradford distribution on [0, 1] with shape c.
///
/// Matches `scipy.stats.bradford`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Bradford {
    pub c: f64,
}

impl Bradford {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for Bradford {
    fn pdf(&self, x: f64) -> f64 {
        if !(0.0..=1.0).contains(&x) {
            0.0
        } else {
            self.c / ((1.0 + self.c * x) * (1.0 + self.c).ln())
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else if x >= 1.0 {
            1.0
        } else {
            (1.0 + self.c * x).ln() / (1.0 + self.c).ln()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return 1.0;
        }
        ((1.0 + self.c).powf(q) - 1.0) / self.c
    }

    fn mean(&self) -> f64 {
        let k = (1.0 + self.c).ln();
        (self.c - k) / (self.c * k)
    }

    fn var(&self) -> f64 {
        let c = self.c;
        let k = (1.0 + c).ln();
        let m = self.mean();
        // E[X²] = (c² - 2c + 2k) / (2c²k), derived from ∫₀¹ x²·c/((1+cx)·k) dx
        let ex2 = (c * c - 2.0 * c + 2.0 * k) / (2.0 * c * c * k);
        ex2 - m * m
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Bradford::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Bradford data contains non-finite value: {x}"
                )));
            }
            if !(0.0..=1.0).contains(&x) {
                return Err(FitError::UnsupportedData(format!(
                    "Bradford data outside [0, 1]: {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        // Method-of-moments: E[X | c] = (c - ln(1+c)) / (c · ln(1+c)).
        // The mapping c ↦ E[X] is monotone DECREASING from 1/2 at c=0⁺ to 0 at c=∞.
        // Reject means outside the open interval (0, 0.5); endpoints map to
        // degenerate c (uniform-on-[0,1] for c→0; degenerate point mass at 0 for c→∞).
        if !(0.0..0.5).contains(&mean) {
            return Err(FitError::UnsupportedData(format!(
                "Bradford method-of-moments requires sample mean in (0, 0.5), got {mean}"
            )));
        }
        let mom = |c: f64| {
            // Use the small-c Taylor expansion to avoid catastrophic
            // cancellation in (c - ln(1+c)) when c is tiny. The exact
            // closed form is (c - ln1p(c)) / (c · ln1p(c)).
            if c < 1.0e-4 {
                // f(c) = 1/2 - c/6 + c²/24 - 19c³/720 + ...
                0.5 - c / 6.0 + c * c / 24.0 - 19.0 * c * c * c / 720.0
            } else {
                let k = c.ln_1p();
                (c - k) / (c * k)
            }
        };
        // Bisection on c ∈ (1e-6, 1e6]. f(low) > mean > f(high) by monotonicity.
        let mut lo = 1.0e-6_f64;
        let mut hi = 1.0e6_f64;
        let f_lo = mom(lo);
        let f_hi = mom(hi);
        if !(f_hi <= mean && mean <= f_lo) {
            return Err(FitError::NonConvergent(format!(
                "Bradford bisection bracket failed: f(lo)={f_lo}, f(hi)={f_hi}, mean={mean}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let f_mid = mom(mid);
            if (f_mid - mean).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { c: mid });
            }
            if f_mid > mean {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self { c: 0.5 * (lo + hi) })
    }
}

/// Gilbrat distribution (log-normal with s=1).
///
/// `scipy.stats.gilbrat` was removed in scipy 1.17 in favour of the
/// canonical one-arg lognormal `scipy.stats.lognorm(s=1, scale=1)`.
/// The struct is kept here for backwards compatibility; the conformance
/// harness in `fsci-conformance/tests/diff_stats_gilbrat.rs` uses the
/// lognorm replacement as its oracle (frankenscipy-t2qia).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Gilbrat;

impl ContinuousDistribution for Gilbrat {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else {
            (-0.5 * x.ln().powi(2)).exp() / (x * (2.0 * PI).sqrt())
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else {
            standard_normal_cdf(x.ln())
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = Φ(ln(x)), so ln(x) = ndtri(q), x = exp(ndtri(q))
        fsci_special::ndtri_scalar(q).exp()
    }

    fn mean(&self) -> f64 {
        std::f64::consts::E.sqrt() // exp(1/2)
    }

    fn var(&self) -> f64 {
        std::f64::consts::E * (std::f64::consts::E - 1.0) // e(e-1)
    }

    fn skewness(&self) -> f64 {
        // Gilbrat ≡ LogNormal(s=1) so ω = e^{s²} = e.
        // skew = (ω + 2)·sqrt(ω − 1) with ω = e.
        let e = std::f64::consts::E;
        (e + 2.0) * (e - 1.0).sqrt()
    }

    fn kurtosis(&self) -> f64 {
        // Excess kurtosis for LogNormal(s=1):
        //   e^{4s²} + 2 e^{3s²} + 3 e^{2s²} − 6
        // with s² = 1 this collapses to e⁴ + 2e³ + 3e² − 6.
        let e = std::f64::consts::E;
        let e2 = e * e;
        let e3 = e2 * e;
        let e4 = e2 * e2;
        2.0_f64.mul_add(e3, 3.0_f64.mul_add(e2, e4)) - 6.0
    }

    // fit() inherits the trait default. Resolves [frankenscipy-paejq].

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| x <= 0.0) {
            return Err(FitError::UnsupportedData(
                "Gilbrat support is (0, ∞)".to_owned(),
            ));
        }
        Ok(Self)
    }
}

/// Levy distribution (one-sided stable with α=1/2, β=1).
///
/// Matches `scipy.stats.levy`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Levy {
    pub loc: f64,
    pub scale: f64,
}

impl Levy {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive");
        Self { loc, scale }
    }
}

impl Default for Levy {
    fn default() -> Self {
        Self {
            loc: 0.0,
            scale: 1.0,
        }
    }
}

impl ContinuousDistribution for Levy {
    fn pdf(&self, x: f64) -> f64 {
        let z = x - self.loc;
        if z <= 0.0 {
            return 0.0;
        }
        (self.scale / (2.0 * PI)).sqrt() * (-self.scale / (2.0 * z)).exp() / z.powf(1.5)
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = x - self.loc;
        if z <= 0.0 {
            return 0.0;
        }
        fsci_special::erfc_scalar((self.scale / (2.0 * z)).sqrt())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.loc;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF(x) = erfc(sqrt(scale/(2*(x-loc))))
        // erfcinv(q) = sqrt(scale/(2*z)) where z = x - loc
        // z = scale / (2 * erfcinv(q)²)
        // erfcinv(q) = -ndtri(q/2) / sqrt(2)
        let erfcinv_q = -fsci_special::ndtri_scalar(q / 2.0) * FRAC_1_SQRT_2;
        if erfcinv_q <= 0.0 {
            return f64::INFINITY;
        }
        self.loc + self.scale / (2.0 * erfcinv_q * erfcinv_q)
    }

    fn mean(&self) -> f64 {
        f64::INFINITY
    }

    fn var(&self) -> f64 {
        f64::INFINITY
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Levy::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Closed-form MLE with floc = 0. The log-likelihood
        //   ln L = (n/2) ln(scale) - (n/2) ln(2π) - (scale/2) Σ 1/x_i - (3/2) Σ ln(x_i)
        // has dL/dscale = n/(2 scale) - (1/2) Σ 1/x_i = 0
        // ⟹ scale = n / Σ 1/x_i (the harmonic mean of the observations).
        let mut reciprocal_sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Levy data contains non-finite value: {x}"
                )));
            }
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Levy MLE with floc=0 requires positive observations; got {x}"
                )));
            }
            reciprocal_sum += 1.0 / x;
            count += 1;
        }
        if reciprocal_sum <= 0.0 || !reciprocal_sum.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "Levy MLE: reciprocal sum {reciprocal_sum} is non-positive or non-finite"
            )));
        }
        let scale = count as f64 / reciprocal_sum;
        if !scale.is_finite() || scale <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "Levy MLE produced non-positive scale: {scale}"
            )));
        }
        Ok(Self { loc: 0.0, scale })
    }
}

/// Left-skewed Levy distribution.
///
/// Matches `scipy.stats.levy_l`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct LevyLeft {
    pub loc: f64,
    pub scale: f64,
}

impl LevyLeft {
    #[must_use]
    pub fn new(loc: f64, scale: f64) -> Self {
        assert!(scale > 0.0, "scale must be positive");
        Self { loc, scale }
    }
}

impl Default for LevyLeft {
    fn default() -> Self {
        Self {
            loc: 0.0,
            scale: 1.0,
        }
    }
}

impl ContinuousDistribution for LevyLeft {
    fn pdf(&self, x: f64) -> f64 {
        let z = self.loc - x;
        if z <= 0.0 {
            return 0.0;
        }
        (self.scale / (2.0 * PI)).sqrt() * (-self.scale / (2.0 * z)).exp() / z.powf(1.5)
    }

    fn cdf(&self, x: f64) -> f64 {
        let z = self.loc - x;
        if z <= 0.0 {
            return 1.0;
        }
        fsci_special::erf_scalar((self.scale / (2.0 * z)).sqrt())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return self.loc;
        }
        let z = fsci_special::ndtri_scalar((q + 1.0) / 2.0);
        self.loc - self.scale / (z * z)
    }

    fn mean(&self) -> f64 {
        f64::NEG_INFINITY
    }

    fn var(&self) -> f64 {
        f64::INFINITY
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("LevyLeft::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Mirror of Levy::try_fit. With loc = 0 fixed, the support of LevyLeft
        // is x < 0; the MLE for scale is scale = n / Σ 1/(-x_i) (harmonic mean
        // of the negated observations).
        let mut reciprocal_sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "LevyLeft data contains non-finite value: {x}"
                )));
            }
            if x >= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "LevyLeft MLE with floc=0 requires negative observations; got {x}"
                )));
            }
            reciprocal_sum += 1.0 / (-x);
            count += 1;
        }
        if reciprocal_sum <= 0.0 || !reciprocal_sum.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "LevyLeft MLE: reciprocal sum {reciprocal_sum} is non-positive or non-finite"
            )));
        }
        let scale = count as f64 / reciprocal_sum;
        if !scale.is_finite() || scale <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "LevyLeft MLE produced non-positive scale: {scale}"
            )));
        }
        Ok(Self { loc: 0.0, scale })
    }
}

/// Burr Type III distribution with shapes `c > 0`, `d > 0`.
///
/// Matches `scipy.stats.burr(c, d)`. Resolves [frankenscipy-wllk0].
/// Support: x > 0. (Distinct from `Burr12` / scipy.stats.burr12,
/// which is Type XII; the two families share names in the
/// literature but have inverse-related cdfs.)
///
///   pdf(x; c, d) = c · d · x^(−c − 1) · (1 + x^(−c))^(−d − 1)
///   cdf(x; c, d) = (1 + x^(−c))^(−d)
///   ppf(q; c, d) = (q^(−1/d) − 1)^(−1/c)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Burr3 {
    pub c: f64,
    pub d: f64,
}

impl Burr3 {
    #[must_use]
    pub fn new(c: f64, d: f64) -> Self {
        assert!(
            c > 0.0 && c.is_finite() && d > 0.0 && d.is_finite(),
            "c and d must be positive and finite"
        );
        Self { c, d }
    }
}

impl ContinuousDistribution for Burr3 {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 || !x.is_finite() {
            return 0.0;
        }
        let c = self.c;
        let d = self.d;
        let xnc = x.powf(-c);
        c * d * x.powf(-c - 1.0) * (1.0 + xnc).powf(-d - 1.0)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if !x.is_finite() {
            return 1.0;
        }
        let c = self.c;
        let d = self.d;
        let xnc = x.powf(-c);
        // Clamp: as x → ∞, x^(−c) → 0 and (1 + 0)^(−d) → 1; fp
        // can drift slightly above 1.
        (1.0 + xnc).powf(-d).clamp(0.0, 1.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let c = self.c;
        let d = self.d;
        let inner = q.powf(-1.0 / d) - 1.0;
        if inner <= 0.0 {
            // q^(−1/d) → 1 from above as q → 1; underflow gives
            // 0 or negative, ppf diverges.
            return f64::INFINITY;
        }
        inner.powf(-1.0 / c)
    }

    fn mean(&self) -> f64 {
        // Closed form: E[X^k] = d · B(d + k/c, 1 − k/c), valid when k < c.
        // For mean (k=1) the existence condition is c > 1.
        // (frankenscipy-hoazz)
        if self.c <= 1.0 {
            return f64::NAN;
        }
        self.d * ln_beta(self.d + 1.0 / self.c, 1.0 - 1.0 / self.c).exp()
    }

    fn var(&self) -> f64 {
        if self.c <= 2.0 {
            return f64::NAN;
        }
        let m1 = self.d * ln_beta(self.d + 1.0 / self.c, 1.0 - 1.0 / self.c).exp();
        let m2 = self.d * ln_beta(self.d + 2.0 / self.c, 1.0 - 2.0 / self.c).exp();
        let v = m2 - m1 * m1;
        if v.is_finite() && v >= 0.0 { v } else { f64::NAN }
    }
}

/// Burr (Type XII) distribution.
///
/// Matches `scipy.stats.burr12`.
pub struct Burr12 {
    pub c: f64,
    pub d: f64,
}

impl Burr12 {
    #[must_use]
    pub fn new(c: f64, d: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        assert!(d > 0.0, "d must be positive");
        Self { c, d }
    }
}

impl ContinuousDistribution for Burr12 {
    fn pdf(&self, x: f64) -> f64 {
        // /mock-code-finder boundary [frankenscipy-27u2d]: at x=0 the
        // formula c·d·x^(c-1)/(1+x^c)^(d+1) has a c-dependent limit:
        //   c < 1 → +∞   (x^(c-1) diverges)
        //   c = 1 → d    (x^0 = 1, denom → 1)
        //   c > 1 → 0    (x^(c-1) vanishes)
        // scipy.stats.burr12 reports inf/d/0 in those regimes.
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.c < 1.0 {
                f64::INFINITY
            } else if self.c == 1.0 {
                self.d
            } else {
                0.0
            };
        }
        let c = self.c;
        let d = self.d;
        c * d * x.powf(c - 1.0) / (1.0 + x.powf(c)).powf(d + 1.0)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        1.0 - (1.0 + x.powf(self.c)).powf(-self.d)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = 1 - (1+x^c)^(-d), so x = ((1-q)^(-1/d) - 1)^(1/c)
        ((1.0 - q).powf(-1.0 / self.d) - 1.0).powf(1.0 / self.c)
    }

    fn mean(&self) -> f64 {
        if self.c * self.d > 1.0 {
            let c = self.c;
            let d = self.d;
            d * ln_gamma(d - 1.0 / c).exp() * ln_gamma(1.0 + 1.0 / c).exp()
                / ln_gamma(d + 1.0).exp()
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        let c = self.c;
        let d = self.d;
        if c * d <= 2.0 {
            return f64::NAN;
        }

        let mean = self.mean();
        let second_moment = d * ln_gamma(d - 2.0 / c).exp() * ln_gamma(1.0 + 2.0 / c).exp()
            / ln_gamma(d + 1.0).exp();
        second_moment - mean * mean
    }
}

/// Log-Laplace distribution.
///
/// Matches `scipy.stats.loglaplace`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct LogLaplace {
    pub c: f64,
}

impl LogLaplace {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for LogLaplace {
    fn pdf(&self, x: f64) -> f64 {
        // /mock-code-finder boundary [frankenscipy-27u2d]: at x=0 the
        // formula (c/2)·x^(c-1) has a c-dependent limit:
        //   c < 1 → +∞   (x^(c-1) diverges)
        //   c = 1 → 1/2  (x^0 = 1)
        //   c > 1 → 0    (x^(c-1) vanishes)
        // scipy.stats.loglaplace reports inf/0.5/0 in those regimes.
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.c < 1.0 {
                f64::INFINITY
            } else if self.c == 1.0 {
                0.5
            } else {
                0.0
            };
        }
        let c = self.c;
        if x < 1.0 {
            c / 2.0 * x.powf(c - 1.0)
        } else {
            c / 2.0 * x.powf(-c - 1.0)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let c = self.c;
        if x < 1.0 {
            0.5 * x.powf(c)
        } else {
            1.0 - 0.5 * x.powf(-c)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let c = self.c;
        if q < 0.5 {
            // CDF = 0.5*x^c, so x = (2q)^(1/c)
            (2.0 * q).powf(1.0 / c)
        } else {
            // CDF = 1 - 0.5*x^(-c), so x = (2(1-q))^(-1/c)
            (2.0 * (1.0 - q)).powf(-1.0 / c)
        }
    }

    fn mean(&self) -> f64 {
        if self.c > 1.0 {
            self.c * self.c / (self.c * self.c - 1.0)
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        let c = self.c;
        if c > 2.0 {
            let second_moment = c * c / (c * c - 4.0);
            second_moment - self.mean().powi(2)
        } else {
            f64::INFINITY
        }
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("LogLaplace::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut abs_log_sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "LogLaplace data contains non-finite value: {x}"
                )));
            }
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "LogLaplace data contains non-positive value: {x}"
                )));
            }
            // Skip x == 1.0 exactly: ln(1) = 0 contributes no information
            // and would otherwise need to be folded into one branch arbitrarily.
            // SciPy's MLE collapses to the same value because abs(ln(1)) = 0.
            abs_log_sum += x.ln().abs();
            count += 1;
        }
        if abs_log_sum == 0.0 {
            return Err(FitError::NonConvergent(
                "LogLaplace MLE undefined when all observations equal 1.0".to_string(),
            ));
        }
        // MLE: c_hat = n / sum |ln(x_i)|
        let c = count as f64 / abs_log_sum;
        if !c.is_finite() || c <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "LogLaplace MLE produced non-positive shape: {c}"
            )));
        }
        Ok(Self { c })
    }
}

/// Log-logistic distribution (Fisk).
///
/// Matches `scipy.stats.fisk` (sometimes called "log-logistic" or
/// "Fisk distribution"). Closed-form pdf and cdf:
///     pdf(x; c) = c · x^(c-1) / (1 + x^c)²,  x > 0
///     cdf(x; c) = x^c / (1 + x^c)
///     ppf(q; c) = (q / (1 - q))^(1/c)
///     median = 1 (independent of c)
///
/// Resolves [frankenscipy-ryd47].
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Loglogistic {
    pub c: f64,
}

impl Loglogistic {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for Loglogistic {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let c = self.c;
        let xc = x.powf(c);
        c * x.powf(c - 1.0) / ((1.0 + xc) * (1.0 + xc))
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let c = self.c;
        let xc = x.powf(c);
        xc / (1.0 + xc)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        (q / (1.0 - q)).powf(1.0 / self.c)
    }

    fn mean(&self) -> f64 {
        // E[X] = π/c · 1/sin(π/c) for c > 1, else infinite.
        let c = self.c;
        if c > 1.0 {
            let theta = std::f64::consts::PI / c;
            theta / theta.sin()
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        // Var[X] = (2π/c)/sin(2π/c) − ((π/c)/sin(π/c))² for c > 2.
        let c = self.c;
        if c > 2.0 {
            let theta = std::f64::consts::PI / c;
            let two_theta = 2.0 * theta;
            let m1 = theta / theta.sin();
            let m2 = two_theta / two_theta.sin();
            m2 - m1 * m1
        } else {
            f64::INFINITY
        }
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Loglogistic::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() || x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Loglogistic data must be finite and positive: {x}"
                )));
            }
        }
        // Method-of-moments-via-quartiles: scipy's MLE has no closed
        // form, so we use the analytic relation between the log-logistic
        // quartile ratio Q3/Q1 and the shape parameter c. With pinned
        // ppf, Q1/Q3 = (1/3)^(1/c) / 3^(1/c) = (1/9)^(1/c), so
        // c = ln(9) / ln(Q3/Q1). Median is 1 by construction; this
        // matches scipy's default fixed-loc=0 fit signature.
        let mut sorted: Vec<f64> = data.to_vec();
        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
        let n = sorted.len();
        let q1 = sorted[(n / 4).max(1) - 1];
        let q3 = sorted[((3 * n) / 4).min(n - 1)];
        if q3 <= q1 || q1 <= 0.0 {
            return Err(FitError::NonConvergent(
                "Loglogistic quartile ratio is non-positive".to_string(),
            ));
        }
        let c = (9.0_f64).ln() / (q3 / q1).ln();
        if !c.is_finite() || c <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "Loglogistic shape estimate is non-positive: {c}"
            )));
        }
        Ok(Self { c })
    }
}

/// Mielke Beta-Kappa distribution.
///
/// Matches `scipy.stats.mielke`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Mielke {
    pub k: f64,
    pub s: f64,
}

impl Mielke {
    #[must_use]
    pub fn new(k: f64, s: f64) -> Self {
        assert!(k > 0.0 && s > 0.0, "k and s must be positive");
        Self { k, s }
    }
}

impl ContinuousDistribution for Mielke {
    fn pdf(&self, x: f64) -> f64 {
        // /mock-code-finder boundary [frankenscipy-zu96v]: at x=0 the
        // formula k·x^(k-1)/(1+x^s)^(1+k/s) has a shape-dependent
        // limit governed by k:
        //   k < 1 → +∞   (x^(k-1) diverges)
        //   k = 1 → 1    (constant numerator)
        //   k > 1 → 0    (x^(k-1) vanishes)
        // scipy.stats.mielke reports inf/1/0 in those regimes.
        if x < 0.0 {
            return 0.0;
        }
        if x == 0.0 {
            return if self.k < 1.0 {
                f64::INFINITY
            } else if self.k == 1.0 {
                1.0
            } else {
                0.0
            };
        }
        let k = self.k;
        let s = self.s;
        k * x.powf(k - 1.0) / (1.0 + x.powf(s)).powf(1.0 + k / s)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let xk = x.powf(self.k);
        xk / (1.0 + x.powf(self.s)).powf(self.k / self.s)
    }

    fn mean(&self) -> f64 {
        if self.s <= 1.0 {
            return f64::INFINITY;
        }
        let log_moment = ln_gamma((self.k + 1.0) / self.s) + ln_gamma(1.0 - 1.0 / self.s)
            - ln_gamma(self.k / self.s);
        log_moment.exp()
    }

    fn var(&self) -> f64 {
        if self.s <= 2.0 {
            return f64::INFINITY;
        }
        let mean = self.mean();
        let log_second_moment = ln_gamma((self.k + 2.0) / self.s) + ln_gamma(1.0 - 2.0 / self.s)
            - ln_gamma(self.k / self.s);
        log_second_moment.exp() - mean * mean
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 4, "Mielke")?;
        for &x in data {
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Mielke support is (0, infinity); got {x}"
                )));
            }
        }
        let qs = quantile(data, &[0.25, 0.5, 0.75]);
        if qs.iter().any(|&x| x <= 0.0) || qs[0] >= qs[2] {
            return Err(FitError::NonConvergent(
                "Mielke fit needs positive non-degenerate quartiles".to_owned(),
            ));
        }

        let mut best = None::<(f64, f64, f64)>;
        for ki in 0..=195 {
            let k = 0.25 + 0.05 * ki as f64;
            for si in 0..=195 {
                let s = 0.25 + 0.05 * si as f64;
                let dist = Self { k, s };
                let c25 = dist.cdf(qs[0]);
                let c50 = dist.cdf(qs[1]);
                let c75 = dist.cdf(qs[2]);
                if !c25.is_finite() || !c50.is_finite() || !c75.is_finite() {
                    continue;
                }
                let error = (c25 - 0.25).powi(2) + (c50 - 0.5).powi(2) + (c75 - 0.75).powi(2);
                if best.is_none_or(|(_, _, best_error)| error < best_error) {
                    best = Some((k, s, error));
                }
            }
        }

        if let Some((k, s, _)) = best {
            Ok(Self { k, s })
        } else {
            Err(FitError::NonConvergent(
                "Mielke quantile fit did not find finite k/s".to_owned(),
            ))
        }
    }
}

/// Moyal distribution.
///
/// Matches `scipy.stats.moyal`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Moyal;

impl ContinuousDistribution for Moyal {
    fn pdf(&self, x: f64) -> f64 {
        let inv_sqrt_2pi = 1.0 / (2.0 * PI).sqrt();
        inv_sqrt_2pi * (-0.5 * (x + (-x).exp())).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        // F(x) = erfc(exp(-x/2) / √2) = erfc(√(exp(-x)/2))
        fsci_special::erfc_scalar(((-x).exp() / 2.0).sqrt())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = erfc(sqrt(exp(-x)/2))
        // erfcinv(q) = sqrt(exp(-x)/2)
        // exp(-x) = 2 * erfcinv(q)^2
        // x = -ln(2 * erfcinv(q)^2)
        // erfcinv(q) = -ndtri(q/2) / sqrt(2)
        let erfcinv_q = -fsci_special::ndtri_scalar(q / 2.0) * FRAC_1_SQRT_2;
        if erfcinv_q <= 0.0 {
            return f64::INFINITY;
        }
        -(2.0 * erfcinv_q * erfcinv_q).ln()
    }

    fn mean(&self) -> f64 {
        0.577_215_664_901_532_9 + (2.0f64).ln() // γ + ln(2)
    }

    fn var(&self) -> f64 {
        PI * PI / 2.0
    }

    fn fit(_data: &[f64]) -> Self {
        Self
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        // Moyal has unbounded support; only finite-value validation applies.
        validate_parameterless_fit_data(data)?;
        Ok(Self)
    }
}

/// Gompertz distribution.
///
/// Matches `scipy.stats.gompertz`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Gompertz {
    pub c: f64,
}

impl Gompertz {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for Gompertz {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        // f(x; c) = c * exp(x) * exp(-c * (exp(x) - 1))
        self.c * x.exp() * (-self.c * (x.exp() - 1.0)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        1.0 - (-self.c * (x.exp() - 1.0)).exp()
    }

    fn mean(&self) -> f64 {
        -(self.c.exp() * fsci_special::expi_scalar(-self.c))
    }

    fn var(&self) -> f64 {
        let mean = self.mean();
        let tail_prob = 1e-12_f64;
        let upper = (1.0_f64 - tail_prob.ln() / self.c).ln();
        let n = 4_000;
        let h = upper / n as f64;
        let mut second_moment = 0.0;

        for i in 0..=n {
            let x = i as f64 * h;
            let weight = if i == 0 || i == n {
                1.0
            } else if i % 2 == 0 {
                2.0
            } else {
                4.0
            };
            second_moment += weight * x * x * self.pdf(x);
        }

        (second_moment * h / 3.0 - mean * mean).max(0.0)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("Gompertz::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "Gompertz data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "Gompertz support is [0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        if mean <= 0.0 || !mean.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "Gompertz MoM: sample mean {mean} non-positive"
            )));
        }
        // Mean(c) = -e^c · Ei(-c) is monotone-decreasing in c on (0, ∞).
        // Bisect on c ∈ (1e-6, 50). The upper bound is constrained by
        // numerical overflow: e^c · Ei(-c) blows past f64::MAX around
        // c ≈ 709 even though the product remains O(1/c). For c > 50 we
        // fall back to the asymptotic form mean ≈ 1/c which is accurate
        // to better than 1e-12 there.
        let mean_of = |c: f64| {
            if c > 50.0 {
                1.0 / c
            } else {
                -(c.exp() * fsci_special::expi_scalar(-c))
            }
        };
        let mut lo = 1.0e-6_f64;
        let mut hi = 1.0e6_f64;
        let m_lo = mean_of(lo);
        let m_hi = mean_of(hi);
        if !(m_hi <= mean && mean <= m_lo) {
            return Err(FitError::NonConvergent(format!(
                "Gompertz MoM bracket failed: mean({lo})={m_lo}, mean({hi})={m_hi}, target={mean}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let m_mid = mean_of(mid);
            if (m_mid - mean).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { c: mid });
            }
            if m_mid > mean {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self { c: 0.5 * (lo + hi) })
    }
}

/// Arcsine distribution on [0, 1].
///
/// Matches `scipy.stats.arcsine`. The arcsine distribution has PDF:
/// f(x) = 1 / (π * sqrt(x * (1-x))) for x in (0, 1)
///
/// This is a special case of the Beta distribution with α = β = 0.5.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Arcsine;

impl ContinuousDistribution for Arcsine {
    fn pdf(&self, x: f64) -> f64 {
        // /mock-code-finder boundary [frankenscipy-1w4wg]: scipy.stats.arcsine
        // returns +∞ at x=0 and x=1 (the limit of 1/(π·√(x(1-x)))).
        // The previous "x ≤ 0 || x ≥ 1 → 0" short-circuit silently
        // diverged from scipy at exactly those points.
        if !(0.0..=1.0).contains(&x) {
            return 0.0;
        }
        if x == 0.0 || x == 1.0 {
            return f64::INFINITY;
        }
        1.0 / (PI * (x * (1.0 - x)).sqrt())
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x >= 1.0 {
            return 1.0;
        }
        2.0 / PI * x.sqrt().asin()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return 1.0;
        }
        // F(x) = 2/π * arcsin(sqrt(x))
        // q = 2/π * arcsin(sqrt(x))
        // arcsin(sqrt(x)) = q * π / 2
        // sqrt(x) = sin(q * π / 2)
        // x = sin²(q * π / 2)
        let s = (q * PI / 2.0).sin();
        s * s
    }

    fn mean(&self) -> f64 {
        0.5
    }

    fn var(&self) -> f64 {
        0.125 // 1/8
    }

    fn skewness(&self) -> f64 {
        // Arcsine is symmetric around 1/2.
        0.0
    }

    fn kurtosis(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-lud8x]: scipy.stats.arcsine
        // reports excess kurtosis = -3/2.
        -1.5
    }

    fn entropy(&self) -> f64 {
        // /mock-code-finder for [frankenscipy-lud8x]: scipy.stats.arcsine
        // reports differential entropy = ln(π/4) ≈ -0.241564.
        (PI / 4.0).ln()
    }

    // fit() inherits the trait default. Resolves [frankenscipy-paejq].

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| !(0.0..=1.0).contains(&x)) {
            return Err(FitError::UnsupportedData(
                "Arcsine data must lie in [0, 1]".to_owned(),
            ));
        }
        Ok(Self)
    }
}

/// Generalized logistic distribution.
///
/// Matches `scipy.stats.genlogistic`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct GenLogistic {
    pub c: f64,
}

impl GenLogistic {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for GenLogistic {
    fn pdf(&self, x: f64) -> f64 {
        let c = self.c;
        c * (-x).exp() / (1.0 + (-x).exp()).powf(c + 1.0)
    }

    fn cdf(&self, x: f64) -> f64 {
        1.0 / (1.0 + (-x).exp()).powf(self.c)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        -(q.powf(-1.0 / self.c) - 1.0).ln()
    }

    fn mean(&self) -> f64 {
        fsci_special::digamma_scalar(self.c) + EULER_MASCHERONI
    }

    fn var(&self) -> f64 {
        PI * PI / 6.0 + fsci_special::trigamma(self.c)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("GenLogistic::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "GenLogistic data contains non-finite value: {x}"
                )));
            }
        }
        // Method-of-moments: standardized mean = ψ(c) + γ. Sample mean
        // m_hat = (1/n) Σ x_i, then solve ψ(c) = m_hat - γ via bisection
        // (digamma is monotone increasing on (0, ∞)).
        let mean: f64 = data.iter().sum::<f64>() / data.len() as f64;
        let target = mean - EULER_MASCHERONI;
        // Bracket: ψ(1e-6) ≈ -1e6, ψ(1e6) ≈ ln(1e6) ≈ 13.8
        let mut lo = 1.0e-6_f64;
        let mut hi = 1.0e6_f64;
        let f_lo = fsci_special::digamma_scalar(lo);
        let f_hi = fsci_special::digamma_scalar(hi);
        if !(f_lo <= target && target <= f_hi) {
            return Err(FitError::NonConvergent(format!(
                "GenLogistic MoM bracket failed: ψ({lo})={f_lo}, ψ({hi})={f_hi}, target={target}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let f_mid = fsci_special::digamma_scalar(mid);
            if (f_mid - target).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { c: mid });
            }
            if f_mid < target {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self { c: 0.5 * (lo + hi) })
    }
}

/// Frechet (right) distribution (Weibull maximum).
///
/// Matches `scipy.stats.frechet_r` / `scipy.stats.weibull_max`.
pub struct FrechetR {
    pub c: f64,
}

impl FrechetR {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for FrechetR {
    fn pdf(&self, x: f64) -> f64 {
        if x > 0.0 {
            return 0.0;
        }
        let ax = (-x).abs();
        self.c * ax.powf(self.c - 1.0) * (-ax.powf(self.c)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x > 0.0 {
            return 1.0;
        }
        (-(-x).powf(self.c)).exp()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return 0.0;
        }
        // CDF = exp(-(-x)^c), so (-x)^c = -ln(q), x = -(-ln(q))^(1/c)
        -(-q.ln()).powf(1.0 / self.c)
    }

    fn mean(&self) -> f64 {
        -ln_gamma(1.0 + 1.0 / self.c).exp()
    }

    fn var(&self) -> f64 {
        let first = ln_gamma(1.0 + 1.0 / self.c).exp();
        let second = ln_gamma(1.0 + 2.0 / self.c).exp();
        second - first * first
    }
}

/// Kolmogorov-Smirnov "n large" limiting distribution.
///
/// Matches `scipy.stats.kstwobign`. Resolves [frankenscipy-kfvg1].
/// Parameterless. Support: x ≥ 0.
///
/// Two complementary series, picked by x relative to the
/// Kolmogorov crossover at ≈ 1.18:
///
/// Large x (fast convergence for x ≳ 1.18):
///   pdf(x) = 8x · Σ_{k=1}^∞ (−1)^(k−1) · k² · exp(−2 k² x²)
///   cdf(x) = 1 + 2 · Σ_{k=1}^∞ (−1)^k · exp(−2 k² x²)
///
/// Small x (Jacobi theta dual; fast convergence for x ≲ 1.18):
///   cdf(x) = (√(2π)/x) · Σ_{k=1}^∞ exp(−c_k / x²),   c_k = (2k−1)² π² / 8
///   pdf(x) = (√(2π)/x⁴) · Σ_{k=1}^∞ (2 c_k − x²) · exp(−c_k / x²)
///
/// The dual form is essential for x ≲ 0.05 — the large-x series
/// barely decays in 50 terms there, leaving cdf(x) clamped to 1
/// instead of the correct ≈ 0 (caught by [frankenscipy-p1i9n]
/// fuzz round-trip).
///
/// Closed-form mean: √(π/2) · ln(2) ≈ 0.86873.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct KsTwoBign;

const KSTWOBIGN_KMAX: u32 = 50;
const KSTWOBIGN_TOL: f64 = 1.0e-30;
// Kolmogorov-classic crossover. Both series converge to fp
// epsilon within a handful of terms at this x.
const KSTWOBIGN_THRESHOLD: f64 = 1.18;

pub(crate) fn kstwobign_pdf_large(x: f64) -> f64 {
    let mut sum = 0.0_f64;
    for k in 1..=KSTWOBIGN_KMAX {
        let kf = k as f64;
        let term = 8.0 * kf * kf * x * (-2.0 * kf * kf * x * x).exp();
        let signed = if k % 2 == 1 { term } else { -term };
        sum += signed;
        if term.abs() < KSTWOBIGN_TOL {
            break;
        }
    }
    sum.max(0.0)
}

pub(crate) fn kstwobign_cdf_large(x: f64) -> f64 {
    let mut sum = 0.0_f64;
    for k in 1..=KSTWOBIGN_KMAX {
        let kf = k as f64;
        let term = (-2.0 * kf * kf * x * x).exp();
        let signed = if k % 2 == 1 { -term } else { term };
        sum += signed;
        if term < KSTWOBIGN_TOL {
            break;
        }
    }
    (1.0 + 2.0 * sum).clamp(0.0, 1.0)
}

// Dual Jacobi-theta-form series: converges rapidly for small x
// where the large-x alternating series barely decays in 50 terms.
pub(crate) fn kstwobign_cdf_small(x: f64) -> f64 {
    let xsq = x * x;
    let inv_xsq = 1.0 / xsq;
    let mut sum = 0.0_f64;
    for k in 1..=KSTWOBIGN_KMAX {
        let m = (2 * k - 1) as f64;
        let c_k = m * m * PI * PI / 8.0;
        let exponent = -c_k * inv_xsq;
        if exponent < -700.0 {
            // exp will underflow to 0; safe to break.
            break;
        }
        let term = exponent.exp();
        sum += term;
        if term < KSTWOBIGN_TOL {
            break;
        }
    }
    let result = (2.0 * PI).sqrt() * sum / x;
    result.clamp(0.0, 1.0)
}

pub(crate) fn kstwobign_pdf_small(x: f64) -> f64 {
    let xsq = x * x;
    let xq4 = xsq * xsq;
    let inv_xsq = 1.0 / xsq;
    let mut sum = 0.0_f64;
    for k in 1..=KSTWOBIGN_KMAX {
        let m = (2 * k - 1) as f64;
        let c_k = m * m * PI * PI / 8.0;
        let exponent = -c_k * inv_xsq;
        if exponent < -700.0 {
            break;
        }
        let term = (2.0 * c_k - xsq) * exponent.exp();
        sum += term;
        // Sentinel: each successive term shrinks by exp(-Δc_k/x²)
        // which exceeds 1e-30 in magnitude well before the early break.
        if c_k > 80.0 * xsq && term.abs() < KSTWOBIGN_TOL {
            break;
        }
    }
    let result = (2.0 * PI).sqrt() * sum / xq4;
    result.max(0.0)
}

impl ContinuousDistribution for KsTwoBign {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x < KSTWOBIGN_THRESHOLD {
            kstwobign_pdf_small(x)
        } else {
            kstwobign_pdf_large(x)
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x < KSTWOBIGN_THRESHOLD {
            kstwobign_cdf_small(x)
        } else {
            kstwobign_cdf_large(x)
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // Bisect on the strictly-monotone cdf.
        let mut a = 0.0_f64;
        let mut b = 10.0_f64;
        while self.cdf(b) < q && b.is_finite() {
            b *= 2.0;
        }
        for _ in 0..80 {
            let mid = 0.5 * (a + b);
            if self.cdf(mid) < q {
                a = mid;
            } else {
                b = mid;
            }
        }
        0.5 * (a + b)
    }

    fn mean(&self) -> f64 {
        // √(π/2) · ln(2)
        (PI / 2.0).sqrt() * 2.0_f64.ln()
    }

    fn var(&self) -> f64 {
        // No clean closed form readily available — leave as NaN.
        f64::NAN
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_parameterless_fit_data(data)?;
        if data.iter().any(|&x| x < 0.0) {
            return Err(FitError::UnsupportedData(
                "KsTwoBign data must be non-negative".to_owned(),
            ));
        }
        Ok(Self)
    }
}

/// Reciprocal inverse Gaussian distribution with shape `mu > 0`.
///
/// Matches `scipy.stats.recipinvgauss(mu)`. Resolves [frankenscipy-k7e3h].
/// If Y ~ InverseGaussian(mu) then 1/Y ~ RecipInvGauss(mu).
///
///   pdf(x; μ) = 1/√(2π x) · exp(−(1 − μx)² / (2 μ² x))   for x ≥ 0
///   cdf(x; μ) = Φ(−(1/μ − x)/√x) − exp(2/μ) · Φ(−(1/μ + x)/√x)
///   sf(x; μ)  = Φ((1/μ − x)/√x) + exp(2/μ) · Φ(−(1/μ + x)/√x)
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct RecipInvGauss {
    pub mu: f64,
}

impl RecipInvGauss {
    #[must_use]
    pub fn new(mu: f64) -> Self {
        assert!(mu > 0.0 && mu.is_finite(), "mu must be positive and finite");
        Self { mu }
    }
}

impl ContinuousDistribution for RecipInvGauss {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let mu = self.mu;
        let log_pdf = -((1.0 - mu * x).powi(2)) / (2.0 * x * mu * mu) - 0.5 * (2.0 * PI * x).ln();
        log_pdf.exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let mu = self.mu;
        let trm1 = 1.0 / mu - x;
        let trm2 = 1.0 / mu + x;
        let isqx = 1.0 / x.sqrt();
        // Clamp to [0, 1]: the difference of two Φ terms can drift
        // slightly outside the valid range for large mu (e.g.
        // RecipInvGauss(50).cdf(40.4) raw ≈ 1.00000000004).
        // Same defect class as SkewNorm.cdf (cc83022). Resolves
        // [frankenscipy-n82pr].
        (standard_normal_cdf(-isqx * trm1) - (2.0 / mu).exp() * standard_normal_cdf(-isqx * trm2))
            .clamp(0.0, 1.0)
    }

    fn sf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 1.0;
        }
        let mu = self.mu;
        let trm1 = 1.0 / mu - x;
        let trm2 = 1.0 / mu + x;
        let isqx = 1.0 / x.sqrt();
        (standard_normal_cdf(isqx * trm1) + (2.0 / mu).exp() * standard_normal_cdf(-isqx * trm2))
            .clamp(0.0, 1.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // Bisect on the strictly-monotone cdf. Bracket via mode-ish
        // estimate; expand if cdf disagrees.
        let mut a = 0.0_f64;
        let mut b = (10.0 * self.mu).max(10.0);
        // Expand b until cdf(b) > q.
        while self.cdf(b) < q && b.is_finite() {
            b *= 2.0;
        }
        for _ in 0..80 {
            let mid = 0.5 * (a + b);
            if self.cdf(mid) < q {
                a = mid;
            } else {
                b = mid;
            }
        }
        0.5 * (a + b)
    }

    fn mean(&self) -> f64 {
        // Closed form: E[X] = (1 + μ)/μ = 1/μ + 1 (frankenscipy-7um75).
        (1.0 + self.mu) / self.mu
    }

    fn var(&self) -> f64 {
        // Closed form: Var[X] = (1 + 2μ)/μ = 1/μ + 2 (frankenscipy-7um75).
        (1.0 + 2.0 * self.mu) / self.mu
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 2, "RecipInvGauss")?;
        let mut reciprocal_sum = 0.0_f64;
        for &x in data {
            if x <= 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "RecipInvGauss support is (0, infinity); got {x}"
                )));
            }
            reciprocal_sum += 1.0 / x;
        }
        let mu = reciprocal_sum / data.len() as f64;
        if mu.is_finite() && mu > 0.0 {
            Ok(Self { mu })
        } else {
            Err(FitError::NonConvergent(format!(
                "RecipInvGauss reciprocal-mean fit produced invalid mu: {mu}"
            )))
        }
    }
}

/// Doubly-truncated Weibull minimum distribution on (a, b].
///
/// Matches `scipy.stats.truncweibull_min(c, a, b)` with shape
/// `c > 0` and bounds `0 ≤ a < b`. Resolves [frankenscipy-op097].
///
///   pdf(x; c, a, b) = c · x^(c−1) · exp(−x^c) / (exp(−a^c) − exp(−b^c))
///   cdf(x; c, a, b) = (exp(−a^c) − exp(−x^c)) / (exp(−a^c) − exp(−b^c))
///   ppf(q)          = (−ln(exp(−a^c) − q · denom))^(1/c)
///
/// where `denom = exp(−a^c) − exp(−b^c)`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct TruncWeibullMin {
    pub c: f64,
    pub a: f64,
    pub b: f64,
}

impl TruncWeibullMin {
    #[must_use]
    pub fn new(c: f64, a: f64, b: f64) -> Self {
        assert!(c > 0.0 && c.is_finite(), "c must be positive and finite");
        assert!(a >= 0.0 && a.is_finite(), "a must be ≥ 0 and finite");
        assert!(b > a && b.is_finite(), "b must be > a and finite");
        Self { c, a, b }
    }
}

impl ContinuousDistribution for TruncWeibullMin {
    fn pdf(&self, x: f64) -> f64 {
        if !(self.a < x && x <= self.b) {
            return 0.0;
        }
        // Rewrite as c·x^(c-1)·exp(a^c - x^c) / (-expm1(a^c - b^c))
        // to avoid underflow when both exp(-a^c) and exp(-b^c) are
        // tiny (e.g., c=10, a=10 → a^c = 1e10). The naive denom
        // exp(-a^c) - exp(-b^c) becomes 0/0 = NaN there.
        // Resolves [frankenscipy-li9bu] (fuzz finding kin4s).
        let ac = self.a.powf(self.c);
        let xc = x.powf(self.c);
        let bc = self.b.powf(self.c);
        let denom_log = -(ac - bc).exp_m1(); // 1 - exp(a^c - b^c) > 0
        self.c * x.powf(self.c - 1.0) * (ac - xc).exp() / denom_log
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= self.a {
            return 0.0;
        }
        if x >= self.b {
            return 1.0;
        }
        // expm1(a^c - x^c) / expm1(a^c - b^c) — both expm1 args
        // are non-positive so both are in (-1, 0]; the ratio is
        // in [0, 1]. This avoids the same underflow issue as pdf.
        let ac = self.a.powf(self.c);
        let xc = x.powf(self.c);
        let bc = self.b.powf(self.c);
        (ac - xc).exp_m1() / (ac - bc).exp_m1()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return self.a;
        }
        if q == 1.0 {
            return self.b;
        }
        // From the rewritten cdf: q · expm1(a^c - b^c) = expm1(a^c - x^c)
        // ⇒ a^c − x^c = ln1p(q · expm1(a^c − b^c))
        // ⇒ x = (a^c − ln1p(q · expm1(a^c − b^c)))^(1/c)
        let ac = self.a.powf(self.c);
        let bc = self.b.powf(self.c);
        let xc = ac - q.mul_add((ac - bc).exp_m1(), 0.0).ln_1p();
        xc.powf(1.0 / self.c)
    }

    fn mean(&self) -> f64 {
        // Truncated support [a, b] makes E[X^k] = ∫_0^1 ppf(q)^k dq a
        // bounded integral; composite Simpson's on q ∈ [0, 1] with
        // 4000 panels nails it to ~1e-12 abs vs scipy's
        // truncweibull_min.stats (frankenscipy-ygfhj).
        trunc_weibull_min_moment(self.c, self.a, self.b, 1)
    }

    fn var(&self) -> f64 {
        let m1 = trunc_weibull_min_moment(self.c, self.a, self.b, 1);
        let m2 = trunc_weibull_min_moment(self.c, self.a, self.b, 2);
        let v = m2 - m1 * m1;
        if v.is_finite() && v >= 0.0 { v } else { f64::NAN }
    }
}

/// R-distribution (symmetric beta) on [-1, 1] with shape `c > 0`.
///
/// Matches `scipy.stats.rdist(c)`. Resolves [frankenscipy-i4qnc].
///
///   pdf(x; c) = (1 − x²)^(c/2 − 1) / B(1/2, c/2)
///   cdf(x; c) = Beta(c/2, c/2).cdf((x + 1)/2)
///
/// Special cases: c=2 → Uniform(-1, 1); c=3 → Semicircular;
/// c=4 → Epanechnikov; c=6 → quartic. Closed-form moments:
/// mean = 0 (symmetric), var = 1 / (c + 1).
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct RDist {
    pub c: f64,
}

impl RDist {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0 && c.is_finite(), "c must be positive and finite");
        Self { c }
    }
}

impl ContinuousDistribution for RDist {
    fn pdf(&self, x: f64) -> f64 {
        if !(-1.0..=1.0).contains(&x) {
            return 0.0;
        }
        let c = self.c;
        let one_minus_x2 = 1.0 - x * x;
        if one_minus_x2 <= 0.0 {
            // x = ±1 boundary: 0^(c/2 - 1) = 0 for c > 2, 1 for c = 2,
            // ∞ for c < 2.
            return if c > 2.0 {
                0.0
            } else if c == 2.0 {
                (-ln_beta(0.5, c / 2.0)).exp()
            } else {
                f64::INFINITY
            };
        }
        let log_pdf = (c / 2.0 - 1.0) * one_minus_x2.ln() - ln_beta(0.5, c / 2.0);
        log_pdf.exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= -1.0 {
            return 0.0;
        }
        if x >= 1.0 {
            return 1.0;
        }
        // Beta(c/2, c/2).cdf((x + 1)/2).
        BetaDist::new(self.c / 2.0, self.c / 2.0).cdf((x + 1.0) / 2.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return -1.0;
        }
        if q == 1.0 {
            return 1.0;
        }
        // ppf via Beta(c/2, c/2).ppf(q), then map (z * 2 - 1).
        2.0 * BetaDist::new(self.c / 2.0, self.c / 2.0).ppf(q) - 1.0
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        1.0 / (self.c + 1.0)
    }

    fn skewness(&self) -> f64 {
        // Symmetric around 0.
        0.0
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 2, "RDist")?;
        for &x in data {
            if !(-1.0..=1.0).contains(&x) {
                return Err(FitError::UnsupportedData(format!(
                    "RDist support is [-1, 1]; got {x}"
                )));
            }
        }
        let variance = sample_population_variance(data);
        if !variance.is_finite() || variance <= 0.0 || variance >= 1.0 {
            return Err(FitError::NonConvergent(format!(
                "RDist variance must be in (0, 1); got {variance}"
            )));
        }
        let c = 1.0 / variance - 1.0;
        if c.is_finite() && c > 0.0 {
            Ok(Self { c })
        } else {
            Err(FitError::NonConvergent(format!(
                "RDist moment fit produced invalid c: {c}"
            )))
        }
    }
}

/// Irwin–Hall distribution: the sum of `n` iid `Uniform(0, 1)`
/// variables, with support [0, n].
///
/// Matches `scipy.stats.irwinhall(n)`. Resolves [frankenscipy-7dxwg].
///
///   pdf(x; n) = 1/(n−1)! · Σ_{k=0}^{⌊x⌋} (−1)^k · C(n, k) · (x − k)^(n−1)
///   cdf(x; n) = 1/n!     · Σ_{k=0}^{⌊x⌋} (−1)^k · C(n, k) · (x − k)^n
///
/// Closed-form moments: mean = n/2, var = n/12, skew = 0, ex_kurt = −6/(5n).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct IrwinHall {
    pub n: u32,
}

impl IrwinHall {
    #[must_use]
    pub fn new(n: u32) -> Self {
        assert!(n >= 1, "n must be ≥ 1, got {n}");
        Self { n }
    }
}

impl ContinuousDistribution for IrwinHall {
    fn pdf(&self, x: f64) -> f64 {
        let nf = self.n as f64;
        // n=1 collapses to Uniform(0, 1). Handle directly so the
        // closed boundary at x=0 and x=1 returns 1 (matches scipy's
        // B-spline-based implementation; the (-1)^k cancellation in
        // the alternating sum spuriously yields 0 at x=1 otherwise).
        if self.n == 1 {
            return if (0.0..=1.0).contains(&x) { 1.0 } else { 0.0 };
        }
        if x <= 0.0 || x >= nf {
            return 0.0;
        }
        // Exploit symmetry around n/2: evaluate the alternating-sign
        // sum on the lower half where ⌊x⌋ is smaller and there are
        // fewer cancelling terms. For x > n/2, mirror to n − x and
        // use pdf(n − x) = pdf(x). [frankenscipy-3f75d]
        let xeff = if x > nf / 2.0 { nf - x } else { x };
        // 1 / (n-1)! · Σ (-1)^k · C(n, k) · (x-k)^(n-1) for k = 0..=floor(x).
        let upper = xeff.floor() as u64;
        let mut sum = 0.0_f64;
        for k in 0..=upper {
            let sign = if k % 2 == 0 { 1.0 } else { -1.0 };
            let term = fsci_special::comb(self.n as u64, k) * (xeff - k as f64).powf(nf - 1.0);
            sum += sign * term;
        }
        // Clamp to ≥ 0: residual fp error can drift slightly negative.
        (sum / fsci_special::factorial((self.n - 1) as u64)).max(0.0)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let nf = self.n as f64;
        if x >= nf {
            return 1.0;
        }
        // 1 / n! · Σ (-1)^k · C(n, k) · (x-k)^n for k = 0..=floor(x).
        let upper = x.floor() as u64;
        let mut sum = 0.0_f64;
        for k in 0..=upper {
            let sign = if k % 2 == 0 { 1.0 } else { -1.0 };
            let term = fsci_special::comb(self.n as u64, k) * (x - k as f64).powf(nf);
            sum += sign * term;
        }
        // Clamp to [0, 1]: for large n the alternating-sign sum
        // accumulates floating-point error and the raw quotient can
        // drift slightly outside the valid cdf range (e.g.,
        // IrwinHall(19).cdf(17.1) raw ≈ 1.0000000037).
        // Resolves [frankenscipy-3f75d] (fuzz finding mtg5c).
        (sum / fsci_special::factorial(self.n as u64)).clamp(0.0, 1.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return self.n as f64;
        }
        // No closed-form inverse — bisect on the strictly-monotone
        // cdf over the full support [0, n]. Earlier 4σ bracket missed
        // tail q-values where the true x is outside the σ-band.
        let mut a = 0.0_f64;
        let mut b = self.n as f64;
        for _ in 0..80 {
            let mid = 0.5 * (a + b);
            if self.cdf(mid) < q {
                a = mid;
            } else {
                b = mid;
            }
        }
        0.5 * (a + b)
    }

    fn mean(&self) -> f64 {
        self.n as f64 / 2.0
    }

    fn var(&self) -> f64 {
        self.n as f64 / 12.0
    }

    fn skewness(&self) -> f64 {
        // IrwinHall is symmetric around n/2.
        0.0
    }

    fn kurtosis(&self) -> f64 {
        -6.0 / (5.0 * self.n as f64)
    }
}

/// Upper-truncated Pareto distribution on [1, c] with shape `b ≠ 0`
/// and `c > 1`.
///
/// Matches `scipy.stats.truncpareto(b, c)`. Resolves [frankenscipy-yvjyl].
///
///   pdf(x; b, c) = b · x^(-b-1) / (1 − c^(-b))
///   cdf(x; b, c) = (1 − x^(-b)) / (1 − c^(-b))
///   ppf(q)       = (1 − q · (1 − c^(-b)))^(-1/b)
///
/// For `b > 1` the mean is `b·(1 − c^(1-b)) / ((b-1)·(1 − c^(-b)))`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct TruncPareto {
    pub b: f64,
    pub c: f64,
}

impl TruncPareto {
    #[must_use]
    pub fn new(b: f64, c: f64) -> Self {
        assert!(b != 0.0 && b.is_finite(), "b must be finite and nonzero");
        assert!(c > 1.0 && c.is_finite(), "c must be > 1 and finite");
        Self { b, c }
    }

    /// Common denominator 1 − c^(-b).
    fn denom(&self) -> f64 {
        1.0 - self.c.powf(-self.b)
    }
}

impl ContinuousDistribution for TruncPareto {
    fn pdf(&self, x: f64) -> f64 {
        if !(1.0..=self.c).contains(&x) {
            return 0.0;
        }
        self.b * x.powf(-self.b - 1.0) / self.denom()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x < 1.0 {
            return 0.0;
        }
        if x >= self.c {
            return 1.0;
        }
        (1.0 - x.powf(-self.b)) / self.denom()
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 1.0;
        }
        if q == 1.0 {
            return self.c;
        }
        (1.0 - q * self.denom()).powf(-1.0 / self.b)
    }

    fn mean(&self) -> f64 {
        // E[X] = b · (1 − c^(1-b)) / ((b - 1) · (1 − c^(-b))) for b ≠ 1.
        // For b = 1: E[X] = (c - 1) / ln(c).
        if self.b == 1.0 {
            (self.c - 1.0) / self.c.ln()
        } else {
            self.b * (1.0 - self.c.powf(1.0 - self.b)) / ((self.b - 1.0) * self.denom())
        }
    }

    fn var(&self) -> f64 {
        // Closed form for var via E[X²] - E[X]². E[X²] = b·(c^(2-b) - 1)
        // / ((2-b)·(1 - c^(-b))) for b ≠ 2; for b = 2: 2·ln(c)/(1 - c^(-2)).
        let denom = self.denom();
        let e2 = if self.b == 2.0 {
            2.0 * self.c.ln() / denom
        } else {
            self.b * (self.c.powf(2.0 - self.b) - 1.0) / ((2.0 - self.b) * denom)
        };
        let m = self.mean();
        e2 - m * m
    }
}

/// Truncated exponential distribution on [0, b].
///
/// Matches `scipy.stats.truncexpon`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct TruncExpon {
    pub b: f64,
}

impl TruncExpon {
    #[must_use]
    pub fn new(b: f64) -> Self {
        assert!(b > 0.0, "b must be positive");
        Self { b }
    }
}

impl ContinuousDistribution for TruncExpon {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 || x > self.b {
            0.0
        } else {
            (-x).exp() / (1.0 - (-self.b).exp())
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else if x >= self.b {
            1.0
        } else {
            (1.0 - (-x).exp()) / (1.0 - (-self.b).exp())
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return self.b;
        }
        // CDF = (1-exp(-x))/(1-exp(-b)), so x = -ln(1 - q*(1-exp(-b)))
        -(1.0 - q * (1.0 - (-self.b).exp())).ln()
    }

    fn mean(&self) -> f64 {
        let eb = (-self.b).exp();
        // E[X] = (1 - (1+b)*exp(-b)) / (1 - exp(-b))
        (1.0 - (1.0 + self.b) * eb) / (1.0 - eb)
    }

    fn var(&self) -> f64 {
        let m = self.mean();
        let eb = (-self.b).exp();
        let e2 = (2.0 - (2.0 + 2.0 * self.b + self.b * self.b) * eb) / (1.0 - eb);
        e2 - m * m
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("TruncExpon::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        // Boundary MLE: at fixed rate λ=1, the support is [0, b], so the
        // log-likelihood is monotonically decreasing in b on [max(x_i), ∞).
        // The MLE is therefore b_hat = max(x_i).
        let mut max_obs = f64::NEG_INFINITY;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "TruncExpon data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "TruncExpon data must be non-negative; got {x}"
                )));
            }
            if x > max_obs {
                max_obs = x;
            }
        }
        if max_obs <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "TruncExpon MLE: max observation {max_obs} must be > 0"
            )));
        }
        Ok(Self { b: max_obs })
    }
}

/// Generalized half-logistic distribution.
///
/// Matches `scipy.stats.genhalflogistic`.
pub struct GenHalfLogistic {
    pub c: f64,
}

impl GenHalfLogistic {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for GenHalfLogistic {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let limit = 1.0 / self.c;
        if x >= limit {
            return 0.0;
        }
        2.0 * (1.0 - self.c * x).powf(1.0 / self.c - 1.0)
            / (1.0 + (1.0 - self.c * x).powf(1.0 / self.c)).powi(2)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let limit = 1.0 / self.c;
        if x >= limit {
            return 1.0;
        }
        let t = (1.0 - self.c * x).powf(1.0 / self.c);
        1.0 - 2.0 * t / (1.0 + t)
    }

    fn mean(&self) -> f64 {
        let c = self.c;
        (fsci_special::digamma_scalar(1.0 / c + 1.0) + EULER_MASCHERONI) / c
    }

    fn var(&self) -> f64 {
        fsci_special::trigamma(1.0 / self.c + 1.0) / (self.c * self.c)
    }
}

/// Tukey-Lambda distribution.
///
/// Matches `scipy.stats.tukeylambda`.
pub struct TukeyLambda {
    pub lam: f64,
}

impl TukeyLambda {
    #[must_use]
    pub fn new(lam: f64) -> Self {
        Self { lam }
    }

    fn logistic_cdf(x: f64) -> f64 {
        if x >= 0.0 {
            1.0 / (1.0 + (-x).exp())
        } else {
            let ex = x.exp();
            ex / (1.0 + ex)
        }
    }

    fn quantile_derivative(&self, p: f64) -> f64 {
        let lam = self.lam;
        if lam.abs() < 1e-15 {
            1.0 / p + 1.0 / (1.0 - p)
        } else {
            p.powf(lam - 1.0) + (1.0 - p).powf(lam - 1.0)
        }
    }
}

impl ContinuousDistribution for TukeyLambda {
    fn pdf(&self, x: f64) -> f64 {
        if x.is_nan() {
            return f64::NAN;
        }

        if self.lam.abs() < 1e-15 {
            let cdf = Self::logistic_cdf(x);
            return cdf * (1.0 - cdf);
        }

        let cdf = self.cdf(x);
        if !cdf.is_finite() {
            return f64::NAN;
        }
        if cdf <= 0.0 || cdf >= 1.0 {
            return 0.0;
        }

        1.0 / self.quantile_derivative(cdf)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x.is_nan() {
            return f64::NAN;
        }

        if self.lam > 0.0 {
            let bound = 1.0 / self.lam;
            if x <= -bound {
                return 0.0;
            }
            if x >= bound {
                return 1.0;
            }
        }

        let mut lo = 0.0f64;
        let mut hi = 1.0f64;
        let eps = 1e-12;
        let mut p = Self::logistic_cdf(x).clamp(eps, 1.0 - eps);

        for _ in 0..10 {
            let q = self.ppf(p);
            if !q.is_finite() {
                break;
            }
            if q < x {
                lo = p;
            } else {
                hi = p;
            }
            if (q - x).abs() <= 1e-14 * (1.0 + x.abs()) {
                return p;
            }

            let derivative = self.quantile_derivative(p);
            if !derivative.is_finite() || derivative <= 0.0 {
                break;
            }

            let next = p - (q - x) / derivative;
            if !next.is_finite() || next <= lo || next >= hi {
                break;
            }
            p = next.clamp(eps, 1.0 - eps);
        }

        for _ in 0..60 {
            let mid = (lo + hi) / 2.0;
            let q = self.ppf(mid);
            if q < x {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        (lo + hi) / 2.0
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let lam = self.lam;
        if lam.abs() < 1e-15 {
            // Logistic: Q(p) = ln(p/(1-p))
            (q / (1.0 - q)).ln()
        } else {
            (q.powf(lam) - (1.0 - q).powf(lam)) / lam
        }
    }

    fn mean(&self) -> f64 {
        0.0 // Symmetric
    }

    fn var(&self) -> f64 {
        let lam = self.lam;
        if lam.abs() < 1e-15 {
            return PI * PI / 3.0;
        }
        if lam <= -0.5 {
            return f64::NAN;
        }

        let gamma_ratio = (2.0 * ln_gamma(lam + 1.0) - ln_gamma(2.0 * lam + 2.0)).exp();
        2.0 * (1.0 / (1.0 + 2.0 * lam) - gamma_ratio) / (lam * lam)
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        validate_finite_fit_data(data, 2, "TukeyLambda")?;
        let target_var = sample_population_variance(data);
        if !target_var.is_finite() || target_var <= 0.0 {
            return Err(FitError::NonConvergent(
                "TukeyLambda fit needs positive sample variance".to_owned(),
            ));
        }

        let mut lo = -0.49_f64;
        let mut hi = 20.0_f64;
        if (Self { lam: lo }).var() < target_var {
            return Err(FitError::NonConvergent(format!(
                "TukeyLambda sample variance {target_var} exceeds finite-variance search range"
            )));
        }
        while (Self { lam: hi }).var() > target_var && hi < 1.0e6 {
            hi *= 2.0;
        }
        if (Self { lam: hi }).var() > target_var {
            return Err(FitError::NonConvergent(format!(
                "TukeyLambda sample variance {target_var} is too small to bracket"
            )));
        }
        for _ in 0..100 {
            let mid = 0.5 * (lo + hi);
            if (Self { lam: mid }).var() > target_var {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self {
            lam: 0.5 * (lo + hi),
        })
    }
}

/// Inverse Weibull (Frechet) distribution.
///
/// Matches `scipy.stats.invweibull`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct InvWeibull {
    pub c: f64,
}

impl InvWeibull {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for InvWeibull {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        self.c * x.powf(-self.c - 1.0) * (-x.powf(-self.c)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            0.0
        } else {
            (-x.powf(-self.c)).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        // CDF = exp(-x^(-c)), so x^(-c) = -ln(q), x = (-ln(q))^(-1/c)
        (-q.ln()).powf(-1.0 / self.c)
    }

    fn mean(&self) -> f64 {
        if self.c > 1.0 {
            ln_gamma(1.0 - 1.0 / self.c).exp()
        } else {
            f64::INFINITY
        }
    }

    fn var(&self) -> f64 {
        if self.c <= 2.0 {
            return f64::NAN;
        }

        let g1 = ln_gamma(1.0 - 1.0 / self.c).exp();
        let g2 = ln_gamma(1.0 - 2.0 / self.c).exp();
        g2 - g1 * g1
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("InvWeibull::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "InvWeibull data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "InvWeibull support is [0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        if mean <= 1.0 || !mean.is_finite() {
            return Err(FitError::UnsupportedData(format!(
                "InvWeibull MoM (unit-scale) requires sample mean > 1; got {mean}"
            )));
        }
        // Mean(c) = Γ(1 - 1/c) for c > 1. Monotone-decreasing from ∞ at
        // c→1+ to 1 at c→∞. Bisect on c ∈ (1.001, 1e3).
        let mean_of = |c: f64| ln_gamma(1.0 - 1.0 / c).exp();
        let mut lo = 1.001_f64;
        let mut hi = 1.0e3_f64;
        let m_lo = mean_of(lo);
        let m_hi = mean_of(hi);
        if !(m_hi <= mean && mean <= m_lo) {
            return Err(FitError::NonConvergent(format!(
                "InvWeibull MoM bracket failed: mean({lo})={m_lo}, mean({hi})={m_hi}, target={mean}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let m_mid = mean_of(mid);
            if (m_mid - mean).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { c: mid });
            }
            if m_mid > mean {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self { c: 0.5 * (lo + hi) })
    }
}

/// Generalized normal distribution (exponential power).
///
/// Matches `scipy.stats.gennorm`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct GenNorm {
    pub beta: f64,
}

impl GenNorm {
    #[must_use]
    pub fn new(beta: f64) -> Self {
        assert!(beta > 0.0, "beta must be positive");
        Self { beta }
    }
}

impl ContinuousDistribution for GenNorm {
    fn pdf(&self, x: f64) -> f64 {
        let b = self.beta;
        b / (2.0 * ln_gamma(1.0 / b).exp()) * (-x.abs().powf(b)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        // Numerical integration via the trait default (bisection ppf inverse)
        // For efficiency, use the incomplete gamma
        let b = self.beta;
        let p = lower_regularized_gamma(1.0 / b, x.abs().powf(b));
        if x >= 0.0 {
            0.5 + 0.5 * p
        } else {
            0.5 - 0.5 * p
        }
    }

    fn mean(&self) -> f64 {
        0.0
    }

    fn var(&self) -> f64 {
        let b = self.beta;
        ln_gamma(3.0 / b).exp() / ln_gamma(1.0 / b).exp()
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("GenNorm::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "GenNorm data contains non-finite value: {x}"
                )));
            }
        }
        // Method-of-moments: standardized variance is
        //   Var(β) = Γ(3/β) / Γ(1/β)
        // monotone-decreasing in β. β=1 → Var=2 (Laplace);
        // β=2 → Var=1 (standard normal); β→∞ → Var → 1/3 (uniform).
        // Sample variance about 0 is the natural moment (the distribution
        // is centered at 0).
        let n = data.len() as f64;
        let m2_about_zero: f64 = data.iter().map(|x| x * x).sum::<f64>() / n;
        if !m2_about_zero.is_finite() || m2_about_zero <= 0.0 {
            return Err(FitError::NonConvergent(format!(
                "GenNorm MoM: sample E[x²] {m2_about_zero} non-positive"
            )));
        }
        let var_of = |beta: f64| -> f64 { ln_gamma(3.0 / beta).exp() / ln_gamma(1.0 / beta).exp() };
        // Bracket. β=0.1 gives huge variance; β=50 gives variance ~ 1/3.
        let mut lo = 0.1_f64;
        let mut hi = 50.0_f64;
        let v_lo = var_of(lo);
        let v_hi = var_of(hi);
        // var is monotone-decreasing in β, so v_lo ≥ target ≥ v_hi.
        if !(v_hi <= m2_about_zero && m2_about_zero <= v_lo) {
            return Err(FitError::NonConvergent(format!(
                "GenNorm MoM bracket failed: var({lo})={v_lo}, var({hi})={v_hi}, target={m2_about_zero}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let v_mid = var_of(mid);
            if (v_mid - m2_about_zero).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { beta: mid });
            }
            if v_mid > m2_about_zero {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self {
            beta: 0.5 * (lo + hi),
        })
    }
}

/// Half generalized normal distribution (upper half of `gennorm`).
///
/// Matches `scipy.stats.halfgennorm`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct HalfGenNorm {
    pub beta: f64,
}

impl HalfGenNorm {
    #[must_use]
    pub fn new(beta: f64) -> Self {
        assert!(beta > 0.0, "beta must be positive");
        Self { beta }
    }
}

impl ContinuousDistribution for HalfGenNorm {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 {
            return 0.0;
        }
        let b = self.beta;
        b / ln_gamma(1.0 / b).exp() * (-x.powf(b)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        let b = self.beta;
        lower_regularized_gamma(1.0 / b, x.powf(b))
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }

        let b = self.beta;
        let g = fsci_special::gammaincinv_scalar(1.0 / b, q);
        if g.is_finite() && g >= 0.0 {
            g.powf(1.0 / b)
        } else {
            ppf_bisection(|x| self.cdf(x), q, self.mean(), self.std())
        }
    }

    fn mean(&self) -> f64 {
        let b = self.beta;
        ln_gamma(2.0 / b).exp() / ln_gamma(1.0 / b).exp()
    }

    fn var(&self) -> f64 {
        let b = self.beta;
        let mean = self.mean();
        ln_gamma(3.0 / b).exp() / ln_gamma(1.0 / b).exp() - mean * mean
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("HalfGenNorm::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        let mut sum = 0.0_f64;
        let mut count = 0usize;
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "HalfGenNorm data contains non-finite value: {x}"
                )));
            }
            if x < 0.0 {
                return Err(FitError::UnsupportedData(format!(
                    "HalfGenNorm support is [0, ∞); got {x}"
                )));
            }
            sum += x;
            count += 1;
        }
        let mean = sum / count as f64;
        if mean <= 0.0 || !mean.is_finite() {
            return Err(FitError::NonConvergent(format!(
                "HalfGenNorm MoM: sample mean {mean} non-positive"
            )));
        }
        // Mean(β) = Γ(2/β) / Γ(1/β), monotone-decreasing in β.
        let mean_of = |beta: f64| ln_gamma(2.0 / beta).exp() / ln_gamma(1.0 / beta).exp();
        let mut lo = 0.1_f64;
        let mut hi = 50.0_f64;
        let m_lo = mean_of(lo);
        let m_hi = mean_of(hi);
        if !(m_hi <= mean && mean <= m_lo) {
            return Err(FitError::NonConvergent(format!(
                "HalfGenNorm MoM bracket failed: mean({lo})={m_lo}, mean({hi})={m_hi}, target={mean}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let m_mid = mean_of(mid);
            if (m_mid - mean).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { beta: mid });
            }
            if m_mid > mean {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self {
            beta: 0.5 * (lo + hi),
        })
    }
}

/// Log-gamma distribution.
///
/// Matches `scipy.stats.loggamma`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct LogGamma {
    pub c: f64,
}

impl LogGamma {
    #[must_use]
    pub fn new(c: f64) -> Self {
        assert!(c > 0.0, "c must be positive");
        Self { c }
    }
}

impl ContinuousDistribution for LogGamma {
    fn pdf(&self, x: f64) -> f64 {
        (self.c * x - x.exp() - ln_gamma(self.c)).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        lower_regularized_gamma(self.c, x.exp())
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return f64::NEG_INFINITY;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }

        let g = fsci_special::gammaincinv_scalar(self.c, q);
        if g.is_finite() && g > 0.0 {
            g.ln()
        } else {
            (q.ln() + ln_gamma(self.c + 1.0)) / self.c
        }
    }

    fn mean(&self) -> f64 {
        fsci_special::digamma_scalar(self.c)
    }

    fn var(&self) -> f64 {
        fsci_special::trigamma(self.c)
    }

    fn fit(data: &[f64]) -> Self {
        Self::try_fit(data).unwrap_or_else(|e| {
            panic!("LogGamma::fit failed: {e}");
        })
    }

    fn try_fit(data: &[f64]) -> Result<Self, FitError> {
        if data.len() < 2 {
            return Err(FitError::InsufficientData {
                required: 2,
                actual: data.len(),
            });
        }
        for &x in data {
            if !x.is_finite() {
                return Err(FitError::UnsupportedData(format!(
                    "LogGamma data contains non-finite value: {x}"
                )));
            }
        }
        // Method-of-moments: mean = ψ(c). Solve via bisection on c ∈ (1e-6, 1e6).
        // digamma is monotone-increasing so a single root exists.
        let mean: f64 = data.iter().sum::<f64>() / data.len() as f64;
        let mut lo = 1.0e-6_f64;
        let mut hi = 1.0e6_f64;
        let f_lo = fsci_special::digamma_scalar(lo);
        let f_hi = fsci_special::digamma_scalar(hi);
        if !(f_lo <= mean && mean <= f_hi) {
            return Err(FitError::NonConvergent(format!(
                "LogGamma MoM bracket failed: ψ({lo})={f_lo}, ψ({hi})={f_hi}, target={mean}"
            )));
        }
        for _ in 0..200 {
            let mid = 0.5 * (lo + hi);
            let f_mid = fsci_special::digamma_scalar(mid);
            if (f_mid - mean).abs() < 1.0e-12 || (hi - lo) < lo * 1.0e-12 + 1.0e-15 {
                return Ok(Self { c: mid });
            }
            if f_mid < mean {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        Ok(Self { c: 0.5 * (lo + hi) })
    }
}

/// Alpha distribution.
///
/// Matches `scipy.stats.alpha`.
pub struct Alpha {
    pub a: f64,
}

impl Alpha {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a > 0.0, "a must be positive");
        Self { a }
    }
}

impl ContinuousDistribution for Alpha {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }

        let normalizer = standard_normal_cdf(self.a);
        standard_normal_pdf(self.a - 1.0 / x) / (x * x * normalizer)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }

        standard_normal_cdf(self.a - 1.0 / x) / standard_normal_cdf(self.a)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }

        1.0 / (self.a - fsci_special::ndtri_scalar(q * standard_normal_cdf(self.a)))
    }

    fn mean(&self) -> f64 {
        f64::INFINITY
    }

    fn var(&self) -> f64 {
        f64::INFINITY
    }
}

/// Laplace-asymmetric distribution.
///
/// Matches `scipy.stats.laplace_asymmetric`.
pub struct LaplaceAsymmetric {
    pub kappa: f64,
}

impl LaplaceAsymmetric {
    #[must_use]
    pub fn new(kappa: f64) -> Self {
        assert!(kappa > 0.0, "kappa must be positive");
        Self { kappa }
    }
}

impl ContinuousDistribution for LaplaceAsymmetric {
    fn pdf(&self, x: f64) -> f64 {
        let k = self.kappa;
        let norm = 1.0 / (k + 1.0 / k);
        if x >= 0.0 {
            norm * (-x * k).exp()
        } else {
            norm * (x / k).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        let k = self.kappa;
        if x >= 0.0 {
            // CDF = 1 - exp(-xκ) / (1+κ²)
            1.0 - (-x * k).exp() / (1.0 + k * k)
        } else {
            // CDF = κ² / (1+κ²) * exp(x/κ)
            k * k / (1.0 + k * k) * (x / k).exp()
        }
    }

    fn mean(&self) -> f64 {
        1.0 / self.kappa - self.kappa
    }

    fn var(&self) -> f64 {
        1.0 / (self.kappa * self.kappa) + self.kappa * self.kappa
    }
}

/// Kappa 3-parameter distribution with shape `a > 0`.
///
/// Matches `scipy.stats.kappa3(a)`. Resolves [frankenscipy-okp6z].
/// Support: x ≥ 0. (The "3-parameter" name refers to scipy's
/// shape-only parameterisation; loc and scale come from the
/// outer scipy machinery, not the distribution itself.)
///
///   pdf(x; a) = a · (a + x^a)^(−(a + 1) / a)
///   cdf(x; a) = x · (a + x^a)^(−1 / a)
///   ppf(q; a) = q · (a / (1 − q^a))^(1 / a)
///
/// Mean has no closed form for general a — left as NaN.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Kappa3 {
    pub a: f64,
}

impl Kappa3 {
    #[must_use]
    pub fn new(a: f64) -> Self {
        assert!(a > 0.0 && a.is_finite(), "a must be positive and finite");
        Self { a }
    }
}

impl ContinuousDistribution for Kappa3 {
    fn pdf(&self, x: f64) -> f64 {
        if x < 0.0 || !x.is_finite() {
            return 0.0;
        }
        if x == 0.0 {
            return 0.0;
        }
        let a = self.a;
        let xa = x.powf(a);
        let base = a + xa;
        a * base.powf(-(a + 1.0) / a)
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if !x.is_finite() {
            return 1.0;
        }
        let a = self.a;
        let xa = x.powf(a);
        // Clamp to [0, 1]: when x^a ≫ a (large a + moderate x, or
        // small a + huge x), the closed form drifts a few ulp
        // above 1. Caught by [frankenscipy-4397j] fuzz at
        // (a=19, x≈66) → 1.0 + 2e-16.
        (x * (a + xa).powf(-1.0 / a)).clamp(0.0, 1.0)
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }
        if q == 0.0 {
            return 0.0;
        }
        if q == 1.0 {
            return f64::INFINITY;
        }
        let a = self.a;
        let qa = q.powf(a);
        let denom = 1.0 - qa;
        if denom <= 0.0 {
            // q^a ≥ 1 for q very near 1 with small a — ppf
            // diverges. Return +∞ rather than NaN.
            return f64::INFINITY;
        }
        q * (a / denom).powf(1.0 / a)
    }

    fn mean(&self) -> f64 {
        // E[X] exists only when a > 1 — scipy returns NaN below that
        // threshold (frankenscipy-4htpw).
        if self.a <= 1.0 {
            return f64::NAN;
        }
        kappa3_moment(self.a, 1)
    }

    fn var(&self) -> f64 {
        if self.a <= 2.0 {
            return f64::NAN;
        }
        let m1 = kappa3_moment(self.a, 1);
        let m2 = kappa3_moment(self.a, 2);
        let v = m2 - m1 * m1;
        if v.is_finite() && v >= 0.0 { v } else { f64::NAN }
    }
}

/// Kappa 4-parameter distribution.
///
/// Matches `scipy.stats.kappa4`.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Kappa4 {
    pub h: f64,
    pub k: f64,
}

impl Kappa4 {
    const SHAPE_TOL: f64 = 1e-15;

    #[must_use]
    pub fn new(h: f64, k: f64) -> Self {
        Self { h, k }
    }

    fn normalized_shapes(&self) -> (f64, f64) {
        let h = if self.h.abs() < Self::SHAPE_TOL {
            0.0
        } else {
            self.h
        };
        let k = if self.k.abs() < Self::SHAPE_TOL {
            0.0
        } else {
            self.k
        };
        (h, k)
    }

    fn support(&self) -> (f64, f64) {
        let (h, k) = self.normalized_shapes();
        if h > 0.0 && k > 0.0 {
            ((1.0 - h.powf(-k)) / k, 1.0 / k)
        } else if h > 0.0 && k == 0.0 {
            (h.ln(), f64::INFINITY)
        } else if h > 0.0 && k < 0.0 {
            ((1.0 - h.powf(-k)) / k, f64::INFINITY)
        } else if k > 0.0 {
            (f64::NEG_INFINITY, 1.0 / k)
        } else if k == 0.0 {
            (f64::NEG_INFINITY, f64::INFINITY)
        } else {
            (1.0 / k, f64::INFINITY)
        }
    }

    fn moment_exists(&self, order: f64) -> bool {
        let (h, k) = self.normalized_shapes();
        if k < 0.0 {
            order < -1.0 / k
        } else if h < 0.0 && k > 0.0 {
            order < -k / h
        } else {
            true
        }
    }

    fn raw_moment(&self, order: i32) -> f64 {
        if !self.moment_exists(order as f64) {
            return f64::NAN;
        }
        // Quantile-space integration keeps the numerical surface finite even
        // when the support is semi-infinite.
        simpson_integrate_adaptive(
            |q| {
                let x = self.ppf(q);
                x.powi(order)
            },
            1e-12,
            1.0 - 1e-12,
            4_096,
            1e-12,
            1e-12,
            10,
        )
    }
}

/// Argus distribution (used in high-energy physics).
///
/// Matches `scipy.stats.argus`.
pub struct Argus {
    pub chi: f64,
}

impl Argus {
    #[must_use]
    pub fn new(chi: f64) -> Self {
        assert!(chi > 0.0, "chi must be positive");
        Self { chi }
    }
}

impl ContinuousDistribution for Argus {
    fn pdf(&self, x: f64) -> f64 {
        if x <= 0.0 || x >= 1.0 {
            return 0.0;
        }
        let chi = self.chi;
        let chi2 = chi * chi;
        let t = 1.0 - x * x;
        // Normalization via Ψ(χ) = Φ(χ) - χφ(χ) - 1/2
        // where Φ = standard normal CDF, φ = standard normal PDF
        let phi_chi = standard_normal_cdf(chi);
        let pdf_chi = (-0.5 * chi2).exp() / (2.0 * PI).sqrt();
        let psi = phi_chi - chi * pdf_chi - 0.5;
        let norm = if psi > 0.0 {
            chi.powi(3) / ((2.0 * PI).sqrt() * psi)
        } else {
            1.0
        };
        norm * x * t.sqrt() * (-0.5 * chi2 * t).exp()
    }

    fn cdf(&self, x: f64) -> f64 {
        if x <= 0.0 {
            return 0.0;
        }
        if x >= 1.0 {
            return 1.0;
        }
        // Numerical CDF via Simpson's rule — scale grid for accuracy
        let n = 400;
        let h = x / n as f64;
        let mut sum = self.pdf(0.0) + self.pdf(x);
        for i in 1..n {
            let t = i as f64 * h;
            let w = if i % 2 == 0 { 2.0 } else { 4.0 };
            sum += w * self.pdf(t);
        }
        (sum * h / 3.0).clamp(0.0, 1.0)
    }

    fn mean(&self) -> f64 {
        let a = 0.5 * self.chi * self.chi;
        let gamma_half3 = ln_gamma(1.5).exp();
        let p = fsci_special::gammainc_scalar(1.5, a, RuntimeMode::Strict).unwrap_or(f64::NAN);
        let norm = 2.0 * a.powf(1.5) / (gamma_half3 * p);
        norm * simpson_integrate_adaptive(
            |t| (1.0 - t * t).sqrt() * t * t * (-(a * t * t)).exp(),
            0.0,
            1.0,
            1_024,
            1e-12,
            1e-12,
            8,
        )
    }

    fn var(&self) -> f64 {
        let a = 0.5 * self.chi * self.chi;
        let gamma_half3 = ln_gamma(1.5).exp();
        let gamma_half5 = ln_gamma(2.5).exp();
        let p3 = fsci_special::gammainc_scalar(1.5, a, RuntimeMode::Strict).unwrap_or(f64::NAN);
        let p5 = fsci_special::gammainc_scalar(2.5, a, RuntimeMode::Strict).unwrap_or(f64::NAN);
        let mean = self.mean();
        let gamma3 = p3 * gamma_half3;
        let gamma5 = p5 * gamma_half5;
        let second_moment = 1.0 - gamma5 / (a * gamma3);
        (second_moment - mean * mean).max(0.0)
    }
}

impl ContinuousDistribution for Kappa4 {
    fn pdf(&self, x: f64) -> f64 {
        if x.is_nan() {
            return f64::NAN;
        }

        let (h, k) = self.normalized_shapes();
        let (lower, upper) = self.support();
        if x < lower || x > upper {
            return 0.0;
        }

        if h != 0.0 && k != 0.0 {
            let base = 1.0 - k * x;
            if base < 0.0 {
                return 0.0;
            }
            let transformed = base.powf(1.0 / k);
            let inner = 1.0 - h * transformed;
            if inner < 0.0 {
                return 0.0;
            }
            base.powf(1.0 / k - 1.0) * inner.powf(1.0 / h - 1.0)
        } else if h == 0.0 && k != 0.0 {
            let base = 1.0 - k * x;
            if base < 0.0 {
                return 0.0;
            }
            let transformed = base.powf(1.0 / k);
            base.powf(1.0 / k - 1.0) * (-transformed).exp()
        } else if h != 0.0 {
            let exp_neg_x = (-x).exp();
            let inner = 1.0 - h * exp_neg_x;
            if inner < 0.0 {
                return 0.0;
            }
            exp_neg_x * inner.powf(1.0 / h - 1.0)
        } else {
            let exp_neg_x = (-x).exp();
            (-x - exp_neg_x).exp()
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        if x.is_nan() {
            return f64::NAN;
        }

        let (lower, upper) = self.support();
        if x <= lower {
            return 0.0;
        }
        if x >= upper {
            return 1.0;
        }

        let (h, k) = self.normalized_shapes();
        if h != 0.0 && k != 0.0 {
            let transformed = (1.0 - k * x).powf(1.0 / k);
            (1.0 - h * transformed).powf(1.0 / h)
        } else if h == 0.0 && k != 0.0 {
            (-(1.0 - k * x).powf(1.0 / k)).exp()
        } else if h != 0.0 {
            (1.0 - h * (-x).exp()).powf(1.0 / h)
        } else {
            (-(-x).exp()).exp()
        }
    }

    fn ppf(&self, q: f64) -> f64 {
        if !(0.0..=1.0).contains(&q) {
            return f64::NAN;
        }

        let (lower, upper) = self.support();
        if q == 0.0 {
            return lower;
        }
        if q == 1.0 {
            return upper;
        }

        let (h, k) = self.normalized_shapes();
        if h != 0.0 && k != 0.0 {
            let transformed = ((1.0 - q.powf(h)) / h).powf(k);
            (1.0 - transformed) / k
        } else if h == 0.0 && k != 0.0 {
            (1.0 - (-q.ln()).powf(k)) / k
        } else if h != 0.0 {
            -((1.0 - q.powf(h)) / h).ln()
        } else {
            -(-q.ln()).ln()
        }
    }

    fn mean(&self) -> f64 {
        let (h, k) = self.normalized_shapes();
        if h == 0.0 {
            return GenExtreme::new(k).mean();
        }
        if (h - 1.0).abs() < Self::SHAPE_TOL {
            return GenPareto::new(-k).mean();
        }

        self.raw_moment(1)
    }

    fn var(&self) -> f64 {
        let (h, k) = self.normalized_shapes();
        if h == 0.0 {
            return GenExtreme::new(k).var();
        }
        if (h - 1.0).abs() < Self::SHAPE_TOL {
            return GenPareto::new(-k).var();
        }

        let mean = self.mean();
        let second_moment = self.raw_moment(2);
        let variance = second_moment - mean * mean;
        if variance.is_nan() {
            f64::NAN
        } else {
            variance.max(0.0)
        }
    }
}

/// Crystal Ball distribution (used in high-energy physics).
///
/// Matches `scipy.stats.crystalball`.
pub struct CrystalBall {
    pub beta_param: f64,
    pub m: f64,
}

impl CrystalBall {
    #[must_use]
    pub fn new(beta_param: f64, m: f64) -> Self {
        assert!(beta_param > 0.0, "beta must be positive");
        assert!(m > 1.0, "m must be > 1");
        Self { beta_param, m }
    }
}

impl ContinuousDistribution for CrystalBall {
    fn pdf(&self, x: f64) -> f64 {
        let beta = self.beta_param;
        let m = self.m;

        let gauss_norm = (2.0 * PI).sqrt() * standard_normal_cdf(beta);
        let a = (m / beta).powf(m) * (-0.5 * beta * beta).exp();
        let b = m / beta - beta;
        let tail_norm = if m > 1.0 {
            a * (m / beta).powf(1.0 - m) / (m - 1.0)
        } else {
            100.0 * a // rough estimate for divergent tail
        };
        let total_norm = gauss_norm + tail_norm;

        let unnormalized_pdf = if x > -beta {
            (-0.5 * x * x).exp()
        } else {
            a * (b - x).powf(-m)
        };

        if total_norm > 0.0 {
            unnormalized_pdf / total_norm
        } else {
            0.0
        }
    }

    fn cdf(&self, x: f64) -> f64 {
        let beta = self.beta_param;
        let m = self.m;

        // Analytical normalization: split at x = -beta
        // Gaussian part: ∫_{-β}^{∞} exp(-x²/2) dx = √(2π) * Φ(β)... wait, ∫ from -β to ∞
        // = √(2π) * (1 - Φ(-β)) = √(2π) * Φ(β)
        let gauss_norm = (2.0 * PI).sqrt() * standard_normal_cdf(beta);

        // Power tail part: ∫_{-∞}^{-β} A*(B-x)^{-m} dx
        let a_coeff = (m / beta).powf(m) * (-0.5 * beta * beta).exp();
        let b_val = m / beta - beta;
        // ∫_{-∞}^{-β} A*(B-x)^{-m} dx = A * (B-(-β))^{1-m} / (m-1)
        // B - (-β) = m/β - β + β = m/β
        let tail_norm = if m > 1.0 {
            a_coeff * (m / beta).powf(1.0 - m) / (m - 1.0)
        } else {
            // For m <= 1 the integral diverges; use numerical fallback
            100.0 * a_coeff // rough estimate
        };

        let total_norm = gauss_norm + tail_norm;
        if total_norm <= 0.0 {
            return 0.5;
        }

        // CDF: integrate pdf from -∞ to x
        if x >= -beta {
            // All tail + Gaussian from -β to x
            let gauss_cdf_part =
                (2.0 * PI).sqrt() * (standard_normal_cdf(x) - standard_normal_cdf(-beta));
            (tail_norm + gauss_cdf_part) / total_norm
        } else {
            // Only part of the tail: ∫_{-∞}^{x} A*(B-t)^{-m} dt
            let bx = b_val - x;
            let partial = if m > 1.0 && bx > 0.0 {
                a_coeff * bx.powf(1.0 - m) / (m - 1.0)
            } else {
                0.0
            };
            // tail_norm - ∫_{x}^{-β} = tail_norm - (tail_norm - partial)
            (partial / total_norm).clamp(0.0, 1.0)
        }
    }

    fn mean(&self) -> f64 {
        let beta = self.beta_param;
        let m = self.m;
        if m <= 2.0 {
            return f64::INFINITY;
        }

        let gauss_norm = (2.0 * PI).sqrt() * standard_normal_cdf(beta);
        let a = (m / beta).powf(m) * (-0.5 * beta * beta).exp();
        let b = m / beta - beta;
        let y0 = m / beta;
        let tail_norm = a * y0.powf(1.0 - m) / (m - 1.0);
        let total_norm = gauss_norm + tail_norm;

        let gauss_first = (-0.5 * beta * beta).exp();
        let tail_first = a * (b * y0.powf(1.0 - m) / (m - 1.0) - y0.powf(2.0 - m) / (m - 2.0));

        (gauss_first + tail_first) / total_norm
    }

    fn var(&self) -> f64 {
        let beta = self.beta_param;
        let m = self.m;
        if m <= 3.0 {
            return f64::INFINITY;
        }

        let mean = self.mean();
        let gauss_norm = (2.0 * PI).sqrt() * standard_normal_cdf(beta);
        let a = (m / beta).powf(m) * (-0.5 * beta * beta).exp();
        let b = m / beta - beta;
        let y0 = m / beta;
        let tail_norm = a * y0.powf(1.0 - m) / (m - 1.0);
        let total_norm = gauss_norm + tail_norm;

        let gauss_second = gauss_norm - beta * (-0.5 * beta * beta).exp();
        let tail_second = a
            * (b * b * y0.powf(1.0 - m) / (m - 1.0) - 2.0 * b * y0.powf(2.0 - m) / (m - 2.0)
                + y0.powf(3.0 - m) / (m - 3.0));
        let second_moment = (gauss_second + tail_second) / total_norm;

        (second_moment - mean * mean).max(0.0)
    }
}

// ══════════════════════════════════════════════════════════════════════
// Ranking and Order Statistics
// ══════════════════════════════════════════════════════════════════════

/// Compute quantiles of data at given probabilities.
///
/// Matches `numpy.quantile`.
pub fn quantile(data: &[f64], q: &[f64]) -> Vec<f64> {
    if data.is_empty() || data.iter().any(|v| v.is_nan()) {
        return vec![f64::NAN; q.len()];
    }
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();

    q.iter()
        .map(|&qi| {
            let qi = qi.clamp(0.0, 1.0);
            let idx = qi * (n - 1) as f64;
            let lo = idx.floor() as usize;
            let hi = idx.ceil() as usize;
            let frac = idx - lo as f64;
            if lo == hi || hi >= n {
                sorted[lo.min(n - 1)]
            } else {
                sorted[lo] * (1.0 - frac) + sorted[hi] * frac
            }
        })
        .collect()
}

/// Compute weighted mean.
pub fn weighted_mean(values: &[f64], weights: &[f64]) -> f64 {
    if values.len() != weights.len() {
        return f64::NAN;
    }
    let total_w: f64 = weights.iter().sum();
    if total_w == 0.0 {
        return f64::NAN;
    }
    values
        .iter()
        .zip(weights.iter())
        .map(|(&v, &w)| v * w)
        .sum::<f64>()
        / total_w
}

/// Compute weighted variance.
pub fn weighted_var(values: &[f64], weights: &[f64]) -> f64 {
    if values.len() != weights.len() {
        return f64::NAN;
    }
    let mean = weighted_mean(values, weights);
    let total_w: f64 = weights.iter().sum();
    if total_w == 0.0 {
        return f64::NAN;
    }
    values
        .iter()
        .zip(weights.iter())
        .map(|(&v, &w)| w * (v - mean).powi(2))
        .sum::<f64>()
        / total_w
}

/// Compute the geometric mean.
///
/// Matches `scipy.stats.gmean`.
pub fn gmean(data: &[f64]) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    let n = data.len() as f64;
    let log_sum: f64 = data.iter().map(|&x| x.ln()).sum();
    (log_sum / n).exp()
}

/// Compute the geometric standard deviation.
///
/// The geometric standard deviation is defined as exp(std(log(data))).
/// All values must be positive.
///
/// Matches `scipy.stats.gstd(a)`.
pub fn gstd(data: &[f64]) -> f64 {
    if data.is_empty() || data.len() < 2 {
        return f64::NAN;
    }
    if data.iter().any(|&x| x <= 0.0 || !x.is_finite()) {
        return f64::NAN;
    }
    let n = data.len() as f64;
    let logs: Vec<f64> = data.iter().map(|&x| x.ln()).collect();
    let mean_log = logs.iter().sum::<f64>() / n;
    let var_log = logs.iter().map(|&lx| (lx - mean_log).powi(2)).sum::<f64>() / (n - 1.0);
    var_log.sqrt().exp()
}

/// Compute the harmonic mean.
///
/// Matches `scipy.stats.hmean`.
pub fn hmean(data: &[f64]) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    if data.iter().any(|&x| x.is_nan() || x < 0.0) {
        return f64::NAN;
    }
    if data.contains(&0.0) {
        return 0.0;
    }
    let n = data.len() as f64;
    let inv_sum: f64 = data.iter().map(|&x| 1.0 / x).sum();
    if inv_sum == 0.0 {
        return f64::INFINITY;
    }
    n / inv_sum
}

/// Compute the power mean (generalized mean).
///
/// Matches `scipy.stats.pmean`.
pub fn pmean(data: &[f64], p: f64) -> f64 {
    if data.is_empty() || !p.is_finite() {
        return f64::NAN;
    }
    if data.iter().any(|&x| !x.is_finite()) {
        return f64::NAN;
    }
    if data.iter().any(|&x| x < 0.0) {
        return f64::NAN;
    }
    if p == 0.0 {
        return gmean(data);
    }
    if p < 0.0 && data.contains(&0.0) {
        return 0.0;
    }
    let n = data.len() as f64;
    let power_sum: f64 = data.iter().map(|&x| x.powf(p)).sum();
    (power_sum / n).powf(1.0 / p)
}

/// Circular mean for angular data.
///
/// Matches `scipy.stats.circmean`.
pub fn circmean(data: &[f64]) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    let sin_sum: f64 = data.iter().map(|&x| x.sin()).sum();
    let cos_sum: f64 = data.iter().map(|&x| x.cos()).sum();
    sin_sum.atan2(cos_sum)
}

/// Circular variance for angular data.
///
/// Matches `scipy.stats.circvar`.
pub fn circvar(data: &[f64]) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    let n = data.len() as f64;
    let sin_sum: f64 = data.iter().map(|&x| x.sin()).sum();
    let cos_sum: f64 = data.iter().map(|&x| x.cos()).sum();
    let r = (sin_sum * sin_sum + cos_sum * cos_sum).sqrt() / n;
    1.0 - r
}

/// Circular standard deviation for angular data.
///
/// Matches `scipy.stats.circstd`.
pub fn circstd(data: &[f64]) -> f64 {
    let v = circvar(data);
    if v <= 0.0 {
        return 0.0;
    }
    (-2.0 * (1.0 - v).ln()).sqrt()
}

/// Result for directional statistics.
#[derive(Debug, Clone, PartialEq)]
pub struct DirectionalStatsResult {
    /// Mean direction as unit vector.
    pub mean_direction: Vec<f64>,
    /// Mean resultant length (0 to 1, higher = less dispersed).
    pub mean_resultant_length: f64,
}

/// Compute directional statistics for 2D vector data.
///
/// Computes mean direction and mean resultant length for a set of
/// 2D vectors (e.g., unit vectors on a circle).
///
/// Similar to `scipy.stats.directional_stats` for 2D case.
///
/// # Arguments
/// * `data` - Slice of 2D vectors as [x, y] pairs
/// * `normalize` - If true, normalize input vectors to unit length
///
/// # Returns
/// `DirectionalStatsResult` with mean_direction and mean_resultant_length.
pub fn directional_stats(data: &[[f64; 2]], normalize: bool) -> DirectionalStatsResult {
    let n = data.len();
    if n == 0 {
        return DirectionalStatsResult {
            mean_direction: vec![f64::NAN, f64::NAN],
            mean_resultant_length: f64::NAN,
        };
    }

    let nf = n as f64;
    let mut sum_x = 0.0;
    let mut sum_y = 0.0;

    for &[x, y] in data {
        if normalize {
            let norm = (x * x + y * y).sqrt();
            if norm > 0.0 {
                sum_x += x / norm;
                sum_y += y / norm;
            }
        } else {
            sum_x += x;
            sum_y += y;
        }
    }

    let mean_x = sum_x / nf;
    let mean_y = sum_y / nf;
    let mean_resultant_length = (mean_x * mean_x + mean_y * mean_y).sqrt();

    let mean_direction = if mean_resultant_length > 0.0 {
        vec![
            mean_x / mean_resultant_length,
            mean_y / mean_resultant_length,
        ]
    } else {
        vec![f64::NAN, f64::NAN]
    };

    DirectionalStatsResult {
        mean_direction,
        mean_resultant_length,
    }
}

// ══════════════════════════════════════════════════════════════════════
// Statistical Tests
// ══════════════════════════════════════════════════════════════════════

/// Result of a statistical test.
#[derive(Debug, Clone, PartialEq)]
pub struct TtestResult {
    /// Test statistic.
    pub statistic: f64,
    /// Two-sided p-value.
    pub pvalue: f64,
    /// Degrees of freedom.
    pub df: f64,
}

/// Result of a variance homogeneity test.
#[derive(Debug, Clone, PartialEq)]
pub struct VarianceTestResult {
    /// Test statistic.
    pub statistic: f64,
    /// Right-tail p-value.
    pub pvalue: f64,
}

fn invalid_variance_test_result() -> VarianceTestResult {
    VarianceTestResult {
        statistic: f64::NAN,
        pvalue: f64::NAN,
    }
}

fn sample_mean(data: &[f64]) -> f64 {
    data.iter().sum::<f64>() / data.len() as f64
}

fn sample_variance(data: &[f64]) -> f64 {
    if data.len() < 2 {
        return f64::NAN;
    }
    let mean = sample_mean(data);
    data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / (data.len() as f64 - 1.0)
}

fn sample_median(data: &[f64]) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let mid = sorted.len() / 2;
    if sorted.len().is_multiple_of(2) {
        0.5 * (sorted[mid - 1] + sorted[mid])
    } else {
        sorted[mid]
    }
}

/// One-sample t-test: test whether the mean of a sample differs from `popmean`.
///
/// Matches `scipy.stats.ttest_1samp(a, popmean)`.
/// Returns NaN statistic and p-value for samples with fewer than 2 elements.
pub fn ttest_1samp(data: &[f64], popmean: f64) -> TtestResult {
    let n = data.len() as f64;
    if data.len() < 2 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: n - 1.0,
        };
    }
    let mean: f64 = data.iter().sum::<f64>() / n;
    let var: f64 = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / (n - 1.0);
    let se = (var / n).sqrt();
    if se == 0.0 {
        // All values identical: t is infinite or NaN depending on whether mean == popmean
        let statistic = if (mean - popmean).abs() == 0.0 {
            f64::NAN
        } else {
            (mean - popmean).signum() * f64::INFINITY
        };
        return TtestResult {
            statistic,
            pvalue: if statistic.is_nan() { f64::NAN } else { 0.0 },
            df: n - 1.0,
        };
    }
    let t = (mean - popmean) / se;
    let df = n - 1.0;
    let tdist = StudentT::new(df);
    let pvalue = 2.0 * tdist.sf(t.abs());
    TtestResult {
        statistic: t,
        pvalue,
        df,
    }
}

/// One-sample t-test with alternative hypothesis specification.
///
/// Matches `scipy.stats.ttest_1samp(a, popmean, alternative=...)`.
///
/// # Arguments
/// * `data` - Sample data
/// * `popmean` - Expected population mean under H0
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn ttest_1samp_alternative(data: &[f64], popmean: f64, alternative: &str) -> TtestResult {
    let n = data.len() as f64;
    if data.len() < 2 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: n - 1.0,
        };
    }
    let mean: f64 = data.iter().sum::<f64>() / n;
    let var: f64 = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / (n - 1.0);
    let se = (var / n).sqrt();
    if se == 0.0 {
        let statistic = if (mean - popmean).abs() == 0.0 {
            f64::NAN
        } else {
            (mean - popmean).signum() * f64::INFINITY
        };
        return TtestResult {
            statistic,
            pvalue: if statistic.is_nan() { f64::NAN } else { 0.0 },
            df: n - 1.0,
        };
    }
    let t = (mean - popmean) / se;
    let df = n - 1.0;
    let tdist = StudentT::new(df);

    let pvalue = match alternative {
        "less" => tdist.cdf(t),
        "greater" => tdist.sf(t),
        _ => 2.0 * tdist.sf(t.abs()),
    };

    TtestResult {
        statistic: t,
        pvalue,
        df,
    }
}

/// Independent two-sample t-test (equal variance assumed).
///
/// Matches `scipy.stats.ttest_ind(a, b, equal_var=True)`.
/// Each sample must have at least 2 elements; returns NaN otherwise.
pub fn ttest_ind(a: &[f64], b: &[f64]) -> TtestResult {
    let n1 = a.len() as f64;
    let n2 = b.len() as f64;
    let df = n1 + n2 - 2.0;
    if a.len() < 2 || b.len() < 2 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df,
        };
    }
    let mean1: f64 = a.iter().sum::<f64>() / n1;
    let mean2: f64 = b.iter().sum::<f64>() / n2;
    let var1: f64 = a.iter().map(|&x| (x - mean1).powi(2)).sum::<f64>() / (n1 - 1.0);
    let var2: f64 = b.iter().map(|&x| (x - mean2).powi(2)).sum::<f64>() / (n2 - 1.0);

    // Pooled variance
    let sp2 = ((n1 - 1.0) * var1 + (n2 - 1.0) * var2) / df;
    let se = (sp2 * (1.0 / n1 + 1.0 / n2)).sqrt();

    if se == 0.0 {
        let statistic = if (mean1 - mean2).abs() == 0.0 {
            f64::NAN
        } else {
            (mean1 - mean2).signum() * f64::INFINITY
        };
        return TtestResult {
            statistic,
            pvalue: if statistic.is_nan() { f64::NAN } else { 0.0 },
            df,
        };
    }

    let t = (mean1 - mean2) / se;

    let tdist = StudentT::new(df);
    let pvalue = 2.0 * tdist.sf(t.abs());
    TtestResult {
        statistic: t,
        pvalue,
        df,
    }
}

/// Independent two-sample t-test with alternative hypothesis specification.
///
/// Matches `scipy.stats.ttest_ind(a, b, equal_var=True, alternative=...)`.
///
/// # Arguments
/// * `a`, `b` - Sample data
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn ttest_ind_alternative(a: &[f64], b: &[f64], alternative: &str) -> TtestResult {
    let n1 = a.len() as f64;
    let n2 = b.len() as f64;
    let df = n1 + n2 - 2.0;
    if a.len() < 2 || b.len() < 2 || a.iter().any(|v| v.is_nan()) || b.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df,
        };
    }
    let mean1: f64 = a.iter().sum::<f64>() / n1;
    let mean2: f64 = b.iter().sum::<f64>() / n2;
    let var1: f64 = a.iter().map(|&x| (x - mean1).powi(2)).sum::<f64>() / (n1 - 1.0);
    let var2: f64 = b.iter().map(|&x| (x - mean2).powi(2)).sum::<f64>() / (n2 - 1.0);

    let sp2 = ((n1 - 1.0) * var1 + (n2 - 1.0) * var2) / df;
    let se = (sp2 * (1.0 / n1 + 1.0 / n2)).sqrt();

    if se == 0.0 {
        let statistic = if (mean1 - mean2).abs() == 0.0 {
            f64::NAN
        } else {
            (mean1 - mean2).signum() * f64::INFINITY
        };
        return TtestResult {
            statistic,
            pvalue: if statistic.is_nan() { f64::NAN } else { 0.0 },
            df,
        };
    }

    let t = (mean1 - mean2) / se;
    let tdist = StudentT::new(df);

    let pvalue = match alternative {
        "less" => tdist.cdf(t),
        "greater" => tdist.sf(t),
        _ => 2.0 * tdist.sf(t.abs()),
    };

    TtestResult {
        statistic: t,
        pvalue,
        df,
    }
}

/// Welch's t-test (unequal variance).
///
/// Matches `scipy.stats.ttest_ind(a, b, equal_var=False)`.
/// Each sample must have at least 2 elements; returns NaN otherwise.
pub fn ttest_ind_welch(a: &[f64], b: &[f64]) -> TtestResult {
    if a.len() < 2 || b.len() < 2 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }
    let n1 = a.len() as f64;
    let n2 = b.len() as f64;
    let mean1: f64 = a.iter().sum::<f64>() / n1;
    let mean2: f64 = b.iter().sum::<f64>() / n2;
    let var1: f64 = a.iter().map(|&x| (x - mean1).powi(2)).sum::<f64>() / (n1 - 1.0);
    let var2: f64 = b.iter().map(|&x| (x - mean2).powi(2)).sum::<f64>() / (n2 - 1.0);

    let se = (var1 / n1 + var2 / n2).sqrt();

    // Welch-Satterthwaite degrees of freedom
    let vn1 = var1 / n1;
    let vn2 = var2 / n2;
    let mut df = (vn1 + vn2).powi(2) / (vn1.powi(2) / (n1 - 1.0) + vn2.powi(2) / (n2 - 1.0));
    if df.is_nan() {
        df = 1.0;
    }

    if se == 0.0 {
        let statistic = if (mean1 - mean2).abs() == 0.0 {
            f64::NAN
        } else {
            (mean1 - mean2).signum() * f64::INFINITY
        };
        return TtestResult {
            statistic,
            pvalue: if statistic.is_nan() { f64::NAN } else { 0.0 },
            df,
        };
    }

    let t = (mean1 - mean2) / se;

    let tdist = StudentT::new(df);
    let pvalue = 2.0 * tdist.sf(t.abs());
    TtestResult {
        statistic: t,
        pvalue,
        df,
    }
}

/// Paired t-test for related samples.
///
/// Tests H0: mean of differences a[i] - b[i] is zero.
/// Requires equal-length paired observations.
///
/// Matches `scipy.stats.ttest_rel(a, b, alternative=...)`.
pub fn ttest_rel(
    a: &[f64],
    b: &[f64],
    alternative: Option<&str>,
) -> Result<TtestResult, StatsError> {
    let alternative = validate_hypothesis_alternative(alternative)?;
    if a.len() != b.len() || a.len() < 2 {
        return Ok(TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        });
    }
    let n = a.len() as f64;
    let diffs: Vec<f64> = a.iter().zip(b.iter()).map(|(&ai, &bi)| ai - bi).collect();
    let d_mean = diffs.iter().sum::<f64>() / n;
    let d_var = diffs.iter().map(|&d| (d - d_mean).powi(2)).sum::<f64>() / (n - 1.0);
    let se = (d_var / n).sqrt();
    let df = n - 1.0;
    let tdist = StudentT::new(df);

    if se == 0.0 {
        let statistic = if d_mean == 0.0 {
            f64::NAN
        } else {
            d_mean.signum() * f64::INFINITY
        };
        return Ok(TtestResult {
            statistic,
            pvalue: student_t_alternative_pvalue(statistic, &tdist, alternative),
            df,
        });
    }

    let t = d_mean / se;
    Ok(TtestResult {
        statistic: t,
        pvalue: student_t_alternative_pvalue(t, &tdist, alternative),
        df,
    })
}

/// One-sample chi-squared goodness-of-fit test.
///
/// Tests whether observed frequencies differ significantly from expected.
/// This is a convenience wrapper around `power_divergence` with lambda=1.
///
/// Matches `scipy.stats.chisquare(f_obs, f_exp)`.
pub fn chisquare(f_obs: &[f64], f_exp: Option<&[f64]>) -> (f64, f64) {
    power_divergence(f_obs, f_exp, 1.0)
}

/// 1D Wasserstein distance (earth mover's distance) between two distributions.
///
/// Computes the first Wasserstein distance between empirical distributions
/// defined by samples u and v.
///
/// Matches `scipy.stats.wasserstein_distance(u_values, v_values)`.
pub fn wasserstein_distance(u: &[f64], v: &[f64]) -> f64 {
    if u.is_empty()
        || v.is_empty()
        || u.iter().any(|&val| val.is_nan())
        || v.iter().any(|&val| val.is_nan())
    {
        return f64::NAN;
    }

    // Resolves [frankenscipy-k8sed]: linear merge sweep over the two
    // sorted samples, advancing pointers to track CDF counts. The
    // previous version sorted+deduped a third Vec and called
    // partition_point (O(log N)) per step, totaling O((N+M)·log(N+M)).
    // The two-pointer variant runs in O(N + M).
    let mut u_sorted = u.to_vec();
    let mut v_sorted = v.to_vec();
    u_sorted.sort_by(|a, b| a.total_cmp(b));
    v_sorted.sort_by(|a, b| a.total_cmp(b));

    let nu = u.len() as f64;
    let nv = v.len() as f64;

    // CDF counts: number of u/v values seen so far, ≤ current threshold.
    let mut iu = 0_usize;
    let mut iv = 0_usize;
    let mut prev_val = u_sorted[0].min(v_sorted[0]);
    let mut distance = 0.0_f64;

    while iu < u_sorted.len() || iv < v_sorted.len() {
        // Pick the next breakpoint = min of the two remaining heads.
        let next_val = match (u_sorted.get(iu), v_sorted.get(iv)) {
            (Some(&u_val), Some(&v_val)) => u_val.min(v_val),
            (Some(&u_val), None) => u_val,
            (None, Some(&v_val)) => v_val,
            (None, None) => break,
        };

        // Accumulate area at the previous breakpoint (CDF is a step
        // function — the area between (prev_val, next_val] uses the
        // CDF values established by counts iu, iv up to prev_val).
        let cdf_u = iu as f64 / nu;
        let cdf_v = iv as f64 / nv;
        distance += (cdf_u - cdf_v).abs() * (next_val - prev_val);

        // Advance whichever pointers have head equal to next_val. This
        // is equivalent to partition_point but in O(1) per step.
        while iu < u_sorted.len() && u_sorted[iu] <= next_val {
            iu += 1;
        }
        while iv < v_sorted.len() && v_sorted[iv] <= next_val {
            iv += 1;
        }
        prev_val = next_val;
    }

    distance
}

/// Energy distance between two 1D distributions.
///
/// A statistical distance based on the Cramér distance:
///   D(u, v) = 2 * E|X-Y| - E|X-X'| - E|Y-Y'|
/// where X, X' ~ u and Y, Y' ~ v.
///
/// Matches `scipy.stats.energy_distance(u_values, v_values)`.
pub fn energy_distance(u: &[f64], v: &[f64]) -> f64 {
    if u.is_empty()
        || v.is_empty()
        || u.iter().any(|&val| val.is_nan())
        || v.iter().any(|&val| val.is_nan())
    {
        return f64::NAN;
    }

    let nu = u.len() as f64;
    let nv = v.len() as f64;

    // E|X-Y|: mean of |u_i - v_j| over all pairs.
    // Resolves [frankenscipy-ggmrw]: closed-form sweep on sorted u and v,
    // O((N+M) log(N+M)) total instead of the previous O(N·M) double loop.
    // For each sorted u_i with c = #{v_j ≤ u_i} and S = Σ_{v_j ≤ u_i} v_j,
    //   Σ_j |u_i − v_j| = (2c − M)·u_i + S_total − 2·S.
    let e_xy = cross_set_l1_pair_sum(u, v) / (nu * nv);

    // E|X-X'|: mean of |u_i - u_j| over all pairs.
    // Resolves [frankenscipy-6nuo5]: for sorted s of length n, the
    // upper-triangle sum  Σ_{i<j} (s[j] - s[i])  has the closed form
    //   Σ_i s[i] · (2i − n + 1)         (0-indexed)
    // dropping the inner pair from O(N²) to O(N) after one O(N log N)
    // sort.
    let e_xx = within_set_l1_pair_sum(u) * 2.0 / (nu * nu);
    let e_yy = within_set_l1_pair_sum(v) * 2.0 / (nv * nv);

    let d_sq = 2.0 * e_xy - e_xx - e_yy;
    if d_sq.is_nan() {
        f64::NAN
    } else {
        d_sq.max(0.0).sqrt()
    }
}

/// Compute the cross-set L1 pair sum  Σ_i Σ_j |u_i − v_j|  in
/// O((N+M) log(N+M)) via a two-pointer sweep on the sorted inputs.
/// Equivalent to the naïve O(N·M) double loop. Used by
/// energy_distance to avoid the quadratic cross-set term.
fn cross_set_l1_pair_sum(u: &[f64], v: &[f64]) -> f64 {
    let mut su: Vec<f64> = u.to_vec();
    su.sort_by(|a, b| a.total_cmp(b));
    let mut sv: Vec<f64> = v.to_vec();
    sv.sort_by(|a, b| a.total_cmp(b));

    let m = sv.len();
    let m_f = m as f64;
    let s_total_v: f64 = sv.iter().sum();

    let mut total = 0.0_f64;
    let mut j = 0_usize;
    let mut s_le_v = 0.0_f64;
    for &ui in &su {
        while j < m && sv[j] <= ui {
            s_le_v += sv[j];
            j += 1;
        }
        let c_le = j as f64;
        total += (2.0 * c_le - m_f) * ui + s_total_v - 2.0 * s_le_v;
    }
    total
}

/// Compute the upper-triangle pair sum  Σ_{i<j} |x_j − x_i|  in
/// O(N log N) using the sorted closed form. Equivalent to the naïve
/// O(N²) double loop; used by energy_distance and any other test that
/// needs the within-set L1 pair sum.
fn within_set_l1_pair_sum(x: &[f64]) -> f64 {
    let n = x.len();
    if n < 2 {
        return 0.0;
    }
    let mut sorted: Vec<f64> = x.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let mut sum = 0.0_f64;
    let n_f = n as f64;
    for (i, &val) in sorted.iter().enumerate() {
        sum += val * (2.0 * i as f64 - n_f + 1.0);
    }
    sum
}

// ══════════════════════════════════════════════════════════════════════
// Non-parametric Tests and ANOVA
// ══════════════════════════════════════════════════════════════════════

/// One-way ANOVA (Analysis of Variance).
///
/// Matches `scipy.stats.f_oneway(*groups)`.
///
/// Tests H0: all group means are equal.
/// Assumes normality and equal variances within groups.
pub fn f_oneway(groups: &[&[f64]]) -> TtestResult {
    if groups.len() < 2
        || groups.iter().any(|g| g.is_empty())
        || groups.iter().any(|g| g.iter().any(|v| v.is_nan()))
    {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let k = groups.len() as f64; // number of groups
    let n_total: usize = groups.iter().map(|g| g.len()).sum();
    let nf = n_total as f64;

    if n_total <= groups.len() {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    // Grand mean
    let grand_sum: f64 = groups.iter().flat_map(|g| g.iter()).sum();
    let grand_mean = grand_sum / nf;

    // Between-group sum of squares
    let ss_between: f64 = groups
        .iter()
        .map(|g| {
            let gi_mean: f64 = g.iter().sum::<f64>() / g.len() as f64;
            g.len() as f64 * (gi_mean - grand_mean).powi(2)
        })
        .sum();

    // Within-group sum of squares
    let ss_within: f64 = groups
        .iter()
        .map(|g| {
            let gi_mean: f64 = g.iter().sum::<f64>() / g.len() as f64;
            g.iter().map(|&x| (x - gi_mean).powi(2)).sum::<f64>()
        })
        .sum();

    let df_between = k - 1.0;
    let df_within = nf - k;

    if df_within <= 0.0 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: df_between,
        };
    }

    if ss_within == 0.0 {
        if ss_between == 0.0 {
            return TtestResult {
                statistic: f64::NAN,
                pvalue: f64::NAN,
                df: df_between,
            };
        } else {
            return TtestResult {
                statistic: f64::INFINITY,
                pvalue: 0.0,
                df: df_between,
            };
        }
    }

    let ms_between = ss_between / df_between;
    let ms_within = ss_within / df_within;
    let f_stat = ms_between / ms_within;

    let fdist = FDistribution::new(df_between, df_within);
    let cdf_val = fdist.cdf(f_stat);
    let pvalue = if !cdf_val.is_finite() || !(0.0..=1.0).contains(&cdf_val) {
        if f_stat > 0.0 { 0.0 } else { 1.0 }
    } else {
        (1.0 - cdf_val).max(0.0)
    };

    TtestResult {
        statistic: f_stat,
        pvalue,
        df: df_between,
    }
}

/// One-way ANOVA with nan_policy parameter.
///
/// Matches `scipy.stats.f_oneway(*groups, nan_policy=...)`.
///
/// * `nan_policy` - "propagate" (default), "omit", or "raise"
pub fn f_oneway_with_nan_policy(
    groups: &[&[f64]],
    nan_policy: Option<&str>,
) -> Result<TtestResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;

    let has_nan = groups.iter().any(|g| g.iter().any(|v| v.is_nan()));

    if has_nan {
        match nan_policy {
            "raise" => {
                return Err(StatsError::InvalidArgument(
                    "input contains NaN values".to_string(),
                ));
            }
            "propagate" => {
                return Ok(TtestResult {
                    statistic: f64::NAN,
                    pvalue: f64::NAN,
                    df: f64::NAN,
                });
            }
            "omit" => {
                let cleaned: Vec<Vec<f64>> = groups
                    .iter()
                    .map(|g| g.iter().copied().filter(|v| !v.is_nan()).collect())
                    .collect();
                let cleaned_refs: Vec<&[f64]> = cleaned.iter().map(|v| v.as_slice()).collect();
                return Ok(f_oneway(&cleaned_refs));
            }
            _ => {}
        }
    }

    Ok(f_oneway(groups))
}

/// Result for Tukey's HSD test.
#[derive(Debug, Clone, PartialEq)]
pub struct TukeyHSDResult {
    /// Pairwise mean differences (i,j) = mean_i - mean_j.
    pub statistic: Vec<Vec<f64>>,
    /// Pairwise p-values using Bonferroni correction.
    pub pvalue: Vec<Vec<f64>>,
}

/// Tukey's HSD test for pairwise comparison of group means.
///
/// Post-hoc test after ANOVA to identify which groups differ.
/// Uses Bonferroni-corrected t-tests as approximation.
///
/// Similar to `scipy.stats.tukey_hsd(*groups)`.
///
/// # Arguments
/// * `groups` - Slice of sample arrays for each group
///
/// # Returns
/// `TukeyHSDResult` with matrices of statistics and p-values.
pub fn tukey_hsd(groups: &[&[f64]]) -> TukeyHSDResult {
    let k = groups.len();
    if k < 2 {
        return TukeyHSDResult {
            statistic: vec![],
            pvalue: vec![],
        };
    }

    // Compute group means
    let means: Vec<f64> = groups
        .iter()
        .map(|g| {
            if g.is_empty() {
                f64::NAN
            } else {
                g.iter().sum::<f64>() / g.len() as f64
            }
        })
        .collect();

    // Compute pooled variance (MSE from ANOVA)
    let n_total: usize = groups.iter().map(|g| g.len()).sum();
    let df_within = n_total as f64 - k as f64;

    if df_within <= 0.0 {
        return TukeyHSDResult {
            statistic: vec![vec![f64::NAN; k]; k],
            pvalue: vec![vec![f64::NAN; k]; k],
        };
    }

    let ss_within: f64 = groups
        .iter()
        .zip(means.iter())
        .map(|(g, &m)| g.iter().map(|&x| (x - m).powi(2)).sum::<f64>())
        .sum();
    let mse = ss_within / df_within;

    // Number of pairwise comparisons for Bonferroni
    let num_comparisons = k * (k - 1) / 2;

    // Compute pairwise statistics and p-values
    let mut stat_matrix = vec![vec![0.0; k]; k];
    let mut pval_matrix = vec![vec![1.0; k]; k];

    let tdist = StudentT::new(df_within);

    for i in 0..k {
        for j in 0..k {
            if i == j {
                stat_matrix[i][j] = 0.0;
                pval_matrix[i][j] = 1.0;
            } else {
                let mean_diff = means[i] - means[j];
                stat_matrix[i][j] = mean_diff;

                // Standard error for difference of means
                let ni = groups[i].len() as f64;
                let nj = groups[j].len() as f64;
                let se = (mse * (1.0 / ni + 1.0 / nj)).sqrt();

                if se > 0.0 {
                    let t = mean_diff.abs() / se;
                    let p_raw = 2.0 * (1.0 - tdist.cdf(t));
                    // Bonferroni correction
                    pval_matrix[i][j] = (p_raw * num_comparisons as f64).min(1.0);
                } else {
                    pval_matrix[i][j] = f64::NAN;
                }
            }
        }
    }

    TukeyHSDResult {
        statistic: stat_matrix,
        pvalue: pval_matrix,
    }
}

/// Levene's test for equal variances using median-centered absolute deviations.
///
/// Matches the robust default behavior of `scipy.stats.levene(*groups)`.
pub fn levene(groups: &[&[f64]]) -> VarianceTestResult {
    if groups.len() < 2
        || groups.iter().any(|group| group.len() < 2)
        || groups.iter().any(|g| g.iter().any(|v| v.is_nan()))
    {
        return invalid_variance_test_result();
    }

    let deviations: Vec<Vec<f64>> = groups
        .iter()
        .map(|group| {
            let center = sample_median(group);
            group.iter().map(|&x| (x - center).abs()).collect()
        })
        .collect();

    let k = deviations.len() as f64;
    let n_total: usize = deviations.iter().map(Vec::len).sum();
    let df_within = n_total as f64 - k;
    if df_within <= 0.0 {
        return invalid_variance_test_result();
    }

    let grand_mean = deviations.iter().flatten().sum::<f64>() / n_total as f64;

    let ss_between: f64 = deviations
        .iter()
        .map(|group| {
            let mean = sample_mean(group);
            group.len() as f64 * (mean - grand_mean).powi(2)
        })
        .sum();

    let ss_within: f64 = deviations
        .iter()
        .map(|group| {
            let mean = sample_mean(group);
            group.iter().map(|&x| (x - mean).powi(2)).sum::<f64>()
        })
        .sum();

    if ss_within == 0.0 {
        if ss_between == 0.0 {
            return invalid_variance_test_result();
        }
        return VarianceTestResult {
            statistic: f64::INFINITY,
            pvalue: 0.0,
        };
    }

    let df_between = k - 1.0;
    let w = (df_within / df_between) * (ss_between / ss_within);
    let pvalue = FDistribution::new(df_between, df_within)
        .sf(w)
        .clamp(0.0, 1.0);
    VarianceTestResult {
        statistic: w,
        pvalue,
    }
}

/// Levene's test with nan_policy parameter.
///
/// Matches `scipy.stats.levene(*groups, nan_policy=...)`.
///
/// * `nan_policy` - "propagate" (default), "omit", or "raise"
pub fn levene_with_nan_policy(
    groups: &[&[f64]],
    nan_policy: Option<&str>,
) -> Result<VarianceTestResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;

    let has_nan = groups.iter().any(|g| g.iter().any(|v| v.is_nan()));

    if has_nan {
        match nan_policy {
            "raise" => {
                return Err(StatsError::InvalidArgument(
                    "input contains NaN values".to_string(),
                ));
            }
            "propagate" => {
                return Ok(invalid_variance_test_result());
            }
            "omit" => {
                let cleaned: Vec<Vec<f64>> = groups
                    .iter()
                    .map(|g| g.iter().copied().filter(|v| !v.is_nan()).collect())
                    .collect();
                let cleaned_refs: Vec<&[f64]> = cleaned.iter().map(|v| v.as_slice()).collect();
                return Ok(levene(&cleaned_refs));
            }
            _ => {}
        }
    }

    Ok(levene(groups))
}

/// Bartlett's test for equal variances under normality.
///
/// Matches `scipy.stats.bartlett(*groups)`.
pub fn bartlett(groups: &[&[f64]]) -> VarianceTestResult {
    if groups.len() < 2
        || groups.iter().any(|group| group.len() < 2)
        || groups.iter().any(|g| g.iter().any(|v| v.is_nan()))
    {
        return invalid_variance_test_result();
    }

    let k = groups.len() as f64;
    let n_total: usize = groups.iter().map(|group| group.len()).sum();
    let df = n_total as f64 - k;
    if df <= 0.0 {
        return invalid_variance_test_result();
    }

    let variances: Vec<f64> = groups.iter().map(|group| sample_variance(group)).collect();
    if variances
        .iter()
        .any(|variance| !variance.is_finite() || *variance < 0.0)
    {
        return invalid_variance_test_result();
    }

    let pooled_variance: f64 = groups
        .iter()
        .zip(&variances)
        .map(|(group, variance)| (group.len() as f64 - 1.0) * variance)
        .sum::<f64>()
        / df;

    if pooled_variance <= 0.0 {
        if variances.iter().all(|variance| *variance == 0.0) {
            return invalid_variance_test_result();
        }
        return VarianceTestResult {
            statistic: f64::INFINITY,
            pvalue: 0.0,
        };
    }

    let weighted_log_variance_sum: f64 = groups
        .iter()
        .zip(&variances)
        .map(|(group, variance)| (group.len() as f64 - 1.0) * variance.ln())
        .sum();

    let correction = 1.0
        + (groups
            .iter()
            .map(|group| 1.0 / (group.len() as f64 - 1.0))
            .sum::<f64>()
            - 1.0 / df)
            / (3.0 * (k - 1.0));

    let statistic = (df * pooled_variance.ln() - weighted_log_variance_sum) / correction;
    let pvalue = ChiSquared::new(k - 1.0).sf(statistic).clamp(0.0, 1.0);
    VarianceTestResult { statistic, pvalue }
}

/// Bartlett's test with nan_policy parameter.
///
/// Matches `scipy.stats.bartlett(*groups, nan_policy=...)`.
///
/// * `nan_policy` - "propagate" (default), "omit", or "raise"
pub fn bartlett_with_nan_policy(
    groups: &[&[f64]],
    nan_policy: Option<&str>,
) -> Result<VarianceTestResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;

    let has_nan = groups.iter().any(|g| g.iter().any(|v| v.is_nan()));

    if has_nan {
        match nan_policy {
            "raise" => {
                return Err(StatsError::InvalidArgument(
                    "input contains NaN values".to_string(),
                ));
            }
            "propagate" => {
                return Ok(invalid_variance_test_result());
            }
            "omit" => {
                let cleaned: Vec<Vec<f64>> = groups
                    .iter()
                    .map(|g| g.iter().copied().filter(|v| !v.is_nan()).collect())
                    .collect();
                let cleaned_refs: Vec<&[f64]> = cleaned.iter().map(|v| v.as_slice()).collect();
                return Ok(bartlett(&cleaned_refs));
            }
            _ => {}
        }
    }

    Ok(bartlett(groups))
}

/// Friedman test for repeated measures (non-parametric).
///
/// Tests H0: all treatments have the same effect. Non-parametric alternative
/// to repeated-measures ANOVA. Each group must have the same length.
///
/// Matches `scipy.stats.friedmanchisquare(*groups)`.
pub fn friedmanchisquare(groups: &[&[f64]]) -> TtestResult {
    let k = groups.len();
    if k < 3 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }
    let n = groups[0].len();
    if n < 2
        || groups
            .iter()
            .any(|g| g.len() != n || g.iter().any(|v| v.is_nan()))
    {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    // Rank within each block (row) with tie handling (average ranks)
    // and accumulate Σ(t³-t) over tie groups for scipy's tie correction.
    let mut rank_sums = vec![0.0; k];
    let mut tie_sum = 0.0_f64;
    for block in 0..n {
        let mut vals: Vec<(f64, usize)> = groups
            .iter()
            .enumerate()
            .map(|(j, g)| (g[block], j))
            .collect();
        vals.sort_by(|a, b| a.0.total_cmp(&b.0));

        // Average ranks for ties
        let mut i = 0;
        while i < k {
            let mut j = i + 1;
            while j < k && (vals[j].0 - vals[i].0).abs() < 1e-12 {
                j += 1;
            }
            // Positions i..j all tied — average rank
            let avg_rank = (i..j).map(|r| r as f64 + 1.0).sum::<f64>() / (j - i) as f64;
            for tied in &vals[i..j] {
                rank_sums[tied.1] += avg_rank;
            }
            let t = (j - i) as f64;
            if t > 1.0 {
                tie_sum += t * t * t - t;
            }
            i = j;
        }
    }

    // Friedman statistic: χ² = 12/(nk(k+1)) Σ R_j² - 3n(k+1), then
    // divided by scipy's tie-correction factor (1 - Σ(t³-t)/(n*k*(k²-1))).
    let kf = k as f64;
    let nf = n as f64;
    let sum_sq: f64 = rank_sums.iter().map(|&r| r * r).sum();
    let chi2_uncorrected = 12.0 / (nf * kf * (kf + 1.0)) * sum_sq - 3.0 * nf * (kf + 1.0);
    let denom = nf * kf * (kf * kf - 1.0);
    let c = if denom > 0.0 {
        1.0 - tie_sum / denom
    } else {
        1.0
    };
    let chi2 = if c > 0.0 {
        chi2_uncorrected / c
    } else {
        chi2_uncorrected
    };

    let df = kf - 1.0;
    let dist = ChiSquared::new(df);
    let pvalue = (1.0 - dist.cdf(chi2)).clamp(0.0, 1.0);

    TtestResult {
        statistic: chi2,
        pvalue,
        df,
    }
}

/// Fligner-Killeen test for equal variances.
///
/// A robust non-parametric test that uses the chi-squared distribution
/// of median-centered rank scores.
///
/// Matches `scipy.stats.fligner(*groups)`.
pub fn fligner(groups: &[&[f64]]) -> VarianceTestResult {
    if groups.len() < 2
        || groups.iter().any(|g| g.len() < 2)
        || groups.iter().any(|g| g.iter().any(|v| v.is_nan()))
    {
        return invalid_variance_test_result();
    }

    let k = groups.len();

    // Compute median-centered scores using normal quantiles
    let mut all_scores: Vec<f64> = Vec::new();
    let mut group_sizes: Vec<usize> = Vec::new();

    for group in groups {
        let mut sorted = group.to_vec();
        sorted.sort_by(|a, b| a.total_cmp(b));
        let median = quantile_sorted(&sorted, 0.5);
        let deviations: Vec<f64> = group.iter().map(|&x| (x - median).abs()).collect();
        all_scores.extend_from_slice(&deviations);
        group_sizes.push(group.len());
    }

    let n_total = all_scores.len();
    // Rank all scores using average ranks for ties (matches scipy.stats.rankdata).
    let ranks = rankdata_average(&all_scores);

    // Transform ranks to normal quantile scores
    let nf = n_total as f64;
    let scores: Vec<f64> = ranks
        .iter()
        .map(|&r| standard_normal_ppf((1.0 + r / (nf + 1.0)) / 2.0))
        .collect();

    // Compute group means of scores
    let grand_mean = scores.iter().sum::<f64>() / nf;
    let mut offset = 0;
    let mut numerator = 0.0;
    let mut denominator = 0.0;
    for &ni in &group_sizes {
        let group_mean = scores[offset..offset + ni].iter().sum::<f64>() / ni as f64;
        numerator += ni as f64 * (group_mean - grand_mean).powi(2);
        for score in scores.iter().skip(offset).take(ni) {
            denominator += (score - grand_mean).powi(2);
        }
        offset += ni;
    }

    // scipy normalises by var(a, ddof=1) = sum_sq_dev / (N-1), so the
    // multiplier here is (N - 1), not (N - k).
    let statistic = if denominator > 0.0 {
        (nf - 1.0) * numerator / denominator
    } else {
        f64::NAN
    };

    let df = (k - 1) as f64;
    let dist = ChiSquared::new(df);
    let pvalue = (1.0 - dist.cdf(statistic)).clamp(0.0, 1.0);

    VarianceTestResult { statistic, pvalue }
}

/// Fligner-Killeen test with nan_policy parameter.
///
/// Matches `scipy.stats.fligner(*groups, nan_policy=...)`.
///
/// * `nan_policy` - "propagate" (default), "omit", or "raise"
pub fn fligner_with_nan_policy(
    groups: &[&[f64]],
    nan_policy: Option<&str>,
) -> Result<VarianceTestResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;

    let has_nan = groups.iter().any(|g| g.iter().any(|v| v.is_nan()));

    if has_nan {
        match nan_policy {
            "raise" => {
                return Err(StatsError::InvalidArgument(
                    "input contains NaN values".to_string(),
                ));
            }
            "propagate" => {
                return Ok(invalid_variance_test_result());
            }
            "omit" => {
                let cleaned: Vec<Vec<f64>> = groups
                    .iter()
                    .map(|g| g.iter().copied().filter(|v| !v.is_nan()).collect())
                    .collect();
                let cleaned_refs: Vec<&[f64]> = cleaned.iter().map(|v| v.as_slice()).collect();
                return Ok(fligner(&cleaned_refs));
            }
            _ => {}
        }
    }

    Ok(fligner(groups))
}

/// Mood's test for equal scale parameters.
///
/// Tests H0: two samples have equal scale. Non-parametric.
///
/// Matches `scipy.stats.mood(x, y)`.
pub fn mood(x: &[f64], y: &[f64]) -> TtestResult {
    let m = x.len();
    let n = y.len();
    let total = m + n;
    if m == 0 || n == 0 || total < 3 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan())
    {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let mf = m as f64;
    let nf = n as f64;
    let totalf = total as f64;
    let center = (totalf + 1.0) / 2.0;
    let sum_i = |u: f64| u * (u + 1.0) / 2.0;
    let sum_i2 = |u: f64| u * (u + 1.0) * (2.0 * u + 1.0) / 6.0;

    // Pool observations and aggregate equal-valued groups so the statistic and
    // variance follow SciPy's tie-aware Mielke correction.
    let mut pooled: Vec<(f64, bool)> = x
        .iter()
        .map(|&v| (v, true))
        .chain(y.iter().map(|&v| (v, false)))
        .collect();
    pooled.sort_by(|a, b| a.0.total_cmp(&b.0));

    let mut cumulative = 0.0;
    let mut statistic_sum = 0.0;
    let mut tie_variance_sum = 0.0;
    let mut i = 0;
    while i < pooled.len() {
        let value = pooled[i].0;
        let start = cumulative;
        let mut j = i;
        let mut x_count = 0.0;
        while j < pooled.len() && pooled[j].0 == value {
            if pooled[j].1 {
                x_count += 1.0;
            }
            j += 1;
        }

        let count = (j - i) as f64;
        cumulative += count;
        let lo = start + 1.0;
        let hi = cumulative;
        let rank_sum = sum_i(hi) - sum_i(lo - 1.0);
        let rank_sq_sum = sum_i2(hi) - sum_i2(lo - 1.0);
        let phi = (rank_sq_sum - 2.0 * center * rank_sum + count * center * center) / count;
        statistic_sum += x_count * phi;

        tie_variance_sum += count
            * (count * count - 1.0)
            * (count * count - 4.0 + 15.0 * (totalf - cumulative - start).powi(2));

        i = j;
    }

    let e_m = mf * (totalf * totalf - 1.0) / 12.0;
    let var_m = mf * nf * (totalf + 1.0) * (totalf * totalf - 4.0) / 180.0
        - mf * nf * tie_variance_sum / (180.0 * totalf * (totalf - 1.0));

    if !var_m.is_finite() || var_m <= 0.0 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let z = (statistic_sum - e_m) / var_m.sqrt();
    let norm = Normal::standard();
    let pvalue = (2.0 * ContinuousDistribution::sf(&norm, z.abs())).clamp(0.0, 1.0);

    TtestResult {
        statistic: z,
        pvalue,
        df: f64::NAN, // Non-parametric, no df
    }
}

/// Mood's scale test with alternative hypothesis.
///
/// Matches `scipy.stats.mood(x, y, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn mood_alternative(x: &[f64], y: &[f64], alternative: &str) -> TtestResult {
    let m = x.len();
    let n = y.len();
    let total = m + n;
    if m == 0 || n == 0 || total < 3 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan())
    {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let mf = m as f64;
    let nf = n as f64;
    let totalf = total as f64;
    let center = (totalf + 1.0) / 2.0;
    let sum_i = |u: f64| u * (u + 1.0) / 2.0;
    let sum_i2 = |u: f64| u * (u + 1.0) * (2.0 * u + 1.0) / 6.0;

    let mut pooled: Vec<(f64, bool)> = x
        .iter()
        .map(|&v| (v, true))
        .chain(y.iter().map(|&v| (v, false)))
        .collect();
    pooled.sort_by(|a, b| a.0.total_cmp(&b.0));

    let mut cumulative = 0.0;
    let mut statistic_sum = 0.0;
    let mut tie_variance_sum = 0.0;
    let mut i = 0;
    while i < pooled.len() {
        let value = pooled[i].0;
        let start = cumulative;
        let mut j = i;
        let mut x_count = 0.0;
        while j < pooled.len() && pooled[j].0 == value {
            if pooled[j].1 {
                x_count += 1.0;
            }
            j += 1;
        }

        let count = (j - i) as f64;
        cumulative += count;
        let lo = start + 1.0;
        let hi = cumulative;
        let rank_sum = sum_i(hi) - sum_i(lo - 1.0);
        let rank_sq_sum = sum_i2(hi) - sum_i2(lo - 1.0);
        let phi = (rank_sq_sum - 2.0 * center * rank_sum + count * center * center) / count;
        statistic_sum += x_count * phi;

        tie_variance_sum += count
            * (count * count - 1.0)
            * (count * count - 4.0 + 15.0 * (totalf - cumulative - start).powi(2));

        i = j;
    }

    let e_m = mf * (totalf * totalf - 1.0) / 12.0;
    let var_m = mf * nf * (totalf + 1.0) * (totalf * totalf - 4.0) / 180.0
        - mf * nf * tie_variance_sum / (180.0 * totalf * (totalf - 1.0));

    if !var_m.is_finite() || var_m <= 0.0 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let z = (statistic_sum - e_m) / var_m.sqrt();
    let pvalue = normal_alternative_pvalue(z, alternative).clamp(0.0, 1.0);

    TtestResult {
        statistic: z,
        pvalue,
        df: f64::NAN,
    }
}

/// Mood's median test for equal medians across groups.
///
/// Tests H0: all groups have the same median.
///
/// Matches `scipy.stats.median_test(*groups)`.
pub fn median_test(groups: &[&[f64]]) -> TtestResult {
    if groups.len() < 2
        || groups
            .iter()
            .any(|g| g.is_empty() || g.iter().any(|v| v.is_nan()))
    {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    // Pool all data and find grand median
    let mut all_data: Vec<f64> = groups.iter().flat_map(|g| g.iter().copied()).collect();
    all_data.sort_by(|a, b| a.total_cmp(b));
    let grand_median = quantile_sorted(&all_data, 0.5);

    // Count observations above/below median per group
    let k = groups.len();
    let mut above = vec![0.0; k];
    let mut below = vec![0.0; k];
    for (i, group) in groups.iter().enumerate() {
        for &val in *group {
            if val > grand_median {
                above[i] += 1.0;
            } else {
                below[i] += 1.0;
            }
        }
    }

    // Chi-squared test on the 2×k contingency table
    let table = vec![above, below];
    let result = chi2_contingency(&table, true);
    TtestResult {
        statistic: result.statistic,
        pvalue: result.pvalue,
        df: (k - 1) as f64,
    }
}

/// Ansari-Bradley test for equal scale parameters.
///
/// Matches the core behavior of `scipy.stats.ansari(x, y)` for the
/// default two-sided alternative.
///
/// Delegates to `ansari_alternative(x, y, "two-sided")` so the
/// exact-distribution path (n + m < 55, no ties — see
/// [frankenscipy-1vlpt]) and the normal-tail fallback are shared
/// across both entry points.
pub fn ansari(x: &[f64], y: &[f64]) -> TtestResult {
    ansari_alternative(x, y, "two-sided")
}

/// Ansari-Bradley scale test with alternative hypothesis.
///
/// Matches `scipy.stats.ansari(x, y, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn ansari_alternative(x: &[f64], y: &[f64], alternative: &str) -> TtestResult {
    let n = x.len();
    let m = y.len();
    if n < 1 || m < 1 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let total = n + m;
    let mut pooled = Vec::with_capacity(total);
    pooled.extend_from_slice(x);
    pooled.extend_from_slice(y);
    let ranks = rankdata_average(&pooled);
    let total_f = total as f64;
    let symranks: Vec<f64> = ranks.iter().map(|&r| r.min(total_f - r + 1.0)).collect();
    let statistic: f64 = symranks[..n].iter().sum();

    let repeats = {
        let mut sorted = pooled.clone();
        sorted.sort_by(|a, b| a.total_cmp(b));
        sorted.windows(2).any(|w| w[0].total_cmp(&w[1]).is_eq())
    };

    let n_f = n as f64;
    let m_f = m as f64;
    let mean = if total % 2 == 1 {
        n_f * (total_f + 1.0).powi(2) / (4.0 * total_f)
    } else {
        n_f * (total_f + 2.0) / 4.0
    };

    let variance = if repeats {
        let fac: f64 = symranks.iter().map(|r| r * r).sum();
        if total % 2 == 1 {
            m_f * n_f * (16.0 * total_f * fac - (total_f + 1.0).powi(4))
                / (16.0 * total_f.powi(2) * (total_f - 1.0))
        } else {
            m_f * n_f * (16.0 * fac - total_f * (total_f + 2.0).powi(2))
                / (16.0 * total_f * (total_f - 1.0))
        }
    } else if total % 2 == 1 {
        n_f * m_f * (total_f + 1.0) * (3.0 + total_f.powi(2)) / (48.0 * total_f.powi(2))
    } else {
        m_f * n_f * (total_f + 2.0) * (total_f - 2.0) / (48.0 * (total_f - 1.0))
    };

    // scipy uses the exact distribution when n < 55, m < 55, and there
    // are no ties in the pooled data. For ties or larger samples it
    // falls through to the normal-tail approximation.
    let exact_path = !repeats && n < 55 && m < 55;
    let pvalue = if exact_path {
        ansari_exact_pvalue(statistic, n, total, alternative)
    } else {
        if variance <= 0.0 {
            return TtestResult {
                statistic,
                pvalue: 1.0,
                df: f64::NAN,
            };
        }
        let z = (mean - statistic) / variance.sqrt();
        normal_alternative_pvalue(z, alternative).clamp(0.0, 1.0)
    };

    TtestResult {
        statistic,
        pvalue,
        df: f64::NAN,
    }
}

/// Exact p-value for the Ansari-Bradley test under H0 (random allocation
/// of n, m samples to a pooled rank stream of length N = n + m, no ties).
///
/// Builds the generating function product
///   G(t, x) = ∏_{i=1..N} (1 + x · t^{s_i})    where s_i = min(i, N+1−i)
/// via 2-D dynamic programming and reads off the count for choosing
/// exactly n out of N (the AB statistic conditioning).
///
/// Matches the `_ABW` exact distribution scipy.stats.ansari uses for
/// n + m < 55 with no ties — see scipy/_morestats.py:`ansari` exact
/// branch.
fn ansari_exact_pvalue(stat: f64, n: usize, total: usize, alternative: &str) -> f64 {
    if total == 0 {
        return f64::NAN;
    }
    // Symmetric ranks: s_i = min(i, N+1-i) for i = 1..=N.
    let mut symranks = Vec::with_capacity(total);
    for i in 1..=total {
        symranks.push(i.min(total + 1 - i));
    }
    // DP: dp[j][k] = number of ways to choose j elements with sum k.
    // max_k upper-bounded by sum of n largest symranks (for n=m=N/2 ≈ N²/8).
    let max_sum: usize = {
        let mut sorted = symranks.clone();
        sorted.sort_unstable_by(|a, b| b.cmp(a));
        sorted.iter().take(n).sum()
    };
    let mut dp = vec![vec![0u128; max_sum + 1]; n + 1];
    dp[0][0] = 1;
    for &s in &symranks {
        // Iterate j and k in reverse so each item is used at most once
        // (knapsack-style 0/1 selection).
        for j in (1..=n).rev() {
            for k in s..=max_sum {
                dp[j][k] = dp[j][k].saturating_add(dp[j - 1][k - s]);
            }
        }
    }
    let total_count: u128 = dp[n].iter().sum();
    if total_count == 0 {
        return f64::NAN;
    }
    let total_f = total_count as f64;
    let stat_int = stat.round() as usize;
    if stat_int > max_sum {
        return f64::NAN;
    }
    // CDF/SF on the rounded integer statistic. scipy uses:
    //   cdf(k) = P(AB ≤ k) = sum freqs[..=k] / total
    //   sf(k)  = P(AB ≥ k) = sum freqs[k..] / total
    let cdf: u128 = dp[n][..=stat_int].iter().sum();
    let sf: u128 = dp[n][stat_int..].iter().sum();
    let cdf_f = cdf as f64 / total_f;
    let sf_f = sf as f64 / total_f;
    let pval = match alternative {
        "two-sided" => (2.0 * cdf_f.min(sf_f)).min(1.0),
        "greater" => cdf_f, // AB statistic is _smaller_ when scale ratio is larger
        _ => sf_f,          // "less"
    };
    pval.clamp(0.0, 1.0)
}

///
/// Matches `scipy.stats.mannwhitneyu(x, y, alternative='two-sided')`.
///
/// Non-parametric test: H0: distributions of x and y are equal.
/// Uses normal approximation for p-value (valid for n > 20).
pub fn mannwhitneyu(x: &[f64], y: &[f64]) -> TtestResult {
    if x.len() < 2 || y.len() < 2 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let n1 = x.len();
    let n2 = y.len();
    let n1f = n1 as f64;
    let n2f = n2 as f64;

    // Combine and rank all observations
    let mut combined: Vec<(f64, usize)> = Vec::with_capacity(n1 + n2);
    for &v in x {
        combined.push((v, 0)); // group 0 = x
    }
    for &v in y {
        combined.push((v, 1)); // group 1 = y
    }

    let values: Vec<f64> = combined.iter().map(|&(v, _)| v).collect();
    let ranks = rankdata_average(&values);

    // U statistic: sum of ranks of x - n1*(n1+1)/2
    let rank_sum_x: f64 = ranks
        .iter()
        .zip(combined.iter())
        .filter(|(_, (_, group))| *group == 0)
        .map(|(r, _)| *r)
        .sum();

    let u1 = rank_sum_x - n1f * (n1f + 1.0) / 2.0;
    let u2 = n1f * n2f - u1;
    let u = u1.min(u2); // two-sided: use smaller U

    // Normal approximation. Per br-nknp: include tie correction in
    // sigma and continuity correction (|U - mu| - 0.5) on the z-score
    // to match scipy.stats.mannwhitneyu defaults
    // (use_continuity=True, method='asymptotic').
    let mu = n1f * n2f / 2.0;
    let n = n1f + n2f;

    // Tie correction: sum_t (t^3 - t) over each tied rank group.
    // Implemented by counting equal-rank groups in the sorted ranks.
    let mut sorted_ranks = ranks.clone();
    sorted_ranks.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let mut tie_correction = 0.0_f64;
    let mut i = 0;
    while i < sorted_ranks.len() {
        let mut j = i + 1;
        while j < sorted_ranks.len() && (sorted_ranks[j] - sorted_ranks[i]).abs() < 1e-12 {
            j += 1;
        }
        let t = (j - i) as f64;
        if t > 1.0 {
            tie_correction += t * t * t - t;
        }
        i = j;
    }

    let variance_no_ties = n1f * n2f * (n + 1.0) / 12.0;
    let variance = if n > 1.0 {
        variance_no_ties - n1f * n2f * tie_correction / (12.0 * n * (n - 1.0))
    } else {
        variance_no_ties
    };
    let sigma = variance.max(0.0).sqrt();

    if sigma == 0.0 {
        return TtestResult {
            statistic: u,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    // Continuity correction: subtract 0.5 from |U - mu| to compensate
    // for the discrete-to-continuous approximation. Equivalent to
    // scipy's `z = (U - mu - 0.5*sign(U - mu)) / sigma` for two-sided.
    let abs_diff = (u - mu).abs();
    let z = (abs_diff - 0.5).max(0.0) / sigma;
    let normal = Normal::standard();
    // pvalue = 2 * sf(|z|) for two-sided
    let pvalue = (2.0 * (1.0 - normal.cdf(z))).clamp(0.0, 1.0);

    TtestResult {
        statistic: u,
        pvalue,
        df: f64::NAN,
    }
}

/// Mann-Whitney U test with alternative hypothesis specification.
///
/// Matches `scipy.stats.mannwhitneyu(x, y, alternative=...)`.
///
/// # Arguments
/// * `x`, `y` - Sample data
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn mannwhitneyu_alternative(x: &[f64], y: &[f64], alternative: &str) -> TtestResult {
    if x.len() < 2 || y.len() < 2 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let n1 = x.len();
    let n2 = y.len();
    let n1f = n1 as f64;
    let n2f = n2 as f64;

    let mut combined: Vec<(f64, usize)> = Vec::with_capacity(n1 + n2);
    for &v in x {
        combined.push((v, 0));
    }
    for &v in y {
        combined.push((v, 1));
    }

    let values: Vec<f64> = combined.iter().map(|&(v, _)| v).collect();
    let ranks = rankdata_average(&values);

    let rank_sum_x: f64 = ranks
        .iter()
        .zip(combined.iter())
        .filter(|(_, (_, group))| *group == 0)
        .map(|(r, _)| *r)
        .sum();

    let u1 = rank_sum_x - n1f * (n1f + 1.0) / 2.0;
    let u2 = n1f * n2f - u1;

    let mu = n1f * n2f / 2.0;
    let n = n1f + n2f;

    // br-nknp: tie correction for sigma (matches scipy default).
    let mut sorted_ranks = ranks.clone();
    sorted_ranks.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let mut tie_correction = 0.0_f64;
    let mut i = 0;
    while i < sorted_ranks.len() {
        let mut j = i + 1;
        while j < sorted_ranks.len() && (sorted_ranks[j] - sorted_ranks[i]).abs() < 1e-12 {
            j += 1;
        }
        let t = (j - i) as f64;
        if t > 1.0 {
            tie_correction += t * t * t - t;
        }
        i = j;
    }
    let variance_no_ties = n1f * n2f * (n + 1.0) / 12.0;
    let variance = if n > 1.0 {
        variance_no_ties - n1f * n2f * tie_correction / (12.0 * n * (n - 1.0))
    } else {
        variance_no_ties
    };
    let sigma = variance.max(0.0).sqrt();

    if sigma == 0.0 {
        return TtestResult {
            statistic: u1,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    let normal = Normal::standard();
    let (u, pvalue) = match alternative {
        "less" => {
            let z = (u1 - mu) / sigma;
            (u1, normal.cdf(z))
        }
        "greater" => {
            let z = (u1 - mu) / sigma;
            (u1, normal.sf(z))
        }
        _ => {
            // br-nknp: two-sided with continuity correction.
            let u = u1.min(u2);
            let abs_diff = (u - mu).abs();
            let z = (abs_diff - 0.5).max(0.0) / sigma;
            (u, (2.0 * (1.0 - normal.cdf(z))).clamp(0.0, 1.0))
        }
    };

    TtestResult {
        statistic: u,
        pvalue,
        df: f64::NAN,
    }
}

/// Wilcoxon signed-rank test for paired samples.
///
/// Matches `scipy.stats.wilcoxon(x, y)`.
///
/// Non-parametric test: H0: median of x - y is zero.
pub fn wilcoxon(x: &[f64], y: &[f64]) -> TtestResult {
    if x.len() != y.len() || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    // Compute differences, discard zeros
    let diffs: Vec<f64> = x
        .iter()
        .zip(y.iter())
        .map(|(&xi, &yi)| xi - yi)
        .filter(|&d| d.abs() > 1e-15)
        .collect();

    let nr = diffs.len();
    if nr < 2 {
        return TtestResult {
            statistic: 0.0,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    // Rank the absolute differences
    let abs_diffs: Vec<f64> = diffs.iter().map(|d| d.abs()).collect();
    let ranks = rankdata_average(&abs_diffs);

    // T+ = sum of ranks where difference is positive
    let t_plus: f64 = ranks
        .iter()
        .zip(diffs.iter())
        .filter(|(_, d)| **d > 0.0)
        .map(|(r, _)| *r)
        .sum();

    let t_minus: f64 = ranks
        .iter()
        .zip(diffs.iter())
        .filter(|(_, d)| **d < 0.0)
        .map(|(r, _)| *r)
        .sum();

    let t_stat = t_plus.min(t_minus);
    let nrf = nr as f64;

    // Normal approximation with tie correction. scipy:
    //   sigma² = n*(n+1)*(2n+1)/24 - Σ(t³-t)/48
    // where t are tie-group sizes among absolute differences.
    let mu = nrf * (nrf + 1.0) / 4.0;
    let mut sorted_abs = abs_diffs.clone();
    sorted_abs.sort_by(|a, b| a.total_cmp(b));
    let mut tie_sum = 0.0_f64;
    let mut i = 0;
    while i < sorted_abs.len() {
        let mut j = i + 1;
        while j < sorted_abs.len() && (sorted_abs[j] - sorted_abs[i]).abs() < 1e-12 {
            j += 1;
        }
        let t = (j - i) as f64;
        if t > 1.0 {
            tie_sum += t * t * t - t;
        }
        i = j;
    }
    let variance = (nrf * (nrf + 1.0) * (2.0 * nrf + 1.0) / 24.0) - tie_sum / 48.0;
    let sigma = variance.max(0.0).sqrt();

    if sigma == 0.0 {
        return TtestResult {
            statistic: t_stat,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    let z = (t_stat - mu) / sigma;
    let normal = Normal::standard();
    let pvalue = 2.0 * normal.cdf(z.min(0.0));

    TtestResult {
        statistic: t_stat,
        pvalue,
        df: f64::NAN,
    }
}

/// Wilcoxon signed-rank test with alternative hypothesis specification.
///
/// Matches `scipy.stats.wilcoxon(x, y, alternative=...)`.
///
/// # Arguments
/// * `x`, `y` - Paired sample data
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn wilcoxon_alternative(x: &[f64], y: &[f64], alternative: &str) -> TtestResult {
    if x.len() != y.len() || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let diffs: Vec<f64> = x
        .iter()
        .zip(y.iter())
        .map(|(&xi, &yi)| xi - yi)
        .filter(|&d| d.abs() > 1e-15)
        .collect();

    let nr = diffs.len();
    if nr < 2 {
        return TtestResult {
            statistic: 0.0,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    let abs_diffs: Vec<f64> = diffs.iter().map(|d| d.abs()).collect();
    let ranks = rankdata_average(&abs_diffs);

    let t_plus: f64 = ranks
        .iter()
        .zip(diffs.iter())
        .filter(|(_, d)| **d > 0.0)
        .map(|(r, _)| *r)
        .sum();

    let t_minus: f64 = ranks
        .iter()
        .zip(diffs.iter())
        .filter(|(_, d)| **d < 0.0)
        .map(|(r, _)| *r)
        .sum();

    let nrf = nr as f64;
    let mu = nrf * (nrf + 1.0) / 4.0;

    // Tie correction for sigma (matches scipy's wilcoxon mode='approx'):
    //   sigma² = n*(n+1)*(2n+1)/24 - Σ(t³-t)/48
    // where t are tie-group sizes among the absolute differences.
    let mut sorted_abs = abs_diffs.clone();
    sorted_abs.sort_by(|a, b| a.total_cmp(b));
    let mut tie_sum = 0.0_f64;
    let mut i = 0;
    while i < sorted_abs.len() {
        let mut j = i + 1;
        while j < sorted_abs.len() && (sorted_abs[j] - sorted_abs[i]).abs() < 1e-12 {
            j += 1;
        }
        let t = (j - i) as f64;
        if t > 1.0 {
            tie_sum += t * t * t - t;
        }
        i = j;
    }
    let variance = (nrf * (nrf + 1.0) * (2.0 * nrf + 1.0) / 24.0) - tie_sum / 48.0;
    let sigma = variance.max(0.0).sqrt();

    if sigma == 0.0 {
        return TtestResult {
            statistic: t_plus,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    let normal = Normal::standard();
    let (t_stat, pvalue) = match alternative {
        "less" => {
            let z = (t_plus - mu) / sigma;
            (t_plus, normal.cdf(z))
        }
        "greater" => {
            let z = (t_plus - mu) / sigma;
            (t_plus, normal.sf(z))
        }
        _ => {
            let t = t_plus.min(t_minus);
            let z = (t - mu) / sigma;
            (t, 2.0 * normal.cdf(z.min(0.0)))
        }
    };

    TtestResult {
        statistic: t_stat,
        pvalue,
        df: f64::NAN,
    }
}

/// Kruskal-Wallis H-test for independent samples.
///
/// Matches `scipy.stats.kruskal(*groups)`.
///
/// Non-parametric alternative to one-way ANOVA.
/// Tests H0: all groups come from the same distribution.
pub fn kruskal(groups: &[&[f64]]) -> TtestResult {
    if groups.len() < 2
        || groups.iter().any(|g| g.is_empty())
        || groups.iter().any(|g| g.iter().any(|v| v.is_nan()))
    {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let n_total: usize = groups.iter().map(|g| g.len()).sum();
    let nf = n_total as f64;

    if n_total < 3 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    // Combine all observations and rank
    let mut all_values: Vec<f64> = Vec::with_capacity(n_total);
    let mut group_sizes: Vec<usize> = Vec::with_capacity(groups.len());
    for &g in groups {
        all_values.extend_from_slice(g);
        group_sizes.push(g.len());
    }
    if all_values.iter().all(|&v| v == all_values[0]) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }
    let ranks = rankdata_average(&all_values);

    // Compute H statistic: H = (12/(N(N+1))) * Σ(R_i²/n_i) - 3(N+1)
    let mut offset = 0;
    let mut h_sum = 0.0;
    for &ni in &group_sizes {
        let rank_sum: f64 = ranks[offset..offset + ni].iter().sum();
        h_sum += rank_sum * rank_sum / ni as f64;
        offset += ni;
    }

    let h_uncorrected = 12.0 / (nf * (nf + 1.0)) * h_sum - 3.0 * (nf + 1.0);

    // Tie correction. scipy divides H by C = 1 - Σ(t³-t)/(N³-N) where the
    // sum is over each tie-group size t in the combined sorted observations.
    let mut sorted_values = all_values.clone();
    sorted_values.sort_by(|a, b| a.total_cmp(b));
    let mut tie_sum = 0.0_f64;
    let mut i = 0;
    while i < sorted_values.len() {
        let mut j = i + 1;
        while j < sorted_values.len() && sorted_values[j] == sorted_values[i] {
            j += 1;
        }
        let t = (j - i) as f64;
        if t > 1.0 {
            tie_sum += t * t * t - t;
        }
        i = j;
    }
    let c = 1.0 - tie_sum / (nf * nf * nf - nf);
    let h = if c > 0.0 {
        h_uncorrected / c
    } else {
        h_uncorrected
    };
    let df = groups.len() as f64 - 1.0;

    // P-value from chi-squared distribution
    let chi2 = ChiSquared::new(df);
    let pvalue = chi2.sf(h).clamp(0.0, 1.0);

    TtestResult {
        statistic: h,
        pvalue,
        df,
    }
}

/// Kruskal-Wallis H-test with nan_policy parameter.
///
/// Matches `scipy.stats.kruskal(*groups, nan_policy=...)`.
///
/// * `nan_policy` - "propagate" (default), "omit", or "raise"
pub fn kruskal_with_nan_policy(
    groups: &[&[f64]],
    nan_policy: Option<&str>,
) -> Result<TtestResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;

    // Check for NaN and apply policy
    let has_nan = groups.iter().any(|g| g.iter().any(|v| v.is_nan()));

    if has_nan {
        match nan_policy {
            "raise" => {
                return Err(StatsError::InvalidArgument(
                    "input contains NaN values".to_string(),
                ));
            }
            "propagate" => {
                return Ok(TtestResult {
                    statistic: f64::NAN,
                    pvalue: f64::NAN,
                    df: f64::NAN,
                });
            }
            "omit" => {
                // Filter NaN from each group
                let cleaned: Vec<Vec<f64>> = groups
                    .iter()
                    .map(|g| g.iter().copied().filter(|v| !v.is_nan()).collect())
                    .collect();
                let cleaned_refs: Vec<&[f64]> = cleaned.iter().map(|v| v.as_slice()).collect();
                return Ok(kruskal(&cleaned_refs));
            }
            _ => {}
        }
    }

    Ok(kruskal(groups))
}

/// Wilcoxon rank-sum test for two independent samples.
///
/// Matches `scipy.stats.ranksums(x, y)`.
///
/// Similar to Mann-Whitney U but returns a z-statistic.
pub fn ranksums(x: &[f64], y: &[f64]) -> TtestResult {
    if x.len() < 2 || y.len() < 2 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let n1 = x.len() as f64;
    let n2 = y.len() as f64;

    // Combine and rank
    let mut combined: Vec<f64> = Vec::with_capacity(x.len() + y.len());
    combined.extend_from_slice(x);
    combined.extend_from_slice(y);
    let ranks = rankdata_average(&combined);

    // Sum of ranks for first sample
    let rank_sum_x: f64 = ranks[..x.len()].iter().sum();

    // Expected rank sum under H0
    let expected = n1 * (n1 + n2 + 1.0) / 2.0;
    let sd = (n1 * n2 * (n1 + n2 + 1.0) / 12.0).sqrt();

    if sd == 0.0 {
        return TtestResult {
            statistic: 0.0,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    let z = (rank_sum_x - expected) / sd;
    let normal = Normal::standard();
    let pvalue = 2.0 * normal.cdf(-z.abs()); // two-sided

    TtestResult {
        statistic: z,
        pvalue,
        df: f64::NAN,
    }
}

/// Wilcoxon rank-sum test with alternative hypothesis.
///
/// Matches `scipy.stats.ranksums(x, y, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn ranksums_alternative(x: &[f64], y: &[f64], alternative: &str) -> TtestResult {
    if x.len() < 2 || y.len() < 2 {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let n1 = x.len() as f64;
    let n2 = y.len() as f64;

    let mut combined: Vec<f64> = Vec::with_capacity(x.len() + y.len());
    combined.extend_from_slice(x);
    combined.extend_from_slice(y);
    let ranks = rankdata_average(&combined);

    let rank_sum_x: f64 = ranks[..x.len()].iter().sum();

    let expected = n1 * (n1 + n2 + 1.0) / 2.0;
    let sd = (n1 * n2 * (n1 + n2 + 1.0) / 12.0).sqrt();

    if sd == 0.0 {
        return TtestResult {
            statistic: 0.0,
            pvalue: 1.0,
            df: f64::NAN,
        };
    }

    let z = (rank_sum_x - expected) / sd;
    let pvalue = normal_alternative_pvalue(z, alternative);

    TtestResult {
        statistic: z,
        pvalue,
        df: f64::NAN,
    }
}

// ══════════════════════════════════════════════════════════════════════
// Correlation and Regression
// ══════════════════════════════════════════════════════════════════════

/// Result of linear regression.
#[derive(Debug, Clone, PartialEq)]
pub struct LinregressResult {
    /// Slope of the regression line.
    pub slope: f64,
    /// Intercept of the regression line.
    pub intercept: f64,
    /// Pearson correlation coefficient (r-value).
    pub rvalue: f64,
    /// Two-sided p-value for the hypothesis test that the slope is zero.
    pub pvalue: f64,
    /// Standard error of the estimated slope.
    pub stderr: f64,
    /// Standard error of the estimated intercept.
    pub intercept_stderr: f64,
}

/// Calculate a linear least-squares regression for two sets of measurements.
///
/// Matches `scipy.stats.linregress(x, y)`.
///
/// Returns slope, intercept, r-value, p-value, and standard errors.
pub fn linregress(x: &[f64], y: &[f64]) -> LinregressResult {
    let n = x.len() as f64;
    if x.len() < 2 || x.len() != y.len() {
        return LinregressResult {
            slope: f64::NAN,
            intercept: f64::NAN,
            rvalue: f64::NAN,
            pvalue: f64::NAN,
            stderr: f64::NAN,
            intercept_stderr: f64::NAN,
        };
    }

    let xmean: f64 = x.iter().sum::<f64>() / n;
    let ymean: f64 = y.iter().sum::<f64>() / n;

    // Sums of squares and cross-products
    let mut ssxm = 0.0; // Σ(x - xmean)²
    let mut ssym = 0.0; // Σ(y - ymean)²
    let mut ssxym = 0.0; // Σ(x - xmean)(y - ymean)
    for (&xi, &yi) in x.iter().zip(y.iter()) {
        let dx = xi - xmean;
        let dy = yi - ymean;
        ssxm += dx * dx;
        ssym += dy * dy;
        ssxym += dx * dy;
    }

    if ssxm == 0.0 {
        // All x values identical — slope undefined
        return LinregressResult {
            slope: f64::NAN,
            intercept: f64::NAN,
            rvalue: f64::NAN,
            pvalue: f64::NAN,
            stderr: f64::NAN,
            intercept_stderr: f64::NAN,
        };
    }

    let slope = ssxym / ssxm;
    let intercept = ymean - slope * xmean;

    // Correlation coefficient
    let rvalue = if ssym == 0.0 {
        // All y values identical — perfect fit if slope is 0
        if slope == 0.0 { 1.0 } else { 0.0 }
    } else {
        ssxym / (ssxm * ssym).sqrt()
    };

    // p-value: test H0: slope = 0 using t-distribution
    let df = n - 2.0;
    let (pvalue, stderr, intercept_stderr) = if df > 0.0 {
        // Residual sum of squares
        let r2 = rvalue * rvalue;
        let sse = ssym * (1.0 - r2);
        let mse = sse / df;
        let se_slope = (mse / ssxm).sqrt();
        let se_intercept = (mse * (1.0 / n + xmean * xmean / ssxm)).sqrt();

        let t_stat = if se_slope > 0.0 {
            slope / se_slope
        } else {
            f64::INFINITY
        };

        let pval = if df >= 1.0 && se_slope > 0.0 {
            let tdist = StudentT::new(df);
            2.0 * tdist.sf(t_stat.abs())
        } else {
            0.0
        };
        (pval, se_slope, se_intercept)
    } else {
        (f64::NAN, f64::NAN, f64::NAN)
    };

    LinregressResult {
        slope,
        intercept,
        rvalue,
        pvalue,
        stderr,
        intercept_stderr,
    }
}

/// Result of linregress confidence intervals.
#[derive(Debug, Clone, PartialEq)]
pub struct LinregressCIResult {
    pub slope_lo: f64,
    pub slope_hi: f64,
    pub intercept_lo: f64,
    pub intercept_hi: f64,
}

/// Compute confidence intervals for linear regression slope and intercept.
///
/// # Arguments
/// * `x` - Independent variable data
/// * `y` - Dependent variable data
/// * `alpha` - Significance level (e.g., 0.05 for 95% CI)
pub fn linregress_ci(x: &[f64], y: &[f64], alpha: f64) -> LinregressCIResult {
    let n = x.len();
    if n < 3 || x.len() != y.len() {
        return LinregressCIResult {
            slope_lo: f64::NAN,
            slope_hi: f64::NAN,
            intercept_lo: f64::NAN,
            intercept_hi: f64::NAN,
        };
    }

    let result = linregress(x, y);
    if result.stderr.is_nan() {
        return LinregressCIResult {
            slope_lo: f64::NAN,
            slope_hi: f64::NAN,
            intercept_lo: f64::NAN,
            intercept_hi: f64::NAN,
        };
    }

    let df = n as f64 - 2.0;
    let tdist = StudentT::new(df);
    let t_crit = tdist.ppf(1.0 - alpha / 2.0);

    let slope_margin = t_crit * result.stderr;
    let intercept_margin = t_crit * result.intercept_stderr;

    LinregressCIResult {
        slope_lo: result.slope - slope_margin,
        slope_hi: result.slope + slope_margin,
        intercept_lo: result.intercept - intercept_margin,
        intercept_hi: result.intercept + intercept_margin,
    }
}

/// Result of a correlation test.
#[derive(Debug, Clone, PartialEq)]
pub struct CorrelationResult {
    /// Correlation coefficient.
    pub statistic: f64,
    /// Two-sided p-value.
    pub pvalue: f64,
}

/// Result of Somers' D ordinal association test.
#[derive(Debug, Clone, PartialEq)]
pub struct SomersDResult {
    /// Somers' D statistic.
    pub statistic: f64,
    /// p-value for H0: D = 0.
    pub pvalue: f64,
    /// Contingency table used in the calculation.
    pub table: Vec<Vec<f64>>,
    /// Alias for `statistic`, matching SciPy's result object.
    pub correlation: f64,
}

/// Input surface for `somersd`.
pub enum SomersDInput<'a> {
    /// Independent/dependent ordinal rankings.
    Rankings(&'a [f64], &'a [f64]),
    /// Precomputed contingency table.
    Table(&'a [Vec<f64>]),
}

/// Calculate the Pearson correlation coefficient and p-value.
///
/// Matches `scipy.stats.pearsonr(x, y)`.
///
/// Tests for non-correlation: H0: ρ = 0 (no linear relationship).
pub fn pearsonr(x: &[f64], y: &[f64]) -> CorrelationResult {
    let n = x.len();
    if n < 2 || n != y.len() {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }
    let nf = n as f64;

    let xmean: f64 = x.iter().sum::<f64>() / nf;
    let ymean: f64 = y.iter().sum::<f64>() / nf;

    let mut ssxm = 0.0;
    let mut ssym = 0.0;
    let mut ssxym = 0.0;
    for (&xi, &yi) in x.iter().zip(y.iter()) {
        let dx = xi - xmean;
        let dy = yi - ymean;
        ssxm += dx * dx;
        ssym += dy * dy;
        ssxym += dx * dy;
    }

    let denom = (ssxm * ssym).sqrt();
    if denom == 0.0 {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let r = ssxym / denom;
    // Clamp to [-1, 1] for numerical safety
    let r = r.clamp(-1.0, 1.0);

    // p-value via t-distribution: t = r * sqrt((n-2)/(1-r²))
    let df = nf - 2.0;
    let pvalue = if df > 0.0 && r.abs() < 1.0 {
        let t = r * (df / (1.0 - r * r)).sqrt();
        let tdist = StudentT::new(df);
        2.0 * tdist.sf(t.abs())
    } else if r.abs() >= 1.0 {
        0.0 // Perfect correlation
    } else {
        f64::NAN
    };

    CorrelationResult {
        statistic: r,
        pvalue,
    }
}

/// Calculate Pearson correlation with alternative hypothesis.
///
/// Matches `scipy.stats.pearsonr(x, y, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn pearsonr_alternative(x: &[f64], y: &[f64], alternative: &str) -> CorrelationResult {
    let n = x.len();
    if n < 2 || n != y.len() {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }
    let nf = n as f64;

    let xmean: f64 = x.iter().sum::<f64>() / nf;
    let ymean: f64 = y.iter().sum::<f64>() / nf;

    // scipy-style normalize-first dot product: scale by max-abs first,
    // then take the sqrt of the squared-sum, then dot product on the
    // normalized centred vectors. This avoids overflow on huge inputs
    // and matches scipy's computation order so r near ±1 lands at the
    // same float as scipy (e.g. -0.99999999999999967 instead of exact
    // -1) — relevant for the boundary pvalue (frankenscipy-vgl6u).
    let xm: Vec<f64> = x.iter().map(|&xi| xi - xmean).collect();
    let ym: Vec<f64> = y.iter().map(|&yi| yi - ymean).collect();
    let xmax = xm.iter().map(|v| v.abs()).fold(0.0_f64, f64::max);
    let ymax = ym.iter().map(|v| v.abs()).fold(0.0_f64, f64::max);
    if xmax == 0.0 || ymax == 0.0 {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }
    let normxm = xmax * xm.iter().map(|v| (v / xmax).powi(2)).sum::<f64>().sqrt();
    let normym = ymax * ym.iter().map(|v| (v / ymax).powi(2)).sum::<f64>().sqrt();
    if normxm == 0.0 || normym == 0.0 {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }
    let r = xm
        .iter()
        .zip(ym.iter())
        .map(|(&dx, &dy)| (dx / normxm) * (dy / normym))
        .sum::<f64>()
        .clamp(-1.0, 1.0);

    // p-value via the scipy convention: under the null, r is distributed
    // as Beta(n/2 − 1, n/2 − 1) on (−1, 1). Translate r ∈ [−1, 1] onto
    // u ∈ [0, 1] via u = (r + 1)/2 and call the standard BetaDist cdf.
    // The previous t-distribution path produced p = 0 exactly at r = ±1
    // because of the early clamp; the Beta path mirrors scipy and gives
    // a vanishingly small but non-zero pvalue at the boundary
    // (frankenscipy-vgl6u).
    let ab = nf / 2.0 - 1.0;
    let pvalue = if ab > 0.0 {
        let u = (r + 1.0) / 2.0;
        let beta = BetaDist::new(ab, ab);
        match alternative {
            "less" => beta.cdf(u),
            "greater" => regularized_incomplete_beta(ab, ab, 1.0 - u),
            // Beta(ab, ab) on (−1, 1) is symmetric around 0, so the
            // two-sided pvalue is 2·sf(|r|). Compute sf via the symmetry
            // identity I(x; a, b) = 1 − I(1−x; b, a) to avoid
            // catastrophic cancellation when |r| is close to 1.
            _ => {
                let u_abs = (r.abs() + 1.0) / 2.0;
                (2.0 * regularized_incomplete_beta(ab, ab, 1.0 - u_abs)).clamp(0.0, 1.0)
            }
        }
    } else {
        // df ≤ 0 (n ≤ 2): pvalue undefined.
        f64::NAN
    };

    CorrelationResult {
        statistic: r,
        pvalue,
    }
}

/// Calculate the Spearman rank-order correlation coefficient and p-value.
///
/// Matches `scipy.stats.spearmanr(a, b)`.
///
/// Uses the Pearson correlation of the rank-transformed data.
pub fn spearmanr(x: &[f64], y: &[f64]) -> CorrelationResult {
    let n = x.len();
    if n < 3 || n != y.len() {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let rank_x = rankdata_average(x);
    let rank_y = rankdata_average(y);

    pearsonr(&rank_x, &rank_y)
}

/// Spearman correlation with alternative hypothesis specification.
///
/// Matches `scipy.stats.spearmanr(a, b, alternative=...)`.
pub fn spearmanr_alternative(x: &[f64], y: &[f64], alternative: &str) -> CorrelationResult {
    let n = x.len();
    if n < 3 || n != y.len() {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let rank_x = rankdata_average(x);
    let rank_y = rankdata_average(y);
    let nf = n as f64;
    let xmean: f64 = rank_x.iter().sum::<f64>() / nf;
    let ymean: f64 = rank_y.iter().sum::<f64>() / nf;

    let (mut ssxm, mut ssym, mut ssxym) = (0.0, 0.0, 0.0);
    for (&xi, &yi) in rank_x.iter().zip(rank_y.iter()) {
        let (dx, dy) = (xi - xmean, yi - ymean);
        ssxm += dx * dx;
        ssym += dy * dy;
        ssxym += dx * dy;
    }

    let denom = (ssxm * ssym).sqrt();
    if denom == 0.0 {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let r = (ssxym / denom).clamp(-1.0, 1.0);
    let df = nf - 2.0;

    let pvalue = if df > 0.0 && r.abs() < 1.0 {
        let t = r * (df / (1.0 - r * r)).sqrt();
        let tdist = StudentT::new(df);
        match alternative {
            "less" => tdist.cdf(t),
            "greater" => tdist.sf(t),
            _ => 2.0 * tdist.sf(t.abs()),
        }
    } else if r >= 1.0 {
        // Perfect positive correlation: t → +∞. "less" tail covers
        // everything; "greater" tail covers nothing; two-sided is 0.
        match alternative {
            "less" => 1.0,
            _ => 0.0,
        }
    } else if r <= -1.0 {
        // Perfect negative correlation: t → −∞.
        match alternative {
            "greater" => 1.0,
            _ => 0.0,
        }
    } else {
        f64::NAN
    };

    CorrelationResult {
        statistic: r,
        pvalue,
    }
}

/// Compute ranks with a SciPy-style tie handling method.
///
/// Matches `scipy.stats.rankdata(a, method=...)` for the implemented methods.
pub fn rankdata(data: &[f64], method: Option<&str>) -> Result<Vec<f64>, StatsError> {
    match method.unwrap_or("average").to_ascii_lowercase().as_str() {
        "average" => Ok(rankdata_ties(data, RankTieMethod::Average)),
        "min" => Ok(rankdata_ties(data, RankTieMethod::Min)),
        "max" => Ok(rankdata_ties(data, RankTieMethod::Max)),
        "dense" => Ok(rankdata_ties(data, RankTieMethod::Dense)),
        "ordinal" => Ok(rankdata_ordinal(data)),
        _ => Err(StatsError::InvalidArgument(
            "method must be one of {'average', 'min', 'max', 'dense', 'ordinal'}".to_string(),
        )),
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum RankTieMethod {
    Average,
    Min,
    Max,
    Dense,
}

/// Compute ranks with average tie-breaking.
fn rankdata_average(data: &[f64]) -> Vec<f64> {
    rankdata_ties(data, RankTieMethod::Average)
}

fn rankdata_ties(data: &[f64], method: RankTieMethod) -> Vec<f64> {
    let n = data.len();
    if data.iter().any(|v| v.is_nan()) {
        return vec![f64::NAN; n];
    }

    let mut indexed: Vec<(f64, usize)> = data
        .iter()
        .copied()
        .enumerate()
        .map(|(i, v)| (v, i))
        .collect();
    indexed.sort_by(|a, b| a.0.total_cmp(&b.0));

    let mut ranks = vec![0.0; n];
    let mut i = 0;
    let mut dense_rank = 1.0;
    while i < n {
        let mut j = i + 1;
        while j < n && indexed[j].0 == indexed[i].0 {
            j += 1;
        }

        let tie_rank = match method {
            RankTieMethod::Average => (i + 1 + j) as f64 / 2.0,
            RankTieMethod::Min => (i + 1) as f64,
            RankTieMethod::Max => j as f64,
            RankTieMethod::Dense => dense_rank,
        };
        for item in &indexed[i..j] {
            ranks[item.1] = tie_rank;
        }
        i = j;
        dense_rank += 1.0;
    }

    ranks
}

/// Compute ranks with ordinal tie-breaking.
///
/// Tied elements receive distinct ranks according to the stable input order.
fn rankdata_ordinal(data: &[f64]) -> Vec<f64> {
    let n = data.len();
    if data.iter().any(|v| v.is_nan()) {
        return vec![f64::NAN; n];
    }
    let mut indexed: Vec<(f64, usize)> = data
        .iter()
        .copied()
        .enumerate()
        .map(|(i, v)| (v, i))
        .collect();
    indexed.sort_by(|a, b| a.0.total_cmp(&b.0).then(a.1.cmp(&b.1)));

    let mut ranks = vec![0.0; n];
    for (rank, item) in indexed.iter().enumerate() {
        ranks[item.1] = (rank + 1) as f64;
    }
    ranks
}

/// Returns sign of array elements (-1.0, 0.0, or 1.0).
///
/// Matches `scipy.stats.mstats.msign(x)`.
/// NaN values return NaN.
pub fn msign(data: &[f64]) -> Vec<f64> {
    data.iter()
        .map(|&x| {
            if x.is_nan() {
                f64::NAN
            } else if x > 0.0 {
                1.0
            } else if x < 0.0 {
                -1.0
            } else {
                0.0
            }
        })
        .collect()
}

/// Computes plotting positions for probability plots.
///
/// Matches `scipy.stats.mstats.plotting_positions(data, alpha, beta)`.
/// Uses the formula: p_i = (i - alpha) / (n + 1 - alpha - beta), where i is the rank.
///
/// Common (alpha, beta) values:
/// - (0.4, 0.4): Cunnane (default)
/// - (0.5, 0.5): Hazen
/// - (0.0, 0.0): Weibull
/// - (1.0, 1.0): R default
/// - (0.375, 0.375): Blom
/// - (1/3, 1/3): approximately median-unbiased
pub fn plotting_positions(data: &[f64], alpha: f64, beta: f64) -> Vec<f64> {
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    if n == 0 {
        return vec![];
    }
    let denom = n as f64 + 1.0 - alpha - beta;
    (1..=n).map(|i| (i as f64 - alpha) / denom).collect()
}

/// Counts tied groups in data by tie size.
///
/// Matches `scipy.stats.mstats.count_tied_groups(data)`.
/// Returns a map where keys are tie sizes and values are counts of groups with that size.
/// Groups of size 1 (no ties) are not included.
pub fn count_tied_groups(data: &[f64]) -> std::collections::HashMap<usize, usize> {
    use std::collections::HashMap;
    let mut counts: HashMap<usize, usize> = HashMap::new();
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    if sorted.is_empty() {
        return counts;
    }
    sorted.sort_by(|a, b| a.total_cmp(b));
    let mut i = 0;
    while i < sorted.len() {
        let mut j = i + 1;
        while j < sorted.len() && sorted[j] == sorted[i] {
            j += 1;
        }
        let tie_size = j - i;
        if tie_size > 1 {
            *counts.entry(tie_size).or_insert(0) += 1;
        }
        i = j;
    }
    counts
}

/// Compute the tie correction factor for rank-based statistical tests.
///
/// The tie correction factor T is used to adjust test statistics when
/// there are tied values in the data. It is defined as:
///
/// T = 1 - sum(t_i^3 - t_i) / (n^3 - n)
///
/// where t_i is the number of ties in group i and n is the total number of values.
///
/// Matches `scipy.stats.tiecorrect(rankvals)`.
///
/// # Arguments
/// * `rankvals` - Ranked data (typically from `rankdata` with method="average")
///
/// # Returns
/// The tie correction factor T, where 1.0 means no ties and values < 1.0
/// indicate the presence of ties.
pub fn tiecorrect(rankvals: &[f64]) -> f64 {
    let n = rankvals.len();
    if n < 2 {
        return 1.0;
    }

    let mut sorted = rankvals.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    let mut tie_sum = 0_i64;
    let mut i = 0;
    while i < n {
        let mut j = i + 1;
        while j < n && (sorted[j] - sorted[i]).abs() < 1e-10 {
            j += 1;
        }
        let t = (j - i) as i64;
        if t > 1 {
            tie_sum += t * t * t - t;
        }
        i = j;
    }

    let n3 = (n as i64) * (n as i64) * (n as i64) - (n as i64);
    if n3 == 0 {
        return 1.0;
    }

    1.0 - (tie_sum as f64) / (n3 as f64)
}

/// Result of `find_repeats`.
#[derive(Debug, Clone, PartialEq)]
pub struct RepeatsResult {
    /// Values that appear more than once.
    pub values: Vec<f64>,
    /// Count of each repeated value.
    pub counts: Vec<usize>,
}

/// Find repeated values in an array.
///
/// Returns a list of all values that appear more than once, along with
/// their occurrence counts.
///
/// Matches `scipy.stats.find_repeats(arr)`.
///
/// # Arguments
/// * `arr` - Input data array
///
/// # Returns
/// `RepeatsResult` containing vectors of repeated values and their counts.
pub fn find_repeats(arr: &[f64]) -> RepeatsResult {
    use std::collections::BTreeMap;

    if arr.is_empty() {
        return RepeatsResult {
            values: vec![],
            counts: vec![],
        };
    }

    // Count occurrences using ordered bits for f64 keys (to handle sorting)
    let mut count_map: BTreeMap<i64, (f64, usize)> = BTreeMap::new();
    for &val in arr {
        if val.is_nan() {
            continue;
        }
        let bits = val.to_bits() as i64;
        count_map
            .entry(bits)
            .and_modify(|(_, count)| *count += 1)
            .or_insert((val, 1));
    }

    // Extract only values with count > 1
    let mut values = Vec::new();
    let mut counts = Vec::new();

    for (_, (val, count)) in count_map {
        if count > 1 {
            values.push(val);
            counts.push(count);
        }
    }

    // Sort by value (ascending)
    let mut pairs: Vec<_> = values.into_iter().zip(counts).collect();
    pairs.sort_by(|a, b| a.0.total_cmp(&b.0));

    let (values, counts): (Vec<_>, Vec<_>) = pairs.into_iter().unzip();

    RepeatsResult { values, counts }
}

// ══════════════════════════════════════════════════════════════════════
// Summary Statistics
// ══════════════════════════════════════════════════════════════════════

/// Result of `describe`.
#[derive(Debug, Clone, PartialEq)]
pub struct DescribeResult {
    /// Number of observations.
    pub nobs: usize,
    /// Minimum and maximum values.
    pub minmax: (f64, f64),
    /// Arithmetic mean.
    pub mean: f64,
    /// Unbiased variance (ddof=1).
    pub variance: f64,
    /// Sample skewness (Fisher's definition).
    pub skewness: f64,
    /// Sample excess kurtosis (Fisher's definition).
    pub kurtosis: f64,
}

/// Compute several descriptive statistics of a data set.
///
/// Matches `scipy.stats.describe(a)`.
pub fn describe(data: &[f64]) -> DescribeResult {
    let n = data.len();
    if n < 2 {
        return DescribeResult {
            nobs: n,
            minmax: if n == 1 {
                (data[0], data[0])
            } else {
                (f64::NAN, f64::NAN)
            },
            mean: if n == 1 { data[0] } else { f64::NAN },
            variance: f64::NAN,
            skewness: f64::NAN,
            kurtosis: f64::NAN,
        };
    }

    let nf = n as f64;
    let mean_val = data.iter().sum::<f64>() / nf;
    let min_val = data.iter().copied().fold(f64::INFINITY, |a: f64, b: f64| {
        if a.is_nan() || b.is_nan() {
            f64::NAN
        } else {
            a.min(b)
        }
    });
    let max_val = data
        .iter()
        .copied()
        .fold(f64::NEG_INFINITY, |a: f64, b: f64| {
            if a.is_nan() || b.is_nan() {
                f64::NAN
            } else {
                a.max(b)
            }
        });

    let mut m2 = 0.0;
    let mut m3 = 0.0;
    let mut m4 = 0.0;
    for &x in data {
        let d = x - mean_val;
        let d2 = d * d;
        m2 += d2;
        m3 += d2 * d;
        m4 += d2 * d2;
    }

    let variance_val = m2 / (nf - 1.0);
    let skewness_val = skew_from_moments(nf, m2, m3);
    let kurtosis_val = kurtosis_from_moments(nf, m2, m4);

    DescribeResult {
        nobs: n,
        minmax: (min_val, max_val),
        mean: mean_val,
        variance: variance_val,
        skewness: skewness_val,
        kurtosis: kurtosis_val,
    }
}

/// Compute the sample skewness (Fisher's definition, bias=True).
///
/// Matches `scipy.stats.skew(a, bias=True)`.
/// skew = m3 / m2^(3/2) where m_k are central moments.
pub fn skew(data: &[f64]) -> f64 {
    let n = data.len();
    if n < 3 {
        return f64::NAN;
    }
    let nf = n as f64;
    let mean_val = data.iter().sum::<f64>() / nf;
    let mut m2 = 0.0;
    let mut m3 = 0.0;
    for &x in data {
        let d = x - mean_val;
        let d2 = d * d;
        m2 += d2;
        m3 += d2 * d;
    }
    skew_from_moments(nf, m2, m3)
}

/// Compute the sample excess kurtosis (Fisher's definition, bias=True).
///
/// Matches `scipy.stats.kurtosis(a, fisher=True, bias=True)`.
/// kurtosis = m4 / m2^2 - 3 where m_k are central moments.
pub fn kurtosis(data: &[f64]) -> f64 {
    let n = data.len();
    if n < 4 {
        return f64::NAN;
    }
    let nf = n as f64;
    let mean_val = data.iter().sum::<f64>() / nf;
    let mut m2 = 0.0;
    let mut m4 = 0.0;
    for &x in data {
        let d = x - mean_val;
        let d2 = d * d;
        m2 += d2;
        m4 += d2 * d2;
    }
    kurtosis_from_moments(nf, m2, m4)
}

/// Compute the median absolute deviation (MAD).
///
/// Matches `scipy.stats.median_abs_deviation(a, scale=1.0)`.
/// scipy DIVIDES the raw MAD by `scale`, so pass scale=1.4826
/// to get the normal-consistent std estimator.
pub fn median_abs_deviation(data: &[f64], scale: f64) -> f64 {
    if data.is_empty() || scale == 0.0 {
        return f64::NAN;
    }
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let med = quantile_sorted(&sorted, 0.5);

    let mut diffs: Vec<f64> = data.iter().map(|&x| (x - med).abs()).collect();
    diffs.sort_by(|a, b| a.total_cmp(b));
    let mad = quantile_sorted(&diffs, 0.5);
    mad / scale
}

/// Compute the mode (most frequent value) of a data set.
///
/// For continuous data, returns the smallest value among those with the
/// highest frequency. Returns NaN for empty input.
pub fn mode(data: &[f64]) -> f64 {
    if data.is_empty() || data.iter().any(|v| v.is_nan()) {
        return f64::NAN;
    }
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    let mut best_val = sorted[0];
    let mut best_count = 1usize;
    let mut current_val = sorted[0];
    let mut current_count = 1usize;

    for &v in &sorted[1..] {
        if v == current_val {
            current_count += 1;
        } else {
            if current_count > best_count {
                best_count = current_count;
                best_val = current_val;
            }
            current_val = v;
            current_count = 1;
        }
    }
    if current_count > best_count {
        best_val = current_val;
    }
    best_val
}

/// Compute the k-th central moment of a data set.
///
/// Matches `scipy.stats.moment(a, moment=k)`.
pub fn moment(data: &[f64], k: u32) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    if k == 0 {
        return 1.0;
    }
    let n = data.len() as f64;
    let mean_val = data.iter().sum::<f64>() / n;
    data.iter()
        .map(|&x| (x - mean_val).powi(k as i32))
        .sum::<f64>()
        / n
}

/// Compute the n-th k-statistic (unbiased cumulant estimator).
///
/// K-statistics are unbiased estimators of cumulants:
/// - k1 = sample mean (estimator of population mean)
/// - k2 = unbiased sample variance (estimator of variance)
/// - k3, k4 = higher cumulant estimators
///
/// Matches `scipy.stats.kstat(data, n)`.
///
/// # Arguments
/// * `data` - Input array
/// * `n` - Order of k-statistic (1, 2, 3, or 4)
///
/// # Returns
/// The n-th k-statistic, or NaN for invalid input.
pub fn kstat(data: &[f64], n: u32) -> f64 {
    if data.is_empty() || !(1..=4).contains(&n) {
        return f64::NAN;
    }

    let filtered: Vec<f64> = data.iter().copied().filter(|x| x.is_finite()).collect();
    let nn = filtered.len() as f64;
    if nn < n as f64 {
        return f64::NAN;
    }

    // Compute power sums S[k] = sum(x^k)
    let s1: f64 = filtered.iter().sum();
    let s2: f64 = filtered.iter().map(|&x| x * x).sum();
    let s3: f64 = filtered.iter().map(|&x| x * x * x).sum();
    let s4: f64 = filtered.iter().map(|&x| x.powi(4)).sum();

    match n {
        1 => s1 / nn,
        2 => (nn * s2 - s1 * s1) / (nn * (nn - 1.0)),
        3 => {
            if nn < 3.0 {
                return f64::NAN;
            }
            (2.0 * s1.powi(3) - 3.0 * nn * s1 * s2 + nn * nn * s3) / (nn * (nn - 1.0) * (nn - 2.0))
        }
        4 => {
            if nn < 4.0 {
                return f64::NAN;
            }
            (-6.0 * s1.powi(4) + 12.0 * nn * s1 * s1 * s2
                - 3.0 * nn * (nn - 1.0) * s2 * s2
                - 4.0 * nn * (nn + 1.0) * s1 * s3
                + nn * nn * (nn + 1.0) * s4)
                / (nn * (nn - 1.0) * (nn - 2.0) * (nn - 3.0))
        }
        _ => f64::NAN,
    }
}

/// Compute the variance of k-statistic under normality assumption.
///
/// Returns the variance of the n-th k-statistic assuming the data
/// comes from a normal distribution.
///
/// Matches `scipy.stats.kstatvar(data, n)`.
///
/// # Arguments
/// * `data` - Input array (only length is used)
/// * `n` - Order of k-statistic (1 or 2)
///
/// # Returns
/// Variance of k-statistic, or NaN for invalid input.
pub fn kstatvar(data: &[f64], n: u32) -> f64 {
    let filtered: Vec<f64> = data.iter().copied().filter(|x| x.is_finite()).collect();
    let nn = filtered.len() as f64;

    if nn < 2.0 || !(1..=2).contains(&n) {
        return f64::NAN;
    }

    // Compute k2 (unbiased variance estimate)
    let k2 = kstat(&filtered, 2);

    match n {
        1 => k2 / nn, // Var(k1) = k2/n
        2 => {
            // scipy's general unbiased variance-of-k2 estimator (does
            // NOT assume normality): var(k2) = (2*N*k2² + (N-1)*k4) /
            // (N*(N+1)). The previous formula 2*k2²/(N-1) was the
            // normal-distribution asymptotic and diverged from scipy
            // on non-normal samples.
            if nn < 4.0 {
                return f64::NAN;
            }
            let k4 = kstat(&filtered, 4);
            (2.0 * nn * k2 * k2 + (nn - 1.0) * k4) / (nn * (nn + 1.0))
        }
        _ => f64::NAN,
    }
}

/// Compute L-moments of a sample.
///
/// L-moments are summary statistics based on linear combinations of
/// order statistics. They are more robust to outliers than conventional moments.
///
/// Matches `scipy.stats.lmoment(sample, order, standardize=False)`.
///
/// # Arguments
/// * `data` - Input sample
/// * `order` - Order of L-moment (1, 2, 3, or 4)
///
/// # Returns
/// The L-moment of specified order, or NaN for invalid input.
pub fn lmoment(data: &[f64], order: u32) -> f64 {
    if data.is_empty() || !(1..=4).contains(&order) {
        return f64::NAN;
    }

    let mut sorted: Vec<f64> = data.iter().copied().filter(|x| x.is_finite()).collect();
    let n = sorted.len();
    if n < order as usize {
        return f64::NAN;
    }
    sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));

    let nf = n as f64;

    match order {
        1 => {
            // l_1 = mean
            sorted.iter().sum::<f64>() / nf
        }
        2 => {
            // l_2 = (1/C(n,2)) * sum_{i<j} (x_j - x_i) / 2
            // Equivalently: l_2 = (2/(n*(n-1))) * sum_i (i - (n+1)/2) * x_(i)
            let mut sum = 0.0;
            for (i, &x) in sorted.iter().enumerate() {
                let weight = (2.0 * (i as f64 + 1.0) - nf - 1.0) / (nf * (nf - 1.0));
                sum += weight * x;
            }
            sum
        }
        3 => {
            if n < 3 {
                return f64::NAN;
            }
            // l_3 using probability weighted moments: l_3 = 6*b_2 - 6*b_1 + b_0
            // where b_r = (1/n) * sum C(i-1,r)/C(n-1,r) * x_(i)
            let b0: f64 = sorted.iter().sum::<f64>() / nf;
            let mut b1 = 0.0;
            let mut b2 = 0.0;
            for (i, &x) in sorted.iter().enumerate() {
                let ii = i as f64;
                b1 += ii * x / (nf - 1.0);
                if n > 2 {
                    b2 += ii * (ii - 1.0) * x / ((nf - 1.0) * (nf - 2.0));
                }
            }
            b1 /= nf;
            b2 /= nf;
            6.0 * b2 - 6.0 * b1 + b0
        }
        4 => {
            if n < 4 {
                return f64::NAN;
            }
            // l_4 = 20*b_3 - 30*b_2 + 12*b_1 - b_0
            let b0: f64 = sorted.iter().sum::<f64>() / nf;
            let mut b1 = 0.0;
            let mut b2 = 0.0;
            let mut b3 = 0.0;
            for (i, &x) in sorted.iter().enumerate() {
                let ii = i as f64;
                b1 += ii * x / (nf - 1.0);
                b2 += ii * (ii - 1.0) * x / ((nf - 1.0) * (nf - 2.0));
                b3 += ii * (ii - 1.0) * (ii - 2.0) * x / ((nf - 1.0) * (nf - 2.0) * (nf - 3.0));
            }
            b1 /= nf;
            b2 /= nf;
            b3 /= nf;
            20.0 * b3 - 30.0 * b2 + 12.0 * b1 - b0
        }
        _ => f64::NAN,
    }
}

/// Binomial coefficient for floating point arguments.
#[allow(dead_code)]
fn comb(n: f64, k: f64) -> f64 {
    if k < 0.0 || k > n || n < 0.0 {
        return 0.0;
    }
    if k == 0.0 || k == n {
        return 1.0;
    }
    let k = k.min(n - k);
    let mut result = 1.0;
    for i in 0..(k as usize) {
        result *= (n - i as f64) / (i as f64 + 1.0);
    }
    result
}

/// Standard error of the mean.
///
/// Matches `scipy.stats.sem(a)`.
pub fn sem(data: &[f64]) -> f64 {
    let n = data.len();
    if n < 2 {
        return f64::NAN;
    }
    let nf = n as f64;
    let mean_val = data.iter().sum::<f64>() / nf;
    let var: f64 = data.iter().map(|&x| (x - mean_val).powi(2)).sum::<f64>() / (nf - 1.0);
    (var / nf).sqrt()
}

/// Credible interval result (statistic with low/high bounds).
#[derive(Debug, Clone, PartialEq)]
pub struct CredibleInterval {
    /// Point estimate.
    pub statistic: f64,
    /// Lower bound of credible interval.
    pub low: f64,
    /// Upper bound of credible interval.
    pub high: f64,
}

/// Result of Bayesian MVS estimation.
#[derive(Debug, Clone, PartialEq)]
pub struct BayesMvsResult {
    /// Mean estimate with credible interval.
    pub mean: CredibleInterval,
    /// Variance estimate with credible interval.
    pub variance: CredibleInterval,
    /// Standard deviation estimate with credible interval.
    pub std: CredibleInterval,
}

/// Bayesian credible intervals for mean, variance, and std.
///
/// Uses Jeffrey's prior. For mean, uses t-distribution.
/// For variance, uses chi-squared based intervals.
///
/// Matches `scipy.stats.bayes_mvs(data, alpha)`.
///
/// # Arguments
/// * `data` - Input data (requires at least 2 points)
/// * `alpha` - Credible level (e.g., 0.95 for 95% interval)
///
/// # Returns
/// `BayesMvsResult` with mean, variance, and std estimates.
pub fn bayes_mvs(data: &[f64], alpha: f64) -> BayesMvsResult {
    let n = data.len();
    if n < 2 || alpha <= 0.0 || alpha >= 1.0 {
        return BayesMvsResult {
            mean: CredibleInterval {
                statistic: f64::NAN,
                low: f64::NAN,
                high: f64::NAN,
            },
            variance: CredibleInterval {
                statistic: f64::NAN,
                low: f64::NAN,
                high: f64::NAN,
            },
            std: CredibleInterval {
                statistic: f64::NAN,
                low: f64::NAN,
                high: f64::NAN,
            },
        };
    }

    let nf = n as f64;
    let xbar = data.iter().sum::<f64>() / nf;
    let ss: f64 = data.iter().map(|&x| (x - xbar).powi(2)).sum();

    // For mean: t-distribution with df = n-1
    let df = nf - 1.0;
    let se = (ss / df / nf).sqrt();
    let tdist = StudentT::new(df);
    let t_crit = tdist.ppf(1.0 - (1.0 - alpha) / 2.0);

    let mean_est = CredibleInterval {
        statistic: xbar,
        low: xbar - t_crit * se,
        high: xbar + t_crit * se,
    };

    // For variance: Jeffreys-prior posterior is InverseGamma((n-1)/2, ss/2),
    // so the posterior mean is ss / (n - 3) and the central credible
    // interval uses the chi²(n-1) quantiles via σ² = ss / χ². The
    // .statistic field previously used the unbiased variance ss/(n-1)
    // (frankenscipy-u2y4u), which is the MLE / unbiased estimate, not
    // the posterior mean.
    let chi2_dist = GammaDist::new(df / 2.0, 2.0);
    let chi2_low = chi2_dist.ppf((1.0 - alpha) / 2.0);
    let chi2_high = chi2_dist.ppf(1.0 - (1.0 - alpha) / 2.0);

    let var_stat = if df > 2.0 { ss / (df - 2.0) } else { ss / df };

    let var_est = CredibleInterval {
        statistic: var_stat,
        low: ss / chi2_high,
        high: ss / chi2_low,
    };

    // Posterior mean of σ under the Jeffreys prior:
    //   E[σ | data] = sqrt(ss/2) · Γ((n-2)/2) / Γ((n-1)/2)
    // (sqrt of var_stat differs by a Gamma ratio that approaches 1 for
    // large n; for n=10 it's ~3.6% off scipy). Use the closed form.
    let std_stat = if df > 1.0 {
        let log_gamma_ratio = ln_gamma((df - 1.0) / 2.0) - ln_gamma(df / 2.0);
        (ss / 2.0).sqrt() * log_gamma_ratio.exp()
    } else {
        var_stat.sqrt()
    };

    let std_est = CredibleInterval {
        statistic: std_stat,
        low: (ss / chi2_high).sqrt(),
        high: (ss / chi2_low).sqrt(),
    };

    BayesMvsResult {
        mean: mean_est,
        variance: var_est,
        std: std_est,
    }
}

/// Interquartile range (IQR = Q3 - Q1).
///
/// Matches `scipy.stats.iqr(a)`.
pub fn iqr(data: &[f64]) -> f64 {
    if data.is_empty() || data.iter().any(|v| v.is_nan()) {
        return f64::NAN;
    }
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    quantile_sorted(&sorted, 0.75) - quantile_sorted(&sorted, 0.25)
}

/// Returns ideal fourths (robust quartile estimators).
///
/// Matches `scipy.stats.mstats.idealfourths(data)`.
/// Returns (lower_quartile, upper_quartile) using the ideal fourths algorithm.
pub fn idealfourths(data: &[f64]) -> (f64, f64) {
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    if n < 3 {
        return (f64::NAN, f64::NAN);
    }
    let nf = n as f64;
    let frac = nf / 4.0 + 5.0 / 12.0;
    let j = frac.floor() as usize;
    let h = frac - frac.floor();
    let qlo = (1.0 - h) * sorted[j - 1] + h * sorted[j];
    let k = n - j;
    let qup = (1.0 - h) * sorted[k] + h * sorted[k - 1];
    (qlo, qup)
}

/// Computes alpha-level confidence interval for the median.
///
/// Matches `scipy.stats.mstats.median_cihs(data, alpha)`.
/// Uses the Hettmasperger-Sheather method based on binomial distribution.
/// Returns (lower_bound, upper_bound).
pub fn median_cihs(data: &[f64], alpha: f64) -> (f64, f64) {
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    if n < 2 {
        return (f64::NAN, f64::NAN);
    }
    let alpha = alpha.min(1.0 - alpha);
    let binom = Binomial::new(n as u64, 0.5);

    let mut k = binomial_ppf(&binom, alpha / 2.0);
    let mut gk = binom.cdf(n as u64 - k) - binom.cdf(k.saturating_sub(1));
    if gk < 1.0 - alpha {
        k = k.saturating_sub(1);
        gk = binom.cdf(n as u64 - k) - binom.cdf(k.saturating_sub(1));
    }
    let gkk = binom.cdf(n as u64 - k - 1) - binom.cdf(k);
    let i_val = (gk - 1.0 + alpha) / (gk - gkk);
    let n_minus_k = n as f64 - k as f64;
    let lambd = n_minus_k * i_val / (k as f64 + (n as f64 - 2.0 * k as f64) * i_val);

    let k_idx = k as usize;
    // `k_idx > n` already guards against underflow in `n - k_idx` below;
    // the former `|| n - k_idx > n` dead code was a C-style overflow
    // check that does not translate to Rust's checked/panicking usize
    // arithmetic (br-q4md).
    if k_idx == 0 || k_idx > n {
        return (f64::NAN, f64::NAN);
    }
    let lo = lambd * sorted[k_idx] + (1.0 - lambd) * sorted[k_idx - 1];
    let hi = lambd * sorted[n - k_idx - 1] + (1.0 - lambd) * sorted[n - k_idx];
    (lo, hi)
}

fn binomial_ppf(binom: &Binomial, q: f64) -> u64 {
    if q <= 0.0 {
        return 0;
    }
    if q >= 1.0 {
        return binom.n;
    }
    for k in 0..=binom.n {
        if binom.cdf(k) >= q {
            return k;
        }
    }
    binom.n
}

/// Computes quantile estimates using the Harrell-Davis method.
///
/// Matches `scipy.stats.mstats.hdquantiles(data, prob)`.
/// Uses beta distribution weights for robust quantile estimation.
pub fn hdquantiles(data: &[f64], prob: &[f64]) -> Vec<f64> {
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    if n < 2 {
        return prob.iter().map(|_| f64::NAN).collect();
    }
    let nf = n as f64;
    prob.iter()
        .map(|&p| {
            if p <= 0.0 {
                return sorted[0];
            }
            if p >= 1.0 {
                return sorted[n - 1];
            }
            let a = (nf + 1.0) * p;
            let b = (nf + 1.0) * (1.0 - p);
            let beta = BetaDist::new(a, b);
            let mut hd_sum = 0.0;
            for (k, &val) in sorted.iter().enumerate() {
                let w = beta.cdf((k + 1) as f64 / nf) - beta.cdf(k as f64 / nf);
                hd_sum += w * val;
            }
            hd_sum
        })
        .collect()
}

/// Computes the Harrell-Davis median estimate.
///
/// Matches `scipy.stats.mstats.hdmedian(data)`.
pub fn hdmedian(data: &[f64]) -> f64 {
    let result = hdquantiles(data, &[0.5]);
    result[0]
}

/// Computes standard error of Harrell-Davis quantile estimates by jackknife.
///
/// Matches `scipy.stats.mstats.hdquantiles_sd(data, prob)`.
pub fn hdquantiles_sd(data: &[f64], prob: &[f64]) -> Vec<f64> {
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    if n < 2 {
        return prob.iter().map(|_| f64::NAN).collect();
    }
    let nf = n as f64;
    let nm1 = n - 1;
    let nm1f = nm1 as f64;

    prob.iter()
        .map(|&p| {
            if p <= 0.0 || p >= 1.0 {
                return f64::NAN;
            }
            let a = nf * p;
            let b = nf * (1.0 - p);
            let beta = BetaDist::new(a, b);

            let vv: Vec<f64> = (0..n).map(|i| i as f64 / nm1f).collect();
            let beta_cdf: Vec<f64> = vv.iter().map(|&v| beta.cdf(v)).collect();
            let w: Vec<f64> = (0..nm1).map(|i| beta_cdf[i + 1] - beta_cdf[i]).collect();

            let mut mx = vec![0.0; n];
            let mut cumsum = 0.0;
            for i in 1..n {
                cumsum += w[i - 1] * sorted[i - 1];
                mx[i] = cumsum;
            }
            let mut right_cumsum: Vec<f64> = vec![0.0; nm1];
            cumsum = 0.0;
            for i in (0..nm1).rev() {
                cumsum += w[i] * sorted[i + 1];
                right_cumsum[i] = cumsum;
            }
            for i in 0..nm1 {
                mx[i] += right_cumsum[i];
            }

            let mean_mx = mx.iter().sum::<f64>() / nf;
            let var_mx = mx.iter().map(|&x| (x - mean_mx).powi(2)).sum::<f64>() / nf;
            (var_mx * nm1f).sqrt()
        })
        .collect()
}

/// Computes empirical quantiles using configurable plotting positions.
///
/// Matches `scipy.stats.mstats.mquantiles(a, prob, alphap, betap)`.
/// Returns quantiles at the specified probabilities using the formula:
/// Q(p) = (1-g)*x[j] + g*x[j+1], where j = floor(n*p + m), m = alphap + p*(1 - alphap - betap).
///
/// Common (alphap, betap) values:
/// - (0.4, 0.4): Cunnane (default) - approximately quantile unbiased
/// - (0.5, 0.5): R type 5 - piecewise linear
/// - (1.0, 1.0): R type 7 - R default
/// - (0.0, 0.0): R type 6
/// - (1/3, 1/3): R type 8 - approximately median-unbiased
pub fn mquantiles(data: &[f64], prob: &[f64], alphap: f64, betap: f64) -> Vec<f64> {
    let mut sorted: Vec<f64> = data.iter().copied().filter(|v| !v.is_nan()).collect();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let n = sorted.len();
    if n == 0 {
        return prob.iter().map(|_| f64::NAN).collect();
    }
    let nf = n as f64;
    prob.iter()
        .map(|&p| {
            if !(0.0..=1.0).contains(&p) {
                return f64::NAN;
            }
            let m = alphap + p * (1.0 - alphap - betap);
            // scipy.stats.mstats.mquantiles formula:
            //   aleph = n*p + m
            //   k     = clip(floor(aleph), 1, n-1)        — clip applied to FLOOR
            //   gamma = (aleph - k).clip(0, 1)            — gamma uses unclipped aleph
            //   Q(p)  = (1 - gamma)*data[k-1] + gamma*data[k]
            // fsci's previous code used `saturating_sub(1)` on the floor
            // without clipping (silent k=0/gamma=aleph for sub-1 alephs).
            // See [frankenscipy-13w1q].
            let aleph = nf * p + m;
            let k_unclipped = aleph.floor();
            let k = if n >= 2 {
                k_unclipped.clamp(1.0, nf - 1.0) as usize
            } else {
                1
            };
            let gamma = (aleph - k as f64).clamp(0.0, 1.0);
            let lo = k - 1;
            let hi = k.min(n - 1);
            (1.0 - gamma) * sorted[lo] + gamma * sorted[hi]
        })
        .collect()
}

/// Coefficient of variation (std / mean).
///
/// Matches `scipy.stats.variation(a)`.
pub fn variation(data: &[f64]) -> f64 {
    if data.len() < 2 {
        return f64::NAN;
    }
    let n = data.len() as f64;
    let mean_val = data.iter().sum::<f64>() / n;
    if mean_val == 0.0 {
        return f64::NAN;
    }
    let var: f64 = data.iter().map(|&x| (x - mean_val).powi(2)).sum::<f64>() / n;
    var.sqrt() / mean_val
}

fn mean_std_ddof(data: &[f64], ddof: usize) -> Option<(f64, f64)> {
    let n = data.len();
    if n == 0 || n <= ddof {
        return None;
    }
    let mean = data.iter().sum::<f64>() / n as f64;
    let var = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / (n - ddof) as f64;
    Some((mean, var.sqrt()))
}

/// Compute z-scores: (x - mean) / std.
///
/// Matches `scipy.stats.zscore(a)`.
pub fn zscore(data: &[f64]) -> Vec<f64> {
    let Some((mean_val, std_val)) = mean_std_ddof(data, 0) else {
        return vec![f64::NAN; data.len()];
    };
    if std_val == 0.0 {
        return vec![f64::NAN; data.len()];
    }
    data.iter().map(|&x| (x - mean_val) / std_val).collect()
}

/// Compute relative z-scores using the mean and variance of `compare`.
///
/// Matches the core 1D behavior of `scipy.stats.zmap(scores, compare)`.
pub fn zmap(scores: &[f64], compare: &[f64]) -> Vec<f64> {
    zmap_ddof(scores, compare, 0)
}

/// Compute relative z-scores with an explicit degrees-of-freedom correction.
///
/// Matches the core 1D behavior of `scipy.stats.zmap(scores, compare, ddof=...)`.
pub fn zmap_ddof(scores: &[f64], compare: &[f64], ddof: usize) -> Vec<f64> {
    let Some((mean, std)) = mean_std_ddof(compare, ddof) else {
        return vec![f64::NAN; scores.len()];
    };

    let mut out: Vec<f64> = scores.iter().map(|&score| (score - mean) / std).collect();

    // SciPy's zscore special-cases the exact same array object by replacing
    // constant slices with NaN rather than leaving mixed NaN/inf outputs.
    let same_slice =
        core::ptr::eq(scores.as_ptr(), compare.as_ptr()) && scores.len() == compare.len();
    if same_slice && std <= (f64::EPSILON * mean).abs() {
        out.fill(f64::NAN);
    }

    out
}

/// Compute the geometric z-score for strictly positive data.
///
/// Matches the core 1D behavior of `scipy.stats.gzscore(a)`.
pub fn gzscore(data: &[f64]) -> Vec<f64> {
    gzscore_ddof(data, 0)
}

/// Compute the geometric z-score with an explicit degrees-of-freedom correction.
///
/// Matches the core 1D behavior of `scipy.stats.gzscore(a, ddof=...)`.
pub fn gzscore_ddof(data: &[f64], ddof: usize) -> Vec<f64> {
    let logged: Vec<f64> = data.iter().map(|&value| value.ln()).collect();
    zscore_ddof(&logged, ddof)
}

/// Compute the q-th percentile of data.
///
/// Uses linear interpolation between data points.
/// `q` should be in [0, 100].
///
/// Matches `numpy.percentile(data, q)`.
pub fn percentile(data: &[f64], q: f64) -> f64 {
    if data.is_empty() || q.is_nan() || data.iter().any(|v| v.is_nan()) {
        return f64::NAN;
    }
    let q_frac = (q / 100.0).clamp(0.0, 1.0);
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    quantile_sorted(&sorted, q_frac)
}

/// Compute the percentile rank of a score relative to a list of scores.
///
/// Returns the percentage of values in `data` that are less than or equal to
/// the given `score`, depending on the `kind` parameter.
///
/// # Arguments
/// * `data` - Input data array
/// * `score` - Score to compute percentile rank for
/// * `kind` - Method of calculation:
///   - `"rank"` (default): Average percentage ranking of score
///   - `"weak"`: Percentage of values < score
///   - `"strict"`: Percentage of values <= score
///   - `"mean"`: Average of weak and strict
///
/// Matches `scipy.stats.percentileofscore(a, score, kind)`.
pub fn percentileofscore(data: &[f64], score: f64, kind: Option<&str>) -> f64 {
    if data.is_empty() {
        return f64::NAN;
    }
    let kind = kind.unwrap_or("rank");
    let n = data.len() as f64;

    let n_less = data.iter().filter(|&&x| x < score).count() as f64;
    let n_equal = data
        .iter()
        .filter(|&&x| (x - score).abs() < f64::EPSILON)
        .count() as f64;

    // scipy convention:
    //   left  = count(< score)            = n_less
    //   right = count(<= score)            = n_less + n_equal
    //   plus1 = 1 if score is in data (left < right) else 0
    //   rank  = (left + right + plus1) * 50 / n
    //   weak  = right * 100 / n            (% values <= score)
    //   strict= left * 100 / n             (% values < score)
    //   mean  = (left + right) * 50 / n    (avg of weak and strict)
    let plus1: f64 = if n_equal > 0.0 { 1.0 } else { 0.0 };
    let right = n_less + n_equal;
    match kind {
        "rank" => (n_less + right + plus1) * 50.0 / n,
        "weak" => right * 100.0 / n,
        "strict" => n_less * 100.0 / n,
        "mean" => (n_less + right) * 50.0 / n,
        _ => f64::NAN,
    }
}

/// Compute scores at one or more percentiles of the input sequence.
///
/// Matches the implemented SciPy `scoreatpercentile(a, per, limit=..., interpolation_method=...)`
/// behavior for 1-D inputs.
pub fn scoreatpercentile(
    data: &[f64],
    per: &[f64],
    limit: Option<(f64, f64)>,
    interpolation_method: Option<&str>,
) -> Result<Vec<f64>, StatsError> {
    let method = interpolation_method
        .unwrap_or("fraction")
        .to_ascii_lowercase();
    if !matches!(method.as_str(), "fraction" | "lower" | "higher") {
        return Err(StatsError::InvalidArgument(
            "interpolation_method must be one of {'fraction', 'lower', 'higher'}".to_string(),
        ));
    }

    if data.is_empty() {
        return Ok(vec![f64::NAN; per.len()]);
    }

    let mut filtered = if let Some((lower, upper)) = limit {
        data.iter()
            .copied()
            .filter(|value| lower <= *value && *value <= upper)
            .collect::<Vec<_>>()
    } else {
        data.to_vec()
    };

    if filtered.is_empty() || filtered.iter().any(|value| value.is_nan()) {
        return Ok(vec![f64::NAN; per.len()]);
    }

    filtered.sort_by(|a, b| a.total_cmp(b));
    per.iter()
        .copied()
        .map(|percentile| scoreatpercentile_single(&filtered, percentile, &method))
        .collect()
}

/// Compute the mean after trimming a proportion from each tail.
///
/// Matches `scipy.stats.trim_mean(a, proportiontocut)`.
///
/// # Arguments
/// * `data` — Input array
/// * `proportiontocut` — Fraction to trim from each end (0.0 to 0.5)
pub fn trim_mean(data: &[f64], proportiontocut: f64) -> f64 {
    if data.is_empty() || data.iter().any(|v| v.is_nan()) {
        return f64::NAN;
    }
    let prop = proportiontocut.clamp(0.0, 0.5);
    let n = data.len();
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    let ncut = (n as f64 * prop).floor() as usize;
    let trimmed = &sorted[ncut..n - ncut];
    if trimmed.is_empty() {
        return f64::NAN;
    }
    trimmed.iter().sum::<f64>() / trimmed.len() as f64
}

/// Trim a proportion of elements from both ends of a sorted array.
///
/// Slices off the given proportion from **each** end of the sorted input array,
/// returning the middle portion.
///
/// Matches `scipy.stats.trimboth(a, proportiontocut)`.
///
/// # Arguments
/// * `data` — Input array
/// * `proportiontocut` — Fraction to trim from each end (0.0 to 0.5)
///
/// # Returns
/// A new vector containing the trimmed middle portion of the sorted data.
pub fn trimboth(data: &[f64], proportiontocut: f64) -> Vec<f64> {
    if data.is_empty() {
        return vec![];
    }
    let prop = proportiontocut.clamp(0.0, 0.5);
    let n = data.len();
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    let ncut = (n as f64 * prop).floor() as usize;
    if 2 * ncut >= n {
        return vec![];
    }
    sorted[ncut..n - ncut].to_vec()
}

/// Trim a proportion of elements from one tail of a sorted array.
///
/// Slices off the given proportion from the specified tail of the sorted input,
/// returning the remaining portion.
///
/// Matches `scipy.stats.trim1(a, proportiontocut, tail)`.
///
/// # Arguments
/// * `data` — Input array
/// * `proportiontocut` — Fraction to trim (0.0 to 1.0)
/// * `tail` — Which tail to trim: `"right"` (high values), `"left"` (low values),
///   or `"both"` (equivalent to `trimboth`)
///
/// # Returns
/// A new vector containing the trimmed sorted data.
pub fn trim1(data: &[f64], proportiontocut: f64, tail: &str) -> Vec<f64> {
    if data.is_empty() {
        return vec![];
    }
    let prop = proportiontocut.clamp(0.0, 1.0);
    let n = data.len();
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    let ncut = (n as f64 * prop).floor() as usize;

    match tail {
        "left" => {
            if ncut >= n {
                vec![]
            } else {
                sorted[ncut..].to_vec()
            }
        }
        "right" => {
            if ncut >= n {
                vec![]
            } else {
                sorted[..n - ncut].to_vec()
            }
        }
        "both" => {
            let ncut_both = (n as f64 * prop.min(0.5)).floor() as usize;
            if 2 * ncut_both >= n {
                vec![]
            } else {
                sorted[ncut_both..n - ncut_both].to_vec()
            }
        }
        _ => sorted, // unknown tail, return sorted data unchanged
    }
}

/// Compute the trimmed variance of an array.
///
/// Values outside the specified limits are excluded before computing variance.
///
/// Matches `scipy.stats.tvar(a, limits, inclusive, ddof)`.
///
/// # Arguments
/// * `data` — Input array
/// * `limits` — Tuple of (lower, upper) limits. Values outside are excluded.
/// * `inclusive` — Tuple of bools: whether limits are inclusive (lower, upper)
/// * `ddof` — Delta degrees of freedom (default 1 for sample variance)
///
/// # Returns
/// The trimmed variance, or NaN if fewer than ddof+1 values remain.
pub fn tvar(data: &[f64], limits: (f64, f64), inclusive: (bool, bool), ddof: usize) -> f64 {
    let filtered: Vec<f64> = data
        .iter()
        .copied()
        .filter(|&x| {
            let above_lower = if inclusive.0 {
                x >= limits.0
            } else {
                x > limits.0
            };
            let below_upper = if inclusive.1 {
                x <= limits.1
            } else {
                x < limits.1
            };
            above_lower && below_upper
        })
        .collect();

    if filtered.len() <= ddof {
        return f64::NAN;
    }

    let n = filtered.len() as f64;
    let mean = filtered.iter().sum::<f64>() / n;
    let sum_sq: f64 = filtered.iter().map(|&x| (x - mean).powi(2)).sum();
    sum_sq / (n - ddof as f64)
}

/// Compute the trimmed standard deviation of an array.
///
/// Values outside the specified limits are excluded before computing std dev.
///
/// Matches `scipy.stats.tstd(a, limits, inclusive, ddof)`.
///
/// # Arguments
/// * `data` — Input array
/// * `limits` — Tuple of (lower, upper) limits. Values outside are excluded.
/// * `inclusive` — Tuple of bools: whether limits are inclusive (lower, upper)
/// * `ddof` — Delta degrees of freedom (default 1 for sample std dev)
///
/// # Returns
/// The trimmed standard deviation, or NaN if fewer than ddof+1 values remain.
pub fn tstd(data: &[f64], limits: (f64, f64), inclusive: (bool, bool), ddof: usize) -> f64 {
    tvar(data, limits, inclusive, ddof).sqrt()
}

/// Compute the trimmed mean of an array.
///
/// Values outside the specified limits are excluded before computing mean.
///
/// Matches `scipy.stats.tmean(a, limits, inclusive)`.
///
/// # Arguments
/// * `data` — Input array
/// * `limits` — Tuple of (lower, upper) limits. Values outside are excluded.
/// * `inclusive` — Tuple of bools: whether limits are inclusive (lower, upper)
///
/// # Returns
/// The trimmed mean, or NaN if no values remain after filtering.
pub fn tmean(data: &[f64], limits: (f64, f64), inclusive: (bool, bool)) -> f64 {
    let filtered: Vec<f64> = data
        .iter()
        .copied()
        .filter(|&x| {
            let above_lower = if inclusive.0 {
                x >= limits.0
            } else {
                x > limits.0
            };
            let below_upper = if inclusive.1 {
                x <= limits.1
            } else {
                x < limits.1
            };
            above_lower && below_upper
        })
        .collect();

    if filtered.is_empty() {
        return f64::NAN;
    }

    filtered.iter().sum::<f64>() / filtered.len() as f64
}

/// Compute the trimmed standard error of the mean.
///
/// Values outside the specified limits are excluded before computing SEM.
///
/// Matches `scipy.stats.tsem(a, limits, inclusive, ddof)`.
///
/// # Arguments
/// * `data` — Input array
/// * `limits` — Tuple of (lower, upper) limits. Values outside are excluded.
/// * `inclusive` — Tuple of bools: whether limits are inclusive (lower, upper)
/// * `ddof` — Delta degrees of freedom (default 1)
///
/// # Returns
/// The trimmed SEM, or NaN if fewer than ddof+1 values remain.
pub fn tsem(data: &[f64], limits: (f64, f64), inclusive: (bool, bool), ddof: usize) -> f64 {
    let filtered: Vec<f64> = data
        .iter()
        .copied()
        .filter(|&x| {
            let above_lower = if inclusive.0 {
                x >= limits.0
            } else {
                x > limits.0
            };
            let below_upper = if inclusive.1 {
                x <= limits.1
            } else {
                x < limits.1
            };
            above_lower && below_upper
        })
        .collect();

    if filtered.len() <= ddof {
        return f64::NAN;
    }

    let n = filtered.len() as f64;
    let mean = filtered.iter().sum::<f64>() / n;
    let sum_sq: f64 = filtered.iter().map(|&x| (x - mean).powi(2)).sum();
    let var = sum_sq / (n - ddof as f64);
    (var / n).sqrt()
}

/// Compute the trimmed minimum.
///
/// Returns the minimum value greater than (or equal to) the lower limit.
///
/// Matches `scipy.stats.tmin(a, lowerlimit, inclusive=True)`.
///
/// # Arguments
/// * `data` - Input array
/// * `lowerlimit` - Values below this are ignored
/// * `inclusive` - If true, values equal to limit are included
///
/// # Returns
/// The trimmed minimum, or NaN if no values remain.
pub fn tmin(data: &[f64], lowerlimit: f64, inclusive: bool) -> f64 {
    let filtered: Vec<f64> = data
        .iter()
        .copied()
        .filter(|&x| {
            x.is_finite()
                && if inclusive {
                    x >= lowerlimit
                } else {
                    x > lowerlimit
                }
        })
        .collect();

    if filtered.is_empty() {
        return f64::NAN;
    }

    filtered.iter().copied().fold(f64::INFINITY, f64::min)
}

/// Compute the trimmed maximum.
///
/// Returns the maximum value less than (or equal to) the upper limit.
///
/// Matches `scipy.stats.tmax(a, upperlimit, inclusive=True)`.
///
/// # Arguments
/// * `data` - Input array
/// * `upperlimit` - Values above this are ignored
/// * `inclusive` - If true, values equal to limit are included
///
/// # Returns
/// The trimmed maximum, or NaN if no values remain.
pub fn tmax(data: &[f64], upperlimit: f64, inclusive: bool) -> f64 {
    let filtered: Vec<f64> = data
        .iter()
        .copied()
        .filter(|&x| {
            x.is_finite()
                && if inclusive {
                    x <= upperlimit
                } else {
                    x < upperlimit
                }
        })
        .collect();

    if filtered.is_empty() {
        return f64::NAN;
    }

    filtered.iter().copied().fold(f64::NEG_INFINITY, f64::max)
}

/// Compute the expectile at a given alpha level.
///
/// Expectiles are a generalization of the mean (alpha=0.5). They solve the
/// asymmetric least squares problem where observations above the expectile
/// are weighted by alpha and observations below are weighted by (1-alpha).
///
/// Matches `scipy.stats.expectile(a, alpha)`.
///
/// # Arguments
/// * `data` — Input array
/// * `alpha` — Expectile level in (0, 1). Default 0.5 gives the mean.
///
/// # Returns
/// The expectile value, or NaN for empty input or invalid alpha.
pub fn expectile(data: &[f64], alpha: f64) -> f64 {
    if data.is_empty() || alpha <= 0.0 || alpha >= 1.0 {
        return f64::NAN;
    }

    let filtered: Vec<f64> = data.iter().copied().filter(|x| x.is_finite()).collect();
    if filtered.is_empty() {
        return f64::NAN;
    }

    // Start with the mean as initial guess
    let mut mu = filtered.iter().sum::<f64>() / filtered.len() as f64;

    // Iteratively solve for the expectile using weighted least squares
    for _ in 0..100 {
        let mut sum_w = 0.0;
        let mut sum_wx = 0.0;

        for &x in &filtered {
            let w = if x >= mu { alpha } else { 1.0 - alpha };
            sum_w += w;
            sum_wx += w * x;
        }

        let new_mu = sum_wx / sum_w;
        if (new_mu - mu).abs() < 1e-12 {
            return new_mu;
        }
        mu = new_mu;
    }

    mu
}

/// Estimate the differential entropy of a continuous distribution from samples.
///
/// Uses the Vasicek spacing estimator with window length m. The entropy is
/// estimated as: H = (1/n) * sum(ln(n/(2m) * (X_{i+m} - X_{i-m})))
///
/// Matches `scipy.stats.differential_entropy(values, window_length, base)`.
///
/// # Arguments
/// * `values` — Sample data
/// * `window_length` — Window length for spacing estimator. If None, uses floor(sqrt(n))
/// * `base` — Logarithm base. If None, uses natural log (e)
///
/// # Returns
/// Estimated differential entropy, or NaN for insufficient data.
pub fn differential_entropy(
    values: &[f64],
    window_length: Option<usize>,
    base: Option<f64>,
) -> f64 {
    let filtered: Vec<f64> = values.iter().copied().filter(|x| x.is_finite()).collect();
    let n = filtered.len();

    if n < 2 {
        return f64::NAN;
    }

    // Default window length: floor(sqrt(n))
    let m = window_length
        .unwrap_or_else(|| (n as f64).sqrt().floor() as usize)
        .max(1);

    if 2 * m >= n {
        return f64::NAN;
    }

    // Sort the data
    let mut sorted = filtered;
    sorted.sort_by(|a, b| a.total_cmp(b));

    // Vasicek spacing estimator
    let mut sum_log = 0.0;
    let scale = n as f64 / (2.0 * m as f64);

    for i in m..(n - m) {
        let spacing = sorted[i + m] - sorted[i - m];
        if spacing > 0.0 {
            sum_log += (scale * spacing).ln();
        } else {
            sum_log += f64::NEG_INFINITY;
        }
    }

    let h = sum_log / (n - 2 * m) as f64;

    // Convert to requested base
    if let Some(b) = base
        && b > 0.0
        && b != 1.0
    {
        return h / b.ln();
    }

    h
}

/// Apply O'Brien's transform to test for homogeneity of variance.
///
/// The O'Brien transform converts data for use in a one-way ANOVA to test
/// whether the variances of multiple groups are equal. Each value x_ij is
/// transformed to:
///
/// r_ij = ((n-1.5)*n*(x_ij - mean)^2 - 0.5*var*(n-1)) / ((n-1)*(n-2))
///
/// Matches `scipy.stats.obrientransform(*args)`.
///
/// # Arguments
/// * `groups` — Slice of data groups to transform
///
/// # Returns
/// Vector of transformed groups, or empty if any group has fewer than 3 elements.
pub fn obrientransform(groups: &[&[f64]]) -> Vec<Vec<f64>> {
    let mut result = Vec::with_capacity(groups.len());

    for &group in groups {
        let n = group.len();
        if n < 3 {
            return vec![];
        }

        let n_f = n as f64;
        let mean = group.iter().sum::<f64>() / n_f;
        let var = group.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / (n_f - 1.0);

        let mut transformed = Vec::with_capacity(n);
        let denom = (n_f - 1.0) * (n_f - 2.0);

        for &x in group {
            let diff_sq = (x - mean).powi(2);
            let r = ((n_f - 1.5) * n_f * diff_sq - 0.5 * var * (n_f - 1.0)) / denom;
            transformed.push(r);
        }

        result.push(transformed);
    }

    result
}

/// Result of Page's trend test.
#[derive(Debug, Clone, PartialEq)]
pub struct PageTrendResult {
    /// Page's L statistic.
    pub statistic: f64,
    /// Approximate p-value (one-sided, for increasing trend).
    pub pvalue: f64,
}

/// Perform Page's L test for a monotonic trend in ranked data.
///
/// Tests whether there is a monotonic trend across ordered conditions.
/// Data should be organized as rows (subjects/blocks) by columns (conditions).
///
/// Matches `scipy.stats.page_trend_test(data)`.
///
/// # Arguments
/// * `data` — 2D data where each inner slice is a row (subject), columns are conditions
///
/// # Returns
/// `PageTrendResult` with L statistic and approximate p-value.
pub fn page_trend_test(data: &[&[f64]]) -> PageTrendResult {
    let n = data.len(); // number of subjects/blocks
    if n == 0 {
        return PageTrendResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let k = data[0].len(); // number of conditions
    if k < 2 || data.iter().any(|row| row.len() != k) {
        return PageTrendResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    // Rank within each row
    let mut rank_sums = vec![0.0; k];

    for row in data {
        // Get ranks for this row
        let mut indexed: Vec<(usize, f64)> = row.iter().copied().enumerate().collect();
        indexed.sort_by(|a, b| a.1.total_cmp(&b.1));

        let mut ranks = vec![0.0; k];
        let mut i = 0;
        while i < k {
            let mut j = i + 1;
            while j < k && (indexed[j].1 - indexed[i].1).abs() < 1e-10 {
                j += 1;
            }
            let avg_rank = (i + 1 + j) as f64 / 2.0;
            for idx in i..j {
                ranks[indexed[idx].0] = avg_rank;
            }
            i = j;
        }

        for (col, &rank) in ranks.iter().enumerate() {
            rank_sums[col] += rank;
        }
    }

    // Compute L statistic: sum of (condition_index + 1) * rank_sum
    let l: f64 = rank_sums
        .iter()
        .enumerate()
        .map(|(i, &r)| (i + 1) as f64 * r)
        .sum();

    // Expected value and variance under null hypothesis
    let n_f = n as f64;
    let k_f = k as f64;
    let expected_l = n_f * k_f * (k_f + 1.0).powi(2) / 4.0;
    let var_l = n_f * k_f.powi(2) * (k_f + 1.0).powi(2) * (k_f - 1.0) / 144.0;

    // Z-score approximation
    let z = (l - expected_l) / var_l.sqrt();

    // One-sided p-value (testing for increasing trend)
    let pvalue = 1.0 - standard_normal_cdf(z);

    PageTrendResult {
        statistic: l,
        pvalue,
    }
}

/// Compute a weighted Kendall's tau correlation.
///
/// Weighted tau gives more importance to elements with higher ranks.
/// Uses the default hyperbolic weigher: w(i, j) = 1/(i+1) + 1/(j+1).
///
/// Matches `scipy.stats.weightedtau(x, y)` with default parameters.
///
/// # Arguments
/// * `x` — First ranking
/// * `y` — Second ranking
///
/// # Returns
/// Weighted tau correlation coefficient, or NaN for insufficient data.
pub fn weightedtau(x: &[f64], y: &[f64]) -> f64 {
    let n = x.len();
    if n != y.len() || n < 2 {
        return f64::NAN;
    }

    // scipy.stats.weightedtau defaults to rank=True which averages two τ
    // computations using the *decreasing* lexicographical rank by (x, y)
    // and by (y, x). fsci's rank_values returns ascending ranks (lowest=0),
    // so we flip to descending: highest value gets the most-important rank 0.
    let n_minus_one = (n - 1) as f64;
    let asc_x = rank_values(x);
    let asc_y = rank_values(y);
    let desc_x: Vec<f64> = asc_x.iter().map(|r| n_minus_one - r).collect();
    let desc_y: Vec<f64> = asc_y.iter().map(|r| n_minus_one - r).collect();

    let tau_x = weightedtau_one_side(x, y, &desc_x);
    let tau_y = weightedtau_one_side(x, y, &desc_y);
    if !tau_x.is_finite() || !tau_y.is_finite() {
        return f64::NAN;
    }
    (tau_x + tau_y) / 2.0
}

fn weightedtau_one_side(x: &[f64], y: &[f64], ranks: &[f64]) -> f64 {
    let n = x.len();
    let mut weighted_concordant = 0.0;
    let mut weighted_discordant = 0.0;
    let mut total_weight = 0.0;

    for i in 0..n {
        for j in (i + 1)..n {
            // Hyperbolic weigher applied to the chosen ranking.
            let w = 1.0 / (ranks[i] + 1.0) + 1.0 / (ranks[j] + 1.0);

            let x_diff = x[i] - x[j];
            let y_diff = y[i] - y[j];
            let sign = x_diff * y_diff;

            if sign > 0.0 {
                weighted_concordant += w;
            } else if sign < 0.0 {
                weighted_discordant += w;
            }
            // ties contribute 0

            total_weight += w;
        }
    }

    if total_weight == 0.0 {
        return f64::NAN;
    }

    (weighted_concordant - weighted_discordant) / total_weight
}

/// Helper to get ranks (0-indexed) for weighted tau
fn rank_values(data: &[f64]) -> Vec<f64> {
    let n = data.len();
    let mut indexed: Vec<(usize, f64)> = data.iter().copied().enumerate().collect();
    indexed.sort_by(|a, b| a.1.total_cmp(&b.1));

    let mut ranks = vec![0.0; n];
    let mut i = 0;
    while i < n {
        let mut j = i + 1;
        while j < n && (indexed[j].1 - indexed[i].1).abs() < 1e-10 {
            j += 1;
        }
        let avg_rank = (i + j - 1) as f64 / 2.0;
        for k in i..j {
            ranks[indexed[k].0] = avg_rank;
        }
        i = j;
    }
    ranks
}

/// Result for Chatterjee's Xi correlation.
#[derive(Debug, Clone, PartialEq)]
pub struct ChatterjeeXiResult {
    /// Xi correlation statistic.
    pub statistic: f64,
    /// p-value for independence test.
    pub pvalue: f64,
}

/// Result for multiscale graph correlation.
///
/// Stores the selected MGC statistic, permutation p-value, full local
/// correlation map, and the one-based optimal local scale.
#[derive(Debug, Clone, PartialEq)]
pub struct MultiscaleGraphcorrResult {
    /// Selected multiscale graph correlation statistic in `[0, 1]`.
    pub statistic: f64,
    /// Permutation p-value. Matches SciPy's `1.0` sentinel when `reps == 0`.
    pub pvalue: f64,
    /// Local correlation map across all tested scale pairs.
    pub mgc_map: Vec<Vec<f64>>,
    /// One-based optimal scale in the local correlation map.
    pub opt_scale: (usize, usize),
}

/// Compute Chatterjee's Xi correlation coefficient and independence test.
///
/// Measures association between two variables. Effective even when the
/// association is not monotonic. Returns ~0 for independent variables
/// and ~1 when Y is a measurable function of X.
///
/// Matches `scipy.stats.chatterjeexi(x, y, y_continuous=True)`.
///
/// # Arguments
/// * `x` - Observations of the independent variable
/// * `y` - Corresponding observations of the dependent variable
///
/// # Returns
/// `ChatterjeeXiResult` with statistic and p-value.
///
/// # References
/// Chatterjee, S. (2021). A new coefficient of correlation.
/// Journal of the American Statistical Association.
pub fn chatterjeexi(x: &[f64], y: &[f64]) -> ChatterjeeXiResult {
    let n = x.len();
    if n != y.len() || n < 2 {
        return ChatterjeeXiResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    // Sort indices by x values
    let mut indices: Vec<usize> = (0..n).collect();
    indices.sort_by(|&a, &b| x[a].total_cmp(&x[b]));

    // Reorder y by sorted x
    let y_sorted: Vec<f64> = indices.iter().map(|&i| y[i]).collect();

    // Compute ranks of y_sorted using max method
    let r = rank_max(&y_sorted);

    // Compute sum of |r_{i+1} - r_i|
    let mut num = 0.0;
    for i in 0..(n - 1) {
        num += (r[i + 1] - r[i]).abs();
    }

    // Using y_continuous=True formula: xi = 1 - 3 * num / (n^2 - 1)
    let n_f = n as f64;
    let statistic = 1.0 - 3.0 * num / (n_f * n_f - 1.0);

    // Asymptotic standard deviation for continuous Y: sqrt(2/5) / sqrt(n)
    let std = (2.0_f64 / 5.0).sqrt() / n_f.sqrt();

    // p-value from standard normal (one-tailed, greater)
    let z = statistic / std;
    let pvalue = 1.0 - standard_normal_cdf(z);

    ChatterjeeXiResult { statistic, pvalue }
}

/// Compute the multiscale graph correlation (MGC) statistic.
///
/// MGC is a dependence measure that adapts to the complexity of the relationship
/// between X and Y by computing local correlations at different scales and
/// selecting the optimal scale. This implementation follows Vogelstein et al.
/// (2019) "Discovering and deciphering relationships across disparate data
/// modalities".
///
/// The algorithm:
/// 1. Computes pairwise distance matrices for X and Y
/// 2. Ranks distances within each row to identify k-nearest neighbors
/// 3. Computes local correlations at each scale (k, l) using k-NN for X, l-NN for Y
/// 4. Builds an n×n mgc_map of local correlations
/// 5. Finds optimal scale by smoothing and centering the map
///
/// When `reps > 0`, a permutation test estimates the p-value.
///
/// Matches `scipy.stats.multiscale_graphcorr(x, y, reps=reps, random_state=...)`.
pub fn multiscale_graphcorr(
    x: &[Vec<f64>],
    y: &[Vec<f64>],
    reps: usize,
    random_state: Option<u64>,
) -> Result<MultiscaleGraphcorrResult, StatsError> {
    if x.len() != y.len() {
        return Err(StatsError::InvalidArgument(
            "x and y must have same number of observations".to_string(),
        ));
    }
    validate_graphcorr_observations("x", x)?;
    validate_graphcorr_observations("y", y)?;

    let n = x.len();

    // Compute distance matrices
    let dist_x = pairwise_euclidean_distance_matrix(x);
    let dist_y = pairwise_euclidean_distance_matrix(y);

    // Compute rank matrices (for each row, rank of each distance)
    let rank_x = compute_row_ranks(&dist_x);
    let rank_y = compute_row_ranks(&dist_y);

    // Center the distance matrices
    let centered_x = double_center_distance_matrix(&dist_x);
    let centered_y = double_center_distance_matrix(&dist_y);

    // Build the full n×n mgc_map of local correlations
    let mgc_map = compute_mgc_map(&centered_x, &centered_y, &rank_x, &rank_y, n);

    // Find optimal scale using the smoothed/centered approach
    let (opt_k, opt_l, statistic) = find_optimal_scale(&mgc_map, n);

    // Compute p-value via permutation if requested
    let pvalue = if reps == 0 {
        1.0
    } else {
        mgc_permutation_pvalue(
            &centered_x,
            &centered_y,
            &rank_x,
            &rank_y,
            n,
            statistic,
            reps,
            random_state,
        )
    };

    Ok(MultiscaleGraphcorrResult {
        statistic,
        pvalue,
        mgc_map,
        opt_scale: (opt_k, opt_l),
    })
}

/// Compute row-wise ranks of a distance matrix.
/// For each row, assigns rank 1 to smallest distance, 2 to next, etc.
/// Diagonal (self-distance = 0) gets rank 0.
fn compute_row_ranks(distances: &[Vec<f64>]) -> Vec<Vec<usize>> {
    let n = distances.len();
    let mut ranks = vec![vec![0usize; n]; n];

    for i in 0..n {
        // Get indices sorted by distance (excluding self)
        let mut indexed: Vec<(usize, f64)> = distances[i]
            .iter()
            .enumerate()
            .filter(|(j, _)| *j != i)
            .map(|(j, &d)| (j, d))
            .collect();
        indexed.sort_by(|a, b| a.1.total_cmp(&b.1).then_with(|| a.0.cmp(&b.0)));

        // Self-distance is always rank 0, even when duplicate observations
        // create additional zero distances in the same row.
        ranks[i][i] = 0;
        for (rank, (j, _)) in indexed.iter().enumerate() {
            ranks[i][*j] = rank + 1;
        }
    }
    ranks
}

/// Compute the MGC map of local correlations at each scale (k, l).
/// mgc_map[k][l] is the local correlation using k-NN for X and l-NN for Y.
fn compute_mgc_map(
    centered_x: &[Vec<f64>],
    centered_y: &[Vec<f64>],
    rank_x: &[Vec<usize>],
    rank_y: &[Vec<usize>],
    n: usize,
) -> Vec<Vec<f64>> {
    let mut mgc_map = vec![vec![0.0; n]; n];

    for k in 1..=n {
        for l in 1..=n {
            mgc_map[k - 1][l - 1] =
                local_correlation(centered_x, centered_y, rank_x, rank_y, k, l, n);
        }
    }

    mgc_map
}

/// Compute local correlation at scale (k, l).
/// Uses only pairs (i, j) where j is within k-nearest neighbors of i in X
/// AND i is within l-nearest neighbors of j in Y (or vice versa for symmetry).
fn local_correlation(
    centered_x: &[Vec<f64>],
    centered_y: &[Vec<f64>],
    rank_x: &[Vec<usize>],
    rank_y: &[Vec<usize>],
    k: usize,
    l: usize,
    n: usize,
) -> f64 {
    // Build indicator matrix: A[i][j] = 1 if rank_x[i][j] <= k AND rank_y[i][j] <= l
    // Using the symmetric formulation from MGC paper
    let mut sum_xy = 0.0;
    let mut sum_xx = 0.0;
    let mut sum_yy = 0.0;
    let mut count = 0.0;

    for i in 0..n {
        for j in 0..n {
            if i == j {
                continue;
            }
            // Include (i,j) if within k-NN for X and l-NN for Y
            if rank_x[i][j] < k && rank_y[i][j] < l {
                sum_xy += centered_x[i][j] * centered_y[i][j];
                sum_xx += centered_x[i][j] * centered_x[i][j];
                sum_yy += centered_y[i][j] * centered_y[i][j];
                count += 1.0;
            }
        }
    }

    if count < 1.0 || sum_xx <= f64::EPSILON || sum_yy <= f64::EPSILON {
        return 0.0;
    }

    let corr = sum_xy / (sum_xx.sqrt() * sum_yy.sqrt());
    corr.clamp(-1.0, 1.0).max(0.0) // MGC uses non-negative correlations
}

/// Find optimal scale in the MGC map.
/// Returns (opt_k, opt_l, statistic) using SciPy's thresholded connected region.
fn find_optimal_scale(mgc_map: &[Vec<f64>], n: usize) -> (usize, usize, f64) {
    if n == 0 {
        return (1, 1, 0.0);
    }

    let mut statistic = mgc_map[n - 1][n - 1];
    let mut best_k = n;
    let mut best_l = n;
    let significant_region = threshold_mgc_map(mgc_map, n);
    let significant_area = significant_region
        .iter()
        .flatten()
        .filter(|&&is_significant| is_significant)
        .count();
    let required_area = (0.02 * n as f64).ceil() as usize * n;

    if significant_area >= required_area {
        for k in 0..n {
            for l in 0..n {
                if significant_region[k][l] && mgc_map[k][l] > statistic + 1.0e-12 {
                    statistic = mgc_map[k][l];
                    best_k = k + 1;
                    best_l = l + 1;
                }
            }
        }
    }

    (best_k, best_l, statistic)
}

fn threshold_mgc_map(mgc_map: &[Vec<f64>], n: usize) -> Vec<Vec<bool>> {
    if n <= 1 {
        return vec![vec![false; n]; n];
    }

    let sample_size = (n - 1) as f64;
    let percentile = 1.0 - (0.02 / sample_size);
    let beta_shape = sample_size * (sample_size - 3.0) / 4.0 - 0.5;
    let beta_quantile = fsci_special::betaincinv_scalar(beta_shape, beta_shape, percentile);
    let mut threshold = beta_quantile.mul_add(2.0, -1.0);
    threshold = threshold.max(mgc_map[n - 1][n - 1]);

    let significant: Vec<Vec<bool>> = mgc_map
        .iter()
        .map(|row| row.iter().map(|&value| value > threshold).collect())
        .collect();
    largest_connected_component(&significant, n)
}

fn largest_connected_component(significant: &[Vec<bool>], n: usize) -> Vec<Vec<bool>> {
    let mut seen = vec![vec![false; n]; n];
    let mut best_component = Vec::new();

    for row in 0..n {
        for col in 0..n {
            if !significant[row][col] || seen[row][col] {
                continue;
            }

            let mut component = Vec::new();
            let mut stack = vec![(row, col)];
            seen[row][col] = true;
            while let Some((cur_row, cur_col)) = stack.pop() {
                component.push((cur_row, cur_col));

                for (next_row, next_col) in mgc_neighbors(cur_row, cur_col, n) {
                    if significant[next_row][next_col] && !seen[next_row][next_col] {
                        seen[next_row][next_col] = true;
                        stack.push((next_row, next_col));
                    }
                }
            }

            if component.len() > best_component.len() {
                best_component = component;
            }
        }
    }

    let mut largest = vec![vec![false; n]; n];
    for (row, col) in best_component {
        largest[row][col] = true;
    }
    largest
}

fn mgc_neighbors(row: usize, col: usize, n: usize) -> impl Iterator<Item = (usize, usize)> {
    [
        row.checked_sub(1).map(|next| (next, col)),
        col.checked_sub(1).map(|next| (row, next)),
        (row + 1 < n).then_some((row + 1, col)),
        (col + 1 < n).then_some((row, col + 1)),
    ]
    .into_iter()
    .flatten()
}

/// Compute p-value for MGC via permutation test.
#[allow(clippy::too_many_arguments)]
fn mgc_permutation_pvalue(
    centered_x: &[Vec<f64>],
    centered_y: &[Vec<f64>],
    rank_x: &[Vec<usize>],
    rank_y: &[Vec<usize>],
    n: usize,
    observed: f64,
    reps: usize,
    random_state: Option<u64>,
) -> f64 {
    let mut rng = StdRng::seed_from_u64(random_state.unwrap_or(0));
    let mut permutation: Vec<usize> = (0..n).collect();
    let mut exceedances = 1usize;

    for _ in 0..reps {
        permutation.shuffle(&mut rng);

        // Permute Y's centered matrix and ranks
        let perm_centered_y = permute_matrix(centered_y, &permutation);
        let perm_rank_y = permute_matrix_usize(rank_y, &permutation);

        // Compute MGC map for permuted data
        let perm_map = compute_mgc_map(centered_x, &perm_centered_y, rank_x, &perm_rank_y, n);
        let (_, _, perm_stat) = find_optimal_scale(&perm_map, n);

        if perm_stat >= observed - 1e-12 {
            exceedances += 1;
        }
    }

    exceedances as f64 / (reps + 1) as f64
}

/// Permute rows and columns of a matrix according to a permutation.
fn permute_matrix(matrix: &[Vec<f64>], perm: &[usize]) -> Vec<Vec<f64>> {
    let n = matrix.len();
    let mut result = vec![vec![0.0; n]; n];
    for i in 0..n {
        for j in 0..n {
            result[i][j] = matrix[perm[i]][perm[j]];
        }
    }
    result
}

/// Permute rows and columns of a usize matrix according to a permutation.
fn permute_matrix_usize(matrix: &[Vec<usize>], perm: &[usize]) -> Vec<Vec<usize>> {
    let n = matrix.len();
    let mut result = vec![vec![0usize; n]; n];
    for i in 0..n {
        for j in 0..n {
            result[i][j] = matrix[perm[i]][perm[j]];
        }
    }
    result
}

fn validate_graphcorr_observations(name: &str, data: &[Vec<f64>]) -> Result<(), StatsError> {
    if data.len() < 2 {
        return Err(StatsError::InvalidArgument(format!(
            "{name} must contain at least two observations"
        )));
    }

    let width = data.first().map_or(0, Vec::len);
    if width == 0 {
        return Err(StatsError::InvalidArgument(format!(
            "{name} observations must be non-empty"
        )));
    }

    for row in data {
        if row.len() != width {
            return Err(StatsError::InvalidArgument(format!(
                "{name} must be rectangular with constant row width"
            )));
        }
        if row.iter().any(|value| !value.is_finite()) {
            return Err(StatsError::InvalidArgument(format!(
                "{name} must contain only finite values"
            )));
        }
    }

    Ok(())
}

fn pairwise_euclidean_distance_matrix(data: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let n = data.len();
    let mut distances = vec![vec![0.0; n]; n];
    for i in 0..n {
        for j in (i + 1)..n {
            let distance = data[i]
                .iter()
                .zip(data[j].iter())
                .map(|(left, right)| {
                    let delta = left - right;
                    delta * delta
                })
                .sum::<f64>()
                .sqrt();
            distances[i][j] = distance;
            distances[j][i] = distance;
        }
    }
    distances
}

fn double_center_distance_matrix(distances: &[Vec<f64>]) -> Vec<Vec<f64>> {
    let n = distances.len();
    if n == 0 {
        return Vec::new();
    }

    let row_means: Vec<f64> = distances
        .iter()
        .map(|row| row.iter().sum::<f64>() / n as f64)
        .collect();
    let mut column_means = vec![0.0; n];
    for row in distances {
        for (j, value) in row.iter().enumerate() {
            column_means[j] += value;
        }
    }
    for mean in &mut column_means {
        *mean /= n as f64;
    }
    let total_mean = row_means.iter().sum::<f64>() / n as f64;

    let mut centered = vec![vec![0.0; n]; n];
    for i in 0..n {
        for j in 0..n {
            centered[i][j] = distances[i][j] - row_means[i] - column_means[j] + total_mean;
        }
    }
    centered
}

/// Compute ranks using max method (number of values <= this value)
fn rank_max(data: &[f64]) -> Vec<f64> {
    let n = data.len();
    let mut ranks = vec![0.0; n];

    for i in 0..n {
        let mut count = 0.0;
        for j in 0..n {
            if data[j] <= data[i] {
                count += 1.0;
            }
        }
        ranks[i] = count;
    }
    ranks
}

/// Result of sigma clipping operation.
#[derive(Debug, Clone, PartialEq)]
pub struct SigmaClipResult {
    /// Clipped data array (values within bounds).
    pub clipped: Vec<f64>,
    /// Lower bound used for clipping.
    pub lower: f64,
    /// Upper bound used for clipping.
    pub upper: f64,
}

/// Iteratively sigma-clip data to remove outliers.
///
/// Performs iterative sigma-clipping of array elements. Starting from the full
/// array, elements outside the range [mean - low*std, mean + high*std] are
/// removed. The clipping is repeated until no more elements are removed.
///
/// Matches `scipy.stats.sigmaclip(a, low=low, high=high)`.
///
/// # Arguments
/// * `data` - Input data array
/// * `low` - Number of standard deviations below mean for lower clipping bound
/// * `high` - Number of standard deviations above mean for upper clipping bound
///
/// # Returns
/// `SigmaClipResult` containing clipped array and final bounds.
pub fn sigmaclip(data: &[f64], low: f64, high: f64) -> SigmaClipResult {
    if data.is_empty() {
        return SigmaClipResult {
            clipped: vec![],
            lower: f64::NAN,
            upper: f64::NAN,
        };
    }

    let mut clipped: Vec<f64> = data.iter().copied().filter(|x| x.is_finite()).collect();

    if clipped.is_empty() {
        return SigmaClipResult {
            clipped: vec![],
            lower: f64::NAN,
            upper: f64::NAN,
        };
    }

    loop {
        let n = clipped.len() as f64;
        let mean_val = clipped.iter().sum::<f64>() / n;
        let variance = clipped.iter().map(|&x| (x - mean_val).powi(2)).sum::<f64>() / n;
        let std_val = variance.sqrt();

        let lower = mean_val - low * std_val;
        let upper = mean_val + high * std_val;

        let new_clipped: Vec<f64> = clipped
            .iter()
            .copied()
            .filter(|&x| x >= lower && x <= upper)
            .collect();

        if new_clipped.len() == clipped.len() {
            return SigmaClipResult {
                clipped,
                lower,
                upper,
            };
        }

        if new_clipped.is_empty() {
            return SigmaClipResult {
                clipped: vec![],
                lower: f64::NAN,
                upper: f64::NAN,
            };
        }

        clipped = new_clipped;
    }
}

/// Result for quantile test.
#[derive(Debug, Clone, PartialEq)]
pub struct QuantileTestResult {
    /// Test statistic (T1 or T2 count).
    pub statistic: usize,
    /// Which statistic was used (1 or 2).
    pub statistic_type: u8,
    /// p-value for the test.
    pub pvalue: f64,
}

/// Nonparametric test for a population quantile.
///
/// Tests H0: the p-th population quantile equals q.
/// Uses binomial distribution for the test.
///
/// Matches `scipy.stats.quantile_test(x, q=q, p=p)`.
///
/// # Arguments
/// * `x` - Sample data
/// * `q` - Hypothesized quantile value
/// * `p` - Probability level (0 < p < 1), default 0.5 for median
///
/// # Returns
/// `QuantileTestResult` with statistic, statistic_type, and pvalue.
pub fn quantile_test(x: &[f64], q: f64, p: f64) -> QuantileTestResult {
    let n = x.len();
    if n == 0 || !(0.0..1.0).contains(&p) || p == 0.0 {
        return QuantileTestResult {
            statistic: 0,
            statistic_type: 0,
            pvalue: f64::NAN,
        };
    }

    // T1 = count of x <= q
    let t1 = x.iter().filter(|&&xi| xi <= q).count();
    // T2 = count of x < q
    let t2 = x.iter().filter(|&&xi| xi < q).count();

    let binom = Binomial::new(n as u64, p);

    // For two-sided: use the statistic that gives smaller p-value
    // p_greater: P(Y <= t1) for alternative='greater'
    // p_less: P(Y >= t2) = 1 - P(Y < t2) = 1 - P(Y <= t2-1) for alternative='less'

    let p_greater = DiscreteDistribution::cdf(&binom, t1 as u64);
    let p_less = if t2 > 0 {
        1.0 - DiscreteDistribution::cdf(&binom, (t2 - 1) as u64)
    } else {
        1.0
    };

    // Two-sided: min of doubled p-values, clipped to [0, 1]
    let (statistic, statistic_type, pvalue) = if p_greater <= p_less {
        (t1, 1, (2.0 * p_greater).min(1.0))
    } else {
        (t2, 2, (2.0 * p_less).min(1.0))
    };

    QuantileTestResult {
        statistic,
        statistic_type,
        pvalue,
    }
}

/// Exact binomial test.
///
/// Tests H0: probability of success = p, given k successes in n trials.
/// Returns (k, n, two-sided p-value).
///
/// Matches `scipy.stats.binomtest(k, n, p)`.
pub fn binomtest(k: u64, n: u64, p: f64) -> f64 {
    if n == 0 || k > n || p.is_nan() || !(0.0..=1.0).contains(&p) {
        return f64::NAN;
    }
    if p == 0.0 {
        return if k == 0 { 1.0 } else { 0.0 };
    }
    if p == 1.0 {
        return if k == n { 1.0 } else { 0.0 };
    }

    let binom = Binomial::new(n, p);

    // Two-sided p-value: sum P(X=j) for all j where P(X=j) <= P(X=k)
    let p_observed = DiscreteDistribution::pmf(&binom, k);
    let mut pvalue = 0.0;
    for j in 0..=n {
        let p_j = DiscreteDistribution::pmf(&binom, j);
        if p_j <= p_observed + 1e-14 {
            pvalue += p_j;
        }
    }
    pvalue.min(1.0)
}

// Internal helpers for skewness and kurtosis
fn skew_from_moments(n: f64, m2: f64, m3: f64) -> f64 {
    if m2 == 0.0 {
        return f64::NAN;
    }
    let m2_n = m2 / n;
    let m3_n = m3 / n;
    m3_n / m2_n.powf(1.5)
}

fn kurtosis_from_moments(n: f64, m2: f64, m4: f64) -> f64 {
    if m2 == 0.0 {
        return f64::NAN; // Degenerate: all values identical
    }
    let m2_n = m2 / n;
    let m4_n = m4 / n;
    m4_n / (m2_n * m2_n) - 3.0
}

fn quantile_sorted(sorted: &[f64], q: f64) -> f64 {
    let n = sorted.len();
    if n == 0 {
        return f64::NAN;
    }
    if n == 1 {
        return sorted[0];
    }
    let pos = q * (n - 1) as f64;
    let lo = pos.floor() as usize;
    let hi = pos.ceil() as usize;
    let frac = pos - lo as f64;
    if lo == hi {
        sorted[lo]
    } else {
        sorted[lo] * (1.0 - frac) + sorted[hi] * frac
    }
}

fn scoreatpercentile_single(
    sorted: &[f64],
    per: f64,
    interpolation_method: &str,
) -> Result<f64, StatsError> {
    if !(0.0..=100.0).contains(&per) || per.is_nan() {
        return Err(StatsError::InvalidArgument(
            "percentile must be in the range [0, 100]".to_string(),
        ));
    }
    if sorted.is_empty() {
        return Ok(f64::NAN);
    }
    if sorted.len() == 1 {
        return Ok(sorted[0]);
    }

    let idx = per / 100.0 * (sorted.len() - 1) as f64;
    let lower = idx.floor() as usize;
    let upper = idx.ceil() as usize;

    if lower == upper {
        return Ok(sorted[lower]);
    }

    let value = match interpolation_method {
        "fraction" => {
            let frac = idx - lower as f64;
            sorted[lower] * (1.0 - frac) + sorted[upper] * frac
        }
        "lower" => sorted[lower],
        "higher" => sorted[upper],
        other => {
            return Err(StatsError::InvalidArgument(format!(
                "interpolation_method must be one of {{'fraction', 'lower', 'higher'}}, got {other}"
            )));
        }
    };
    Ok(value)
}

