/// Result of a goodness-of-fit test.
#[derive(Debug, Clone, PartialEq)]
pub struct GoodnessOfFitResult {
    /// Test statistic.
    pub statistic: f64,
    /// p-value.
    pub pvalue: f64,
}

/// Result of the Anderson-Darling test.
#[derive(Debug, Clone, PartialEq)]
pub struct AndersonResult {
    /// Test statistic.
    pub statistic: f64,
    /// Critical values at significance levels [15%, 10%, 5%, 2.5%, 1%].
    pub critical_values: [f64; 5],
    /// Significance levels corresponding to critical values.
    pub significance_level: [f64; 5],
}

/// Result of the k-sample Anderson-Darling test.
#[derive(Debug, Clone, PartialEq)]
pub struct AndersonKSampleResult {
    /// Normalized k-sample Anderson-Darling statistic.
    pub statistic: f64,
    /// Critical values at significance levels [25%, 10%, 5%, 2.5%, 1%, 0.5%, 0.1%].
    pub critical_values: [f64; 7],
    /// Approximate p-value, capped to [0.001, 0.25] without permutation mode.
    pub pvalue: f64,
}

/// Variant of the k-sample Anderson-Darling test.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AndersonKSampleVariant {
    Midrank,
    Right,
    Continuous,
}

/// Target distribution or reference sample for `kstest`.
pub enum KstestTarget<'a> {
    /// One-sample KS against a reference CDF.
    Cdf(fn(f64) -> f64),
    /// Two-sample KS against another sample.
    Sample(&'a [f64]),
}

/// P-value method for the two-sample Cramer-von Mises test.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Cvm2SampleMethod {
    Auto,
    Exact,
    Asymptotic,
}

fn anderson_ksamp_statistic_midrank(
    samples: &[Vec<f64>],
    pooled: &[f64],
    unique: &[f64],
    n: &[usize],
    total: usize,
) -> f64 {
    let mut statistic = 0.0;
    let z_left: Vec<usize> = unique
        .iter()
        .map(|&value| pooled.partition_point(|x| *x < value))
        .collect();
    let lj: Vec<f64> = if total == unique.len() {
        vec![1.0; unique.len()]
    } else {
        unique
            .iter()
            .zip(z_left.iter())
            .map(|(&value, &left)| (pooled.partition_point(|x| *x <= value) - left) as f64)
            .collect()
    };
    let bj: Vec<f64> = z_left
        .iter()
        .zip(lj.iter())
        .map(|(&left, &count)| left as f64 + count / 2.0)
        .collect();

    for (sample, &sample_n) in samples.iter().zip(n.iter()) {
        let mut sorted = sample.clone();
        sorted.sort_by(f64::total_cmp);
        let right_counts: Vec<usize> = unique
            .iter()
            .map(|&value| sorted.partition_point(|x| *x <= value))
            .collect();
        let left_counts: Vec<usize> = unique
            .iter()
            .map(|&value| sorted.partition_point(|x| *x < value))
            .collect();
        let mij: Vec<f64> = right_counts
            .iter()
            .zip(left_counts.iter())
            .map(|(&right, &left)| right as f64 - (right - left) as f64 / 2.0)
            .collect();

        let mut inner_sum = 0.0;
        for ((&l_j, &b_j), &m_ij) in lj.iter().zip(bj.iter()).zip(mij.iter()) {
            let denominator = b_j * (total as f64 - b_j) - total as f64 * l_j / 4.0;
            if denominator > 0.0 {
                let term = l_j / total as f64
                    * (total as f64 * m_ij - b_j * sample_n as f64).powi(2)
                    / denominator;
                inner_sum += term;
            }
        }
        statistic += inner_sum / sample_n as f64;
    }

    statistic * (total as f64 - 1.0) / total as f64
}

fn anderson_ksamp_statistic_right(
    samples: &[Vec<f64>],
    pooled: &[f64],
    unique: &[f64],
    n: &[usize],
    total: usize,
) -> f64 {
    let unique_prefix = &unique[..unique.len().saturating_sub(1)];
    let lj: Vec<f64> = unique_prefix
        .iter()
        .map(|&value| {
            let left = pooled.partition_point(|x| *x < value);
            let right = pooled.partition_point(|x| *x <= value);
            (right - left) as f64
        })
        .collect();
    let mut bj = Vec::with_capacity(lj.len());
    let mut running = 0.0;
    for &count in &lj {
        running += count;
        bj.push(running);
    }

    let mut statistic = 0.0;
    for (sample, &sample_n) in samples.iter().zip(n.iter()) {
        let mut sorted = sample.clone();
        sorted.sort_by(f64::total_cmp);
        let mij: Vec<f64> = unique_prefix
            .iter()
            .map(|&value| sorted.partition_point(|x| *x <= value) as f64)
            .collect();
        let mut inner_sum = 0.0;
        for ((&l_j, &b_j), &m_ij) in lj.iter().zip(bj.iter()).zip(mij.iter()) {
            let denominator = b_j * (total as f64 - b_j);
            if denominator > 0.0 {
                inner_sum += l_j / total as f64
                    * (total as f64 * m_ij - b_j * sample_n as f64).powi(2)
                    / denominator;
            }
        }
        statistic += inner_sum / sample_n as f64;
    }
    statistic
}

fn anderson_ksamp_statistic_continuous(
    samples: &[Vec<f64>],
    pooled: &[f64],
    n: &[usize],
    total: usize,
) -> f64 {
    let mut statistic = 0.0;
    let js: Vec<f64> = (1..total).map(|j| j as f64).collect();

    for (sample, &sample_n) in samples.iter().zip(n.iter()) {
        let mut sorted = sample.clone();
        sorted.sort_by(f64::total_cmp);
        let mij: Vec<f64> = pooled[..pooled.len().saturating_sub(1)]
            .iter()
            .map(|&value| sorted.partition_point(|x| *x <= value) as f64)
            .collect();
        let mut inner_sum = 0.0;
        for (&j, &m_ij) in js.iter().zip(mij.iter()) {
            inner_sum +=
                (total as f64 * m_ij - j * sample_n as f64).powi(2) / (j * (total as f64 - j));
        }
        statistic += inner_sum / sample_n as f64;
    }

    statistic / total as f64
}

fn quadratic_least_squares_eval(xs: &[f64], ys: &[f64], x: f64) -> f64 {
    let n = xs.len() as f64;
    let sum_x = xs.iter().sum::<f64>();
    let sum_x2 = xs.iter().map(|value| value * value).sum::<f64>();
    let sum_x3 = xs.iter().map(|value| value * value * value).sum::<f64>();
    let sum_x4 = xs
        .iter()
        .map(|value| value * value * value * value)
        .sum::<f64>();
    let sum_y = ys.iter().sum::<f64>();
    let sum_xy = xs
        .iter()
        .zip(ys.iter())
        .map(|(xv, yv)| xv * yv)
        .sum::<f64>();
    let sum_x2y = xs
        .iter()
        .zip(ys.iter())
        .map(|(xv, yv)| xv * xv * yv)
        .sum::<f64>();

    let mut augmented = [
        [sum_x4, sum_x3, sum_x2, sum_x2y],
        [sum_x3, sum_x2, sum_x, sum_xy],
        [sum_x2, sum_x, n, sum_y],
    ];

    for pivot in 0..3 {
        let (best_row, best_value) = augmented
            .iter()
            .enumerate()
            .skip(pivot)
            .map(|(row_idx, row)| (row_idx, row[pivot].abs()))
            .max_by(|left, right| left.1.total_cmp(&right.1))
            .unwrap_or((pivot, 0.0));
        if best_value <= f64::EPSILON {
            return f64::NAN;
        }
        if best_row != pivot {
            augmented.swap(pivot, best_row);
        }

        let pivot_value = augmented[pivot][pivot];
        for value in augmented[pivot].iter_mut().skip(pivot) {
            *value /= pivot_value;
        }

        for row in 0..3 {
            if row == pivot {
                continue;
            }
            let factor = augmented[row][pivot];
            let pivot_slice: Vec<f64> = augmented[pivot].iter().copied().skip(pivot).collect();
            for (value, pivot_value) in augmented[row]
                .iter_mut()
                .skip(pivot)
                .zip(pivot_slice.iter())
            {
                *value -= factor * pivot_value;
            }
        }
    }

    let a = augmented[0][3];
    let b = augmented[1][3];
    let c = augmented[2][3];
    a * x * x + b * x + c
}

/// K-sample Anderson-Darling test.
///
/// Matches the core non-permutation behavior of `scipy.stats.anderson_ksamp`.
pub fn anderson_ksamp(
    samples: &[Vec<f64>],
    variant: Option<AndersonKSampleVariant>,
) -> Result<AndersonKSampleResult, StatsError> {
    if samples.len() < 2 {
        return Err(StatsError::InvalidArgument(
            "anderson_ksamp needs at least two samples".to_string(),
        ));
    }
    if samples.iter().any(Vec::is_empty) {
        return Err(StatsError::InvalidArgument(
            "anderson_ksamp encountered sample without observations".to_string(),
        ));
    }

    let mut pooled: Vec<f64> = samples
        .iter()
        .flat_map(|sample| sample.iter().copied())
        .collect();
    pooled.sort_by(f64::total_cmp);
    let mut unique = pooled.clone();
    unique.dedup_by(|a, b| a.total_cmp(b).is_eq());
    if unique.len() < 2 {
        return Err(StatsError::InvalidArgument(
            "anderson_ksamp needs more than one distinct observation".to_string(),
        ));
    }

    let n: Vec<usize> = samples.iter().map(Vec::len).collect();
    let total = pooled.len();
    let k = samples.len();
    let statistic_raw = match variant.unwrap_or(AndersonKSampleVariant::Midrank) {
        AndersonKSampleVariant::Midrank => {
            anderson_ksamp_statistic_midrank(samples, &pooled, &unique, &n, total)
        }
        AndersonKSampleVariant::Right => {
            anderson_ksamp_statistic_right(samples, &pooled, &unique, &n, total)
        }
        AndersonKSampleVariant::Continuous => {
            anderson_ksamp_statistic_continuous(samples, &pooled, &n, total)
        }
    };

    let harmonic_sum: f64 = n.iter().map(|&count| 1.0 / count as f64).sum();
    let hs_cs: Vec<f64> = (2..=(total - 1))
        .rev()
        .scan(0.0, |acc, value| {
            *acc += 1.0 / value as f64;
            Some(*acc)
        })
        .collect();
    let h = hs_cs.last().copied().unwrap_or(0.0) + 1.0;
    let g: f64 = hs_cs
        .iter()
        .zip(2..total)
        .map(|(&value, denom)| value / denom as f64)
        .sum();

    let m = (k - 1) as f64;
    let a = (4.0 * g - 6.0) * m + (10.0 - 6.0 * g) * harmonic_sum;
    let b = (2.0 * g - 4.0) * (k * k) as f64
        + 8.0 * h * k as f64
        + (2.0 * g - 14.0 * h - 4.0) * harmonic_sum
        - 8.0 * h
        + 4.0 * g
        - 6.0;
    let c = (6.0 * h + 2.0 * g - 2.0) * (k * k) as f64
        + (4.0 * h - 4.0 * g + 6.0) * k as f64
        + (2.0 * h - 6.0) * harmonic_sum
        + 4.0 * h;
    let d = (2.0 * h + 6.0) * (k * k) as f64 - 4.0 * h * k as f64;
    let total_f = total as f64;
    let sigma_sq = (a * total_f.powi(3) + b * total_f.powi(2) + c * total_f + d)
        / ((total_f - 1.0) * (total_f - 2.0) * (total_f - 3.0));
    let normalized = (statistic_raw - m) / sigma_sq.sqrt();

    let b0 = [0.675, 1.281, 1.645, 1.96, 2.326, 2.573, 3.085];
    let b1 = [-0.245, 0.25, 0.678, 1.149, 1.822, 2.364, 3.615];
    let b2 = [-0.105, -0.305, -0.362, -0.391, -0.396, -0.345, -0.154];
    let critical_values = std::array::from_fn(|i| b0[i] + b1[i] / m.sqrt() + b2[i] / m);
    let significance: [f64; 7] = [0.25, 0.1, 0.05, 0.025, 0.01, 0.005, 0.001];
    let pvalue = if normalized < critical_values[0] {
        significance[0]
    } else if normalized > critical_values[critical_values.len() - 1] {
        significance[significance.len() - 1]
    } else {
        let ys: Vec<f64> = significance.iter().map(|value| (*value).ln()).collect();
        let xs: Vec<f64> = critical_values.to_vec();
        quadratic_least_squares_eval(&xs, &ys, normalized).exp()
    };

    Ok(AndersonKSampleResult {
        statistic: normalized,
        critical_values,
        pvalue: pvalue.clamp(0.001, 0.25),
    })
}

/// One-sample Kolmogorov-Smirnov test.
///
/// Tests H0: data comes from the distribution specified by `cdf_func`.
/// The CDF function maps x -> P(X <= x) for the reference distribution.
///
/// Matches `scipy.stats.ks_1samp(data, cdf_func)`.
pub fn ks_1samp(data: &[f64], cdf_func: impl Fn(f64) -> f64) -> GoodnessOfFitResult {
    let n = data.len();
    if n == 0 || data.iter().any(|v| v.is_nan()) {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }
    let nf = n as f64;

    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    // D = max_i { max(|i/n - F(x_i)|, |(i-1)/n - F(x_i)|) }
    let mut d_stat = 0.0_f64;
    for (i, &x) in sorted.iter().enumerate() {
        let f_x = cdf_func(x);
        let d_plus = ((i + 1) as f64 / nf - f_x).abs();
        let d_minus = (f_x - i as f64 / nf).abs();
        d_stat = if d_stat.is_nan() || d_plus.is_nan() || d_minus.is_nan() {
            f64::NAN
        } else {
            d_stat.max(d_plus).max(d_minus)
        };
    }

    let pvalue = kolmogorov_pvalue(d_stat, nf);

    GoodnessOfFitResult {
        statistic: d_stat,
        pvalue,
    }
}

/// Kolmogorov-Smirnov test wrapper.
///
/// Dispatches to one-sample or two-sample KS based on `target`.
///
/// Matches the core SciPy surface of `scipy.stats.kstest`.
pub fn kstest(data: &[f64], target: KstestTarget<'_>) -> GoodnessOfFitResult {
    match target {
        KstestTarget::Cdf(cdf) => ks_1samp(data, cdf),
        KstestTarget::Sample(reference) => ks_2samp(data, reference),
    }
}

/// Epps-Singleton two-sample test with SciPy's default support points.
pub fn epps_singleton_2samp(x: &[f64], y: &[f64]) -> GoodnessOfFitResult {
    match epps_singleton_2samp_with_t(x, y, &[0.4, 0.8]) {
        Ok(result) => result,
        Err(_) => GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        },
    }
}

/// Epps-Singleton two-sample test with explicit positive support points `t`.
pub fn epps_singleton_2samp_with_t(
    x: &[f64],
    y: &[f64],
    t: &[f64],
) -> Result<GoodnessOfFitResult, StatsError> {
    if x.len() < 5 || y.len() < 5 {
        return Ok(GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        });
    }
    if t.is_empty() {
        return Err(StatsError::InvalidArgument(
            "t must not be empty".to_string(),
        ));
    }
    if t.iter().any(|&value| value <= 0.0 || !value.is_finite()) {
        return Err(StatsError::InvalidArgument(
            "t must contain positive finite elements only".to_string(),
        ));
    }
    for (i, &value) in t.iter().enumerate() {
        if t.iter().skip(i + 1).any(|&other| other == value) {
            return Err(StatsError::InvalidArgument(
                "t must contain distinct elements".to_string(),
            ));
        }
    }
    if x.iter().any(|v| !v.is_finite()) || y.iter().any(|v| !v.is_finite()) {
        return Ok(GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        });
    }

    let mut pooled = x.to_vec();
    pooled.extend_from_slice(y);
    let sigma = iqr(&pooled) / 2.0;
    if !sigma.is_finite() || sigma == 0.0 {
        return Ok(GoodnessOfFitResult {
            statistic: 0.0,
            pvalue: f64::NAN,
        });
    }

    let scaled_t: Vec<f64> = t.iter().map(|&value| value / sigma).collect();
    let feature_dim = 2 * scaled_t.len();
    let feature_row = |sample: f64| -> Vec<f64> {
        let mut row = Vec::with_capacity(feature_dim);
        for &t_value in &scaled_t {
            row.push((t_value * sample).cos());
        }
        for &t_value in &scaled_t {
            row.push((t_value * sample).sin());
        }
        row
    };

    let gx: Vec<Vec<f64>> = x.iter().copied().map(feature_row).collect();
    let gy: Vec<Vec<f64>> = y.iter().copied().map(feature_row).collect();
    let cov_x = covariance_biased(&gx);
    let cov_y = covariance_biased(&gy);

    let nx = x.len() as f64;
    let ny = y.len() as f64;
    let n_total = nx + ny;
    let mut est_cov = vec![vec![0.0; feature_dim]; feature_dim];
    for (i, row) in est_cov.iter_mut().enumerate() {
        for (j, value) in row.iter_mut().enumerate() {
            *value = (n_total / nx) * cov_x[i][j] + (n_total / ny) * cov_y[i][j];
        }
    }

    let (pinv, rank) = symmetric_pseudoinverse_and_rank(&est_cov);
    if rank == 0 {
        return Ok(GoodnessOfFitResult {
            statistic: 0.0,
            pvalue: f64::NAN,
        });
    }

    let mut mean_x = vec![0.0; feature_dim];
    let mut mean_y = vec![0.0; feature_dim];
    for row in &gx {
        for (j, value) in row.iter().enumerate() {
            mean_x[j] += value;
        }
    }
    for row in &gy {
        for (j, value) in row.iter().enumerate() {
            mean_y[j] += value;
        }
    }
    for value in &mut mean_x {
        *value /= nx;
    }
    for value in &mut mean_y {
        *value /= ny;
    }
    let g_diff: Vec<f64> = mean_x
        .iter()
        .zip(mean_y.iter())
        .map(|(&a, &b)| a - b)
        .collect();
    let pinv_times_diff = matvec_mul(&pinv, &g_diff);
    let mut statistic = n_total * dot(&g_diff, &pinv_times_diff);

    if x.len().max(y.len()) < 25 {
        let correction = 1.0 / (1.0 + n_total.powf(-0.45) + 10.1 * (nx.powf(-1.7) + ny.powf(-1.7)));
        statistic *= correction;
    }

    let pvalue = ChiSquared::new(rank as f64).sf(statistic).clamp(0.0, 1.0);
    Ok(GoodnessOfFitResult { statistic, pvalue })
}

fn cvm_cdf_inf(x: f64) -> f64 {
    if !x.is_finite() {
        return f64::NAN;
    }
    if x <= 0.0 {
        return 0.0;
    }

    let mut total = 0.0;
    for k in 0..256 {
        let kf = k as f64;
        let y = 4.0 * kf + 1.0;
        let q = y * y / (16.0 * x);
        let coeff = (ln_gamma(kf + 0.5) - ln_gamma(kf + 1.0)).exp() / (PI.powf(1.5) * x.sqrt());
        let term = coeff * y.sqrt() * (-q).exp() * modified_bessel_k(0.25, q);
        if !term.is_finite() {
            break;
        }
        total += term;
        if term.abs() < 1e-10 {
            break;
        }
    }
    total.clamp(0.0, 1.0)
}

/// Csörgő-Faraway (1996) finite-sample correction term ψ₁_mod for the
/// Cramér-von Mises cdf. Defined in equation 1.10 of the paper, with
/// the V(x)/12 term factored out (added back at the call site as the
/// (1 + 1/(12n)) factor on cvm_cdf_inf(x)).
///
/// This port mirrors `scipy.stats._hypotests._psi1_mod` line-for-line
/// (frankenscipy-4cv67); it is itself a port of Faraway's MAPLE code
/// and the goftest R package.
fn cvm_psi1_mod(x: f64) -> f64 {
    if x <= 0.0 || !x.is_finite() {
        return 0.0;
    }
    let sx = 2.0 * x.sqrt();
    let y1 = x.powf(0.75);
    let y2 = x.powf(1.25);
    let sqrt_pi = PI.sqrt();

    let ed2 = |y: f64| -> f64 {
        let z = y * y / 4.0;
        let b = modified_bessel_k(0.25, z) + modified_bessel_k(0.75, z);
        (-z).exp() * (y / 2.0).powf(1.5) * b / sqrt_pi
    };
    let ed3 = |y: f64| -> f64 {
        let z = y * y / 4.0;
        let k14 = modified_bessel_k(0.25, z);
        let k34 = modified_bessel_k(0.75, z);
        // fsci_special::kv(1.25, z) returns NaN today (negative-order
        // iv sign bug), so we obtain K_{5/4}(z) via the upward
        // recurrence K_{ν+1}(z) = K_{ν-1}(z) + (2ν/z) K_ν(z) with
        // ν = 1/4, giving K_{5/4}(z) = K_{3/4}(z) + K_{1/4}(z) / (2z).
        let k54 = k34 + k14 / (2.0 * z);
        let kv_terms = 2.0 * k14 + 3.0 * k34 - k54;
        ((-z).exp() / sqrt_pi) * (y / 2.0).powf(2.5) * kv_terms
    };

    let mut tot = 0.0_f64;
    for k in 0..256usize {
        let kf = k as f64;
        let m = 2.0 * kf + 1.0;
        let g1 = ln_gamma(kf + 0.5).exp();
        let g3 = ln_gamma(kf + 1.5).exp();
        let e1 = m * g1 * ed2((4.0 * kf + 3.0) / sx) / (9.0 * y1);
        let e2 = g1 * ed3((4.0 * kf + 1.0) / sx) / (72.0 * y2);
        let e3 = 2.0 * (m + 2.0) * g3 * ed3((4.0 * kf + 5.0) / sx) / (12.0 * y2);
        let e4 = 7.0 * m * g1 * ed2((4.0 * kf + 1.0) / sx) / (144.0 * y1);
        let e5 = 7.0 * m * g1 * ed2((4.0 * kf + 5.0) / sx) / (144.0 * y1);
        let a_k = e1 + e2 + e3 + e4 + e5;
        let gamma_kp1 = ln_gamma(kf + 1.0).exp();
        let z = -a_k / (PI * gamma_kp1);
        if !z.is_finite() {
            break;
        }
        tot += z;
        if z.abs() < 1.0e-7 && k > 0 {
            break;
        }
    }
    tot
}

fn cvm_cdf(x: f64, n: Option<usize>) -> f64 {
    if !x.is_finite() {
        return f64::NAN;
    }
    match n {
        None => cvm_cdf_inf(x),
        Some(sample_size) => {
            let nf = sample_size as f64;
            if x <= 1.0 / (12.0 * nf) {
                0.0
            } else if x >= nf / 3.0 {
                1.0
            } else {
                // Csörgő-Faraway 1996 finite-n correction
                // (frankenscipy-4cv67):
                //   F_n(x) ≈ F_∞(x) · (1 + 1/(12n)) + ψ₁_mod(x) / n
                // where ψ₁_mod is given by `cvm_psi1_mod` and the (1 +
                // 1/(12n)) factor absorbs the V(x)/12 term factored
                // out of ψ₁ for the second-call-saving of F_∞.
                let inf = cvm_cdf_inf(x);
                (inf * (1.0 + 1.0 / (12.0 * nf)) + cvm_psi1_mod(x) / nf).clamp(0.0, 1.0)
            }
        }
    }
}

/// One-sample Cramer-von Mises goodness-of-fit test.
///
/// Matches `scipy.stats.cramervonmises(data, cdf)`.
pub fn cramervonmises(data: &[f64], cdf_func: impl Fn(f64) -> f64) -> GoodnessOfFitResult {
    let n = data.len();
    if n <= 1 {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    let nf = n as f64;
    let statistic = sorted
        .iter()
        .enumerate()
        .fold(1.0 / (12.0 * nf), |acc, (i, &x)| {
            let ui = (2.0 * (i + 1) as f64 - 1.0) / (2.0 * nf);
            let cdf = cdf_func(x);
            acc + (ui - cdf) * (ui - cdf)
        });
    let pvalue = (1.0 - cvm_cdf(statistic, Some(n))).clamp(0.0, 1.0);

    GoodnessOfFitResult { statistic, pvalue }
}

fn lcm_u64(a: u64, b: u64) -> u64 {
    a / gcd_u64(a, b) * b
}

fn gcd_u64(mut a: u64, mut b: u64) -> u64 {
    while b != 0 {
        let r = a % b;
        a = b;
        b = r;
    }
    a
}

fn binomial_u128(n: u64, k: u64) -> u128 {
    let k = k.min(n - k);
    let mut result = 1u128;
    for i in 0..k {
        result = result * (n - i) as u128 / (i + 1) as u128;
    }
    result
}

fn cvm_2samp_exact_pvalue(u_stat: u64, nx: usize, ny: usize) -> f64 {
    use std::collections::BTreeMap;

    let m = nx as u64;
    let n = ny as u64;
    let lcm = lcm_u64(m, n);
    let a = lcm / m;
    let b = lcm / n;
    let mn = m * n;
    let zeta = (lcm as i128
        * lcm as i128
        * (m + n) as i128
        * (6 * u_stat as i128 - (mn * (4 * mn - 1)) as i128))
        / (6 * mn as i128 * mn as i128);

    let mut gs: Vec<BTreeMap<i128, u128>> = std::iter::once({
        let mut seed = BTreeMap::new();
        seed.insert(0, 1);
        seed
    })
    .chain((0..m).map(|_| BTreeMap::new()))
    .collect();

    for u in 0..=n {
        let mut next_gs = Vec::with_capacity((m + 1) as usize);
        let mut tmp: BTreeMap<i128, u128> = BTreeMap::new();
        for v in 0..=m {
            for (&value, &freq) in &gs[v as usize] {
                *tmp.entry(value).or_insert(0) += freq;
            }
            let shift = (a as i128 * v as i128 - b as i128 * u as i128).pow(2);
            let shifted = tmp
                .iter()
                .map(|(&value, &freq)| (value + shift, freq))
                .collect::<BTreeMap<_, _>>();
            next_gs.push(shifted.clone());
            tmp = shifted;
        }
        gs = next_gs;
    }

    let combinations = binomial_u128(m + n, m) as f64;
    let tail = gs[m as usize]
        .iter()
        .filter(|(value, _)| **value >= zeta)
        .map(|(_, &freq)| freq as f64)
        .sum::<f64>();
    (tail / combinations).clamp(0.0, 1.0)
}

fn cvm_2samp_asymptotic_pvalue(statistic: f64, nx: usize, ny: usize) -> f64 {
    let nxf = nx as f64;
    let nyf = ny as f64;
    let n_total = nxf + nyf;
    let k = nxf * nyf;
    let expected_t = (1.0 + 1.0 / n_total) / 6.0;
    let variance_t = (n_total + 1.0)
        * (4.0 * k * n_total - 3.0 * (nxf * nxf + nyf * nyf) - 2.0 * k)
        / (45.0 * n_total * n_total * 4.0 * k);
    let normalized = 1.0 / 6.0 + (statistic - expected_t) / (45.0 * variance_t).sqrt();
    if normalized < 0.003 {
        1.0
    } else {
        (1.0 - cvm_cdf_inf(normalized)).clamp(0.0, 1.0)
    }
}

/// Two-sample Cramer-von Mises test with SciPy's default auto method.
///
/// Matches `scipy.stats.cramervonmises_2samp(x, y)`.
pub fn cramervonmises_2samp(x: &[f64], y: &[f64]) -> GoodnessOfFitResult {
    cramervonmises_2samp_with_method(x, y, Cvm2SampleMethod::Auto)
}

/// Two-sample Cramer-von Mises test with explicit p-value method selection.
pub fn cramervonmises_2samp_with_method(
    x: &[f64],
    y: &[f64],
    method: Cvm2SampleMethod,
) -> GoodnessOfFitResult {
    let nx = x.len();
    let ny = y.len();
    if nx <= 1 || ny <= 1 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let mut xa = x.to_vec();
    let mut ya = y.to_vec();
    xa.sort_by(|a, b| a.total_cmp(b));
    ya.sort_by(|a, b| a.total_cmp(b));

    let mut pooled = xa.clone();
    pooled.extend_from_slice(&ya);
    let ranks = rankdata_average(&pooled);
    let rx = &ranks[..nx];
    let ry = &ranks[nx..];

    let u_stat_x = rx
        .iter()
        .enumerate()
        .map(|(i, &rank)| (rank - (i + 1) as f64).powi(2))
        .sum::<f64>();
    let u_stat_y = ry
        .iter()
        .enumerate()
        .map(|(i, &rank)| (rank - (i + 1) as f64).powi(2))
        .sum::<f64>();
    let u_stat = nx as f64 * u_stat_x + ny as f64 * u_stat_y;
    let k = (nx * ny) as f64;
    let n_total = (nx + ny) as f64;
    let statistic = u_stat / (k * n_total) - (4.0 * k - 1.0) / (6.0 * n_total);

    let pvalue = match method {
        Cvm2SampleMethod::Exact => cvm_2samp_exact_pvalue(u_stat.round() as u64, nx, ny),
        Cvm2SampleMethod::Asymptotic => cvm_2samp_asymptotic_pvalue(statistic, nx, ny),
        Cvm2SampleMethod::Auto => {
            if nx.max(ny) > 20 {
                cvm_2samp_asymptotic_pvalue(statistic, nx, ny)
            } else {
                cvm_2samp_exact_pvalue(u_stat.round() as u64, nx, ny)
            }
        }
    };

    GoodnessOfFitResult { statistic, pvalue }
}

/// Two-sample Kolmogorov-Smirnov test.
///
/// Tests H0: two samples come from the same continuous distribution.
///
/// Matches `scipy.stats.ks_2samp(data1, data2)`.
pub fn ks_2samp(data1: &[f64], data2: &[f64]) -> GoodnessOfFitResult {
    let n1 = data1.len();
    let n2 = data2.len();
    if n1 == 0 || n2 == 0 || data1.iter().any(|v| v.is_nan()) || data2.iter().any(|v| v.is_nan()) {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let mut sorted1 = data1.to_vec();
    let mut sorted2 = data2.to_vec();
    sorted1.sort_by(|a, b| a.total_cmp(b));
    sorted2.sort_by(|a, b| a.total_cmp(b));

    // Walk both sorted arrays, computing max |F1(x) - F2(x)|
    let n1f = n1 as f64;
    let n2f = n2 as f64;
    let mut i = 0;
    let mut j = 0;
    let mut d_stat = 0.0_f64;

    while i < n1 || j < n2 {
        let val1 = if i < n1 { sorted1[i] } else { f64::INFINITY };
        let val2 = if j < n2 { sorted2[j] } else { f64::INFINITY };
        let current_val = val1.min(val2);

        // Advance both indices past all elements <= current_val to handle ties
        while i < n1 && sorted1[i] <= current_val {
            i += 1;
        }
        while j < n2 && sorted2[j] <= current_val {
            j += 1;
        }

        let diff = (i as f64 / n1f - j as f64 / n2f).abs();
        d_stat = d_stat.max(diff);
    }

    let (statistic, pvalue) =
        if let Some((exact_d, exact_pvalue)) = ks_2samp_exact_pvalue(d_stat, n1, n2) {
            (exact_d, exact_pvalue)
        } else {
            let en = (n1f * n2f / (n1f + n2f)).sqrt();
            (d_stat, kolmogorov_pvalue(d_stat, en * en))
        };

    GoodnessOfFitResult { statistic, pvalue }
}

/// Two-sample Kolmogorov-Smirnov test with alternative hypothesis.
///
/// Matches `scipy.stats.ks_2samp(data1, data2, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
///   - "two-sided": max|F1(x) - F2(x)|
///   - "greater": max(F1(x) - F2(x)) - tests if F1 > F2
///   - "less": max(F2(x) - F1(x)) - tests if F1 < F2
pub fn ks_2samp_alternative(
    data1: &[f64],
    data2: &[f64],
    alternative: &str,
) -> GoodnessOfFitResult {
    let n1 = data1.len();
    let n2 = data2.len();
    if n1 == 0 || n2 == 0 || data1.iter().any(|v| v.is_nan()) || data2.iter().any(|v| v.is_nan()) {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let mut sorted1 = data1.to_vec();
    let mut sorted2 = data2.to_vec();
    sorted1.sort_by(|a, b| a.total_cmp(b));
    sorted2.sort_by(|a, b| a.total_cmp(b));

    let n1f = n1 as f64;
    let n2f = n2 as f64;
    let mut i = 0;
    let mut j = 0;
    let mut d_plus = 0.0_f64; // max(F1 - F2)
    let mut d_minus = 0.0_f64; // max(F2 - F1)

    while i < n1 || j < n2 {
        let val1 = if i < n1 { sorted1[i] } else { f64::INFINITY };
        let val2 = if j < n2 { sorted2[j] } else { f64::INFINITY };
        let current_val = val1.min(val2);

        while i < n1 && sorted1[i] <= current_val {
            i += 1;
        }
        while j < n2 && sorted2[j] <= current_val {
            j += 1;
        }

        let diff = i as f64 / n1f - j as f64 / n2f;
        d_plus = d_plus.max(diff);
        d_minus = d_minus.max(-diff);
    }

    let (d_stat, mode) = match alternative {
        "greater" => (d_plus, "greater"),
        "less" => (d_minus, "less"),
        _ => (d_plus.max(d_minus), "two-sided"),
    };

    let en = (n1f * n2f / (n1f + n2f)).sqrt();
    let pvalue = if mode == "two-sided" {
        kolmogorov_pvalue(d_stat, en * en)
    } else {
        // One-sided asymptotic: Hodges' Eqn 5.3 correction (matches
        // scipy.stats.ks_2samp asymp branch). scipy uses
        //   z = sqrt(m*n/(m+n)) * d_stat
        // where m = max(n1, n2), n = min(n1, n2). fsci's `en` above is
        // ALREADY sqrt(n1*n2/(n1+n2)) (the inner ratio is already taken
        // sqrt of), so z = en * d_stat directly — DON'T sqrt again.
        //   expt = -2 z² - 2 z (m + 2n) / [3 sqrt(m n (m+n))]
        // (See Hodges 1958, "The significance probability of the
        // Smirnov two-sample test", Eqn 5.3.)
        let z = en * d_stat;
        let m = n1f.max(n2f);
        let n_min = n1f.min(n2f);
        let denom = (m * n_min * (m + n_min)).sqrt();
        let correction = if denom > 0.0 {
            2.0 * z * (m + 2.0 * n_min) / denom / 3.0
        } else {
            0.0
        };
        let expt = -2.0 * z * z - correction;
        expt.exp()
    };

    GoodnessOfFitResult {
        statistic: d_stat,
        pvalue: pvalue.clamp(0.0, 1.0),
    }
}

fn ks_2samp_exact_pvalue(d: f64, n1: usize, n2: usize) -> Option<(f64, f64)> {
    if n1 == 0 || n2 == 0 || n1.saturating_mul(n2) > KS_2SAMP_EXACT_MAX_CELLS {
        return None;
    }

    let n1u = n1 as u64;
    let n2u = n2 as u64;
    let g = gcd_u64(n1u, n2u);
    let lcm = (n1u / g).checked_mul(n2u)?;
    let h = (d * lcm as f64).round() as u64;
    let snapped_d = h as f64 / lcm as f64;

    if h == 0 {
        return Some((snapped_d, 1.0));
    }

    let a = (n2u / g) as i128;
    let b = (n1u / g) as i128;
    let mut inside_prob = vec![0.0_f64; n2 + 1];

    for i in 0..=n1 {
        let mut left_prob = 0.0_f64;
        for (j, cell) in inside_prob.iter_mut().enumerate().take(n2 + 1) {
            let top_prob = *cell;
            let current = if i == 0 && j == 0 {
                1.0
            } else {
                let delta = ((i as i128 * a) - (j as i128 * b)).unsigned_abs();
                if delta >= h as u128 {
                    0.0
                } else if i == 0 {
                    left_prob
                } else if j == 0 {
                    top_prob
                } else {
                    let denom = (i + j) as f64;
                    top_prob * (i as f64 / denom) + left_prob * (j as f64 / denom)
                }
            };
            *cell = current;
            left_prob = current;
        }
    }

    Some((snapped_d, (1.0 - inside_prob[n2]).clamp(0.0, 1.0)))
}

fn shapiro_poly(coeffs: &[f64], x: f64) -> f64 {
    let nord = coeffs.len();
    let mut result = coeffs[0];
    if nord == 1 {
        return result;
    }

    let mut p = x * coeffs[nord - 1];
    if nord == 2 {
        return result + p;
    }

    for ind in (1..=(nord - 2)).rev() {
        p = (p + coeffs[ind]) * x;
    }
    result += p;
    result
}

fn shapiro_ppnd(p: f64) -> f64 {
    const SPLIT: f64 = 0.42;
    const A0: f64 = 2.50662823884;
    const A1: f64 = -18.61500062529;
    const A2: f64 = 41.39119773534;
    const A3: f64 = -25.44106049637;
    const B1: f64 = -8.47351093090;
    const B2: f64 = 23.08336743743;
    const B3: f64 = -21.06224101826;
    const B4: f64 = 3.13082909833;
    const C0: f64 = -2.78718931138;
    const C1: f64 = -2.29796479134;
    const C2: f64 = 4.85014127135;
    const C3: f64 = 2.32121276858;
    const D1: f64 = 3.54388924762;
    const D2: f64 = 1.63706781897;

    let q = p - 0.5;
    if q.abs() <= SPLIT {
        let r = q * q;
        let mut temp = q * (((A3 * r + A2) * r + A1) * r + A0);
        temp /= ((((B4 * r + B3) * r + B2) * r + B1) * r) + 1.0;
        return temp;
    }

    let mut r = if q > 0.0 { 1.0 - p } else { p };
    if r <= 0.0 {
        return 0.0;
    }

    r = (-r.ln()).sqrt();
    let mut temp = (((C3 * r + C2) * r + C1) * r) + C0;
    temp /= ((D2 * r + D1) * r) + 1.0;
    if q < 0.0 { -temp } else { temp }
}

fn shapiro_alnorm(x: f64, upper: bool) -> f64 {
    const LTONE: f64 = 7.0;
    const UTZERO: f64 = 38.0;
    const CON: f64 = 1.28;
    const A1: f64 = 0.398_942_280_444;
    const A2: f64 = 0.399_903_438_504;
    const A3: f64 = 5.758_854_804_58;
    const A4: f64 = 29.821_355_780_8;
    const A5: f64 = 2.624_331_216_79;
    const A6: f64 = 48.695_993_069_2;
    const A7: f64 = 5.928_857_244_38;
    const B1: f64 = 0.398_942_280_385;
    const B2: f64 = 3.8052e-8;
    const B3: f64 = 1.000_006_153_02;
    const B4: f64 = 3.980_647_94e-4;
    const B5: f64 = 1.986_153_813_64;
    const B6: f64 = 0.151_679_116_635;
    const B7: f64 = 5.293_303_249_26;
    const B8: f64 = 4.838_591_280_8;
    const B9: f64 = 15.150_897_245_1;
    const B10: f64 = 0.742_380_924_027;
    const B11: f64 = 30.789_933_034;
    const B12: f64 = 3.990_194_170_11;

    let mut z = x;
    let mut upper_tail = upper;
    if !matches!(z.partial_cmp(&0.0), Some(std::cmp::Ordering::Greater)) {
        upper_tail = false;
        z = -z;
    }

    if !((z <= LTONE) || (upper_tail && z <= UTZERO)) {
        return if upper_tail { 0.0 } else { 1.0 };
    }

    let y = 0.5 * z * z;
    let temp = if z <= CON {
        0.5 - z * (A1 - A2 * y / (y + A3 - A4 / (y + A5 + A6 / (y + A7))))
    } else {
        B1 * (-y).exp()
            / (z - B2
                + B3 / (z + B4 + B5 / (z - B6 + B7 / (z + B8 - B9 / (z + B10 + B11 / (z + B12))))))
    };
    if upper_tail { temp } else { 1.0 - temp }
}

fn shapiro_swilk(sorted: &[f64]) -> GoodnessOfFitResult {
    const C1: [f64; 6] = [0.0, 0.221157, -0.147981, -2.07119, 4.434685, -2.706056];
    const C2: [f64; 6] = [0.0, 0.042981, -0.293762, -1.752461, 5.682633, -3.582633];
    const C3: [f64; 4] = [0.5440, -0.39978, 0.025054, -0.0006714];
    const C4: [f64; 4] = [1.3822, -0.77857, 0.062767, -0.0020322];
    const C5: [f64; 4] = [-1.5861, -0.31082, -0.083751, 0.0038915];
    const C6: [f64; 3] = [-0.4803, -0.082676, 0.0030302];
    const G: [f64; 2] = [-2.273, 0.459];
    const SMALL: f64 = 1e-19;
    const SQRTH: f64 = std::f64::consts::FRAC_1_SQRT_2;
    const PI6: f64 = 6.0 / std::f64::consts::PI;

    let n = sorted.len();
    let n2 = n / 2;
    let an = n as f64;
    let mut a = vec![0.0; n2];

    if n == 3 {
        a[0] = SQRTH;
    } else {
        let an25 = an + 0.25;
        let mut summ2 = 0.0;
        for (index, coeff) in a.iter_mut().enumerate() {
            let temp = shapiro_ppnd((index as f64 + 1.0 - 0.375) / an25);
            *coeff = temp;
            summ2 += temp * temp;
        }
        summ2 *= 2.0;

        let ssumm2 = summ2.sqrt();
        let rsn = 1.0 / an.sqrt();
        let a1 = shapiro_poly(&C1, rsn) - (a[0] / ssumm2);

        let (start, fac) = if n > 5 {
            let a2 = -(a[1] / ssumm2) + shapiro_poly(&C2, rsn);
            let numerator = summ2 - (2.0 * a[0] * a[0]) - (2.0 * a[1] * a[1]);
            let denominator = 1.0 - (2.0 * a1 * a1) - (2.0 * a2 * a2);
            a[1] = a2;
            (2, (numerator / denominator).sqrt())
        } else {
            let numerator = summ2 - (2.0 * a[0] * a[0]);
            let denominator = 1.0 - (2.0 * a1 * a1);
            (1, (numerator / denominator).sqrt())
        };

        a[0] = a1;
        for coeff in a.iter_mut().skip(start) {
            *coeff *= -1.0 / fac;
        }
    }

    let range = sorted[n - 1] - sorted[0];
    if range < SMALL {
        return GoodnessOfFitResult {
            statistic: 1.0,
            pvalue: 1.0,
        };
    }

    let mut sx = sorted[0] / range;
    let mut sa = -a[0];
    let mut mirrored = n - 2;
    for index in 1..n {
        let xi = sorted[index] / range;
        sx += xi;
        if index != mirrored {
            let sign = if index < mirrored { -1.0 } else { 1.0 };
            sa += sign * a[index.min(mirrored)];
        }
        mirrored = mirrored.saturating_sub(1);
    }

    sa /= an;
    sx /= an;

    let mut ssa = 0.0;
    let mut ssx = 0.0;
    let mut sax = 0.0;
    mirrored = n - 1;
    for (index, &value) in sorted.iter().enumerate() {
        let asa = if index != mirrored {
            let sign = if index < mirrored { -1.0 } else { 1.0 };
            sign * a[index.min(mirrored)] - sa
        } else {
            -sa
        };
        let xsx = value / range - sx;
        ssa += asa * asa;
        ssx += xsx * xsx;
        sax += asa * xsx;
        mirrored = mirrored.saturating_sub(1);
    }

    let ssassx = (ssa * ssx).sqrt();
    let w1 = (ssassx - sax) * (ssassx + sax) / (ssa * ssx);
    let w = 1.0 - w1;

    let pvalue = if n == 3 {
        if w < 0.75 {
            return GoodnessOfFitResult {
                statistic: 0.75,
                pvalue: 0.0,
            };
        }
        1.0 - PI6 * w.sqrt().acos()
    } else {
        let mut y = w1.ln();
        let xx = an.ln();
        let (m, s) = if n <= 11 {
            let gamma = shapiro_poly(&G, an);
            if y >= gamma {
                return GoodnessOfFitResult {
                    statistic: w,
                    pvalue: SMALL,
                };
            }
            y = -(gamma - y).ln();
            (shapiro_poly(&C3, an), shapiro_poly(&C4, an).exp())
        } else {
            (shapiro_poly(&C5, xx), shapiro_poly(&C6, xx).exp())
        };
        shapiro_alnorm((y - m) / s, true)
    };

    GoodnessOfFitResult {
        statistic: w,
        pvalue: pvalue.clamp(0.0, 1.0),
    }
}

/// Shapiro-Wilk test for normality.
///
/// Tests H0: data was drawn from a normal distribution.
/// Most powerful normality test for small to moderate sample sizes.
///
/// Matches `scipy.stats.shapiro(data)`.
///
/// Uses the Royston (1995) `swilk` algorithm that SciPy wraps.
pub fn shapiro(data: &[f64]) -> GoodnessOfFitResult {
    if data.len() < 3 {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));
    shapiro_swilk(&sorted)
}

/// D'Agostino's skewness test for normality.
///
/// Tests H0: the population skewness matches the normal distribution's skewness.
///
/// Matches `scipy.stats.skewtest(data, nan_policy=..., alternative=...)`.
pub fn skewtest(
    data: &[f64],
    nan_policy: Option<&str>,
    alternative: Option<&str>,
) -> Result<GoodnessOfFitResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;
    let alternative = validate_hypothesis_alternative(alternative)?;

    let filtered;
    let working = match nan_policy {
        "propagate" => {
            if data.iter().any(|value| value.is_nan()) {
                return Ok(GoodnessOfFitResult {
                    statistic: f64::NAN,
                    pvalue: f64::NAN,
                });
            }
            data
        }
        "raise" => {
            if data.iter().any(|value| value.is_nan()) {
                return Err(StatsError::InvalidArgument(
                    "The input contains nan values".to_string(),
                ));
            }
            data
        }
        "omit" => {
            filtered = data
                .iter()
                .copied()
                .filter(|value| !value.is_nan())
                .collect::<Vec<_>>();
            filtered.as_slice()
        }
        other => {
            return Err(StatsError::InvalidArgument(format!(
                "nan_policy must be one of {{'propagate', 'raise', 'omit'}}, got {other}"
            )));
        }
    };

    if working.len() < 8 {
        return Ok(GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        });
    }

    let z = dagostino_skewtest_z(skew(working), working.len() as f64);
    Ok(GoodnessOfFitResult {
        statistic: z,
        pvalue: normal_alternative_pvalue(z, alternative),
    })
}

/// Test whether the kurtosis of a sample differs from a normal distribution.
///
/// Tests H0: the sample was drawn from a population with normal kurtosis.
/// Uses the Anscombe-Glynn transformation (1983) to convert excess kurtosis
/// to a z-score that is approximately standard normal.
///
/// Requires n >= 20 for valid asymptotic approximation.
///
/// Matches `scipy.stats.kurtosistest(data, nan_policy=..., alternative=...)`.
pub fn kurtosistest(
    data: &[f64],
    nan_policy: Option<&str>,
    alternative: Option<&str>,
) -> Result<GoodnessOfFitResult, StatsError> {
    let nan_policy = validate_nan_policy(nan_policy)?;
    let alternative = validate_hypothesis_alternative(alternative)?;

    let filtered;
    let working = match nan_policy {
        "propagate" => {
            if data.iter().any(|value| value.is_nan()) {
                return Ok(GoodnessOfFitResult {
                    statistic: f64::NAN,
                    pvalue: f64::NAN,
                });
            }
            data
        }
        "raise" => {
            if data.iter().any(|value| value.is_nan()) {
                return Err(StatsError::InvalidArgument(
                    "The input contains nan values".to_string(),
                ));
            }
            data
        }
        "omit" => {
            filtered = data
                .iter()
                .copied()
                .filter(|value| !value.is_nan())
                .collect::<Vec<_>>();
            filtered.as_slice()
        }
        other => {
            return Err(StatsError::InvalidArgument(format!(
                "nan_policy must be one of {{'propagate', 'raise', 'omit'}}, got {other}"
            )));
        }
    };

    if working.len() < 20 {
        return Ok(GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        });
    }

    let n = working.len() as f64;
    let mean_val = working.iter().sum::<f64>() / n;
    let mut m2 = 0.0;
    let mut m4 = 0.0;
    for &x in working {
        let d = x - mean_val;
        let d2 = d * d;
        m2 += d2;
        m4 += d2 * d2;
    }
    let m2_n = m2 / n;
    let m4_n = m4 / n;
    let g2 = m4_n / (m2_n * m2_n) - 3.0;

    let z = dagostino_kurttest_z(g2, n);
    Ok(GoodnessOfFitResult {
        statistic: z,
        pvalue: normal_alternative_pvalue(z, alternative),
    })
}

/// D'Agostino-Pearson omnibus test for normality.
///
/// Tests H0: data was drawn from a normal distribution by combining
/// the skewness test and kurtosis test into an omnibus chi-squared test.
///
/// Matches `scipy.stats.normaltest(data)`.
pub fn normaltest(data: &[f64]) -> GoodnessOfFitResult {
    let n = data.len();
    if n < 8 {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let nf = n as f64;
    let mean_val = data.iter().sum::<f64>() / nf;

    // Compute central moments
    let mut m2 = 0.0;
    let mut m3 = 0.0;
    let mut m4 = 0.0;
    for &x in data {
        let d = x - mean_val;
        let d2 = d * d;
        m2 += d2;
        m3 += d2 * d;
        m4 += d2 * d2;
    }
    let m2_n = m2 / nf;
    let m3_n = m3 / nf;
    let m4_n = m4 / nf;

    // Skewness test (D'Agostino 1990)
    let g1 = m3_n / m2_n.powf(1.5); // sample skewness
    let z_skew = dagostino_skewtest_z(g1, nf);

    // Kurtosis test (Anscombe & Glynn 1983)
    let g2 = m4_n / (m2_n * m2_n) - 3.0; // excess kurtosis
    let z_kurt = dagostino_kurttest_z(g2, nf);

    // Omnibus: K² = z_skew² + z_kurt² ~ chi²(2)
    let k2 = z_skew * z_skew + z_kurt * z_kurt;

    // p-value from chi-squared(2) survival function
    // For chi²(2): P(X > x) = exp(-x/2)
    let pvalue = (-k2 / 2.0).exp();

    GoodnessOfFitResult {
        statistic: k2,
        pvalue,
    }
}

/// Jarque-Bera test for normality.
///
/// Tests H0: data was drawn from a normal distribution using the sample
/// skewness and excess kurtosis.
///
/// Matches `scipy.stats.jarque_bera(data)`.
pub fn jarque_bera(data: &[f64]) -> GoodnessOfFitResult {
    let n = data.len();
    if n < 2 {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let nf = n as f64;
    let mean_val = data.iter().sum::<f64>() / nf;
    let mut m2 = 0.0;
    let mut m3 = 0.0;
    let mut m4 = 0.0;
    for &x in data {
        let d = x - mean_val;
        let d2 = d * d;
        m2 += d2;
        m3 += d2 * d;
        m4 += d2 * d2;
    }

    if m2 == 0.0 {
        return GoodnessOfFitResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let skewness = skew_from_moments(nf, m2, m3);
    let excess_kurtosis = kurtosis_from_moments(nf, m2, m4);
    let statistic = nf / 6.0 * (skewness * skewness + 0.25 * excess_kurtosis * excess_kurtosis);
    let pvalue = ChiSquared::new(2.0).sf(statistic).clamp(0.0, 1.0);

    GoodnessOfFitResult { statistic, pvalue }
}

/// Anderson-Darling test for a specified distribution.
///
/// Tests H0: data comes from the given distribution family.
/// Currently supports `"norm"` (normal distribution).
///
/// Returns the test statistic and critical values at significance levels
/// [15%, 10%, 5%, 2.5%, 1%].
///
/// Matches `scipy.stats.anderson(data, dist='norm')`.
pub fn anderson(data: &[f64], dist: &str) -> AndersonResult {
    let n = data.len();
    if n < 3 || dist != "norm" {
        return AndersonResult {
            statistic: f64::NAN,
            critical_values: [f64::NAN; 5],
            significance_level: [15.0, 10.0, 5.0, 2.5, 1.0],
        };
    }

    let nf = n as f64;

    // Fit normal parameters from data
    let mean_val = data.iter().sum::<f64>() / nf;
    let var_val: f64 = data.iter().map(|&x| (x - mean_val).powi(2)).sum::<f64>() / (nf - 1.0);
    let std_val = var_val.sqrt();

    if std_val == 0.0 {
        return AndersonResult {
            statistic: f64::INFINITY,
            critical_values: anderson_critical_values_norm(nf),
            significance_level: [15.0, 10.0, 5.0, 2.5, 1.0],
        };
    }

    // Sort and standardize
    let mut sorted = data.to_vec();
    sorted.sort_by(|a, b| a.total_cmp(b));

    let norm = Normal::standard();

    // A² = -n - (1/n) * sum_{i=1}^{n} (2i-1) * [ln(F(Y_i)) + ln(1 - F(Y_{n+1-i}))]
    let mut s = 0.0;
    for i in 0..n {
        let z = (sorted[i] - mean_val) / std_val;
        let f_z = ContinuousDistribution::cdf(&norm, z);
        // Clamp to avoid ln(0)
        let f_z = f_z.clamp(1e-15, 1.0 - 1e-15);

        let z_rev = (sorted[n - 1 - i] - mean_val) / std_val;
        let f_z_rev = ContinuousDistribution::cdf(&norm, z_rev);
        let f_z_rev = f_z_rev.clamp(1e-15, 1.0 - 1e-15);

        s += (2.0 * (i + 1) as f64 - 1.0) * (f_z.ln() + (1.0 - f_z_rev).ln());
    }

    let a2 = -nf - s / nf;

    AndersonResult {
        statistic: a2,
        critical_values: anderson_critical_values_norm(nf),
        significance_level: [15.0, 10.0, 5.0, 2.5, 1.0],
    }
}

/// Critical values for Anderson-Darling test with normal distribution at
/// significance levels [15%, 10%, 5%, 2.5%, 1%]. Matches scipy 1.17.1's
/// formula in `scipy/stats/_morestats.py::anderson` for `dist='norm'`:
///   `around(_Avals_norm / (1.0 + 0.75/N + 2.25/N**2), 3)`
/// scipy 1.17 updated `_Avals_norm` from the historical Stephens 1974 table
/// `[0.576, 0.656, 0.787, 0.918, 1.092]` to the refined values below
/// `[0.561, 0.631, 0.752, 0.873, 1.035]`.
fn anderson_critical_values_norm(n: f64) -> [f64; 5] {
    let avals = [0.561, 0.631, 0.752, 0.873, 1.035];
    let scale = 1.0 + 0.75 / n + 2.25 / (n * n);
    let round3 = |v: f64| (v * 1000.0).round() / 1000.0;
    [
        round3(avals[0] / scale),
        round3(avals[1] / scale),
        round3(avals[2] / scale),
        round3(avals[3] / scale),
        round3(avals[4] / scale),
    ]
}

/// Kolmogorov distribution p-value: P(D_n >= d).
/// Uses the Kolmogorov-Smirnov limiting distribution approximation.
fn kolmogorov_pvalue(d: f64, n: f64) -> f64 {
    if d <= 0.0 {
        return 1.0;
    }
    if d >= 1.0 {
        return 0.0;
    }

    // Effective value: sqrt(n) * d
    let s = n.sqrt() * d;

    // For large s, use asymptotic series (Kolmogorov's formula):
    // P(sqrt(n)*D_n > s) ≈ 2 * sum_{k=1}^{inf} (-1)^{k+1} * exp(-2*k²*s²)
    let mut pval = 0.0;
    for k in 1..=100 {
        let kf = k as f64;
        let term = (-2.0 * kf * kf * s * s).exp();
        if term < 1e-20 {
            break;
        }
        if k % 2 == 1 {
            pval += term;
        } else {
            pval -= term;
        }
    }
    (2.0 * pval).clamp(0.0, 1.0)
}

/// D'Agostino's skewness test z-score.
fn dagostino_skewtest_z(g1: f64, n: f64) -> f64 {
    if !g1.is_finite() || n < 8.0 {
        return f64::NAN;
    }

    // D'Agostino (1990) transformation of sample skewness to z-score
    let y = g1 * ((n + 1.0) * (n + 3.0) / (6.0 * (n - 2.0))).sqrt();
    let beta2 = 3.0 * (n * n + 27.0 * n - 70.0) * (n + 1.0) * (n + 3.0)
        / ((n - 2.0) * (n + 5.0) * (n + 7.0) * (n + 9.0));
    let w2 = -1.0 + (2.0 * (beta2 - 1.0)).sqrt();
    if !(w2.is_finite() && w2 > 1.0) {
        return f64::NAN;
    }

    let delta = 1.0 / (0.5 * w2.ln()).sqrt();
    let alpha = (2.0 / (w2 - 1.0)).sqrt();
    let y = if y == 0.0 { 1.0 } else { y };
    let transformed = y / alpha + ((y / alpha).powi(2) + 1.0).sqrt();
    if transformed <= 0.0 || !transformed.is_finite() {
        return f64::NAN;
    }
    delta * transformed.ln()
}

/// Anscombe & Glynn kurtosis test z-score.
fn dagostino_kurttest_z(g2: f64, n: f64) -> f64 {
    // Expected value and variance of excess kurtosis under normality
    let e_g2 = -6.0 / (n + 1.0);
    let var_g2 = 24.0 * n * (n - 2.0) * (n - 3.0) / ((n + 1.0) * (n + 1.0) * (n + 3.0) * (n + 5.0));
    let std_g2 = var_g2.sqrt();

    if std_g2 == 0.0 {
        return 0.0;
    }

    // Standardize
    let x = (g2 - e_g2) / std_g2;

    // Apply cube-root transformation (Anscombe & Glynn)
    let beta1 = 6.0 * (n * n - 5.0 * n + 2.0) / ((n + 7.0) * (n + 9.0))
        * (6.0 * (n + 3.0) * (n + 5.0) / (n * (n - 2.0) * (n - 3.0))).sqrt();

    let a = 6.0 + 8.0 / beta1 * (2.0 / beta1 + (1.0 + 4.0 / (beta1 * beta1)).sqrt());
    let z_term = ((1.0 - 2.0 / a) / (1.0 + x * (2.0 / (a - 4.0)).sqrt())).abs();
    if z_term <= 0.0 {
        return 0.0;
    }
    (1.0 - 2.0 / (9.0 * a) - z_term.powf(1.0 / 3.0)) / (2.0 / (9.0 * a)).sqrt()
}

