/// Gaussian Kernel Density Estimator.
///
/// Matches `scipy.stats.gaussian_kde(dataset)`.
///
/// Uses Silverman's rule for bandwidth selection by default.
#[derive(Debug, Clone)]
pub struct GaussianKde {
    /// Data points.
    dataset: Vec<f64>,
    /// Bandwidth (standard deviation of the Gaussian kernel).
    bandwidth: f64,
}

impl GaussianKde {
    /// Create a new Gaussian KDE from data.
    ///
    /// Uses Silverman's rule: bw = n^(-1/5) * std(data).
    pub fn new(data: &[f64]) -> Self {
        let n = data.len() as f64;
        let mean = data.iter().sum::<f64>() / n;
        let var = data.iter().map(|&x| (x - mean) * (x - mean)).sum::<f64>() / n;
        let std_dev = var.sqrt();
        let bw = std_dev * n.powf(-0.2); // Silverman's rule
        Self {
            dataset: data.to_vec(),
            bandwidth: bw.max(f64::EPSILON),
        }
    }

    /// Create a KDE with a specified bandwidth.
    pub fn with_bandwidth(data: &[f64], bandwidth: f64) -> Self {
        Self {
            dataset: data.to_vec(),
            bandwidth: bandwidth.max(f64::EPSILON),
        }
    }

    /// Evaluate the KDE at a single point.
    pub fn evaluate(&self, x: f64) -> f64 {
        let n = self.dataset.len() as f64;
        let inv_bw = 1.0 / self.bandwidth;
        let norm = inv_bw / (n * (2.0 * std::f64::consts::PI).sqrt());
        self.dataset
            .iter()
            .map(|&xi| {
                let z = (x - xi) * inv_bw;
                norm * (-0.5 * z * z).exp()
            })
            .sum()
    }

    /// Evaluate the KDE at multiple points.
    pub fn evaluate_many(&self, points: &[f64]) -> Vec<f64> {
        points.iter().map(|&x| self.evaluate(x)).collect()
    }

    /// Return the bandwidth.
    pub fn bandwidth(&self) -> f64 {
        self.bandwidth
    }
}

/// Compute the Shannon entropy of a discrete probability distribution.
///
/// Matches `scipy.stats.entropy(pk, base)`.
///
/// H = -Σ p_k * log(p_k), with 0*log(0) = 0 by convention.
///
/// # Arguments
/// * `pk` — Probability distribution (will be normalized if not summing to 1).
/// * `base` — Logarithm base (None = natural log, Some(2) = bits).
pub fn entropy(pk: &[f64], base: Option<f64>) -> f64 {
    if pk.is_empty() {
        return 0.0;
    }
    if pk.iter().any(|&p| p < 0.0) {
        return f64::NEG_INFINITY;
    }
    let total: f64 = pk.iter().sum();
    if total == 0.0 {
        return f64::NAN;
    }

    let h: f64 = pk
        .iter()
        .map(|&p| {
            let prob = p / total;
            if prob > 0.0 { -prob * prob.ln() } else { 0.0 }
        })
        .sum();

    match base {
        Some(b) => h / b.ln(),
        None => h,
    }
}

/// Result of Box-Cox transformation.
#[derive(Debug, Clone)]
pub struct BoxCoxResult {
    /// Transformed data.
    pub data: Vec<f64>,
    /// Optimal lambda parameter.
    pub lmbda: f64,
}

/// Apply Box-Cox transformation to data.
///
/// Matches `scipy.stats.boxcox(x, lmbda)`.
///
/// Transforms positive data to approximate normality.
/// `y = (x^λ - 1) / λ` if λ ≠ 0, `y = ln(x)` if λ = 0.
///
/// # Arguments
/// * `data` — Input data (must be positive).
/// * `lmbda` — If None, find the optimal λ that maximizes the log-likelihood.
///   If Some(λ), use that value.
pub fn boxcox(data: &[f64], lmbda: Option<f64>) -> Result<BoxCoxResult, String> {
    if data.is_empty() {
        return Err("data must not be empty".to_string());
    }
    for (i, &v) in data.iter().enumerate() {
        if v <= 0.0 {
            return Err(format!(
                "data[{i}] = {v}: Box-Cox requires all positive values"
            ));
        }
    }

    let lambda = lmbda.unwrap_or_else(|| find_optimal_boxcox_lambda(data));

    let transformed: Vec<f64> = data
        .iter()
        .map(|&x| {
            if lambda.abs() < 1e-10 {
                x.ln()
            } else {
                (x.powf(lambda) - 1.0) / lambda
            }
        })
        .collect();

    Ok(BoxCoxResult {
        data: transformed,
        lmbda: lambda,
    })
}

/// Find optimal Box-Cox lambda by maximizing log-likelihood over a grid.
fn find_optimal_boxcox_lambda(data: &[f64]) -> f64 {
    let n = data.len() as f64;
    let log_geometric_mean: f64 = data.iter().map(|&x| x.ln()).sum::<f64>() / n;

    let mut best_lambda = 0.0;
    let mut best_ll = f64::NEG_INFINITY;

    // Search lambda in [-2, 2] with resolution 0.01.
    let steps = 400;
    for i in 0..=steps {
        let lambda = -2.0 + 4.0 * i as f64 / steps as f64;

        let transformed: Vec<f64> = data
            .iter()
            .map(|&x| {
                if lambda.abs() < 1e-10 {
                    x.ln()
                } else {
                    (x.powf(lambda) - 1.0) / lambda
                }
            })
            .collect();

        let mean = transformed.iter().sum::<f64>() / n;
        let var = transformed.iter().map(|&y| (y - mean).powi(2)).sum::<f64>() / n;

        if var <= 0.0 {
            continue;
        }

        // Log-likelihood (up to constants):
        // -n/2 * ln(var) + (lambda - 1) * sum(ln(x))
        let ll = -n / 2.0 * var.ln() + (lambda - 1.0) * log_geometric_mean * n;

        if ll > best_ll {
            best_ll = ll;
            best_lambda = lambda;
        }
    }

    best_lambda
}

/// Find optimal Box-Cox transformation parameter lambda.
///
/// Searches for the lambda that maximizes the Box-Cox log-likelihood.
/// Matches `scipy.stats.boxcox_normmax(x, brack, method='mle')`.
///
/// # Arguments
/// * `data` - Input data (must be positive)
/// * `brack` - Search bracket (low, high) for lambda
pub fn boxcox_normmax(data: &[f64], brack: (f64, f64)) -> f64 {
    let n = data.len();
    if n == 0 {
        return f64::NAN;
    }
    for &v in data {
        if v <= 0.0 {
            return f64::NAN;
        }
    }

    let (lo, hi) = brack;
    let nf = n as f64;
    let log_sum: f64 = data.iter().map(|&x| x.ln()).sum();

    let mut best_lambda = lo;
    let mut best_ll = f64::NEG_INFINITY;

    let steps = 400;
    for i in 0..=steps {
        let lambda = lo + (hi - lo) * i as f64 / steps as f64;

        let transformed: Vec<f64> = data
            .iter()
            .map(|&x| {
                if lambda.abs() < 1e-10 {
                    x.ln()
                } else {
                    (x.powf(lambda) - 1.0) / lambda
                }
            })
            .collect();

        let mean = transformed.iter().sum::<f64>() / nf;
        let var = transformed.iter().map(|&y| (y - mean).powi(2)).sum::<f64>() / nf;

        if var <= 0.0 {
            continue;
        }

        let ll = -nf / 2.0 * var.ln() + (lambda - 1.0) * log_sum;

        if ll > best_ll {
            best_ll = ll;
            best_lambda = lambda;
        }
    }

    best_lambda
}

/// Box-Cox log-likelihood function.
///
/// Computes the log-likelihood of observing the data given a Box-Cox parameter lambda.
/// Matches `scipy.stats.boxcox_llf(lmb, data)`.
pub fn boxcox_llf(lmb: f64, data: &[f64]) -> f64 {
    let n = data.len();
    if n == 0 {
        return f64::NAN;
    }
    for &v in data {
        if v <= 0.0 {
            return f64::NEG_INFINITY;
        }
    }

    let nf = n as f64;
    let transformed: Vec<f64> = data
        .iter()
        .map(|&x| {
            if lmb.abs() < 1e-10 {
                x.ln()
            } else {
                (x.powf(lmb) - 1.0) / lmb
            }
        })
        .collect();

    let mean = transformed.iter().sum::<f64>() / nf;
    let var = transformed.iter().map(|&y| (y - mean).powi(2)).sum::<f64>() / nf;

    if var <= 0.0 {
        return f64::NEG_INFINITY;
    }

    let log_sum: f64 = data.iter().map(|&x| x.ln()).sum();
    -nf / 2.0 * var.ln() + (lmb - 1.0) * log_sum
}

/// Kendall's tau rank correlation coefficient.
///
/// Matches `scipy.stats.kendalltau(x, y)`.
///
/// Returns (tau, p_value). The p-value is approximate for large n.
pub fn kendalltau(x: &[f64], y: &[f64]) -> CorrelationResult {
    let n = x.len();
    if n < 2 || x.len() != y.len() {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    // Count concordant and discordant pairs.
    let mut concordant: i64 = 0;
    let mut discordant: i64 = 0;
    let mut x_ties: i64 = 0;
    let mut y_ties: i64 = 0;

    // Resolves [frankenscipy-q4s5e]: hoist x[i]/y[i] out of inner loop,
    // use dx == 0.0 / dy == 0.0 in place of the redundant equality
    // check (mathematically identical for finite inputs), and only
    // compute dx*dy when at least one side is untied. Saves ~3 indexed
    // accesses + 1 mul per inner iter on a hot O(N²) loop.
    for i in 0..n {
        let xi = x[i];
        let yi = y[i];
        for j in (i + 1)..n {
            let dx = xi - x[j];
            let dy = yi - y[j];
            let x_tied = dx == 0.0;
            let y_tied = dy == 0.0;
            if x_tied {
                x_ties += 1;
            }
            if y_tied {
                y_ties += 1;
            }
            if !x_tied && !y_tied {
                let product = dx * dy;
                if product > 0.0 {
                    concordant += 1;
                } else if product < 0.0 {
                    discordant += 1;
                }
            }
        }
    }

    let n_pairs = (n * (n - 1) / 2) as f64;
    let denom = ((n_pairs - x_ties as f64) * (n_pairs - y_ties as f64)).sqrt();

    if denom == 0.0 {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let tau = (concordant - discordant) as f64 / denom;

    // br-hx5t: scipy uses exact-distribution pvalue when n is small and
    // the data is untied. For tied data or large n, fall back to the
    // normal approximation.
    let pvalue = if x_ties == 0 && y_ties == 0 && n <= 25 {
        kendalltau_exact_two_sided_pvalue(n, discordant)
    } else {
        let n_f = n as f64;
        let var = (2.0 * (2.0 * n_f + 5.0)) / (9.0 * n_f * (n_f - 1.0));
        let z = tau / var.sqrt();
        2.0 * (1.0 - standard_normal_cdf(z.abs()))
    };

    CorrelationResult {
        statistic: tau,
        pvalue,
    }
}

/// br-hx5t: exact two-sided pvalue for Kendall's tau under the null
/// hypothesis of independent untied ranks. Builds the Mahonian
/// distribution of inversion counts (= discordant pairs under the
/// independence hypothesis with x ranked 1..N) and sums the tail mass
/// where |C-D| >= |observed C - observed D|.
fn kendalltau_exact_two_sided_pvalue(n: usize, observed_discordant: i64) -> f64 {
    let total = (n * (n - 1) / 2) as i64;
    if total == 0 {
        return f64::NAN;
    }
    let observed_s = total - 2 * observed_discordant;
    if observed_s == 0 {
        return 1.0;
    }
    let max_inv = total as usize;
    let mut f: Vec<u128> = vec![0; max_inv + 1];
    f[0] = 1;
    for m in 2..=n {
        let mut new_f = vec![0u128; max_inv + 1];
        // f_m(k) = sum_{j=0..m-1} f_{m-1}(k-j)  — Mahonian recurrence.
        // Compute via prefix sums for an O(N*total) algorithm.
        let mut prefix: Vec<u128> = vec![0; max_inv + 2];
        for k in 0..=max_inv {
            prefix[k + 1] = prefix[k] + f[k];
        }
        for (k, new_f_k) in new_f.iter_mut().enumerate() {
            let lo = (k + 1).saturating_sub(m);
            let hi = k + 1;
            *new_f_k = prefix[hi] - prefix[lo];
        }
        f = new_f;
    }
    let total_perms: u128 = f.iter().sum();
    let abs_s = observed_s.unsigned_abs() as i64;
    let low_threshold = ((total - abs_s) / 2) as usize;
    let high_threshold = ((total + abs_s) / 2) as usize;
    let count_low: u128 = f.iter().take(low_threshold + 1).sum();
    let count_high: u128 = f.iter().skip(high_threshold).sum();
    (count_low + count_high) as f64 / total_perms as f64
}

/// Kendall's tau correlation with alternative hypothesis.
///
/// Matches `scipy.stats.kendalltau(x, y, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn kendalltau_alternative(x: &[f64], y: &[f64], alternative: &str) -> CorrelationResult {
    let n = x.len();
    if n < 2 || x.len() != y.len() {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let mut concordant: i64 = 0;
    let mut discordant: i64 = 0;
    let mut x_ties: i64 = 0;
    let mut y_ties: i64 = 0;

    // Resolves [frankenscipy-q4s5e]: hoist x[i]/y[i] out of inner loop,
    // use dx == 0.0 / dy == 0.0 in place of the redundant equality
    // check (mathematically identical for finite inputs), and only
    // compute dx*dy when at least one side is untied. Saves ~3 indexed
    // accesses + 1 mul per inner iter on a hot O(N²) loop.
    for i in 0..n {
        let xi = x[i];
        let yi = y[i];
        for j in (i + 1)..n {
            let dx = xi - x[j];
            let dy = yi - y[j];
            let x_tied = dx == 0.0;
            let y_tied = dy == 0.0;
            if x_tied {
                x_ties += 1;
            }
            if y_tied {
                y_ties += 1;
            }
            if !x_tied && !y_tied {
                let product = dx * dy;
                if product > 0.0 {
                    concordant += 1;
                } else if product < 0.0 {
                    discordant += 1;
                }
            }
        }
    }

    let n_pairs = (n * (n - 1) / 2) as f64;
    let denom = ((n_pairs - x_ties as f64) * (n_pairs - y_ties as f64)).sqrt();

    if denom == 0.0 {
        return CorrelationResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    let tau = (concordant - discordant) as f64 / denom;

    // br-hx5t: exact path for untied small n; otherwise asymptotic.
    let pvalue = if x_ties == 0 && y_ties == 0 && n <= 25 {
        kendalltau_exact_alternative_pvalue(n, discordant, alternative)
    } else {
        let n_f = n as f64;
        let var = (2.0 * (2.0 * n_f + 5.0)) / (9.0 * n_f * (n_f - 1.0));
        let z = tau / var.sqrt();
        normal_alternative_pvalue(z, alternative)
    };

    CorrelationResult {
        statistic: tau,
        pvalue,
    }
}

/// br-hx5t: exact one-sided / two-sided pvalue for Kendall's tau under
/// independent untied ranks. The "greater" alternative tests whether the
/// statistic S=C-D exceeds the observed value, equivalent to
/// P(D' <= observed_d). "less" is the mirror; "two-sided" matches the
/// two-tailed exact path.
fn kendalltau_exact_alternative_pvalue(
    n: usize,
    observed_discordant: i64,
    alternative: &str,
) -> f64 {
    let total = (n * (n - 1) / 2) as i64;
    if total == 0 {
        return f64::NAN;
    }
    let max_inv = total as usize;
    let mut f: Vec<u128> = vec![0; max_inv + 1];
    f[0] = 1;
    for m in 2..=n {
        let mut new_f = vec![0u128; max_inv + 1];
        let mut prefix: Vec<u128> = vec![0; max_inv + 2];
        for k in 0..=max_inv {
            prefix[k + 1] = prefix[k] + f[k];
        }
        for (k, new_f_k) in new_f.iter_mut().enumerate() {
            let lo = (k + 1).saturating_sub(m);
            let hi = k + 1;
            *new_f_k = prefix[hi] - prefix[lo];
        }
        f = new_f;
    }
    let total_perms: u128 = f.iter().sum();
    let d = observed_discordant as usize;
    match alternative {
        "greater" => {
            // S' >= s_obs => D' <= d_obs
            let count: u128 = f.iter().take(d + 1).sum();
            count as f64 / total_perms as f64
        }
        "less" => {
            // S' <= s_obs => D' >= d_obs
            let count: u128 = f.iter().skip(d).sum();
            count as f64 / total_perms as f64
        }
        "two-sided" => {
            let observed_s = total - 2 * observed_discordant;
            if observed_s == 0 {
                return 1.0;
            }
            let abs_s = observed_s.unsigned_abs() as i64;
            let low_threshold = ((total - abs_s) / 2) as usize;
            let high_threshold = ((total + abs_s) / 2) as usize;
            let count_low: u128 = f.iter().take(low_threshold + 1).sum();
            let count_high: u128 = f.iter().skip(high_threshold).sum();
            (count_low + count_high) as f64 / total_perms as f64
        }
        _ => f64::NAN,
    }
}

/// Standard normal CDF approximation.
fn standard_normal_cdf(x: f64) -> f64 {
    // /mock-code-finder for [frankenscipy-6exgz]: the naïve form
    // 0.5·(1 + erf(x/√2)) suffers catastrophic cancellation for
    // x ≲ -3 because erf returns close to −1 and 1 + (−1 + ε) = ε
    // loses most of its trailing bits. For negative x, use the
    // numerically-stable Φ(x) = 0.5·erfc(−x/√2) instead. Drop-in
    // — same inputs, just better tail precision. Fixes the latent
    // defect family that produced clamps in SkewNorm.cdf (cc83022),
    // IrwinHall.cdf (7612637), and RecipInvGauss.cdf (814af81).
    let z = x / std::f64::consts::SQRT_2;
    let raw = if x < 0.0 {
        0.5 * fsci_special::erfc_scalar(-z)
    } else {
        0.5 * (1.0 + fsci_special::erf_scalar(z))
    };
    // erf_scalar's series can overshoot 1 by a few ulp for moderate
    // arguments (z ≈ 4–4.5), pushing Φ slightly above 1; the dual
    // path can drift slightly below 0. Clamp to keep callers safe
    // (caught by [frankenscipy-evspb] fuzz: PowerLognorm.cdf got
    // ln_1p(-1.0001) = NaN at c=10, s=0.1, x=1.87).
    raw.clamp(0.0, 1.0)
}

fn standard_normal_pdf(x: f64) -> f64 {
    (-0.5 * x * x).exp() / (2.0 * PI).sqrt()
}

/// Compute the `k`-th raw moment of `PowerLognorm(c, s)`:
///   E[X^k] = ∫_0^∞ x^k · pdf(x) dx
/// via the substitution u = Φ⁻¹((1-q)^{1/c}) where q = 1 − Φ(u)^c, x = exp(-s·u),
/// dq = c · Φ(u)^{c-1} · φ(u) du. That gives the smooth integrand
///   E[X^k] = ∫_{-∞}^{∞} exp(-k·s·u) · c · Φ(u)^{c-1} · φ(u) du
/// which decays super-exponentially at both ends thanks to the Gaussian
/// φ(u) factor. Composite Simpson's rule on u ∈ [-30, 30] with 6000
/// panels gives ≤ 1e-9 abs error vs scipy's stats.powerlognorm for the
/// (c, s) range that has finite moments (frankenscipy-rkdhd).
fn powerlognorm_moment(c: f64, s: f64, k: u32) -> f64 {
    let kf = f64::from(k);
    let u_lo = -30.0_f64;
    let u_hi = 30.0_f64;
    let steps = 6000usize;
    let h = (u_hi - u_lo) / steps as f64;
    let log_norm_const = -0.5 * (2.0 * PI).ln();
    let ln_c = c.ln();
    let integrand = |u: f64| -> f64 {
        let big_phi = standard_normal_cdf(u);
        if big_phi <= 0.0 {
            return 0.0;
        }
        let log_phi = log_norm_const - 0.5 * u * u;
        let log_int = -kf * s * u + ln_c + (c - 1.0) * big_phi.ln() + log_phi;
        if !log_int.is_finite() || log_int < -700.0 {
            return 0.0;
        }
        log_int.exp()
    };
    let mut sum = integrand(u_lo) + integrand(u_hi);
    for i in 1..steps {
        let u = u_lo + i as f64 * h;
        let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
        sum += coef * integrand(u);
    }
    sum * h / 3.0
}

/// k-th raw moment of `Kappa3(a)`:
///   E[X^k] = ∫_0^∞ x^k · a · (a + x^a)^{-(a+1)/a} dx
/// substituted u = ln(x) gives
///   E[X^k] = ∫_{-∞}^{∞} exp((k+1)u) · a · (a + exp(a·u))^{-(a+1)/a} du
/// which integrates over a smooth bell-shaped curve when k < a (the
/// existence condition for the moment). Returns `f64::INFINITY` when
/// k ≥ a — caller is expected to gate that out. (frankenscipy-4htpw)
fn kappa3_moment(a: f64, k: u32) -> f64 {
    let kf = f64::from(k);
    if kf >= a {
        return f64::INFINITY;
    }
    let u_lo = -30.0_f64;
    let u_hi = 30.0_f64;
    let steps = 6000usize;
    let h = (u_hi - u_lo) / steps as f64;
    let ln_a = a.ln();
    let integrand = |u: f64| -> f64 {
        let au = a * u;
        // a + exp(a·u) = a · (1 + exp(a·u - ln a)). Use log-add for stability.
        let log_base = if au > ln_a + 700.0 {
            au
        } else if au < ln_a - 700.0 {
            ln_a
        } else {
            let m = au.max(ln_a);
            m + ((au - m).exp() + (ln_a - m).exp()).ln()
        };
        let log_int = (kf + 1.0) * u + ln_a - (a + 1.0) / a * log_base;
        if !log_int.is_finite() || log_int < -700.0 {
            return 0.0;
        }
        log_int.exp()
    };
    let mut sum = integrand(u_lo) + integrand(u_hi);
    for i in 1..steps {
        let u = u_lo + i as f64 * h;
        let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
        sum += coef * integrand(u);
    }
    sum * h / 3.0
}

/// k-th raw moment of `TruncWeibullMin(c, a, b)` via ppf substitution.
///   E[X^k] = ∫_0^1 ppf(q)^k dq
/// composite Simpson's on q ∈ [0, 1] with 4000 panels. The integrand
/// is bounded (support is [a, b]), so this converges to ~1e-12 abs.
/// (frankenscipy-ygfhj)
fn trunc_weibull_min_moment(c: f64, a: f64, b: f64, k: u32) -> f64 {
    let kf = f64::from(k);
    let ac = a.powf(c);
    let bc = b.powf(c);
    let expm1_ab = (ac - bc).exp_m1();
    let inv_c = 1.0 / c;
    let ppf = |q: f64| -> f64 {
        if q <= 0.0 {
            return a;
        }
        if q >= 1.0 {
            return b;
        }
        let xc = ac - (q * expm1_ab).ln_1p();
        xc.powf(inv_c)
    };
    let steps = 4000usize;
    let h = 1.0 / steps as f64;
    let mut sum = ppf(0.0).powf(kf) + ppf(1.0).powf(kf);
    for i in 1..steps {
        let q = i as f64 * h;
        let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
        sum += coef * ppf(q).powf(kf);
    }
    sum * h / 3.0
}

/// k-th raw moment of `ExponPow(b)`. We integrate in x-space using
/// the substitution u = ln(1 + s) where s = −ln(1 − q), so x = u^{1/b}:
///   E[X^k] = ∫_0^∞ u^{k/b} · (1 − exp(−exp(u) + 1)) … no — keep it
/// simpler. The cleanest path is back-substituting q ↦ x directly via
/// the cdf:
///   E[X^k] = ∫_0^∞ x^k · pdf(x) dx
///         = ∫_0^∞ x^k · b · x^{b−1} · exp(x^b − exp(x^b) + 1) dx.
/// Substitute t = x^b ⇒ x = t^{1/b}, dx = t^{1/b − 1} / b dt:
///   E[X^k] = ∫_0^∞ t^{k/b} · exp(t − e^t + 1) dt
///         = e · ∫_0^∞ t^{k/b} · exp(t − e^t) dt.
/// The integrand has a sharp peak near t = 0 (where t − e^t is most
/// negative — at t=0 it's −1; for t>0 it falls off super-fast since
/// exp(t) − t grows like exp(t)). Most mass lives in t ∈ [0, 5]; the
/// integrand drops to ~1e−300 by t = 10. Use composite Simpson's with
/// 20 000 panels on [0, 10] for ≤ 1e−12 abs vs scipy.stats.exponpow
/// (frankenscipy-uba7f).
fn exponpow_moment(b: f64, k: u32) -> f64 {
    let kf = f64::from(k);
    let exponent = kf / b;
    let t_max = 10.0_f64;
    let steps = 60_000usize;
    let h = t_max / steps as f64;
    let integrand = |t: f64| -> f64 {
        if t <= 0.0 {
            // t^{k/b} → 0 for k/b > 0, t→0; safe to clamp to 0.
            return 0.0;
        }
        let exponent_term = t - t.exp();
        if exponent_term < -700.0 {
            return 0.0;
        }
        t.powf(exponent) * exponent_term.exp()
    };
    let mut sum = integrand(0.0) + integrand(t_max);
    for i in 1..steps {
        let t = i as f64 * h;
        let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
        sum += coef * integrand(t);
    }
    (sum * h / 3.0) * std::f64::consts::E
}

/// k-th raw moment of `HalfLogistic` via the substitution q = tanh(s),
/// turning E[X^k] = ∫_0^1 (2 atanh q)^k dq into
///   E[X^k] = 2^k · ∫_0^∞ s^k · sech²(s) ds
/// where sech²(s) decays exponentially. Composite Simpson's on
/// s ∈ [0, 30] with 6000 panels gives ≤ 1e-12 abs (frankenscipy-okhq6).
fn halflogistic_raw_moment(k: u32) -> f64 {
    let kf = f64::from(k);
    let s_max = 30.0_f64;
    let steps = 6000usize;
    let h = s_max / steps as f64;
    let integrand = |s: f64| -> f64 {
        // sech²(s) = 4 / (e^s + e^{-s})²; for moderate s use the closed form,
        // for large s switch to 4·e^{-2s} to keep precision.
        let sech2 = if s > 30.0 {
            0.0
        } else if s < 1e-8 {
            1.0
        } else {
            let cosh = s.cosh();
            1.0 / (cosh * cosh)
        };
        s.powf(kf) * sech2
    };
    let mut sum = integrand(0.0) + integrand(s_max);
    for i in 1..steps {
        let s = i as f64 * h;
        let coef = if i % 2 == 0 { 2.0 } else { 4.0 };
        sum += coef * integrand(s);
    }
    (sum * h / 3.0) * 2.0_f64.powi(k as i32)
}

fn normal_alternative_pvalue(z: f64, alternative: &str) -> f64 {
    if z.is_nan() {
        return f64::NAN;
    }
    if z == f64::INFINITY {
        return match alternative {
            "two-sided" | "greater" => 0.0,
            "less" => 1.0,
            _ => f64::NAN,
        };
    }
    if z == f64::NEG_INFINITY {
        return match alternative {
            "two-sided" | "less" => 0.0,
            "greater" => 1.0,
            _ => f64::NAN,
        };
    }
    let normal = Normal::standard();
    match alternative {
        "two-sided" => (2.0 * ContinuousDistribution::sf(&normal, z.abs())).clamp(0.0, 1.0),
        "less" => ContinuousDistribution::cdf(&normal, z).clamp(0.0, 1.0),
        "greater" => ContinuousDistribution::sf(&normal, z).clamp(0.0, 1.0),
        _ => f64::NAN,
    }
}

fn student_t_alternative_pvalue(statistic: f64, t_dist: &StudentT, alternative: &str) -> f64 {
    if statistic.is_nan() {
        return f64::NAN;
    }
    match alternative {
        "two-sided" => (2.0 * ContinuousDistribution::sf(t_dist, statistic.abs())).clamp(0.0, 1.0),
        "less" => ContinuousDistribution::cdf(t_dist, statistic).clamp(0.0, 1.0),
        "greater" => ContinuousDistribution::sf(t_dist, statistic).clamp(0.0, 1.0),
        _ => f64::NAN,
    }
}

fn validate_hypothesis_alternative(alternative: Option<&str>) -> Result<&'static str, StatsError> {
    match alternative
        .unwrap_or("two-sided")
        .to_ascii_lowercase()
        .as_str()
    {
        "two-sided" => Ok("two-sided"),
        "less" => Ok("less"),
        "greater" => Ok("greater"),
        _ => Err(StatsError::InvalidArgument(
            "alternative must be one of {'two-sided', 'less', 'greater'}".to_string(),
        )),
    }
}

fn validate_nan_policy(nan_policy: Option<&str>) -> Result<&'static str, StatsError> {
    match nan_policy
        .unwrap_or("propagate")
        .to_ascii_lowercase()
        .as_str()
    {
        "propagate" => Ok("propagate"),
        "omit" => Ok("omit"),
        "raise" => Ok("raise"),
        _ => Err(StatsError::InvalidArgument(
            "nan_policy must be one of {'propagate', 'omit', 'raise'}".to_string(),
        )),
    }
}

fn somers_from_rankings(x: &[f64], y: &[f64]) -> Result<Vec<Vec<f64>>, StatsError> {
    if x.len() != y.len() {
        return Err(StatsError::InvalidArgument(
            "Rankings must be of equal length.".to_string(),
        ));
    }

    let mut x_levels = x.to_vec();
    x_levels.sort_by(f64::total_cmp);
    x_levels.dedup_by(|a, b| a.total_cmp(b).is_eq());

    let mut y_levels = y.to_vec();
    y_levels.sort_by(f64::total_cmp);
    y_levels.dedup_by(|a, b| a.total_cmp(b).is_eq());

    let mut table = vec![vec![0.0; y_levels.len()]; x_levels.len()];
    for (&xi, &yi) in x.iter().zip(y.iter()) {
        let row = x_levels
            .binary_search_by(|value| value.total_cmp(&xi))
            .unwrap_or(0);
        let col = y_levels
            .binary_search_by(|value| value.total_cmp(&yi))
            .unwrap_or(0);
        table[row][col] += 1.0;
    }
    Ok(table)
}

fn somers_validate_table(table: &[Vec<f64>]) -> Result<Vec<Vec<f64>>, StatsError> {
    if table.is_empty() {
        return Err(StatsError::InvalidArgument(
            "x must be either a 1D or 2D array".to_string(),
        ));
    }
    let cols = table[0].len();
    if cols == 0 || table.iter().any(|row| row.len() != cols) {
        return Err(StatsError::InvalidArgument(
            "contingency table must be rectangular".to_string(),
        ));
    }
    if table
        .iter()
        .flatten()
        .any(|&value| value < 0.0 || !value.is_finite())
    {
        return Err(StatsError::InvalidArgument(
            "All elements of the contingency table must be non-negative.".to_string(),
        ));
    }
    if table
        .iter()
        .flatten()
        .any(|&value| (value - value.round()).abs() > 1e-12)
    {
        return Err(StatsError::InvalidArgument(
            "All elements of the contingency table must be integer.".to_string(),
        ));
    }
    if table
        .iter()
        .flatten()
        .filter(|&&value| value != 0.0)
        .count()
        < 2
    {
        return Err(StatsError::InvalidArgument(
            "At least two elements of the contingency table must be nonzero.".to_string(),
        ));
    }
    Ok(table.to_vec())
}

fn somers_aij(table: &[Vec<f64>], i: usize, j: usize) -> f64 {
    let upper_left: f64 = table
        .iter()
        .take(i)
        .map(|row| row.iter().take(j).sum::<f64>())
        .sum();
    let lower_right: f64 = table
        .iter()
        .skip(i + 1)
        .map(|row| row.iter().skip(j + 1).sum::<f64>())
        .sum();
    upper_left + lower_right
}

fn somers_dij(table: &[Vec<f64>], i: usize, j: usize) -> f64 {
    let lower_left: f64 = table
        .iter()
        .skip(i + 1)
        .map(|row| row.iter().take(j).sum::<f64>())
        .sum();
    let upper_right: f64 = table
        .iter()
        .take(i)
        .map(|row| row.iter().skip(j + 1).sum::<f64>())
        .sum();
    lower_left + upper_right
}

/// Somers' D ordinal association test.
///
/// Matches the core behavior of `scipy.stats.somersd`.
pub fn somersd(
    input: SomersDInput<'_>,
    alternative: Option<&str>,
) -> Result<SomersDResult, StatsError> {
    let alternative = validate_hypothesis_alternative(alternative)?;
    let table = match input {
        SomersDInput::Rankings(x, y) => somers_from_rankings(x, y)?,
        SomersDInput::Table(table) => somers_validate_table(table)?,
    };

    if table.len() <= 1 || table[0].len() <= 1 {
        return Ok(SomersDResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            table,
            correlation: f64::NAN,
        });
    }

    let total: f64 = table.iter().flatten().sum();
    let total_sq = total * total;
    let sri2: f64 = table
        .iter()
        .map(|row| {
            let row_sum: f64 = row.iter().sum();
            row_sum * row_sum
        })
        .sum();

    let mut p = 0.0;
    let mut q = 0.0;
    let mut a_term = 0.0;
    for (i, row) in table.iter().enumerate() {
        for (j, &cell) in row.iter().enumerate() {
            let aij = somers_aij(&table, i, j);
            let dij = somers_dij(&table, i, j);
            p += cell * aij;
            q += cell * dij;
            a_term += cell * (aij - dij).powi(2);
        }
    }

    let statistic = (p - q) / (total_sq - sri2);
    let s = a_term - (p - q).powi(2) / total;
    let z = if s > 0.0 {
        (p - q) / (4.0 * s).sqrt()
    } else if p > q {
        f64::INFINITY
    } else if p < q {
        f64::NEG_INFINITY
    } else {
        0.0
    };
    let pvalue = normal_alternative_pvalue(z, alternative);

    Ok(SomersDResult {
        statistic,
        pvalue,
        table,
        correlation: statistic,
    })
}

// ── Fisher's exact test ──────────────────────────────────────────────

/// Result of Fisher's exact test.
#[derive(Debug, Clone, PartialEq)]
pub struct FisherExactResult {
    /// Sample odds ratio: (a*d) / (b*c) for table [[a,b],[c,d]].
    pub odds_ratio: f64,
    /// Two-sided p-value from the hypergeometric distribution.
    pub pvalue: f64,
}

/// Fisher's exact test for a 2x2 contingency table.
///
/// Computes the exact p-value using the hypergeometric distribution.
/// This is the gold standard for small-sample contingency tables where
/// chi-squared approximation is unreliable.
///
/// Matches `scipy.stats.fisher_exact(table)`.
///
/// # Arguments
/// * `table` — 2x2 contingency table [[a, b], [c, d]] with non-negative integer counts.
pub fn fisher_exact(table: &[[f64; 2]; 2]) -> FisherExactResult {
    let a = table[0][0];
    let b = table[0][1];
    let c = table[1][0];
    let d = table[1][1];

    // Odds ratio
    let odds_ratio = if b * c > 0.0 {
        (a * d) / (b * c)
    } else if a * d > 0.0 {
        f64::INFINITY
    } else {
        f64::NAN
    };

    // Marginals
    let row0 = a + b; // n
    let col0 = a + c; // K
    let total = a + b + c + d; // N

    if total == 0.0 {
        return FisherExactResult {
            odds_ratio,
            pvalue: 1.0,
        };
    }

    // Use hypergeometric distribution: X ~ Hypergeometric(N=total, K=col0, n=row0)
    // P(X = k) = C(K,k) C(N-K,n-k) / C(N,n)
    let big_m = total as u64;
    let n_succ = col0 as u64;
    let n_draw = row0 as u64;

    let hyper = Hypergeometric::new(big_m, n_succ, n_draw);

    // Two-sided p-value: sum probabilities of all outcomes as extreme or more extreme
    // than the observed value (where "extreme" means pmf <= pmf(observed))
    let observed_k = a as u64;
    let p_observed = hyper.pmf(observed_k);

    let k_min = (n_draw + n_succ).saturating_sub(big_m);
    let k_max = n_draw.min(n_succ);

    let mut pvalue = 0.0;
    for k in k_min..=k_max {
        let p_k = hyper.pmf(k);
        if p_k <= p_observed + 1e-14 {
            pvalue += p_k;
        }
    }

    // Clamp to [0, 1]
    let pvalue = pvalue.clamp(0.0, 1.0);

    FisherExactResult { odds_ratio, pvalue }
}

// ── Chi-squared contingency test ─────────────────────────────────────

/// Result of a chi-squared contingency test.
#[derive(Debug, Clone, PartialEq)]
pub struct Chi2ContingencyResult {
    /// Chi-squared test statistic.
    pub statistic: f64,
    /// P-value from chi-squared distribution.
    pub pvalue: f64,
    /// Degrees of freedom.
    pub dof: usize,
    /// Expected frequencies under the null hypothesis of independence.
    pub expected: Vec<Vec<f64>>,
}

/// Chi-squared test of independence for a contingency table.
///
/// Tests whether the row and column variables are independent.
/// Matches `scipy.stats.chi2_contingency(observed, correction=...)`.
///
/// # Arguments
/// * `observed` — 2D contingency table of observed frequencies (rows x cols).
/// * `correction` — Whether to apply Yates' continuity correction when the
///   degrees of freedom equal 1 (SciPy's default behavior for 2x2 tables).
///
/// # Returns
/// (chi2 statistic, p-value, degrees of freedom, expected frequencies)
pub fn chi2_contingency(observed: &[Vec<f64>], correction: bool) -> Chi2ContingencyResult {
    let nrows = observed.len();
    if nrows == 0 {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }
    let ncols = observed[0].len();
    // Validate all rows have the same number of columns
    if observed.iter().any(|row| row.len() != ncols) {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }
    if ncols == 0 || nrows < 2 || ncols < 2 {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }
    if observed
        .iter()
        .flat_map(|row| row.iter())
        .any(|&value| !value.is_finite() || value < 0.0)
    {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }

    // Compute row totals, column totals, grand total
    let row_totals: Vec<f64> = observed.iter().map(|row| row.iter().sum()).collect();
    let mut col_totals = vec![0.0; ncols];
    for row in observed {
        for (j, &val) in row.iter().enumerate() {
            col_totals[j] += val;
        }
    }
    let grand_total: f64 = row_totals.iter().sum();

    if grand_total == 0.0 {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }

    // Expected frequencies: e_ij = row_i_total * col_j_total / grand_total
    let expected: Vec<Vec<f64>> = (0..nrows)
        .map(|i| {
            (0..ncols)
                .map(|j| row_totals[i] * col_totals[j] / grand_total)
                .collect()
        })
        .collect();

    // Chi-squared statistic: Σ (o_ij - e_ij)² / e_ij
    let dof = (nrows - 1) * (ncols - 1);
    let use_yates_correction = correction && dof == 1;
    let chi2: f64 = observed
        .iter()
        .zip(expected.iter())
        .flat_map(|(obs_row, exp_row)| {
            obs_row.iter().zip(exp_row.iter()).map(|(&o, &e)| {
                if e > 0.0 {
                    let diff = (o - e).abs();
                    let corrected = if use_yates_correction {
                        (diff - diff.min(0.5)).powi(2)
                    } else {
                        diff.powi(2)
                    };
                    corrected / e
                } else {
                    0.0
                }
            })
        })
        .sum();

    // P-value from chi-squared distribution
    let pvalue = if dof > 0 {
        let dist = ChiSquared::new(dof as f64);
        dist.sf(chi2).clamp(0.0, 1.0)
    } else {
        f64::NAN
    };

    Chi2ContingencyResult {
        statistic: chi2,
        pvalue,
        dof,
        expected,
    }
}

/// Chi-squared contingency test with lambda_ parameter for power divergence.
///
/// Matches `scipy.stats.chi2_contingency(observed, lambda_=...)`.
///
/// * `lambda_` - Power divergence parameter:
///   - 1.0: Pearson chi-squared (default)
///   - 0.0: Log-likelihood ratio (G-test)
///   - -1.0: Modified log-likelihood ratio
///   - -0.5: Freeman-Tukey
///   - -2.0: Neyman
///   - 2/3: Cressie-Read
pub fn chi2_contingency_with_lambda(
    observed: &[Vec<f64>],
    correction: bool,
    lambda_: f64,
) -> Chi2ContingencyResult {
    let nrows = observed.len();
    if nrows == 0 {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }
    let ncols = observed[0].len();
    if observed.iter().any(|row| row.len() != ncols) || ncols == 0 || nrows < 2 || ncols < 2 {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }
    if observed
        .iter()
        .flat_map(|row| row.iter())
        .any(|&v| !v.is_finite() || v < 0.0)
    {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }

    let row_totals: Vec<f64> = observed.iter().map(|row| row.iter().sum()).collect();
    let mut col_totals = vec![0.0; ncols];
    for row in observed {
        for (j, &val) in row.iter().enumerate() {
            col_totals[j] += val;
        }
    }
    let grand_total: f64 = row_totals.iter().sum();

    if grand_total == 0.0 {
        return Chi2ContingencyResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            dof: 0,
            expected: Vec::new(),
        };
    }

    let expected: Vec<Vec<f64>> = (0..nrows)
        .map(|i| {
            (0..ncols)
                .map(|j| row_totals[i] * col_totals[j] / grand_total)
                .collect()
        })
        .collect();

    let dof = (nrows - 1) * (ncols - 1);
    let use_yates = correction && dof == 1;

    // Compute power divergence statistic
    let stat = if (lambda_ - 1.0).abs() < 1e-10 {
        // Pearson chi-squared: Σ (o-e)²/e
        observed
            .iter()
            .zip(expected.iter())
            .flat_map(|(obs_row, exp_row)| {
                obs_row.iter().zip(exp_row.iter()).map(|(&o, &e)| {
                    if e > 0.0 {
                        let diff = if use_yates {
                            ((o - e).abs() - 0.5).max(0.0)
                        } else {
                            o - e
                        };
                        diff.powi(2) / e
                    } else {
                        0.0
                    }
                })
            })
            .sum()
    } else if lambda_.abs() < 1e-10 {
        // G-test (lambda=0): 2 Σ o ln(o/e)
        2.0 * observed
            .iter()
            .zip(expected.iter())
            .flat_map(|(obs_row, exp_row)| {
                obs_row.iter().zip(exp_row.iter()).map(|(&o, &e)| {
                    if o > 0.0 && e > 0.0 {
                        o * (o / e).ln()
                    } else {
                        0.0
                    }
                })
            })
            .sum::<f64>()
    } else if (lambda_ + 1.0).abs() < 1e-10 {
        // Modified log-likelihood ratio (lambda=-1): 2 Σ e ln(e/o)
        2.0 * observed
            .iter()
            .zip(expected.iter())
            .flat_map(|(obs_row, exp_row)| {
                obs_row.iter().zip(exp_row.iter()).map(|(&o, &e)| {
                    if o > 0.0 && e > 0.0 {
                        e * (e / o).ln()
                    } else {
                        0.0
                    }
                })
            })
            .sum::<f64>()
    } else {
        // General power divergence: 2/(λ(λ+1)) Σ o((o/e)^λ - 1)
        let factor = 2.0 / (lambda_ * (lambda_ + 1.0));
        factor
            * observed
                .iter()
                .zip(expected.iter())
                .flat_map(|(obs_row, exp_row)| {
                    obs_row.iter().zip(exp_row.iter()).map(|(&o, &e)| {
                        if o > 0.0 && e > 0.0 {
                            o * ((o / e).powf(lambda_) - 1.0)
                        } else {
                            0.0
                        }
                    })
                })
                .sum::<f64>()
    };

    let pvalue = if dof > 0 {
        ChiSquared::new(dof as f64).sf(stat).clamp(0.0, 1.0)
    } else {
        f64::NAN
    };

    Chi2ContingencyResult {
        statistic: stat,
        pvalue,
        dof,
        expected,
    }
}

/// Power divergence statistic and test.
///
/// Computes the power divergence statistic for testing whether observed
/// frequencies differ from expected frequencies.
///
/// Matches `scipy.stats.power_divergence(f_obs, f_exp, lambda_)`.
///
/// # Arguments
/// * `f_obs` — Observed frequencies.
/// * `f_exp` — Expected frequencies (if None, assumes uniform).
/// * `lambda_` — Power divergence parameter. 1.0 = Pearson chi-squared, 0.0 = G-test.
///
/// # Returns
/// (statistic, p-value) where p-value is from chi-squared distribution with len-1 dof.
pub fn power_divergence(f_obs: &[f64], f_exp: Option<&[f64]>, lambda_: f64) -> (f64, f64) {
    let n = f_obs.len();
    if n < 2 {
        return (f64::NAN, f64::NAN);
    }
    if f_obs.iter().any(|&value| !value.is_finite() || value < 0.0) {
        return (f64::NAN, f64::NAN);
    }

    // Default expected: uniform
    let total: f64 = f_obs.iter().sum();
    if !total.is_finite() || total <= 0.0 {
        return (f64::NAN, f64::NAN);
    }
    let uniform_exp = total / n as f64;
    let default_exp: Vec<f64> = vec![uniform_exp; n];
    let exp = f_exp.unwrap_or(&default_exp);

    if exp.len() != n {
        return (f64::NAN, f64::NAN);
    }
    if exp.iter().any(|&value| !value.is_finite() || value < 0.0) {
        return (f64::NAN, f64::NAN);
    }
    let exp_total: f64 = exp.iter().sum();
    let rel_tol = f64::EPSILON.sqrt();
    let scale = total.abs().max(exp_total.abs()).max(1.0);
    if (total - exp_total).abs() > rel_tol * scale {
        return (f64::NAN, f64::NAN);
    }

    let stat = if (lambda_ - 1.0).abs() < 1e-10 {
        // Pearson chi-squared: Σ (o-e)²/e
        f_obs
            .iter()
            .zip(exp.iter())
            .map(|(&o, &e)| if e > 0.0 { (o - e).powi(2) / e } else { 0.0 })
            .sum()
    } else if lambda_.abs() < 1e-10 {
        // G-test (log-likelihood ratio): 2 Σ o ln(o/e)
        2.0 * f_obs
            .iter()
            .zip(exp.iter())
            .map(|(&o, &e)| {
                if o > 0.0 && e > 0.0 {
                    o * (o / e).ln()
                } else {
                    0.0
                }
            })
            .sum::<f64>()
    } else if (lambda_ + 1.0).abs() < 1e-10 {
        // Modified log-likelihood ratio (lambda=-1):
        // 2 Σ e ln(e/o). The general formula above factors
        // 2/(λ*(λ+1)) which is 2/0 here, so use the limit.
        2.0 * f_obs
            .iter()
            .zip(exp.iter())
            .map(|(&o, &e)| {
                if o > 0.0 && e > 0.0 {
                    e * (e / o).ln()
                } else {
                    0.0
                }
            })
            .sum::<f64>()
    } else {
        // General power divergence: 2/(λ(λ+1)) Σ o((o/e)^λ - 1)
        let factor = 2.0 / (lambda_ * (lambda_ + 1.0));
        factor
            * f_obs
                .iter()
                .zip(exp.iter())
                .map(|(&o, &e)| {
                    if o > 0.0 && e > 0.0 {
                        o * ((o / e).powf(lambda_) - 1.0)
                    } else {
                        0.0
                    }
                })
                .sum::<f64>()
    };

    let dof = (n - 1) as f64;
    let pvalue = if dof > 0.0 {
        let dist = ChiSquared::new(dof);
        dist.sf(stat).clamp(0.0, 1.0)
    } else {
        f64::NAN
    };

    (stat, pvalue)
}

/// Permutation test: estimate p-value by random permutation.
///
/// Matches `scipy.stats.permutation_test` (simplified).
pub fn permutation_test<F>(
    x: &[f64],
    y: &[f64],
    stat_fn: F,
    n_permutations: usize,
    seed: u64,
) -> (f64, f64)
where
    F: Fn(&[f64], &[f64]) -> f64,
{
    if x.is_empty()
        || y.is_empty()
        || n_permutations == 0
        || x.iter().any(|v| v.is_nan())
        || y.iter().any(|v| v.is_nan())
    {
        return (f64::NAN, f64::NAN);
    }
    let observed = stat_fn(x, y);
    let n = x.len() + y.len();
    let mut combined: Vec<f64> = x.iter().chain(y.iter()).cloned().collect();
    let mut rng = seed;
    let mut count_extreme = 0usize;

    for _ in 0..n_permutations {
        for i in (1..n).rev() {
            rng = rng.wrapping_mul(6364136223846793005).wrapping_add(1);
            let j = (rng >> 33) as usize % (i + 1);
            combined.swap(i, j);
        }

        let perm_stat = stat_fn(&combined[..x.len()], &combined[x.len()..]);
        if perm_stat.abs() >= observed.abs() {
            count_extreme += 1;
        }
    }

    let pvalue = (count_extreme + 1) as f64 / (n_permutations + 1) as f64;
    (observed, pvalue)
}

/// Brunner-Munzel test for stochastic equality.
///
/// Tests H₀: P(X > Y) = 0.5.
/// Matches `scipy.stats.brunnermunzel`.
pub fn brunnermunzel(x: &[f64], y: &[f64]) -> TtestResult {
    let nx = x.len();
    let ny = y.len();
    if nx < 2 || ny < 2 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let nxf = nx as f64;
    let nyf = ny as f64;

    // Compute mean rank for each group in combined sample
    let mut combined: Vec<(f64, usize)> = x
        .iter()
        .enumerate()
        .map(|(i, &v)| (v, i))
        .chain(y.iter().enumerate().map(|(i, &v)| (v, nx + i)))
        .collect();
    combined.sort_by(|a, b| a.0.total_cmp(&b.0));

    let mut ranks = vec![0.0; nx + ny];
    let mut i = 0;
    while i < combined.len() {
        let mut j = i + 1;
        while j < combined.len() && combined[j].0 == combined[i].0 {
            j += 1;
        }
        let avg_rank = (i + j + 1) as f64 / 2.0;
        for k in i..j {
            ranks[combined[k].1] = avg_rank;
        }
        i = j;
    }

    let mean_rx: f64 = ranks[..nx].iter().sum::<f64>() / nxf;
    let mean_ry: f64 = ranks[nx..].iter().sum::<f64>() / nyf;

    // Within-group ranks
    let rank_within = |data: &[f64]| -> Vec<f64> {
        let mut indexed: Vec<(usize, f64)> = data.iter().cloned().enumerate().collect();
        indexed.sort_by(|a, b| a.1.total_cmp(&b.1));
        let mut r = vec![0.0; data.len()];
        let mut k = 0;
        while k < indexed.len() {
            let mut l = k + 1;
            while l < indexed.len() && indexed[l].1.total_cmp(&indexed[k].1).is_eq() {
                l += 1;
            }
            let avg = (k + l + 1) as f64 / 2.0;
            for m in k..l {
                r[indexed[m].0] = avg;
            }
            k = l;
        }
        r
    };

    let rx_within = rank_within(x);
    let ry_within = rank_within(y);

    let sx2: f64 = ranks[..nx]
        .iter()
        .zip(rx_within.iter())
        .map(|(&ri, &rwi)| (ri - rwi - mean_rx + (nxf + 1.0) / 2.0).powi(2))
        .sum::<f64>()
        / (nxf - 1.0);

    let sy2: f64 = ranks[nx..]
        .iter()
        .zip(ry_within.iter())
        .map(|(&ri, &rwi)| (ri - rwi - mean_ry + (nyf + 1.0) / 2.0).powi(2))
        .sum::<f64>()
        / (nyf - 1.0);

    let nf = nxf + nyf;
    let rank_delta = mean_ry - mean_rx;
    let denom = (nxf * sx2 + nyf * sy2).sqrt();
    let (w, df, pvalue) = if denom > 0.0 {
        let w = nxf * nyf * rank_delta / (nf * denom);
        let df_num = (nxf * sx2 + nyf * sy2).powi(2);
        let df_den = (nxf * sx2).powi(2) / (nxf - 1.0) + (nyf * sy2).powi(2) / (nyf - 1.0);
        let df = if df_den > 0.0 {
            df_num / df_den
        } else {
            f64::NAN
        };
        let pvalue = if df.is_finite() {
            let t_dist = StudentT::new(df);
            2.0 * (1.0 - t_dist.cdf(w.abs()))
        } else {
            f64::NAN
        };
        (w, df, pvalue)
    } else {
        let w = if rank_delta > 0.0 {
            f64::INFINITY
        } else if rank_delta < 0.0 {
            f64::NEG_INFINITY
        } else {
            f64::NAN
        };
        (w, f64::NAN, f64::NAN)
    };

    TtestResult {
        statistic: w,
        pvalue: pvalue.clamp(0.0, 1.0),
        df,
    }
}

/// Brunner-Munzel test with alternative hypothesis.
///
/// Matches `scipy.stats.brunnermunzel(x, y, alternative=...)`.
///
/// * `alternative` - "two-sided" (default), "less", or "greater"
pub fn brunnermunzel_alternative(x: &[f64], y: &[f64], alternative: &str) -> TtestResult {
    let nx = x.len();
    let ny = y.len();
    if nx < 2 || ny < 2 || x.iter().any(|v| v.is_nan()) || y.iter().any(|v| v.is_nan()) {
        return TtestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
            df: f64::NAN,
        };
    }

    let nxf = nx as f64;
    let nyf = ny as f64;

    let mut combined: Vec<(f64, usize)> = x
        .iter()
        .enumerate()
        .map(|(i, &v)| (v, i))
        .chain(y.iter().enumerate().map(|(i, &v)| (v, nx + i)))
        .collect();
    combined.sort_by(|a, b| a.0.total_cmp(&b.0));

    let mut ranks = vec![0.0; nx + ny];
    let mut i = 0;
    while i < combined.len() {
        let mut j = i + 1;
        while j < combined.len() && combined[j].0 == combined[i].0 {
            j += 1;
        }
        let avg_rank = (i + j + 1) as f64 / 2.0;
        for k in i..j {
            ranks[combined[k].1] = avg_rank;
        }
        i = j;
    }

    let mean_rx: f64 = ranks[..nx].iter().sum::<f64>() / nxf;
    let mean_ry: f64 = ranks[nx..].iter().sum::<f64>() / nyf;

    let rank_within = |data: &[f64]| -> Vec<f64> {
        let mut indexed: Vec<(usize, f64)> = data.iter().cloned().enumerate().collect();
        indexed.sort_by(|a, b| a.1.total_cmp(&b.1));
        let mut r = vec![0.0; data.len()];
        let mut k = 0;
        while k < indexed.len() {
            let mut l = k + 1;
            while l < indexed.len() && indexed[l].1.total_cmp(&indexed[k].1).is_eq() {
                l += 1;
            }
            let avg = (k + l + 1) as f64 / 2.0;
            for m in k..l {
                r[indexed[m].0] = avg;
            }
            k = l;
        }
        r
    };

    let rx_within = rank_within(x);
    let ry_within = rank_within(y);

    let sx2: f64 = ranks[..nx]
        .iter()
        .zip(rx_within.iter())
        .map(|(&ri, &rwi)| (ri - rwi - mean_rx + (nxf + 1.0) / 2.0).powi(2))
        .sum::<f64>()
        / (nxf - 1.0);

    let sy2: f64 = ranks[nx..]
        .iter()
        .zip(ry_within.iter())
        .map(|(&ri, &rwi)| (ri - rwi - mean_ry + (nyf + 1.0) / 2.0).powi(2))
        .sum::<f64>()
        / (nyf - 1.0);

    let nf = nxf + nyf;
    let rank_delta = mean_ry - mean_rx;
    let denom = (nxf * sx2 + nyf * sy2).sqrt();

    let (w, df, pvalue) = if denom > 0.0 {
        let w = nxf * nyf * rank_delta / (nf * denom);
        let df_num = (nxf * sx2 + nyf * sy2).powi(2);
        let df_den = (nxf * sx2).powi(2) / (nxf - 1.0) + (nyf * sy2).powi(2) / (nyf - 1.0);
        let df = if df_den > 0.0 {
            df_num / df_den
        } else {
            f64::NAN
        };
        let pvalue = if df.is_finite() {
            let t_dist = StudentT::new(df);
            // scipy's brunnermunzel uses inverted alternative semantics
            // because W > 0 corresponds to mean_ry > mean_rx:
            //   'less'    (H1: x < y) → sf(w)   (small for w > 0)
            //   'greater' (H1: x > y) → cdf(w)  (large for w > 0)
            // student_t_alternative_pvalue uses the standard t-test
            // convention, so swap 'less' ↔ 'greater' at the call site.
            let bm_alt = match alternative {
                "less" => "greater",
                "greater" => "less",
                other => other,
            };
            student_t_alternative_pvalue(w, &t_dist, bm_alt)
        } else {
            f64::NAN
        };
        (w, df, pvalue)
    } else {
        let w = if rank_delta > 0.0 {
            f64::INFINITY
        } else if rank_delta < 0.0 {
            f64::NEG_INFINITY
        } else {
            f64::NAN
        };
        (w, f64::NAN, f64::NAN)
    };

    TtestResult {
        statistic: w,
        pvalue: pvalue.clamp(0.0, 1.0),
        df,
    }
}

/// Alexander-Govern test for comparing means of k groups.
///
/// More robust alternative to one-way ANOVA for unequal variances.
/// Matches `scipy.stats.alexandergovern`.
pub fn alexandergovern(groups: &[&[f64]]) -> VarianceTestResult {
    let k = groups.len();
    if k < 2 || groups.iter().any(|g| g.len() < 2) {
        return VarianceTestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    // Step 1: per-group mean and SE² = s²/n with ddof=1.
    let means: Vec<f64> = groups
        .iter()
        .map(|g| g.iter().sum::<f64>() / g.len() as f64)
        .collect();
    let se2: Vec<f64> = groups
        .iter()
        .zip(means.iter())
        .map(|(g, &m)| {
            let n = g.len() as f64;
            let var = g.iter().map(|&x| (x - m).powi(2)).sum::<f64>() / (n - 1.0);
            var / n
        })
        .collect();
    if se2.iter().any(|&v| !v.is_finite() || v <= 0.0) {
        return VarianceTestResult {
            statistic: f64::NAN,
            pvalue: f64::NAN,
        };
    }

    // Step 2: weights w_i = (1/SE_i²) / Σ(1/SE_j²); Step 3: variance-weighted
    // common mean Σ w_i · mean_i.
    let inv_se2: Vec<f64> = se2.iter().map(|v| 1.0 / v).collect();
    let denom: f64 = inv_se2.iter().sum();
    let weights: Vec<f64> = inv_se2.iter().map(|w| w / denom).collect();
    let weighted_mean: f64 = weights.iter().zip(means.iter()).map(|(w, m)| w * m).sum();

    // Step 4: per-group t-statistic.
    let t_stats: Vec<f64> = means
        .iter()
        .zip(se2.iter())
        .map(|(&m, &v)| (m - weighted_mean) / v.sqrt())
        .collect();

    // Steps 5-8: Hill's normalising transformation. Per scipy.stats:
    //   v = n_i − 1, a = v − 0.5, b = 48 a²
    //   c = sqrt(a · ln(1 + t²/v))
    //   z = c + (c³ + 3c)/b
    //         − (4c⁷ + 33c⁵ + 240c³ + 855c) / (10b² + 8bc⁴ + 1000b)
    let z_vals: Vec<f64> = groups
        .iter()
        .zip(t_stats.iter())
        .map(|(g, &t)| {
            let v = (g.len() - 1) as f64;
            let a = v - 0.5;
            let b = 48.0 * a * a;
            let c = (a * (1.0 + t * t / v).ln()).sqrt();
            let c3 = c * c * c;
            let c5 = c3 * c * c;
            let c7 = c5 * c * c;
            let num_correct = 4.0 * c7 + 33.0 * c5 + 240.0 * c3 + 855.0 * c;
            let den_correct = 10.0 * b * b + 8.0 * b * c * c * c * c + 1000.0 * b;
            c + (c3 + 3.0 * c) / b - num_correct / den_correct
        })
        .collect();

    // Step 9: A = Σ z_i².
    let stat: f64 = z_vals.iter().map(|z| z * z).sum();

    let df = (k - 1) as f64;
    let chi2 = ChiSquared::new(df);
    let pvalue = chi2.sf(stat).clamp(0.0, 1.0);

    VarianceTestResult {
        statistic: stat,
        pvalue,
    }
}

// ══════════════════════════════════════════════════════════════════════
// Multiple Comparison Corrections
// ══════════════════════════════════════════════════════════════════════

/// Result of a multiple comparison correction.
#[derive(Debug, Clone)]
pub struct MultitestResult {
    /// Corrected p-values.
    pub pvalues_corrected: Vec<f64>,
    /// Whether each test is rejected at the given alpha.
    pub reject: Vec<bool>,
}

fn validate_probability_vector(values: &[f64], name: &str) -> Result<(), StatsError> {
    if values.is_empty() {
        return Err(StatsError::InvalidArgument(format!(
            "{name} must not be empty"
        )));
    }
    for (idx, &value) in values.iter().enumerate() {
        if !value.is_finite() || !(0.0..=1.0).contains(&value) {
            return Err(StatsError::InvalidArgument(format!(
                "{name}[{idx}] must be finite and lie in [0, 1]"
            )));
        }
    }
    Ok(())
}

fn harmonic_number(n: usize) -> f64 {
    (1..=n).map(|k| 1.0 / k as f64).sum()
}

fn fdr_adjusted_pvalues(pvalues: &[f64], scale: f64) -> Vec<f64> {
    let n = pvalues.len();
    if n == 0 {
        return Vec::new();
    }

    let mut indexed: Vec<(usize, f64)> = pvalues.iter().copied().enumerate().collect();
    indexed.sort_by(|a, b| a.1.total_cmp(&b.1));

    let mut corrected = vec![0.0; n];
    let mut running_min = 1.0f64;

    for (rank, &(orig_idx, p)) in indexed.iter().enumerate().rev() {
        let adjusted = (p * scale * n as f64 / (rank + 1) as f64).min(1.0);
        running_min = running_min.min(adjusted);
        corrected[orig_idx] = running_min;
    }

    corrected
}

/// Bonferroni correction: multiply each p-value by the number of tests.
///
/// Matches `scipy.stats.false_discovery_control` and `statsmodels.multipletests(method='bonferroni')`.
pub fn multipletests_bonferroni(pvalues: &[f64], alpha: f64) -> MultitestResult {
    let n = pvalues.len();
    let corrected: Vec<f64> = pvalues.iter().map(|&p| (p * n as f64).min(1.0)).collect();
    let reject: Vec<bool> = corrected.iter().map(|&p| p < alpha).collect();
    MultitestResult {
        pvalues_corrected: corrected,
        reject,
    }
}

/// Šidák correction: 1 - (1 - p)^n.
///
/// Less conservative than Bonferroni for independent tests.
pub fn multipletests_sidak(pvalues: &[f64], alpha: f64) -> MultitestResult {
    let n = pvalues.len();
    let corrected: Vec<f64> = pvalues
        .iter()
        .map(|&p| (1.0 - (1.0 - p).powi(n as i32)).min(1.0))
        .collect();
    let reject: Vec<bool> = corrected.iter().map(|&p| p < alpha).collect();
    MultitestResult {
        pvalues_corrected: corrected,
        reject,
    }
}

/// Holm-Bonferroni step-down correction.
///
/// Matches `statsmodels.multipletests(method='holm')`.
pub fn multipletests_holm(pvalues: &[f64], alpha: f64) -> MultitestResult {
    let n = pvalues.len();
    if n == 0 {
        return MultitestResult {
            pvalues_corrected: vec![],
            reject: vec![],
        };
    }

    // Sort p-values, keeping track of original indices
    let mut indexed: Vec<(usize, f64)> = pvalues.iter().copied().enumerate().collect();
    indexed.sort_by(|a, b| a.1.total_cmp(&b.1));

    let mut corrected = vec![0.0; n];
    let mut running_max = 0.0f64;

    for (rank, &(orig_idx, p)) in indexed.iter().enumerate() {
        let factor = (n - rank) as f64;
        let adjusted = (p * factor).min(1.0);
        // Enforce monotonicity: corrected p-values must be non-decreasing
        running_max = running_max.max(adjusted);
        corrected[orig_idx] = running_max;
    }

    let reject: Vec<bool> = corrected.iter().map(|&p| p < alpha).collect();
    MultitestResult {
        pvalues_corrected: corrected,
        reject,
    }
}

/// Benjamini-Hochberg (FDR) correction.
///
/// Controls false discovery rate rather than family-wise error rate.
/// Matches `statsmodels.multipletests(method='fdr_bh')`.
pub fn multipletests_fdr_bh(pvalues: &[f64], alpha: f64) -> MultitestResult {
    let n = pvalues.len();
    if n == 0 {
        return MultitestResult {
            pvalues_corrected: vec![],
            reject: vec![],
        };
    }

    let mut indexed: Vec<(usize, f64)> = pvalues.iter().copied().enumerate().collect();
    indexed.sort_by(|a, b| a.1.total_cmp(&b.1));

    let mut corrected = vec![0.0; n];
    let mut running_min = 1.0f64;

    // Process from largest to smallest p-value
    for (rank, &(orig_idx, p)) in indexed.iter().enumerate().rev() {
        let adjusted = (p * n as f64 / (rank + 1) as f64).min(1.0);
        running_min = running_min.min(adjusted);
        corrected[orig_idx] = running_min;
    }

    let reject: Vec<bool> = corrected.iter().map(|&p| p < alpha).collect();
    MultitestResult {
        pvalues_corrected: corrected,
        reject,
    }
}

/// Combine independent p-values into a single test statistic and p-value.
///
/// Supported methods: `"fisher"` (default), `"pearson"`, `"tippett"`, `"stouffer"`,
/// `"mudholkar_george"`.
///
/// Matches the core behavior of `scipy.stats.combine_pvalues`.
pub fn combine_pvalues(
    pvalues: &[f64],
    method: Option<&str>,
    weights: Option<&[f64]>,
) -> Result<GoodnessOfFitResult, StatsError> {
    validate_probability_vector(pvalues, "pvalues")?;
    let method = method.unwrap_or("fisher");
    let k = pvalues.len() as f64;

    let result = match method {
        "fisher" => {
            let statistic = if pvalues.contains(&0.0) {
                f64::INFINITY
            } else {
                -2.0 * pvalues.iter().map(|&p| p.ln()).sum::<f64>()
            };
            let pvalue = ChiSquared::new(2.0 * k).sf(statistic).clamp(0.0, 1.0);
            GoodnessOfFitResult { statistic, pvalue }
        }
        "pearson" => {
            let statistic = if pvalues.contains(&1.0) {
                f64::NEG_INFINITY
            } else {
                2.0 * pvalues.iter().map(|&p| (1.0 - p).ln()).sum::<f64>()
            };
            let pvalue = ChiSquared::new(2.0 * k).cdf(-statistic).clamp(0.0, 1.0);
            GoodnessOfFitResult { statistic, pvalue }
        }
        "tippett" => {
            let statistic = pvalues
                .iter()
                .copied()
                .fold(f64::INFINITY, |a: f64, b: f64| {
                    if a.is_nan() || b.is_nan() {
                        f64::NAN
                    } else {
                        a.min(b)
                    }
                });
            let pvalue = (1.0 - (1.0 - statistic).powf(k)).clamp(0.0, 1.0);
            GoodnessOfFitResult { statistic, pvalue }
        }
        "stouffer" => {
            let weights = if let Some(weights) = weights {
                if weights.len() != pvalues.len() {
                    return Err(StatsError::InvalidArgument(
                        "weights must have the same length as pvalues".to_string(),
                    ));
                }
                if weights.iter().any(|&w| !w.is_finite() || w < 0.0) {
                    return Err(StatsError::InvalidArgument(
                        "weights must be finite and non-negative".to_string(),
                    ));
                }
                weights.to_vec()
            } else {
                vec![1.0; pvalues.len()]
            };

            let weight_norm = weights.iter().map(|&w| w * w).sum::<f64>().sqrt();
            if weight_norm == 0.0 {
                return Err(StatsError::InvalidArgument(
                    "weights must not all be zero".to_string(),
                ));
            }

            let statistic = weights
                .iter()
                .zip(pvalues.iter())
                .map(|(&w, &p)| {
                    let bounded = p.clamp(f64::MIN_POSITIVE, 1.0 - f64::EPSILON);
                    w * standard_normal_ppf(1.0 - bounded)
                })
                .sum::<f64>()
                / weight_norm;
            let pvalue = Normal::standard().sf(statistic).clamp(0.0, 1.0);
            GoodnessOfFitResult { statistic, pvalue }
        }
        "mudholkar_george" => {
            let mut has_zero = false;
            let mut has_one = false;
            let mut logit_sum = 0.0;

            for &p in pvalues {
                if p == 0.0 {
                    has_zero = true;
                } else if p == 1.0 {
                    has_one = true;
                } else {
                    logit_sum += p.ln() - (1.0 - p).ln();
                }
            }

            let statistic = if has_zero && has_one {
                f64::NAN
            } else if has_zero {
                f64::NEG_INFINITY
            } else if has_one {
                f64::INFINITY
            } else {
                -logit_sum
            };

            let pvalue = if !statistic.is_finite() {
                if statistic.is_nan() {
                    f64::NAN
                } else if statistic == f64::INFINITY {
                    0.0
                } else {
                    1.0
                }
            } else {
                // scipy.stats.combine_pvalues mudholkar_george branch:
                //   normalizing_factor = sqrt(3/n) / π
                //   nu                 = 5·n + 4
                //   approx_factor      = sqrt(nu / (nu − 2))
                //   pvalue             = T(nu).sf(statistic · normalizing · approx)
                // fsci previously used a Logistic-tail approximation,
                // which drifts from scipy by up to 0.12 abs on mixed
                // fixtures (frankenscipy-v51r8).
                let normalizing = (3.0 / k).sqrt() / std::f64::consts::PI;
                let nu = 5.0 * k + 4.0;
                let approx_factor = (nu / (nu - 2.0)).sqrt();
                let z = statistic * normalizing * approx_factor;
                StudentT::new(nu).sf(z).clamp(0.0, 1.0)
            };

            GoodnessOfFitResult { statistic, pvalue }
        }
        _ => {
            return Err(StatsError::InvalidArgument(format!(
                "unsupported combine_pvalues method: {method}"
            )));
        }
    };

    Ok(result)
}

/// Adjust p-values to control the false discovery rate.
///
/// Supported methods: `"bh"` (default) and `"by"`.
///
/// Matches the core behavior of `scipy.stats.false_discovery_control`.
pub fn false_discovery_control(
    pvalues: &[f64],
    method: Option<&str>,
) -> Result<Vec<f64>, StatsError> {
    validate_probability_vector(pvalues, "pvalues")?;
    let method = method.unwrap_or("bh");

    let corrected = match method {
        "bh" => fdr_adjusted_pvalues(pvalues, 1.0),
        "by" => fdr_adjusted_pvalues(pvalues, harmonic_number(pvalues.len())),
        _ => {
            return Err(StatsError::InvalidArgument(format!(
                "unsupported false_discovery_control method: {method}"
            )));
        }
    };

    Ok(corrected)
}

fn poisson_quantile_bounds(mu: f64, lower_q: f64, upper_q: f64) -> (usize, usize) {
    debug_assert!(mu > 0.0);
    debug_assert!(lower_q >= 0.0 && upper_q <= 1.0 && lower_q <= upper_q);

    // Compute log-pmf via the lgamma form for numerical stability
    // (the previous incremental recursion `pmf *= mu/k` from `exp(-mu)`
    // accumulated drift and never reached upper_q for moderate mu —
    // see [frankenscipy-jd4o2]).
    let log_mu = mu.ln();
    let log_pmf_at = |k: usize| -> f64 {
        let kf = k as f64;
        -mu + kf * log_mu - ln_gamma(kf + 1.0)
    };

    // Search sufficient range: mode ± 12·sqrt(mu) + 50 covers >> 1−1e-16
    // for mu up to a few thousand. Use saturating for the lower edge.
    let span = (12.0 * mu.sqrt()).ceil() as usize + 50;
    let upper_search = (mu as usize).saturating_add(span);

    // Forward CDF accumulation in linear space — pmfs are bounded ≤ 1 so
    // no overflow risk; underflow at extreme tails just adds 0, which is
    // fine for the bound search.
    let mut cdf = 0.0;
    let mut lower = None;
    let mut upper = upper_search;
    for k in 0..=upper_search {
        cdf += log_pmf_at(k).exp();
        if cdf > 1.0 {
            cdf = 1.0;
        }
        if lower.is_none() && cdf >= lower_q {
            lower = Some(k);
        }
        if cdf >= upper_q {
            upper = k;
            break;
        }
    }

    (lower.unwrap_or(0), upper)
}

fn validate_poisson_means_test(
    k1: i64,
    n1: f64,
    k2: i64,
    n2: f64,
    diff: f64,
    alternative: &str,
) -> Result<&str, StatsError> {
    if k1 < 0 || k2 < 0 {
        return Err(StatsError::InvalidArgument(
            "`k1` and `k2` must be greater than or equal to 0.".to_string(),
        ));
    }
    if !n1.is_finite() || !n2.is_finite() || n1 <= 0.0 || n2 <= 0.0 {
        return Err(StatsError::InvalidArgument(
            "`n1` and `n2` must be greater than 0.".to_string(),
        ));
    }
    if diff.is_nan() || diff < 0.0 {
        return Err(StatsError::InvalidArgument(
            "diff must be greater than or equal to 0.".to_string(),
        ));
    }

    match alternative.to_ascii_lowercase().as_str() {
        "two-sided" => Ok("two-sided"),
        "less" => Ok("less"),
        "greater" => Ok("greater"),
        _ => Err(StatsError::InvalidArgument(
            "Alternative must be one of '{'two-sided', 'less', 'greater'}'.".to_string(),
        )),
    }
}

/// Poisson means E-test for the difference between two Poisson rates.
///
/// Matches the core behavior of `scipy.stats.poisson_means_test`.
pub fn poisson_means_test(
    k1: i64,
    n1: f64,
    k2: i64,
    n2: f64,
    diff: f64,
    alternative: Option<&str>,
) -> Result<GoodnessOfFitResult, StatsError> {
    let alternative =
        validate_poisson_means_test(k1, n1, k2, n2, diff, alternative.unwrap_or("two-sided"))?;

    let k1f = k1 as f64;
    let k2f = k2 as f64;
    let lambda_hat2 = (k1f + k2f) / (n1 + n2) - diff * n1 / (n1 + n2);
    if lambda_hat2 <= 0.0 || !lambda_hat2.is_finite() {
        return Ok(GoodnessOfFitResult {
            statistic: 0.0,
            pvalue: 1.0,
        });
    }

    let variance = k1f / (n1 * n1) + k2f / (n2 * n2);
    let observed = (k1f / n1 - k2f / n2 - diff) / variance.sqrt();

    let mu1 = n1 * (lambda_hat2 + diff);
    let mu2 = n2 * lambda_hat2;
    let (x1_lb, x1_ub) = poisson_quantile_bounds(mu1, 1e-10, 1.0 - 1e-16);
    let (x2_lb, x2_ub) = poisson_quantile_bounds(mu2, 1e-10, 1.0 - 1e-16);

    // Pre-compute log-space PMFs once per dimension for numerical stability
    // (the previous incremental recursion `pmf *= mu/k` from `exp(-mu)` was
    // fine for small mu but accumulated drift on n=200+/k=60+ fixtures and
    // produced summed pvalues of 0 — see [frankenscipy-jd4o2]).
    //
    //   ln pmf(k; mu) = -mu + k·ln(mu) - lgamma(k+1)
    let log_mu1 = mu1.ln();
    let log_mu2 = mu2.ln();
    let pmf1: Vec<f64> = (x1_lb..=x1_ub)
        .map(|x| (-mu1 + x as f64 * log_mu1 - ln_gamma(x as f64 + 1.0)).exp())
        .collect();
    let pmf2: Vec<f64> = (x2_lb..=x2_ub)
        .map(|x| (-mu2 + x as f64 * log_mu2 - ln_gamma(x as f64 + 1.0)).exp())
        .collect();

    let mut pvalue = 0.0;
    for (i, x1) in (x1_lb..=x1_ub).enumerate() {
        let prob_x1 = pmf1[i];
        let lambda_x1 = x1 as f64 / n1;

        for (j, x2) in (x2_lb..=x2_ub).enumerate() {
            let prob_x2 = pmf2[j];
            let lambda_x2 = x2 as f64 / n2;
            let delta = lambda_x1 - lambda_x2 - diff;
            let var_x1x2 = lambda_x1 / n1 + lambda_x2 / n2;
            let pivot = if var_x1x2 > 0.0 {
                delta / var_x1x2.sqrt()
            } else {
                f64::NAN
            };

            let include = match alternative {
                "two-sided" => pivot.abs() >= observed.abs(),
                "less" => pivot <= observed,
                "greater" => pivot >= observed,
                _ => false,
            };
            if include {
                pvalue += prob_x1 * prob_x2;
            }
        }
    }

    Ok(GoodnessOfFitResult {
        statistic: observed,
        pvalue: pvalue.clamp(0.0, 1.0),
    })
}

// ══════════════════════════════════════════════════════════════════════
// Effect Sizes
// ══════════════════════════════════════════════════════════════════════

/// Cohen's d: standardized mean difference between two groups.
///
/// Uses pooled standard deviation.
pub fn cohens_d(group1: &[f64], group2: &[f64]) -> f64 {
    let n1 = group1.len() as f64;
    let n2 = group2.len() as f64;
    if n1 < 2.0 || n2 < 2.0 {
        return f64::NAN;
    }

    let mean1: f64 = group1.iter().sum::<f64>() / n1;
    let mean2: f64 = group2.iter().sum::<f64>() / n2;

    let var1: f64 = group1.iter().map(|&x| (x - mean1).powi(2)).sum::<f64>() / (n1 - 1.0);
    let var2: f64 = group2.iter().map(|&x| (x - mean2).powi(2)).sum::<f64>() / (n2 - 1.0);

    let pooled_std = (((n1 - 1.0) * var1 + (n2 - 1.0) * var2) / (n1 + n2 - 2.0)).sqrt();

    if pooled_std == 0.0 {
        return if (mean1 - mean2).abs() < 1e-15 {
            0.0
        } else {
            f64::INFINITY * (mean1 - mean2).signum()
        };
    }

    (mean1 - mean2) / pooled_std
}

/// Cramér's V: association measure for contingency tables.
///
/// V = sqrt(χ²/(n * min(r-1, c-1))), where χ² is the chi-squared statistic.
pub fn cramers_v(observed: &[Vec<f64>]) -> f64 {
    let result = chi2_contingency(observed, true);
    let n: f64 = observed.iter().flat_map(|row| row.iter()).sum();
    let r = observed.len();
    if r == 0 {
        return 0.0;
    }
    let c = observed[0].len();
    let min_dim = (r - 1).min(c - 1);
    if min_dim == 0 || n == 0.0 {
        return 0.0;
    }
    (result.statistic / (n * min_dim as f64)).sqrt()
}

/// Point-biserial correlation: correlation between binary and continuous variable.
///
/// Equivalent to Pearson r when one variable is dichotomous.
pub fn pointbiserialr(binary: &[f64], continuous: &[f64]) -> CorrelationResult {
    // Point-biserial is just Pearson correlation
    pearsonr(binary, continuous)
}

/// Rank-biserial correlation for Mann-Whitney U test.
///
/// r = 1 - 2U/(n1*n2).
pub fn rank_biserial(u_stat: f64, n1: usize, n2: usize) -> f64 {
    let n = n1 as f64 * n2 as f64;
    if n == 0.0 {
        return f64::NAN;
    }
    1.0 - 2.0 * u_stat / n
}

