    fn pearson3_skew_kurt_match_scipy() {
        // scipy.stats.pearson3.stats(skew=s, moments='sk') = (s, 1.5*s²)
        for s in [0.0_f64, 0.5, 1.0, 2.0, -1.5] {
            let d = Pearson3::new(s);
            assert!(
                (d.skewness() - s).abs() < 1e-15,
                "Pearson3({s}).skew = {}",
                d.skewness()
            );
            assert!(
                (d.kurtosis() - 1.5 * s * s).abs() < 1e-15,
                "Pearson3({s}).kurt = {}",
                d.kurtosis()
            );
        }
    }

