    #[test]
    fn gumbel_left_sf_preserves_right_tail_precision() {
        // GumbelLeft.sf = exp(-exp(z)). For large positive z, exp(z) → ∞,
        // exp(-∞) → 0, so sf → 0 directly. Default 1 - cdf = 1 - (1 - sf)
        // would lose precision when cdf ≈ 1.
        let g = GumbelLeft::new(0.0, 1.0);
        // GumbelLeft has sf → 0 in the RIGHT tail (x → +∞), but the
        // precision-sensitive case is x = +small (cdf near 1 minus tiny).
        // At z = 4: cdf = 1 - exp(-e^4) ≈ 1 - exp(-54.6) ≈ 1 - 1.7e-24.
        // Default 1 - cdf collapses; closed form returns ~1.7e-24 directly.
        let z = 4.0_f64;
        let actual = g.sf(z);
        let expected = (-z.exp()).exp();
        assert!(
            actual > 0.0,
            "GumbelLeft.sf(4) must be strictly positive, got {actual}"
        );
        let rel = (actual - expected).abs() / expected.abs();
        assert!(
            rel < 1e-12,
            "GumbelLeft sf far right tail: got {actual}, expected {expected} (rel={rel})"
        );
        for &x in &[-2.0_f64, -1.0, 0.0, 1.0, 3.0] {
            assert_close(g.sf(x) + g.cdf(x), 1.0, 1e-12, "GumbelLeft sf + cdf = 1");
        }
    }

    #[test]
    fn logistic_pareto_lomax_try_fit_returns_real_fit_not_not_implemented() {
        // /mock-code-finder regression for [frankenscipy-covaj]: each
        // distribution has a working fit() but used to inherit the
        // trait-default try_fit returning NotImplemented. After the
        // fix, try_fit must surface a real fit (or a typed error for
        // bad input) rather than NotImplemented.

        // Logistic: method-of-moments on a synthetic sample around loc=2.
        let logistic_sample: Vec<f64> = (0..100)
            .map(|i| {
                // CDF inverse at evenly spaced quantiles to seed a clean fit.
                let q = (i as f64 + 0.5) / 100.0;
                2.0 + 0.5 * (q / (1.0 - q)).ln()
            })
            .collect();
        let log_fit = <Logistic as ContinuousDistribution>::try_fit(&logistic_sample)
            .expect("Logistic try_fit must succeed on clean sample");
        assert!(
            (log_fit.loc - 2.0).abs() < 0.05,
            "Logistic try_fit loc {}, expected ~2.0",
            log_fit.loc
        );

        // Pareto: MLE on samples drawn from Pareto(b=2, scale=1).
        // Sample x_i = scale / (1 - q_i)^(1/b).
        let pareto_sample: Vec<f64> = (0..100)
            .map(|i| {
                let q = (i as f64 + 0.5) / 100.0;
                1.0 / (1.0 - q).powf(0.5)
            })
            .collect();
        let par_fit = <Pareto as ContinuousDistribution>::try_fit(&pareto_sample)
            .expect("Pareto try_fit must succeed on clean sample");
        assert!(
            par_fit.scale > 0.0 && par_fit.b > 0.0,
            "Pareto try_fit produced positive params: b={}, scale={}",
            par_fit.b,
            par_fit.scale
        );

        // Lomax: MLE on samples drawn from Lomax(c=3).
        let lomax_sample: Vec<f64> = (0..100)
            .map(|i| {
                let q = (i as f64 + 0.5) / 100.0;
                (1.0 - q).powf(-1.0 / 3.0) - 1.0
            })
            .collect();
        let lom_fit = <Lomax as ContinuousDistribution>::try_fit(&lomax_sample)
            .expect("Lomax try_fit must succeed on clean sample");
        assert!(
            lom_fit.c > 0.0 && lom_fit.c.is_finite(),
            "Lomax try_fit produced finite positive c: {}",
            lom_fit.c
        );

        // Typed errors instead of panics on bad input.
        match <Logistic as ContinuousDistribution>::try_fit(&[]) {
            Err(FitError::InsufficientData { .. }) => {}
            other => panic!("Logistic empty -> InsufficientData; got {other:?}"),
        }
        match <Pareto as ContinuousDistribution>::try_fit(&[1.0, -2.0]) {
            Err(FitError::UnsupportedData(_)) => {}
            other => panic!("Pareto with non-positive sample -> UnsupportedData; got {other:?}"),
        }
        match <Lomax as ContinuousDistribution>::try_fit(&[-1.0]) {
            Err(FitError::UnsupportedData(_)) => {}
            other => panic!("Lomax with negative sample -> UnsupportedData; got {other:?}"),
        }
    }

    #[test]
    fn acf_centered_form_matches_naive_recompute() {
        // /profiling-software-performance regression for
        // [frankenscipy-l9nh4]: acf now pre-centers once instead of
        // re-subtracting mean inside each lag's inner sum. Verify
        // the optimized form produces identical lags vs. an explicit
        // naïve implementation that recomputes at every lag.
        fn naive_acf(data: &[f64], max_lag: usize) -> Vec<f64> {
            let n = data.len();
            if n < 2 {
                return vec![1.0];
            }
            let mean: f64 = data.iter().sum::<f64>() / n as f64;
            let var: f64 = data.iter().map(|&v| (v - mean).powi(2)).sum();
            if var == 0.0 {
                return vec![1.0; max_lag + 1];
            }
            (0..=max_lag.min(n - 1))
                .map(|lag| {
                    let sum: f64 = (0..n - lag)
                        .map(|i| (data[i] - mean) * (data[i + lag] - mean))
                        .sum();
                    sum / var
                })
                .collect()
        }

        let series: Vec<f64> = (0..30)
            .map(|i| {
                let t = i as f64 * 0.1;
                t.sin() + 0.3 * (1.7 * t).cos() - 0.5
            })
            .collect();
        for &max_lag in &[0_usize, 5, 15] {
            let opt = acf(&series, max_lag);
            let nav = naive_acf(&series, max_lag);
            assert_eq!(opt.len(), nav.len(), "acf length max_lag={max_lag}");
            for (i, (&a, &b)) in opt.iter().zip(nav.iter()).enumerate() {
                assert!(
                    (a - b).abs() < 1e-12,
                    "acf disagrees at lag {i}: optimized={a}, naive={b}"
                );
            }
        }

        // Constant input → all 1.0 (var == 0 branch).
        assert_eq!(acf(&[5.0; 10], 4), vec![1.0; 5]);
    }

    #[test]
    fn laplace_is_symmetric_around_loc() {
        // /testing-metamorphic for [frankenscipy-53yu7]: Laplace is
        // symmetric around loc, so for any d:
        //
        //   Laplace(loc, s).cdf(loc + d) + Laplace(loc, s).cdf(loc - d) = 1
        //   Laplace(loc, s).sf(loc + d) + Laplace(loc, s).sf(loc - d) = 1
        //   Laplace(loc, s).pdf(loc + d) = Laplace(loc, s).pdf(loc - d)
        //
        // Independent verification of the cdf/sf piecewise split:
        // a sign error in either branch would surface as mismatch.
        let cases: &[(f64, f64)] = &[(0.0, 1.0), (-2.0, 0.5), (3.0, 2.0), (-1.5, 4.0)];
        let ds = [0.0_f64, 0.25, 0.5, 1.0, 2.5, 5.0];
        for &(loc, scale) in cases {
            let l = Laplace::new(loc, scale);
            for &d in &ds {
                let xp = loc + d;
                let xm = loc - d;
                assert_close(
                    l.cdf(xp) + l.cdf(xm),
                    1.0,
                    1e-12,
                    &format!("Laplace({loc},{scale}).cdf(loc±d) sums to 1 at d={d}"),
                );
                assert_close(
                    l.sf(xp) + l.sf(xm),
                    1.0,
                    1e-12,
                    &format!("Laplace({loc},{scale}).sf(loc±d) sums to 1 at d={d}"),
                );
                assert_close(
                    l.pdf(xp),
                    l.pdf(xm),
                    1e-12,
                    &format!("Laplace({loc},{scale}).pdf is symmetric at d={d}"),
                );
            }
        }
    }

    #[test]
    fn gumbel_and_gumbel_left_are_mirrors() {
        // /testing-metamorphic for [frankenscipy-bwwz7]: GumbelLeft is
        // the mirror of Gumbel through x → -x and loc → -loc:
        //
        //   Gumbel(loc, s).cdf(x) + GumbelLeft(-loc, s).cdf(-x) = 1
        //   Gumbel(loc, s).pdf(x)  =  GumbelLeft(-loc, s).pdf(-x)
        //   Gumbel(loc, s).sf(x)   =  GumbelLeft(-loc, s).cdf(-x)
        //
        // A sign error in either side would surface as a mismatch.
        let cases: &[(f64, f64)] = &[(0.0, 1.0), (-1.0, 0.5), (2.0, 3.0), (-3.0, 2.5)];
        let xs = [-4.0_f64, -1.0, -0.25, 0.0, 0.25, 1.0, 4.0];
        for &(loc, scale) in cases {
            let g = Gumbel::new(loc, scale);
            let gl = GumbelLeft::new(-loc, scale);
            for &x in &xs {
                let g_cdf = g.cdf(x);
                let gl_cdf_neg = gl.cdf(-x);
                assert_close(
                    g_cdf + gl_cdf_neg,
                    1.0,
                    1e-12,
                    &format!("Gumbel({loc},{scale}).cdf({x}) + GumbelLeft.cdf(-{x}) = 1"),
                );

                let g_pdf = g.pdf(x);
                let gl_pdf_neg = gl.pdf(-x);
                assert_close(
                    g_pdf,
                    gl_pdf_neg,
                    1e-12,
                    &format!("Gumbel({loc},{scale}).pdf({x}) = GumbelLeft.pdf(-{x})"),
                );

                let g_sf = g.sf(x);
                let gl_cdf_neg2 = gl.cdf(-x);
                assert_close(
                    g_sf,
                    gl_cdf_neg2,
                    1e-12,
                    &format!("Gumbel({loc},{scale}).sf({x}) = GumbelLeft.cdf(-{x})"),
                );
            }
        }
    }

    #[test]
    fn chi_squared_df2_is_exponential_scale_2() {
        // /testing-metamorphic for [frankenscipy-wlsd1]: textbook identity
        // ChiSquared(df=2) and Exponential(rate=1/2 = scale=2) are
        // identically distributed — both have pdf (1/2)·exp(-x/2) for
        // x ≥ 0. Pin pdf/cdf/sf agreement at multiple x.
        let chi2 = ChiSquared::new(2.0);
        let exp = Exponential::from_scale(2.0);
        for &x in &[0.0_f64, 0.1, 0.5, 1.0, 2.0, 3.5, 5.0, 10.0] {
            assert_close(
                chi2.pdf(x),
                exp.pdf(x),
                1e-12,
                &format!("ChiSquared(df=2).pdf({x}) vs Exponential(scale=2).pdf({x})"),
            );
            assert_close(
                chi2.cdf(x),
                exp.cdf(x),
                1e-12,
                &format!("ChiSquared(df=2).cdf({x}) vs Exponential(scale=2).cdf({x})"),
            );
            assert_close(
                chi2.sf(x),
                exp.sf(x),
                1e-12,
                &format!("ChiSquared(df=2).sf({x}) vs Exponential(scale=2).sf({x})"),
            );
        }
    }

    #[test]
    fn chi_df1_is_half_normal() {
        // /testing-metamorphic for [frankenscipy-qla9y]: Chi(df=1) is
        // identically HalfNormal — both have pdf √(2/π)·exp(-x²/2) on
        // x≥0. Pin pdf/cdf/sf agreement at multiple x.
        // Combined with qpcaq this gives a triangle of identities tying
        // HalfNormal, Chi(df=1), and ChiSquared(df=1) together.
        let chi = Chi::new(1.0);
        let hn = HalfNormal;
        for &x in &[0.0_f64, 0.1, 0.5, 1.0, 2.0, 3.5, 5.0] {
            assert_close(
                chi.pdf(x),
                hn.pdf(x),
                1e-10,
                &format!("Chi(df=1).pdf({x}) vs HalfNormal.pdf({x})"),
            );
            assert_close(
                chi.cdf(x),
                hn.cdf(x),
                1e-9,
                &format!("Chi(df=1).cdf({x}) vs HalfNormal.cdf({x})"),
            );
            assert_close(
                chi.sf(x),
                hn.sf(x),
                1e-9,
                &format!("Chi(df=1).sf({x}) vs HalfNormal.sf({x})"),
            );
        }
    }

    #[test]
    fn half_normal_squared_is_chi_squared_df1() {
        // /testing-metamorphic for [frankenscipy-qpcaq]: if X ~ N(0,1)
        // then |X| ~ HalfNormal and X² ~ ChiSquared(df=1). Equivalent:
        //
        //   HalfNormal.cdf(x) = ChiSquared(df=1).cdf(x²)  for x ≥ 0
        //   HalfNormal.sf(x)  = ChiSquared(df=1).sf(x²)
        //
        // Independent verification: a normalization or integration
        // error in either side would surface as a mismatch.
        let hn = HalfNormal;
        let chi2 = ChiSquared::new(1.0);
        for &x in &[0.0_f64, 0.1, 0.5, 1.0, 2.0, 3.5, 5.0] {
            let cdf_hn = hn.cdf(x);
            let cdf_chi2 = chi2.cdf(x * x);
            assert_close(
                cdf_hn,
                cdf_chi2,
                1e-9,
                &format!("HalfNormal.cdf({x}) vs ChiSquared(df=1).cdf({x}²)"),
            );

            let sf_hn = hn.sf(x);
            let sf_chi2 = chi2.sf(x * x);
            assert_close(
                sf_hn,
                sf_chi2,
                1e-9,
                &format!("HalfNormal.sf({x}) vs ChiSquared(df=1).sf({x}²)"),
            );
        }
    }

    #[test]
    fn lomax_is_pareto_shifted_by_one() {
        // /testing-metamorphic regression for [frankenscipy-gnwtk]:
        // Lomax (Pareto type II) is the textbook shift of Pareto
        // type I by 1:
        //   Lomax(c).pdf(x) = Pareto(c, scale=1).pdf(x + 1)
        //   Lomax(c).cdf(x) = Pareto(c, scale=1).cdf(x + 1)
        //   Lomax(c).sf(x)  = Pareto(c, scale=1).sf(x + 1)
        // for x ≥ 0. Independent verification of both implementations:
        // a normalization or sign error in either side would mismatch.
        let shapes = [0.5_f64, 1.0, 2.0, 3.5, 7.0];
        let xs = [0.0_f64, 0.1, 0.5, 1.0, 3.0, 10.0, 100.0];
        for &c in &shapes {
            let lomax = Lomax::new(c);
            let pareto = Pareto::new(c, 1.0);
            for &x in &xs {
                let lp = lomax.pdf(x);
                let pp = pareto.pdf(x + 1.0);
                assert_close(
                    lp,
                    pp,
                    1e-12 * pp.abs().max(1.0),
                    &format!("Lomax(c={c}).pdf({x}) vs Pareto(c, 1).pdf({}+1)", x),
                );

                let lc = lomax.cdf(x);
                let pc = pareto.cdf(x + 1.0);
                assert_close(
                    lc,
                    pc,
                    1e-12,
                    &format!("Lomax(c={c}).cdf({x}) vs Pareto(c, 1).cdf({}+1)", x),
                );

                let ls = lomax.sf(x);
                let ps = pareto.sf(x + 1.0);
                let scale = ls.abs().max(ps.abs()).max(1.0);
                assert!(
                    (ls - ps).abs() < 1e-12 * scale,
                    "Lomax(c={c}).sf({x}) = {ls} vs Pareto(c, 1).sf({x}+1) = {ps}"
                );
            }
        }
    }

    #[test]
    fn exponweib_pdf_boundary_matches_scipy() {
        // /testing-metamorphic regression for [frankenscipy-3ahgi]:
        // exponweib.pdf at x=0 is governed by c·a:
        //   c·a < 1 → +∞;  c·a == 1 → a·c;  c·a > 1 → 0
        // Pin all three regimes plus the canonical (a=c=1)
        // identity scipy reports as 1.0.
        // c·a > 1 → 0
        assert_close(
            ExponWeibull::new(2.0, 2.0).pdf(0.0),
            0.0,
            1e-12,
            "ExponWeibull(a=2, c=2).pdf(0) = 0",
        );
        assert_close(
            ExponWeibull::new(2.0, 1.0).pdf(0.0),
            0.0,
            1e-12,
            "ExponWeibull(a=2, c=1).pdf(0) = 0",
        );
        // c·a == 1 → a·c = 1
        assert_close(
            ExponWeibull::new(1.0, 1.0).pdf(0.0),
            1.0,
            1e-12,
            "ExponWeibull(a=1, c=1).pdf(0) = 1 (matches scipy)",
        );
        // c·a < 1 → +∞
        let p = ExponWeibull::new(0.5, 0.5).pdf(0.0);
        assert!(
            p.is_infinite() && p > 0.0,
            "ExponWeibull(a=0.5, c=0.5).pdf(0) = +∞"
        );
        // x outside support
        assert_eq!(ExponWeibull::new(2.0, 2.0).pdf(-0.1), 0.0);
    }

