    #[test]
    fn arcsine_pdf_boundaries_match_scipy() {
        // /mock-code-finder regression for [frankenscipy-1w4wg]:
        // arcsine.pdf = 1/(π·√(x(1-x))) diverges to +∞ at x=0 and
        // x=1 — scipy returns inf there. The previous short-circuit
        // returned 0, silently diverging from scipy.
        let dist = Arcsine;
        assert!(dist.pdf(0.0).is_infinite() && dist.pdf(0.0) > 0.0);
        assert!(dist.pdf(1.0).is_infinite() && dist.pdf(1.0) > 0.0);
        // Outside support still returns 0.
        assert_eq!(dist.pdf(-0.1), 0.0);
        assert_eq!(dist.pdf(1.1), 0.0);
        // Mid-interval still finite & positive.
        let mid = dist.pdf(0.5);
        assert!(mid.is_finite() && mid > 0.0);
        // Near-boundary samples blow up smoothly.
        for x in [0.001_f64, 0.01, 0.1].iter() {
            let p = dist.pdf(*x);
            let mirror = dist.pdf(1.0 - x);
            assert!(p.is_finite() && p > 0.0);
            assert_close(p, mirror, 1e-12, "Arcsine.pdf is symmetric around 0.5");
        }
    }

    #[test]
    fn beta_pdf_boundaries_match_scipy() {
        // /testing-metamorphic regression for [frankenscipy-rsx33]:
        // scipy.stats.beta(a, b).pdf at x=0 is the limit of
        // x^(a-1)·(1-x)^(b-1)/B(a,b):
        //   a > 1 → 0
        //   a = 1 → 1/B(1, b) = b
        //   a < 1 → +∞
        // Symmetric for x=1 in b. Pin all six branch cases plus
        // x slightly inside the open interval to confirm continuity.
        // x = 0
        assert_close(
            BetaDist::new(2.0, 3.0).pdf(0.0),
            0.0,
            1e-12,
            "Beta(2,3).pdf(0) = 0 (a>1)",
        );
        assert_close(
            BetaDist::new(1.0, 1.0).pdf(0.0),
            1.0,
            1e-12,
            "Beta(1,1).pdf(0) = 1/B(1,1) = 1",
        );
        assert_close(
            BetaDist::new(1.0, 2.0).pdf(0.0),
            2.0,
            1e-12,
            "Beta(1,2).pdf(0) = 1/B(1,2) = 2",
        );
        assert!(
            BetaDist::new(0.5, 0.5).pdf(0.0).is_infinite(),
            "Beta(0.5,0.5).pdf(0) = ∞ (a<1)"
        );
        // x = 1
        assert_close(
            BetaDist::new(2.0, 3.0).pdf(1.0),
            0.0,
            1e-12,
            "Beta(2,3).pdf(1) = 0 (b>1)",
        );
        assert_close(
            BetaDist::new(1.0, 1.0).pdf(1.0),
            1.0,
            1e-12,
            "Beta(1,1).pdf(1) = 1",
        );
        assert_close(
            BetaDist::new(2.0, 1.0).pdf(1.0),
            2.0,
            1e-12,
            "Beta(2,1).pdf(1) = 1/B(2,1) = 2",
        );
        assert!(
            BetaDist::new(0.5, 0.5).pdf(1.0).is_infinite(),
            "Beta(0.5,0.5).pdf(1) = ∞ (b<1)"
        );
        // x outside [0, 1]
        assert_eq!(BetaDist::new(2.0, 3.0).pdf(-0.1), 0.0);
        assert_eq!(BetaDist::new(2.0, 3.0).pdf(1.1), 0.0);
    }

    #[test]
    fn beta_one_one_is_uniform_zero_one() {
        // /testing-metamorphic for [frankenscipy-rsx33]: textbook
        // identity Beta(1, 1) ≡ Uniform(0, 1). Across the whole
        // support including boundaries, pdf and cdf must agree.
        // Independent verification: BetaDist routes through
        // ln_beta + regularized_incomplete_beta, while Uniform
        // uses closed-form constant pdf and linear cdf.
        let beta = BetaDist::new(1.0, 1.0);
        let u = Uniform::new(0.0, 1.0);
        for &x in &[0.0_f64, 0.001, 0.1, 0.25, 0.5, 0.75, 0.9, 0.999, 1.0] {
            assert_close(
                beta.pdf(x),
                u.pdf(x),
                1e-12,
                &format!("Beta(1,1).pdf({x}) vs Uniform(0,1).pdf"),
            );
            assert_close(
                beta.cdf(x),
                u.cdf(x),
                1e-12,
                &format!("Beta(1,1).cdf({x}) vs Uniform(0,1).cdf"),
            );
        }
    }

