        //   scipy.stats.halfcauchy.entropy() = ln(2π) ≈ 1.8378770664093453
        let dist = HalfCauchy;
        assert_close(dist.entropy(), (2.0 * PI).ln(), 1e-15, "HalfCauchy.entropy");
        assert!((dist.entropy() - 1.837_877_066_409_345_3).abs() < 1e-13);
