    #[test]
    fn cosine_higher_moments_match_scipy() {
        // /mock-code-finder for [frankenscipy-lud8x]: pin closed-form
        // skew/kurt/entropy. scipy.stats.cosine values:
        //   skew = 0
        //   ex_kurt = -6(π⁴ - 90)/(5(π² - 6)²) ≈ -0.5937628755982794
        //   entropy = ln(4π) − 1 ≈ 1.5310242469692907
        let dist = CosineDistribution;
        assert_close(dist.skewness(), 0.0, 1e-15, "Cosine.skewness");
        let pi2 = PI * PI;
        let pi4 = pi2 * pi2;
        let ex_kurt = -6.0 * (pi4 - 90.0) / (5.0 * (pi2 - 6.0).powi(2));
        assert_close(dist.kurtosis(), ex_kurt, 1e-15, "Cosine.kurtosis");
        assert!((dist.kurtosis() - (-0.593_762_875_598_279_4)).abs() < 1e-13);
        assert_close(
            dist.entropy(),
            (4.0 * PI).ln() - 1.0,
            1e-15,
            "Cosine.entropy",
        );
        assert!((dist.entropy() - 1.531_024_246_969_290_7).abs() < 1e-13);
    }

    #[test]
    fn f_one_v_cdf_is_studentt_squared() {
        // /testing-metamorphic for [frankenscipy-gfeto]: textbook
        // identity If T ~ StudentT(ν), then T² ~ F(1, ν). At the
        // CDF level, for t > 0 and x = t²:
        //
        //   F(1, ν).cdf(t²) = P(|T| ≤ t) = 2·StudentT(ν).cdf(t) − 1
        //
        // Independent verification: F.cdf invokes
        // regularized_incomplete_beta(0.5, 0.5ν, t²/(t²+ν)) directly,
        // while StudentT.cdf invokes the symmetric form
        // regularized_incomplete_beta(0.5ν, 0.5, ν/(t²+ν)) and folds
        // via I_x(a,b) + I_{1-x}(b,a) = 1. A bug in either parameter
        // swap surfaces as a mismatch.
        for &v in &[1.0_f64, 2.0, 5.0, 30.0, 100.0] {
            let f = FDistribution::new(1.0, v);
            let t = StudentT { df: v };
            for &t_val in &[0.1_f64, 0.5, 1.0, 2.0, 5.0] {
                let x = t_val * t_val;
                let lhs = f.cdf(x);
                let rhs = 2.0 * t.cdf(t_val) - 1.0;
                assert_close(
                    lhs,
                    rhs,
                    1e-10,
                    &format!("F(1, {v}).cdf({x}) vs 2·T({v}).cdf({t_val}) − 1"),
                );
                // sf = 1 - cdf, equivalent through the same identity
                // routed via two different code paths.
                let lhs_sf = f.sf(x);
                let rhs_sf = 2.0 * t.sf(t_val);
                assert_close(
                    lhs_sf,
                    rhs_sf,
                    1e-10,
                    &format!("F(1, {v}).sf({x}) vs 2·T({v}).sf({t_val})"),
                );
            }
        }
    }

    #[test]
    fn halflogistic_is_folded_logistic() {
        // /testing-metamorphic for [frankenscipy-z6ssa]: textbook
        // identity HalfLogistic ≡ |Logistic(0, 1)|. For x ≥ 0:
        //   HalfLogistic.pdf(x) = 2 · Logistic.pdf(x)
        //   HalfLogistic.cdf(x) = 2 · Logistic.cdf(x) − 1
        //   HalfLogistic.sf(x)  = 2 · Logistic.sf(x)
        // Independent verification across two distinct code paths:
        // Logistic uses exp/(1+exp)² with translation/scale logic;
        // HalfLogistic uses 2·exp(-x)/(1+exp(-x))² directly. The
        // algebraic equivalence at x ≥ 0 holds only if both
        // implementations are correct.
        let hl = HalfLogistic;
        let lg = Logistic::new(0.0, 1.0);
        for &x in &[0.0_f64, 0.05, 0.5, 1.0, 2.5, 5.0, 10.0] {
            assert_close(
                hl.pdf(x),
                2.0 * lg.pdf(x),
                1e-12,
                &format!("HalfLogistic.pdf({x}) vs 2·Logistic.pdf({x})"),
            );
            assert_close(
                hl.cdf(x),
                2.0 * lg.cdf(x) - 1.0,
                1e-12,
                &format!("HalfLogistic.cdf({x}) vs 2·Logistic.cdf({x}) − 1"),
            );
            assert_close(
                hl.sf(x),
                2.0 * lg.sf(x),
                1e-12,
                &format!("HalfLogistic.sf({x}) vs 2·Logistic.sf({x})"),
            );
        }
    }

    #[test]
    fn betaprime_is_beta_under_x_over_one_plus_x() {
        // /testing-metamorphic for [frankenscipy-2n31z]: textbook
        // identity BetaPrime(α, β) ≡ Beta(α, β) under Y = X/(1+X).
        //   cdf:  BetaPrime(a, b).cdf(x) = Beta(a, b).cdf(x/(1+x))
        //   sf:   BetaPrime(a, b).sf(x)  = Beta(a, b).sf(x/(1+x))
        //   pdf:  BetaPrime(a, b).pdf(x) = Beta(a, b).pdf(x/(1+x)) / (1+x)²
        // Independent verification across two distinct implementations:
        // BetaPrime.cdf and Beta.cdf both go through
        // regularized_incomplete_beta but with different parameterization,
        // and the pdf paths differ entirely.
        let shapes = [(0.5_f64, 1.5), (1.0, 1.0), (2.0, 3.0), (5.0, 0.7)];
        let xs = [0.001_f64, 0.1, 0.5, 1.0, 2.5, 10.0];
        for (a, b) in shapes {
            let bp = BetaDist::new(a, b);
            let bprime = BetaPrime::new(a, b);
            for x in xs {
                let y = x / (1.0 + x);
                let scale_pdf = (1.0 + x) * (1.0 + x);
                assert_close(
                    bprime.pdf(x),
                    bp.pdf(y) / scale_pdf,
                    1e-10 * bp.pdf(y).abs().max(1.0),
                    &format!("BetaPrime({a},{b}).pdf({x}) vs Beta.pdf({y})/(1+{x})²"),
                );
                assert_close(
                    bprime.cdf(x),
                    bp.cdf(y),
                    1e-10,
                    &format!("BetaPrime({a},{b}).cdf({x}) vs Beta.cdf({y})"),
                );
                assert_close(
                    bprime.sf(x),
                    bp.sf(y),
                    1e-10,
                    &format!("BetaPrime({a},{b}).sf({x}) vs Beta.sf({y})"),
                );
            }
        }
    }

    #[test]
    fn skewnorm_cdf_clamps_for_large_a() {
        // /testing-fuzzing regression for [frankenscipy-r7dbb]:
        // For large |a|, Owen's T (10-pt Gauss-Legendre) loses
        // precision in the deep tail and the raw formula
        // Φ(x) − 2·T(x, a) can drift slightly outside [0, 1].
        // scipy.stats.skewnorm clamps via np.clip(cdf, 0, 1);
        // fsci must match.
        let dist = SkewNorm::new(50.0);
        // Pre-fix this returned -0.024.
        let c = dist.cdf(-1.0);
        assert!(
            (0.0..=1.0).contains(&c),
            "SkewNorm(50).cdf(-1) = {c} must be in [0, 1]"
        );
        // Stress sweep: every (a, x) result must lie in [0, 1].
        for &a in &[-50.0_f64, -10.0, -1.0, 0.0, 1.0, 10.0, 50.0] {
            let dist = SkewNorm::new(a);
            for &x in &[-1.0e6_f64, -10.0, -1.0, 0.0, 1.0, 10.0, 1.0e6] {
                let c = dist.cdf(x);
                assert!(
                    (0.0..=1.0).contains(&c),
                    "cdf({x}; a={a}) = {c} must be in [0, 1]"
                );
            }
        }
    }

