    #[test]
    fn exponpow_ppf_inverts_cdf() {
        // /porting-to-rust [frankenscipy-5q0ap]: round-trip on the
        // interior of the support. The cdf saturates very rapidly
        // (cdf(2; b=2) ≈ 1 to ~1 ulp), so the ppf can't recover x
        // there — that's a numerical limit of any closed-form inverse.
        for &b in &[0.5_f64, 1.0, 2.0, 3.5] {
            let dist = ExponPow::new(b);
            // Choose probes where cdf stays comfortably below saturation.
            for &x in &[0.05_f64, 0.25, 0.5, 0.9] {
                let q = dist.cdf(x);
                if q >= 1.0 - 1e-12 {
                    continue;
                }
                let recovered = dist.ppf(q);
                let scale = x.abs().max(1.0);
                assert!(
                    (recovered - x).abs() < 1e-10 * scale,
                    "ExponPow({b}).ppf(cdf({x})) = {recovered}, want {x}"
                );
            }
        }
    }

    /// ExponPow.mean/var via numerical integration of E[X^k] in
    /// t = x^b space, where the integrand is t^{k/b} · e · exp(t − e^t).
    /// Anchored against scipy.stats.exponpow.stats (frankenscipy-uba7f).
    #[test]
    fn exponpow_mean_var_match_scipy() {
        let cases: [(f64, f64, f64); 5] = [
            (0.5, 0.5319307700648661, 0.4393011898344849),
            (1.0, 0.5963473623176415, 0.1763005935216577),
            (1.5, 0.6648334123684801, 0.1151488381280384),
            (2.0, 0.7157241036160373, 0.0840863698206612),
            (3.0, 0.7830957047380310, 0.0515945295893273),
        ];
        for (b, em, ev) in cases {
            let d = ExponPow::new(b);
            let m = d.mean();
            let v = d.var();
            assert!(
                (m - em).abs() < 1e-5,
                "ExponPow({b}).mean = {m}, scipy {em}"
            );
            assert!(
                (v - ev).abs() < 1e-5,
                "ExponPow({b}).var = {v}, scipy {ev}"
            );
        }
    }

    #[test]
    fn exponpow_b1_is_gompertz_c1() {
        // /testing-metamorphic for [frankenscipy-z5ssy]: textbook
        // identity ExponPow(b=1) ≡ Gompertz(c=1). Both pdf forms
        // reduce to exp(1 + x − exp(x)) for x ≥ 0.
        // Independent verification across two distinct code paths:
        // ExponPow uses logpdf = 1 + ln(b) + (b−1)·ln(x) + xb − exp(xb);
        // Gompertz uses self.c · exp(x) · exp(-self.c · (exp(x) − 1)).
        let ep = ExponPow::new(1.0);
        let g = Gompertz::new(1.0);
        for &x in &[0.0_f64, 0.05, 0.5, 1.0, 1.5, 2.0, 3.0] {
            assert_close(
                ep.pdf(x),
                g.pdf(x),
                1e-12,
                &format!("ExponPow(1).pdf({x}) vs Gompertz(1).pdf({x})"),
            );
            assert_close(
                ep.cdf(x),
                g.cdf(x),
                1e-12,
                &format!("ExponPow(1).cdf({x}) vs Gompertz(1).cdf({x})"),
            );
            assert_close(
                ep.sf(x),
                g.sf(x),
                1e-9,
                &format!("ExponPow(1).sf({x}) vs Gompertz(1).sf({x})"),
            );
        }
    }

    #[test]
    fn gilbrat_is_lognormal_unit_unit() {
        // /testing-metamorphic for [frankenscipy-97rpr]: textbook
        // identity Gilbrat ≡ Lognormal(s=1, scale=1). Gilbrat is the
        // parameterless lognormal at unit shape and scale.
        // Independent verification across two distinct code paths:
        // Gilbrat uses exp(-0.5·(ln x)²) / (x·√(2π)) directly and
        // standard_normal_cdf for cdf; Lognormal uses
        // (z = ln(x/scale)/s)·exp / (x·s·√(2π)) and erf_scalar.
        let g = Gilbrat;
        let ln = Lognormal::new(1.0, 1.0);
        for &x in &[0.001_f64, 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 100.0] {
            assert_close(
                g.pdf(x),
                ln.pdf(x),
                1e-12,
                &format!("Gilbrat.pdf({x}) vs Lognormal(1, 1).pdf({x})"),
            );
            assert_close(
                g.cdf(x),
                ln.cdf(x),
                1e-12,
                &format!("Gilbrat.cdf({x}) vs Lognormal(1, 1).cdf({x})"),
            );
            assert_close(
                g.sf(x),
                ln.sf(x),
                1e-12,
                &format!("Gilbrat.sf({x}) vs Lognormal(1, 1).sf({x})"),
            );
        }
    }

