        let reference = BetaDist::new(2.0, 5.0);
        let mean = reference.mean();
        let var = reference.var();
        let delta = (1.5 * var).sqrt();
        let data = [mean - delta, mean, mean + delta];
        let fitted = BetaDist::fit(&data);
