    #[test]
    fn rankdata_no_ties() {
        let ranks = rankdata(&[3.0, 1.0, 2.0], None).expect("rankdata average");
        assert_close(ranks[0], 3.0, 1e-12, "rank of 3.0");
        assert_close(ranks[1], 1.0, 1e-12, "rank of 1.0");
        assert_close(ranks[2], 2.0, 1e-12, "rank of 2.0");
    }

    #[test]
    fn rankdata_with_ties() {
        let ranks = rankdata(&[1.0, 2.0, 2.0, 4.0], Some("average")).expect("rankdata average");
        assert_close(ranks[0], 1.0, 1e-12, "rank of 1.0");
        assert_close(ranks[1], 2.5, 1e-12, "rank of 2.0 (tied)");
        assert_close(ranks[2], 2.5, 1e-12, "rank of 2.0 (tied)");
        assert_close(ranks[3], 4.0, 1e-12, "rank of 4.0");
    }

    #[test]
    fn rankdata_ordinal_matches_scipy_reference() {
        let ranks = rankdata(&[1.0, 2.0, 2.0, 4.0], Some("ordinal")).expect("rankdata ordinal");
        assert_close(ranks[0], 1.0, 1e-12, "rank of 1.0");
        assert_close(ranks[1], 2.0, 1e-12, "first tied rank");
        assert_close(ranks[2], 3.0, 1e-12, "second tied rank");
        assert_close(ranks[3], 4.0, 1e-12, "rank of 4.0");
    }

    #[test]
    fn rankdata_dense_min_max_match_scipy_reference() {
        let dense = rankdata(&[1.0, 2.0, 2.0, 4.0], Some("dense")).expect("rankdata dense");
        assert_eq!(dense, vec![1.0, 2.0, 2.0, 3.0]);

        let min = rankdata(&[1.0, 2.0, 2.0, 4.0], Some("min")).expect("rankdata min");
        assert_eq!(min, vec![1.0, 2.0, 2.0, 4.0]);

        let max = rankdata(&[1.0, 2.0, 2.0, 4.0], Some("max")).expect("rankdata max");
        assert_eq!(max, vec![1.0, 3.0, 3.0, 4.0]);
    }

    #[test]
    fn rankdata_metamorphic_monotone_transform_invariants() -> Result<(), StatsError> {
        let tied = [3.0, -2.0, 3.0, 0.5, -2.0, 9.0];
        let increasing: Vec<f64> = tied.iter().map(|&x| 4.0 * x + 11.0).collect();
        for method in ["average", "min", "max", "dense", "ordinal"] {
            let baseline = rankdata(&tied, Some(method))?;
            let transformed = rankdata(&increasing, Some(method))?;
            assert_eq!(
                transformed, baseline,
                "strictly increasing affine transform must preserve {method} ranks"
            );
        }

        let no_ties = [-3.0, 7.0, 0.0, 11.0, 2.0];
        let decreasing: Vec<f64> = no_ties.iter().map(|&x| -5.0 * x + 1.0).collect();
        let n_plus_one = 6.0;
        for method in ["average", "min", "max", "dense", "ordinal"] {
            let baseline = rankdata(&no_ties, Some(method))?;
            let transformed = rankdata(&decreasing, Some(method))?;
            let expected: Vec<f64> = baseline.iter().map(|rank| n_plus_one - rank).collect();
            assert_eq!(
                transformed, expected,
                "strictly decreasing affine transform must reverse no-tie {method} ranks"
            );
        }
        Ok(())
    }

    #[test]
    fn rankdata_nan_and_invalid_method_match_scipy_shape() {
        let ranks = rankdata(&[1.0, f64::NAN, 2.0], Some("ordinal")).expect("nan rankdata");
        assert!(
            ranks.iter().all(|rank| rank.is_nan()),
            "NaN input should propagate"
        );

        let err = rankdata(&[1.0, 2.0], Some("competition")).expect_err("invalid method");
        assert_eq!(
            err,
            StatsError::InvalidArgument(
                "method must be one of {'average', 'min', 'max', 'dense', 'ordinal'}".to_string()
            )
        );
    }

    // ── tiecorrect tests ──────────────────────────────────────────

    #[test]
    fn tiecorrect_no_ties() {
        // No ties: [1, 2, 3, 4] → T = 1.0
        let ranks = vec![1.0, 2.0, 3.0, 4.0];
        let t = tiecorrect(&ranks);
        assert!((t - 1.0).abs() < 1e-10, "no ties should give T=1: {}", t);
    }

    #[test]
    fn tiecorrect_with_ties() {
        // Ranks with ties: [1.5, 1.5, 3, 4] (two values tied at rank 1.5)
        let ranks = vec![1.5, 1.5, 3.0, 4.0];
        let t = tiecorrect(&ranks);
        // T = 1 - (2^3 - 2) / (4^3 - 4) = 1 - 6/60 = 1 - 0.1 = 0.9
        assert!((t - 0.9).abs() < 1e-10, "one tie group of 2: {}", t);
    }

    #[test]
    fn tiecorrect_all_tied() {
        // All same rank: [2.5, 2.5, 2.5, 2.5]
        let ranks = vec![2.5, 2.5, 2.5, 2.5];
        let t = tiecorrect(&ranks);
        // T = 1 - (4^3 - 4) / (4^3 - 4) = 0
        assert!((t - 0.0).abs() < 1e-10, "all tied: {}", t);
    }

    #[test]
    fn tiecorrect_multiple_tie_groups() {
        // [1.5, 1.5, 3.5, 3.5, 5.5, 5.5]
        let ranks = vec![1.5, 1.5, 3.5, 3.5, 5.5, 5.5];
        let t = tiecorrect(&ranks);
        // Three groups of 2: sum = 3*(8-2) = 18, n^3 - n = 216 - 6 = 210
        // T = 1 - 18/210 = 1 - 3/35 ≈ 0.914
        assert!(t < 1.0 && t > 0.9, "multiple tie groups: {}", t);
    }

    #[test]
    fn tiecorrect_empty_and_single() {
        assert!((tiecorrect(&[]) - 1.0).abs() < 1e-10, "empty");
        assert!((tiecorrect(&[1.0]) - 1.0).abs() < 1e-10, "single");
    }

