    #[test]
    fn ks_1samp_normal_data_from_normal_cdf() {
        // Data drawn from N(0,1) tested against N(0,1) CDF → high p-value
        let data: Vec<f64> = (0..200)
            .map(|i| {
                let u = (i as f64 + 0.5) / 200.0;
                standard_normal_ppf(u)
            })
            .collect();
        let norm = Normal::standard();
        let result = ks_1samp(&data, |x| ContinuousDistribution::cdf(&norm, x));
        assert!(
            result.pvalue > 0.05,
            "normal data vs normal CDF should not reject: p={}",
            result.pvalue
        );
    }

    #[test]
    fn ks_1samp_uniform_data_from_normal_cdf() {
        // Uniform data tested against Normal CDF → low p-value (reject)
        let data: Vec<f64> = (0..100).map(|i| (i as f64) / 99.0 * 6.0 - 3.0).collect();
        let norm = Normal::standard();
        let result = ks_1samp(&data, |x| ContinuousDistribution::cdf(&norm, x));
        assert!(
            result.pvalue < 0.05,
            "uniform data vs normal CDF should reject: p={}",
            result.pvalue
        );
    }

    #[test]
    fn ks_1samp_empty_returns_nan() {
        let result = ks_1samp(&[], |x| x);
        assert!(result.statistic.is_nan());
        assert!(result.pvalue.is_nan());
    }

    #[test]
    fn ks_1samp_matches_scipy_asymptotic_reference_values() {
        let uniform_samples: Vec<f64> = (0..100).map(|i| (i as f64 + 0.5) / 100.0).collect();
        let uniform = ks_1samp(&uniform_samples, |x| x.clamp(0.0, 1.0));
        assert_close(
            uniform.statistic,
            0.005_000_000_000_000_004_4,
            1.0e-15,
            "ks_1samp uniform statistic",
        );
        assert_close(uniform.pvalue, 1.0, 1.0e-15, "ks_1samp uniform pvalue");

        let skewed_samples: Vec<f64> = (0..50).map(|i| (i as f64 / 50.0).powi(2)).collect();
        let skewed = ks_1samp(&skewed_samples, |x| x.clamp(0.0, 1.0));
        assert_close(skewed.statistic, 0.27, 1.0e-15, "ks_1samp skewed statistic");
        assert_close(
            skewed.pvalue,
            0.001_364_656_105_079_237,
            1.0e-15,
            "ks_1samp skewed pvalue",
        );

        let normalish = [-1.2, -0.7, -0.2, 0.0, 0.1, 0.4, 0.9, 1.3];
        let normal = Normal::standard();
        let normalish_result = ks_1samp(&normalish, |x| ContinuousDistribution::cdf(&normal, x));
        assert_close(
            normalish_result.statistic,
            0.170_740_290_560_896_96,
            1.0e-15,
            "ks_1samp normal statistic",
        );
        assert_close(
            normalish_result.pvalue,
            0.973_828_230_896_588_7,
            1.0e-15,
            "ks_1samp normal pvalue",
        );
    }

    #[test]
    fn kstest_dispatches_to_one_sample() {
        fn normal_cdf(x: f64) -> f64 {
            ContinuousDistribution::cdf(&Normal::standard(), x)
        }

        let data: Vec<f64> = (0..80)
            .map(|i| standard_normal_ppf((i as f64 + 0.5) / 80.0))
            .collect();
        let direct = ks_1samp(&data, normal_cdf);
        let wrapped = kstest(&data, KstestTarget::Cdf(normal_cdf));
        assert_close(
            wrapped.statistic,
            direct.statistic,
            1e-12,
            "kstest one-sample statistic",
        );
        assert_close(
            wrapped.pvalue,
            direct.pvalue,
            1e-12,
            "kstest one-sample pvalue",
        );
    }

