        let row1 = [1.0, 2.0, 3.0, 4.0];
        let row2 = [1.0, 3.0, 2.0, 4.0];
        let row3 = [2.0, 1.0, 3.0, 4.0];
        let result = page_trend_test(&[&row1, &row2, &row3]);
        assert!(result.statistic.is_finite());
        assert!(result.pvalue.is_finite());
