    #[test]
    fn planck_is_boltzmann_limit() {
        // /testing-metamorphic [frankenscipy-lp6dv]:
        // Planck(λ) is exactly the N → ∞ limit of Boltzmann(λ, N).
        // For finite N, the difference scales with e^(−λN) — at
        // N = 50 with λ ≥ 1 the bound is ≤ exp(−50) ≈ 2e-22.
        for &lam in &[1.0_f64, 1.5, 2.0, 3.0] {
            let pl = Planck::new(lam);
            let bo = Boltzmann::new(lam, 50);
            for k in 0..6u64 {
                assert!(
                    (pl.pmf(k) - bo.pmf(k)).abs() < 1e-12,
                    "Planck.pmf({k}; λ={lam}) ≠ Boltzmann.pmf({k}; λ={lam}, N=50)"
                );
                assert!(
                    (pl.cdf(k) - bo.cdf(k)).abs() < 1e-12,
                    "Planck.cdf({k}; λ={lam}) ≠ Boltzmann.cdf({k}; λ={lam}, N=50)"
                );
            }
        }
    }

    #[test]
    fn boltzmann_geometric_limit() {
        // /testing-metamorphic [frankenscipy-nvrxh]:
        // As N → ∞ with λ fixed, Boltzmann(λ, N).pmf(k)
        // approaches the standard truncated-geometric form
        // (1 − e^(−λ)) · e^(−λk) — the geometric distribution
        // with success probability p = 1 − e^(−λ), shifted so
        // k = 0 is the first trial. Pin the limit.
        let lam = 1.5_f64;
        let p = -(-lam).exp_m1();
        let large = Boltzmann::new(lam, 100);
        for k in 0..6u64 {
            let want = p * (-lam * k as f64).exp();
            assert!(
                (large.pmf(k) - want).abs() < 1e-12,
                "Boltzmann(λ={lam}, N=100).pmf({k}) = {}, want {want} (geometric limit)",
                large.pmf(k)
            );
        }
    }

    #[test]
    fn powerlognorm_c1_matches_lognormal() {
        // /testing-metamorphic [frankenscipy-ybgru]:
        // PowerLognorm(c=1, s) is algebraically identical to
        // Lognormal(s=s, scale=1):
        //
        //   PowerLognorm pdf(x; 1, s) = 1 · φ(ln x / s) · Φ(−ln x / s)^0 / (x · s)
        //                              = φ(ln x / s) / (x · s)
        //
        //   Lognormal    pdf(x; s, 1) = φ(ln x / s) / (x · s)
        //
        //   PowerLognorm cdf(x; 1, s) = 1 − Φ(−ln x / s)
        //                              = Φ(ln x / s)
        //
        //   Lognormal    cdf(x; s, 1) = Φ(ln x / s)
        //
        // Pin both identities. Future tweaks to either family
        // that accidentally break this equivalence (sign flips,
        // z reformulation, divergent normal-helper paths) trip
        // this test rather than slipping through.
        let pl = PowerLognorm::new(1.0, 1.0);
        let ln = Lognormal::new(1.0, 1.0);
        for &s in &[0.5_f64, 1.0, 1.5, 2.0] {
            let pl = PowerLognorm::new(1.0, s);
            let ln = Lognormal::new(s, 1.0);
            for &x in &[0.05_f64, 0.3, 1.0, 2.5, 5.0, 20.0] {
                let dp = (pl.pdf(x) - ln.pdf(x)).abs();
                let dc = (pl.cdf(x) - ln.cdf(x)).abs();
                assert!(
                    dp < 1.0e-13,
                    "pdf identity broken at s={s}, x={x}: \
                     PowerLognorm={}, Lognormal={}, diff={dp}",
                    pl.pdf(x),
                    ln.pdf(x)
                );
                assert!(
                    dc < 1.0e-13,
                    "cdf identity broken at s={s}, x={x}: \
                     PowerLognorm={}, Lognormal={}, diff={dc}",
                    pl.cdf(x),
                    ln.cdf(x)
                );
            }
        }
        // Suppress unused-warning at default params if loop body
        // gets refactored in future.
        let _ = (pl, ln);
    }

    #[test]
    fn kappa3_a1_matches_lomax_c1() {
        // /testing-metamorphic [frankenscipy-zf1ms]:
        // Kappa3(a=1) is algebraically identical to Lomax(c=1):
        //
        //   Kappa3 pdf(x; 1) = 1 · (1 + x)^(−(1+1)/1) = (1 + x)^(−2)
        //   Kappa3 cdf(x; 1) = x · (1 + x)^(−1/1) = x / (1 + x)
        //
        //   Lomax pdf(x; 1) = 1 / (1 + x)^(1+1) = (1 + x)^(−2)
        //   Lomax cdf(x; 1) = 1 − (1 + x)^(−1) = x / (1 + x)
        //
        // Pin the identity. Future tweaks to either family that
        // accidentally break it (e.g., a redefinition of the
        // shape parameter, a sign flip in the exponent) trip
        // this test rather than slipping through.
        let kappa3 = Kappa3::new(1.0);
        let lomax = Lomax::new(1.0);
        for &x in &[0.1_f64, 0.5, 1.0, 2.0, 5.0, 10.0, 50.0, 100.0] {
            let dp = (kappa3.pdf(x) - lomax.pdf(x)).abs();
            let dc = (kappa3.cdf(x) - lomax.cdf(x)).abs();
            assert!(
                dp < 1.0e-13,
                "pdf identity broken at x={x}: kappa3={}, lomax={}, diff={dp}",
                kappa3.pdf(x),
                lomax.pdf(x)
            );
            assert!(
                dc < 1.0e-13,
                "cdf identity broken at x={x}: kappa3={}, lomax={}, diff={dc}",
                kappa3.cdf(x),
                lomax.cdf(x)
            );
        }
    }

