        assert_close(t6.kurtosis(), 3.0, 1e-10, "StudentT(6) kurtosis");

        let t10 = StudentT::new(10.0);
        assert_close(t10.kurtosis(), 1.0, 1e-10, "StudentT(10) kurtosis");

