    fn dist_interval_invalid() {
        let n = Normal::standard();
        let (lower, upper) = n.interval(-0.1);
        assert!(lower.is_nan());
        assert!(upper.is_nan());

        let (lower2, upper2) = n.interval(1.5);
        assert!(lower2.is_nan());
        assert!(upper2.is_nan());
    }

