    #[test]
    fn cumsum_closed_form_and_last_equals_total() {
        // /testing-metamorphic for [frankenscipy-cvcna]:
        //   cumsum([1, 2, 3, 4]) = [1, 3, 6, 10]; last entry = sum.
        let r = cumsum(&[1.0_f64, 2.0, 3.0, 4.0]);
        assert_eq!(r, vec![1.0, 3.0, 6.0, 10.0]);
        assert_eq!(*r.last().unwrap(), 10.0);

        // Single-element input returns the element.
        assert_eq!(cumsum(&[42.0_f64]), vec![42.0]);

        // Empty input returns empty.
        assert_eq!(cumsum(&[]), Vec::<f64>::new());

        // Random-ish input: last entry equals raw sum.
        let data = vec![1.7_f64, -3.1, 2.9, 0.4, 5.0];
        let raw_sum: f64 = data.iter().sum();
        let cs = cumsum(&data);
        assert!((cs.last().copied().unwrap() - raw_sum).abs() < 1e-12);
    }

    #[test]
    fn cumprod_closed_form_and_last_equals_product() {
        // cumprod([1, 2, 3, 4]) = [1, 2, 6, 24] (factorial sequence).
        let r = cumprod(&[1.0_f64, 2.0, 3.0, 4.0]);
        assert_eq!(r, vec![1.0, 2.0, 6.0, 24.0]);
        assert_eq!(*r.last().unwrap(), 24.0);

        // cumprod containing zero must yield zeros from that point on.
        let r = cumprod(&[2.0_f64, 3.0, 0.0, 5.0]);
        assert_eq!(r, vec![2.0, 6.0, 0.0, 0.0]);

        assert_eq!(cumprod(&[]), Vec::<f64>::new());
        assert_eq!(cumprod(&[7.0]), vec![7.0]);
    }

    #[test]
    fn diff_basic_and_inverse_with_cumsum() {
        // diff([1, 3, 6, 10, 4]) = [2, 3, 4, -6]
        let r = diff(&[1.0_f64, 3.0, 6.0, 10.0, 4.0]);
        assert_eq!(r, vec![2.0, 3.0, 4.0, -6.0]);

        // Empty / singleton return empty.
        assert_eq!(diff(&[]), Vec::<f64>::new());
        assert_eq!(diff(&[5.0_f64]), Vec::<f64>::new());

        // Metamorphic: diff(cumsum(x)) = x[1..]. Each pairwise
        // difference of the running sum recovers the original value.
        let x = vec![3.0_f64, 1.5, -2.7, 5.0, 0.3];
        let cs = cumsum(&x);
        let dcs = diff(&cs);
        // dcs[i] = cs[i+1] - cs[i] = x[i+1].
        for (i, &expected) in x.iter().skip(1).enumerate() {
            assert!(
                (dcs[i] - expected).abs() < 1e-12,
                "diff(cumsum)[{i}] = {} != x[{}] = {expected}",
                dcs[i],
                i + 1
            );
        }
    }

    #[test]
    fn anglit_pdf_cdf_match_closed_form() {
        // /testing-golden-artifacts for [frankenscipy-qznjs]:
        // anglit pdf(x) = cos(2x), cdf(x) = (sin(2x) + 1)/2 on [-π/4, π/4].
        let dist = Anglit;
        // pdf(0) = cos(0) = 1
        assert!((dist.pdf(0.0) - 1.0).abs() < 1e-12);
        // pdf(±π/8) = cos(±π/4) = √2/2
        let q = std::f64::consts::PI / 8.0;
        assert!((dist.pdf(q) - 2.0_f64.sqrt() / 2.0).abs() < 1e-12);
        assert!((dist.pdf(-q) - 2.0_f64.sqrt() / 2.0).abs() < 1e-12);
        // pdf at boundary ±π/4 = cos(±π/2) = 0
        assert!(dist.pdf(std::f64::consts::FRAC_PI_4).abs() < 1e-12);
        assert!(dist.pdf(-std::f64::consts::FRAC_PI_4).abs() < 1e-12);
        // pdf out of support
        assert_eq!(dist.pdf(std::f64::consts::FRAC_PI_4 + 0.1), 0.0);
        assert_eq!(dist.pdf(-std::f64::consts::FRAC_PI_4 - 0.1), 0.0);
        // cdf endpoints
        assert!(dist.cdf(-std::f64::consts::FRAC_PI_4).abs() < 1e-12);
        assert!((dist.cdf(std::f64::consts::FRAC_PI_4) - 1.0).abs() < 1e-12);
        // cdf(0) = (sin(0) + 1)/2 = 0.5 (median)
        assert!((dist.cdf(0.0) - 0.5).abs() < 1e-12);
        // cdf saturation outside support
        assert_eq!(dist.cdf(-1.0), 0.0);
        assert_eq!(dist.cdf(1.0), 1.0);
    }

    #[test]
    fn anglit_ppf_inverts_cdf_on_grid() {
        // /testing-metamorphic: ppf(cdf(x)) ≈ x and cdf(ppf(q)) ≈ q.
        let dist = Anglit;
        for &q in &[0.05_f64, 0.25, 0.5, 0.75, 0.95] {
            let x = dist.ppf(q);
            let q_back = dist.cdf(x);
            assert!(
                (q_back - q).abs() < 1e-12,
                "anglit cdf(ppf({q}) = {x}) = {q_back}"
            );
        }
        // Boundary identities.
        assert!((dist.ppf(0.0) - (-std::f64::consts::FRAC_PI_4)).abs() < 1e-12);
        assert!((dist.ppf(1.0) - std::f64::consts::FRAC_PI_4).abs() < 1e-12);
        assert!((dist.ppf(0.5) - 0.0).abs() < 1e-12);
    }

    #[test]
    fn anglit_mean_and_variance_match_closed_form() {
        let dist = Anglit;
        // Symmetric distribution centered at 0.
        assert_eq!(dist.mean(), 0.0);
        // var = π²/16 − 1/2 ≈ 0.116850275068
        let expected_var = std::f64::consts::PI * std::f64::consts::PI / 16.0 - 0.5;
        assert!((dist.var() - expected_var).abs() < 1e-12);
    }

    #[test]
    fn parameterless_fit_anglit_cosine_moyal() {
        // Anglit support [-π/4, π/4]
        assert_eq!(Anglit::try_fit(&[-0.5, 0.0, 0.5]).unwrap(), Anglit);
        assert!(matches!(
            Anglit::try_fit(&[1.0]),
            Err(FitError::UnsupportedData(_))
        ));
        // CosineDistribution support [-π, π]
        assert_eq!(
            CosineDistribution::try_fit(&[-2.0, 0.0, 2.0]).unwrap(),
            CosineDistribution
        );
        assert!(matches!(
            CosineDistribution::try_fit(&[10.0]),
            Err(FitError::UnsupportedData(_))
        ));
        // Moyal support ℝ; only NaN/empty are rejected.
        assert_eq!(Moyal::try_fit(&[-50.0, 0.0, 50.0]).unwrap(), Moyal);
        assert!(matches!(
            Moyal::try_fit(&[f64::INFINITY]),
            Err(FitError::UnsupportedData(_))
        ));
    }

