    fn mielke_ppf_for_test(dist: Mielke, q: f64) -> f64 {
        let mut lo = 0.0_f64;
        let mut hi = 1.0_f64;
        while dist.cdf(hi) < q {
            hi *= 2.0;
        }
        for _ in 0..80 {
            let mid = 0.5 * (lo + hi);
            if dist.cdf(mid) < q {
                lo = mid;
            } else {
                hi = mid;
            }
        }
        0.5 * (lo + hi)
    }

    #[test]
    fn fit_gap_quantile_families_recover_synthetic_shapes() {
        let exponpow = ExponPow::new(2.5);
        let data = [exponpow.ppf(0.25), exponpow.ppf(0.5), exponpow.ppf(0.75)];
        let fitted = ExponPow::try_fit(&data).expect("ExponPow fit");
        assert_close(fitted.b, 2.5, 1e-12, "ExponPow median fit");

        let exponweib = ExponWeibull::new(2.0, 1.5);
        let data = [0.1, 0.25, 0.5, 0.75, 0.9].map(|q| exponweib.ppf(q));
        let fitted = ExponWeibull::try_fit(&data).expect("ExponWeibull fit");
        assert!(
            (fitted.a - 2.0).abs() <= 0.02 && (fitted.c - 1.5).abs() <= 0.02,
            "ExponWeibull fit got a={}, c={}",
            fitted.a,
            fitted.c
        );

        let power_lognorm = PowerLognorm::new(2.0, 0.7);
        let data = [0.1, 0.25, 0.5, 0.75, 0.9].map(|q| power_lognorm.ppf(q));
        let fitted = PowerLognorm::try_fit(&data).expect("PowerLognorm fit");
        assert!(
            (fitted.c - 2.0).abs() <= 0.02 && (fitted.s - 0.7).abs() <= 0.02,
            "PowerLognorm fit got c={}, s={}",
            fitted.c,
            fitted.s
        );

        let genextreme = GenExtreme::new(0.2);
        let data = [0.1, 0.25, 0.5, 0.75, 0.9].map(|q| genextreme.ppf(q));
        let fitted = GenExtreme::try_fit(&data).expect("GenExtreme fit");
        assert_close(fitted.c, 0.2, 0.005, "GenExtreme quartile fit");

        let mielke = Mielke::new(2.0, 4.0);
        let data = [0.1, 0.25, 0.5, 0.75, 0.9].map(|q| mielke_ppf_for_test(mielke, q));
        let fitted = Mielke::try_fit(&data).expect("Mielke fit");
        assert!(
            (fitted.k - 2.0).abs() <= 0.1 && (fitted.s - 4.0).abs() <= 0.1,
            "Mielke fit got k={}, s={}",
            fitted.k,
            fitted.s
        );
    }

    #[test]
    fn fit_gap_moment_and_circular_families_validate_support_and_shapes() {
        let rdist_std = (1.0_f64 / 5.0).sqrt();
        let fitted = RDist::try_fit(&[-rdist_std, rdist_std]).expect("RDist fit");
        assert_close(fitted.c, 4.0, 1e-12, "RDist variance inversion");

        let recip = RecipInvGauss::try_fit(&[1.0, 2.0, 4.0]).expect("RecipInvGauss fit");
        assert_close(
            recip.mu,
            (1.0 + 0.5 + 0.25) / 3.0,
            1e-12,
            "RecipInvGauss reciprocal mean",
        );

        let tukey_std = (1.0_f64 / 3.0).sqrt();
        let fitted = TukeyLambda::try_fit(&[-tukey_std, tukey_std]).expect("TukeyLambda fit");
        assert_close(fitted.lam, 1.0, 1e-6, "TukeyLambda variance inversion");

        let true_nct = NoncentralT::new(8.05, 1.1);
        let nct_mean = true_nct.mean();
        let nct_std = true_nct.var().sqrt();
        let fitted = NoncentralT::try_fit(&[
            nct_mean - nct_std,
            nct_mean + nct_std,
            nct_mean - nct_std,
            nct_mean + nct_std,
        ])
        .expect("NoncentralT fit");
        assert!(
            (fitted.df - true_nct.df).abs() <= 0.11 && (fitted.nc - true_nct.nc).abs() <= 0.03,
            "NoncentralT fit got df={}, nc={}",
            fitted.df,
            fitted.nc
        );

        let skewed = [-0.3_f64, 0.0, 0.5, 1.2, 2.0];
        let sample_skew = sample_standardized_skewness(&skewed);
        let fitted = SkewNorm::try_fit(&skewed).expect("SkewNorm fit");
        assert!(fitted.a > 0.0, "positive sample skew should fit positive a");
        assert_close(
            fitted.skewness(),
            sample_skew,
            1e-10,
            "SkewNorm skew inversion",
        );

        assert_eq!(KsTwoBign::try_fit(&[0.1, 0.5, 1.0]).unwrap(), KsTwoBign);
        assert!(matches!(
            KsTwoBign::try_fit(&[-0.1]),
            Err(FitError::UnsupportedData(_))
        ));

        let wrapped = WrapCauchy::try_fit(&[0.0, 0.2, 2.0 * PI - 0.2]).expect("WrapCauchy fit");
        assert!(
            wrapped.c > 0.9 && wrapped.c < 1.0,
            "WrapCauchy concentration = {}",
            wrapped.c
        );

        let vonmises = VonMises::try_fit(&[-0.2, -0.1, 0.0, 0.1, 0.2]).expect("VonMises fit");
        assert!(
            vonmises.kappa > 0.0,
            "clustered angles should produce kappa > 0"
        );
        assert!(
            vonmises.loc.abs() < 1e-12,
            "symmetric angle cluster should fit loc=0, got {}",
            vonmises.loc
        );
    }

    #[test]
    fn circular_stats_metamorphic_known_distributions() {
        // /testing-metamorphic + /testing-conformance-harnesses:
        //   - circmean of n equally-spaced angles {0, 2π/n, 4π/n, …} → 0
        //     (rotation-symmetric: vector sum is zero).
        //   - circvar of single point = 0 (zero spread).
        //   - circmean is rotation-equivariant: circmean(x + α) ≡
        //     circmean(x) + α (mod 2π).
        let pi = std::f64::consts::PI;
        let symm: Vec<f64> = (0..6).map(|k| k as f64 * 2.0 * pi / 6.0).collect();
        let cv = circvar(&symm);
        // Rotation-symmetric → R = 0 → variance = 1.
        assert!((cv - 1.0).abs() < 1e-12, "circvar(symmetric) = {cv}");

        // Single point → variance = 0.
        let single = [0.42_f64];
        let cv1 = circvar(&single);
        assert!(cv1.abs() < 1e-12, "circvar(single) = {cv1}");

        // Rotation equivariance: circmean(x + α) = circmean(x) + α (mod 2π).
        let x = [0.1_f64, 0.3, 0.5];
        let alpha = 1.2_f64;
        let m_x = circmean(&x);
        let x_shifted: Vec<f64> = x.iter().map(|&v| v + alpha).collect();
        let m_shifted = circmean(&x_shifted);
        // Compare modulo 2π.
        let diff = ((m_shifted - m_x - alpha) / (2.0 * pi)).round() * 2.0 * pi;
        let residual = m_shifted - m_x - alpha - diff;
        assert!(
            residual.abs() < 1e-12,
            "circmean rotation equivariance: residual = {residual}"
        );
    }

    #[test]
    fn pmean_metamorphic_p1_is_arithmetic_p_minus_1_is_harmonic() {
        // /testing-metamorphic: power mean specializes to known means.
        //   p =  1 → arithmetic mean
        //   p = −1 → harmonic mean
        //   p =  0 → geometric mean (already short-circuits)
        let data = [1.0_f64, 2.0, 4.0, 8.0];
        let arith = data.iter().sum::<f64>() / data.len() as f64;
        let harm = data.len() as f64 / data.iter().map(|x| 1.0 / x).sum::<f64>();
        let geo = data.iter().map(|x| x.ln()).sum::<f64>() / data.len() as f64;
        let geo = geo.exp();
        assert!((pmean(&data, 1.0) - arith).abs() < 1e-12);
        assert!((pmean(&data, -1.0) - harm).abs() < 1e-12);
        assert!((pmean(&data, 0.0) - geo).abs() < 1e-12);
        // Power-mean inequality at p > p': arithmetic ≥ geometric ≥ harmonic.
        assert!(arith >= geo - 1e-12);
        assert!(geo >= harm - 1e-12);
    }

    #[test]
    fn entropy_matches_scipy_reference_points() {
        // /testing-conformance-harnesses: pin Shannon entropy at
        // closed-form values matching scipy.stats.entropy:
        //   entropy([0.5, 0.5]) = ln(2)
        //   entropy([1.0]) = 0
        //   entropy([0.25; 4]) = 2·ln(2)
        //   entropy([0.5, 0.5], base=2) = 1 (bits)
        let ln_2 = 2.0_f64.ln();
        assert!((entropy(&[0.5_f64, 0.5], None) - ln_2).abs() < 1e-12);
        assert!(entropy(&[1.0_f64], None).abs() < 1e-12);
        assert!((entropy(&[0.25_f64, 0.25, 0.25, 0.25], None) - 2.0 * ln_2).abs() < 1e-12);
        assert!((entropy(&[0.5_f64, 0.5], Some(2.0)) - 1.0).abs() < 1e-12);
        // Empty input → 0 by fsci convention; scipy raises but the
        // existing API contract returns 0.
        assert_eq!(entropy(&[], None), 0.0);
        // Negative probability → −∞ sentinel (out-of-domain).
        assert!(entropy(&[-0.5_f64, 1.5], None).is_infinite());
    }

    #[test]
    fn three_more_distributions_have_closed_form_mode() {
        // /modes-of-reasoning extension [frankenscipy-71mv5].
        // StudentT mode = 0.
        assert_close(StudentT::new(5.0).mode(), 0.0, 1e-12, "StudentT mode = 0");
        // BetaDist(a=3, b=2): mode = (3-1)/(3+2-2) = 2/3.
        assert_close(
            BetaDist::new(3.0, 2.0).mode(),
            2.0 / 3.0,
            1e-12,
            "BetaDist mode = (a-1)/(a+b-2)",
        );
        // BetaDist(a=1, b=1): mode = NaN (uniform; no interior peak).
        assert!(
            BetaDist::new(1.0, 1.0).mode().is_nan(),
            "BetaDist a=b=1 mode is NaN"
        );
        // BetaDist(a=0.5, b=2): mode = NaN (a < 1, pdf diverges at 0).
        assert!(
            BetaDist::new(0.5, 2.0).mode().is_nan(),
            "BetaDist a<1 mode is NaN"
        );
        // InverseGamma(a=2): mode = 1/(2+1) = 1/3.
        assert_close(
            InverseGamma::new(2.0).mode(),
            1.0 / 3.0,
            1e-12,
            "InverseGamma mode = 1/(a+1)",
        );
    }

    #[test]
    fn four_distributions_have_closed_form_skewness() {
        // /mock-code-finder [frankenscipy-y718j]: pin closed-form
        // skewness for 4 distributions that previously inherited NaN.

        // Pareto(b=4, scale=1): 2(1+4)/(4-3) · √((4-2)/4) = 10·√0.5
        let p = Pareto::new(4.0, 1.0);
        assert_close(
            p.skewness(),
            10.0 * 0.5_f64.sqrt(),
            1e-12,
            "Pareto(b=4) skewness",
        );
        // Pareto(b=3): NaN (boundary, third moment undefined).
        assert!(Pareto::new(3.0, 1.0).skewness().is_nan(), "Pareto(b=3) NaN");
        assert!(Pareto::new(2.0, 1.0).skewness().is_nan(), "Pareto(b=2) NaN");

        // Rayleigh: 2(π-3)·√π / (4-π)^1.5 ≈ 0.6311
        let r = Rayleigh::new(1.0);
        let expected_r = 2.0 * (PI - 3.0) * PI.sqrt() / (4.0 - PI).powf(1.5);
        assert_close(r.skewness(), expected_r, 1e-12, "Rayleigh skewness");
        // Constant in scale: scaling shouldn't change skewness.
        assert_close(
            Rayleigh::new(7.5).skewness(),
            expected_r,
            1e-12,
            "Rayleigh skewness scale-invariant",
        );

        // GumbelLeft: -1.139547... (mirror of Gumbel).
        let gl = GumbelLeft::new(0.0, 1.0);
        assert_close(
            gl.skewness(),
            -1.139_547_099_404_648_7,
            1e-12,
            "GumbelLeft skewness",
        );
        // Gumbel skewness positive.
        assert_close(
            Gumbel::new(0.0, 1.0).skewness(),
            1.139_547_099_404_648_7,
            1e-12,
            "Gumbel skewness (sign check)",
        );

        // Maxwell: 2√2·(16-5π) / (3π-8)^(3/2) ≈ 0.4857
        let m = Maxwell::new(1.0);
        let expected_m =
            2.0 * std::f64::consts::SQRT_2 * (16.0 - 5.0 * PI) / (3.0 * PI - 8.0).powf(1.5);
        assert_close(m.skewness(), expected_m, 1e-12, "Maxwell skewness");
    }

    #[test]
    fn bradford_closed_form_anchors() {
        // /testing-golden-artifacts for [frankenscipy-04ghb]: Bradford
        // had fit-side tests but no pdf/cdf/ppf/mean anchors.
        for &c in &[0.5_f64, 1.0, 2.0, 5.0] {
            let bd = Bradford::new(c);
            let k = (1.0 + c).ln();

            // (1) cdf boundaries.
            assert_eq!(bd.cdf(0.0), 0.0, "Bradford(c={c}) cdf(0) = 0");
            assert_eq!(bd.cdf(1.0), 1.0, "Bradford(c={c}) cdf(1) = 1");
            // (2) ppf boundaries.
            assert_close(
                bd.ppf(0.0),
                0.0,
                1e-12,
                &format!("Bradford(c={c}) ppf(0) = 0"),
            );
            assert_close(
                bd.ppf(1.0),
                1.0,
                1e-12,
                &format!("Bradford(c={c}) ppf(1) = 1"),
            );
            // (3) pdf at boundaries (closed form).
            assert_close(
                bd.pdf(0.0),
                c / k,
                1e-12,
                &format!("Bradford(c={c}) pdf(0) = c/ln(1+c)"),
            );
            assert_close(
                bd.pdf(1.0),
                c / ((1.0 + c) * k),
                1e-12,
                &format!("Bradford(c={c}) pdf(1) = c/((1+c)·ln(1+c))"),
            );
            // (4) cdf at midpoint x=0.5: ln(1 + c·0.5)/ln(1+c).
            assert_close(
                bd.cdf(0.5),
                (1.0 + c * 0.5).ln() / k,
                1e-12,
                &format!("Bradford(c={c}) cdf(0.5) closed form"),
            );
            // (5) ppf↔cdf roundtrip.
            for &q in &[0.1_f64, 0.25, 0.5, 0.75, 0.9] {
                let x = bd.ppf(q);
                let r = bd.cdf(x);
                assert_close(r, q, 1e-9, &format!("Bradford(c={c}) cdf(ppf({q})) = {r}"));
            }
            // (6) mean closed form.
            assert_close(
                bd.mean(),
                (c - k) / (c * k),
                1e-12,
                &format!("Bradford(c={c}) mean = (c - ln(1+c))/(c·ln(1+c))"),
            );
        }
    }

    #[test]
    fn lomax_closed_form_entropy() {
        // /modes-of-reasoning extension [frankenscipy-2ea4i]:
        // H(Lomax(c)) = 1 + 1/c − ln(c).
        let lomax = Lomax::new(2.0);
        let expected = 1.0 + 1.0 / 2.0 - 2.0_f64.ln();
        assert_close(lomax.entropy(), expected, 1e-12, "Lomax entropy");
        // Sanity: c=1 → H = 1 + 1 - 0 = 2 (exponential limit).
        assert_close(
            Lomax::new(1.0).entropy(),
            2.0,
            1e-12,
            "Lomax(c=1) entropy = 2",
        );
    }

    #[test]
    fn five_distributions_have_closed_form_entropy() {
        // /modes-of-reasoning [frankenscipy-vngzr]: pin closed-form
        // entropy formulas. Each value is independent of any test
        // harness — pure closed-form arithmetic in the implementation.

        // HalfNormal: 0.5·ln(πe/2) ≈ 0.7257913526...
        assert_close(
            HalfNormal.entropy(),
            0.5 * (PI * std::f64::consts::E / 2.0).ln(),
            1e-12,
            "HalfNormal entropy = 0.5·ln(πe/2)",
        );

        // Pareto(b=2, scale=3): ln(3/2) + 1/2 + 1.
        let p = Pareto::new(2.0, 3.0);
        assert_close(
            p.entropy(),
            (3.0_f64 / 2.0).ln() + 0.5 + 1.0,
            1e-12,
            "Pareto entropy = ln(scale/b) + 1/b + 1",
        );

        // Rayleigh(σ=2): 1 + ln(2/√2) + γ/2 = 1 + ln(√2) + γ/2.
        let r = Rayleigh::new(2.0);
        let expected_r =
            1.0 + (2.0_f64 / std::f64::consts::SQRT_2).ln() + 0.577_215_664_901_532_9 / 2.0;
        assert_close(r.entropy(), expected_r, 1e-12, "Rayleigh entropy");

        // GumbelLeft(loc=-1, scale=2): ln(2) + γ + 1.
        let gl = GumbelLeft::new(-1.0, 2.0);
        assert_close(
            gl.entropy(),
            2.0_f64.ln() + 0.577_215_664_901_532_9 + 1.0,
            1e-12,
            "GumbelLeft entropy",
        );

        // Triangular(left=0, mode=1, right=2): 0.5 + ln(2/2) = 0.5.
        let t = Triangular::new(0.0, 1.0, 2.0);
        assert_close(t.entropy(), 0.5, 1e-12, "Triangular entropy at width 2");
    }

    #[test]
    fn nine_distributions_now_have_closed_form_mode() {
        // /modes-of-reasoning [frankenscipy-cxgdg]: pin closed-form
        // mode for the 9 distributions that previously inherited the
        // trait-default NaN. Independent of any test harness — these
        // anchors guard the mode against regressions.
        assert_close(
            ChiSquared::new(5.0).mode(),
            3.0,
            1e-12,
            "ChiSquared mode = max(df-2, 0)",
        );
        assert_close(
            ChiSquared::new(1.0).mode(),
            0.0,
            1e-12,
            "ChiSquared mode lower clamp",
        );
        // Lognormal mode = scale · exp(-s²); for s=1, scale=e: mode = e · e^-1 = 1.
        let ln = Lognormal {
            s: 1.0,
            scale: std::f64::consts::E,
        };
        assert_close(ln.mode(), 1.0, 1e-12, "Lognormal mode");
        assert_close(
            Pareto::new(2.0, 3.0).mode(),
            3.0,
            1e-12,
            "Pareto mode = scale",
        );
        assert_close(
            Rayleigh::new(2.5).mode(),
            2.5,
            1e-12,
            "Rayleigh mode = scale",
        );
        assert_close(
            GumbelLeft::new(-1.5, 2.0).mode(),
            -1.5,
            1e-12,
            "GumbelLeft mode = loc",
        );
        assert_close(
            Maxwell::new(1.0).mode(),
            std::f64::consts::SQRT_2,
            1e-12,
            "Maxwell mode = scale·√2",
        );
        assert_close(HalfNormal.mode(), 0.0, 1e-12, "HalfNormal mode = 0");
        assert_close(HalfLogistic.mode(), 0.0, 1e-12, "HalfLogistic mode = 0");
        assert_close(HalfCauchy.mode(), 0.0, 1e-12, "HalfCauchy mode = 0");
    }

    #[test]
    fn fatigue_life_closed_form_anchors() {
        // /testing-golden-artifacts for [frankenscipy-jodxb]: FatigueLife
        // (Birnbaum-Saunders) had zero tests. Pin closed-form anchors.

        // (1) cdf(0) = 0 and pdf(0) = 0 across multiple c.
        for &c in &[0.1_f64, 0.5, 1.0, 2.0] {
            let f = FatigueLife::new(c);
            assert_eq!(f.cdf(0.0), 0.0);
            assert_eq!(f.pdf(0.0), 0.0);
            // (2) cdf(1) = 0.5 — at x=1, the z = (√1 - 1/√1)/c = 0,
            // and Φ(0) = 0.5 universally across c.
            assert_close(f.cdf(1.0), 0.5, 1e-12, &format!("FL(c={c}) cdf(1) = 0.5"));
            // (3) ppf(0.5) = 1 (inverse).
            assert_close(f.ppf(0.5), 1.0, 1e-9, &format!("FL(c={c}) ppf(0.5) = 1"));
            // (4) mean closed form: 1 + c²/2.
            assert_close(
                f.mean(),
                1.0 + 0.5 * c * c,
                1e-12,
                &format!("FL(c={c}) mean"),
            );
            // (5) var closed form: c² · (5c² + 4) / 4.
            assert_close(
                f.var(),
                0.25 * c * c * (5.0 * c * c + 4.0),
                1e-12,
                &format!("FL(c={c}) var"),
            );
        }
    }

